import type { IAtomicStore } from '../store/interfaces.ts';
import type { IAuditWriter, IAuditReader, IAuditAdmin, AuditEntry, StoredAuditEntry, LogQuery } from './types.ts';
import type { LogId } from '../brand.ts';
import { generateLogId } from '../brand.ts';
import { shouldLogAudit } from './log-policy.ts';
import { shouldPersist } from './persistence-policy.ts';
import { resolveFacility, encodePriority } from './kern-level.ts';
import { formatDmesgLine } from '../utils/dmesg.ts';
import { encodeCursor, decodeCursor, cursorFromEntry, xorHash } from './types.ts';
import { getBootId } from './context.ts';

const PFX_AUDIT = 'audit:ring:';
const IDX_AUDIT = 'audit:ring:ids';
const MAX_IN_MEMORY = 2000;
const MAX_KV_BATCH = 1000;

/** Strip _-prefixed keys to prevent trusted field forgery (journald convention). */
function sanitizeMetadata(meta: Record<string, unknown> | undefined): Record<string, unknown> | undefined {
  if (!meta) return undefined;
  const cleaned: Record<string, unknown> = {};
  let hasKeys = false;
  for (const [k, v] of Object.entries(meta)) {
    if (!k.startsWith('_')) { cleaned[k] = v; hasKeys = true; }
  }
  return hasKeys ? cleaned : undefined;
}

export class HybridAuditLogger implements IAuditWriter, IAuditReader, IAuditAdmin {
  readonly #atomic: IAtomicStore | undefined;
  readonly #memory: StoredAuditEntry[] = [];
  readonly #maxInMemory: number;
  #seq = 0;
  readonly #bootId: string;
  readonly #machineHash: string;

  public constructor(atomic?: IAtomicStore, maxInMemory = MAX_IN_MEMORY) {
    this.#atomic = atomic;
    this.#maxInMemory = maxInMemory;
    // Derive machine hash from boot ID (stable within a process lifetime).
    this.#bootId = getBootId() ?? '00000000-0000-0000-0000-000000000000';
    this.#machineHash = hashBootId(this.#bootId);
  }

  public write(entry: AuditEntry): void {
    void this.#store(entry);
  }

  async #store(entry: AuditEntry): Promise<LogId> {
    const id = generateLogId();
    const now = Date.now();
    const facilityCode = resolveFacility(entry.facility);
    // Strip _-prefixed keys from metadata to prevent trusted field forgery (journald convention).
    const safeMeta = sanitizeMetadata(entry.metadata);
    // Generate journald-style cursor with tamper-detection xor_hash.
    const seq = ++this.#seq;
    const cursor = encodeCursor(cursorFromEntry(
      { id, timestamp: now } as unknown as StoredAuditEntry,
      this.#bootId,
      seq,
      this.#machineHash,
    ));
    const stored: StoredAuditEntry = {
      id, timestamp: now, priority: encodePriority(facilityCode, entry.level),
      level: entry.level, facility: entry.facility,
      message: entry.message, actorId: entry.actorId,
      cursor,
      ...(entry.trusted ? { trusted: entry.trusted } : {}),
      ...(safeMeta ? { metadata: safeMeta } : {}),
    };

    this.#memory.push(stored);
    if (this.#memory.length > this.#maxInMemory) this.#memory.shift();

    // Gate durable persistence with persistence policy (KV/DO costs real money).
    // Memory ring buffer and console output are free — always allowed.
    if (this.#atomic && shouldPersist(entry)) {
      await this.#persistToStore(stored).catch(() => { /* noop */ });
    }

    if (shouldLogAudit(entry.facility, entry.level)) {
      console.log(formatDmesgLine(entry.message, entry.actorId));
    }
    return id;
  }

  public async query(params?: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    let all = this.#filterEntries(params);
    if (this.#atomic) {
      const fromKV = await this.#queryFromStore(params ?? {});
      const memIds = new Set(all.map(e => e.id));
      all = [...all, ...fromKV.filter(e => !memIds.has(e.id))].sort((a, b) => b.timestamp - a.timestamp);
    }
    // Apply afterCursor filter — skip entries up to and including the cursor position.
    if (params?.afterCursor) {
      const cursor = decodeCursor(params.afterCursor);
      if (cursor && this.#validateCursor(cursor)) {
        all = all.filter(e => {
          if (!e.cursor) return true; // entries without cursor pass through
          const ec = decodeCursor(e.cursor);
          return ec ? ec.i > cursor.i : true;
        });
      }
    }
    const total = all.length;
    if (params?.offset) all = all.slice(params.offset);
    if (params?.limit) all = all.slice(0, params.limit);
    // Return the cursor of the last entry as nextCursor for incremental consumption.
    const lastCursor: string | undefined = all.at(-1)?.cursor;
    return { entries: all, total, ...(lastCursor ? { nextCursor: lastCursor } : {}) };
  }

  /** Validate cursor integrity via xor_hash. Returns false if tampered. */
  #validateCursor(c: { s: string; i: number; b: string; m: number; t: number; x: string }): boolean {
    const expected = xorHash({ s: c.s, i: c.i, b: c.b, m: c.m, t: c.t });
    return c.x === expected;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async getById(id: LogId): Promise<StoredAuditEntry | null> {
    return this.#memory.find(e => e.id === id) ?? null;
  }

  public async queryAsync(params: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    return this.query(params);
  }

  #filterEntries(params?: LogQuery): StoredAuditEntry[] {
    let f = [...this.#memory];
    if (params?.facility) f = f.filter(e => e.facility === params.facility);
    if (params?.startTs !== undefined) f = f.filter(e => e.timestamp >= params.startTs!);
    if (params?.endTs !== undefined) f = f.filter(e => e.timestamp <= params.endTs!);
    return f;
  }

  async #persistToStore(e: StoredAuditEntry): Promise<void> {
    if (!this.#atomic) return;
    const idx = await this.#atomic.get<string[]>(IDX_AUDIT);
    const ids = idx?.value ?? [];
    ids.push(e.id);
    if (ids.length > MAX_KV_BATCH) ids.shift();
    await this.#atomic.set(`${PFX_AUDIT}${e.id}`, e, null);
    await this.#atomic.set(IDX_AUDIT, ids, idx?.version ?? null);
  }

  async #queryFromStore(params: LogQuery): Promise<StoredAuditEntry[]> {
    if (!this.#atomic) return [];
    const idx = await this.#atomic.get<string[]>(IDX_AUDIT);
    if (!idx) return [];
    const entries = (await Promise.all(
      idx.value.map(id => this.#atomic!.get<StoredAuditEntry>(PFX_AUDIT + id)),
    )).filter(e => e).map(e => e!.value);
    let f = entries;
    if (params.facility) f = f.filter(e => e.facility === params.facility);
    if (params.startTs !== undefined) f = f.filter(e => e.timestamp >= params.startTs!);
    if (params.endTs !== undefined) f = f.filter(e => e.timestamp <= params.endTs!);
    return f;
  }

  // ─── IAuditAdmin ───


  public async prune(beforeTs: number): Promise<number> {
    // Filter in-memory
    const kept = this.#memory.filter(e => e.timestamp >= beforeTs);
    this.#memory.length = 0;
    this.#memory.push(...kept);
    // Filter KV
    if (this.#atomic) {
      const idx = await this.#atomic.get<string[]>(IDX_AUDIT);
      if (idx) {
        let removed = 0;
        for (const id of idx.value) {
          const entry = await this.#atomic.get<StoredAuditEntry>(PFX_AUDIT + id);
          if (entry && entry.value.timestamp < beforeTs) {
            await this.#atomic.set(PFX_AUDIT + id, null, entry.version);
            removed++;
          }
        }
        return removed;
      }
    }
    return 0;
  }

  public async pruneByIds(ids: readonly string[]): Promise<number> {
    const idSet = new Set(ids);
    const kept = this.#memory.filter(e => !idSet.has(e.id));
    this.#memory.length = 0;
    this.#memory.push(...kept);
    if (this.#atomic) {
      let removed = 0;
      for (const id of idSet) {
        const entry = await this.#atomic.get<StoredAuditEntry>(PFX_AUDIT + id);
        if (entry) {
          await this.#atomic.set(PFX_AUDIT + id, null, entry.version);
          removed++;
        }
      }
      return removed;
    }
    return 0;
  }
}

/** Derive a short machine hash from a boot UUID for cursor.s field. */
function hashBootId(bootId: string): string {
  let h = 0;
  for (let i = 0; i < bootId.length; i++) h ^= bootId.charCodeAt(i) << ((i % 4) * 8);
  return (h >>> 0).toString(16).padStart(8, '0');
}

/**
 * Kernel log levels (0-7), matching syslog convention.
 *
 * <0> KERN_EMERG   — 系统不可用
 * <1> KERN_ALERT   — 需要立即操作
 * <2> KERN_CRIT    — 严重条件
 * <3> KERN_ERR     — 错误条件
 * <4> KERN_WARNING — 警告条件
 * <5> KERN_NOTICE  — 正常但重要的通知
 * <6> KERN_INFO    — 信息性消息
 * <7> KERN_DEBUG   — 调试级别消息
 */
export const enum KernLevel {
  EMERG   = 0,
  ALERT   = 1,
  CRIT    = 2,
  ERR     = 3,
  WARNING = 4,
  NOTICE  = 5,
  INFO    = 6,
  DEBUG   = 7,
}

const KERN_NAMES: Record<number, string> = {
  0: 'EMERG', 1: 'ALERT', 2: 'CRIT', 3: 'ERR',
  4: 'WARNING', 5: 'NOTICE', 6: 'INFO', 7: 'DEBUG',
};

export function kernLevelName(level: KernLevel): string {
  return KERN_NAMES[level] ?? `LEVEL_${String(level)}`;
}

// ═══════════════════════════════════════════════════════════
// Facility encoding — syslog-style facility × 8 + severity
// ═══════════════════════════════════════════════════════════

/** Syslog-style facility codes. Values 0-23, with 16-23 reserved for local use. */
export const enum AuditFacility {
  KERN     = 0,  // 内核/系统
  SANDBOX  = 1,  // 沙箱操作
  IMAGE    = 2,  // 镜像管理
  AUTH     = 3,  // 认证
  PERM     = 4,  // 权限检查
  NETWORK  = 5,  // 网络操作
  VOLUME   = 6,  // 存储卷
  HTTP     = 7,  // HTTP 请求
  PROVIDER = 8,  // Provider 调用
  DNS      = 9,  // DNS 操作
  QUEUE    = 10, // 消息队列
  TEMPLATE = 11, // 模板解析
  // 16-23: 留给自定义
  LOCAL0 = 16, LOCAL1 = 17, LOCAL2 = 18, LOCAL3 = 19,
  LOCAL4 = 20, LOCAL5 = 21, LOCAL6 = 22, LOCAL7 = 23,
}

const FACILITY_NAMES: Record<number, string> = {
  0: 'kern', 1: 'sandbox', 2: 'image', 3: 'auth', 4: 'perm',
  5: 'network', 6: 'volume', 7: 'http', 8: 'provider', 9: 'dns',
  10: 'queue', 11: 'template',
  16: 'local0', 17: 'local1', 18: 'local2', 19: 'local3',
  20: 'local4', 21: 'local5', 22: 'local6', 23: 'local7',
};

/**
 * Map facility string name to numeric code. Unknown facilities → LOCAL0 (16).
 *
 * Typed as `as const` + `satisfies` to preserve literal key types for
 * `FacilityName` union — typos in facility strings → compile error.
 */
const NAME_TO_FACILITY = {
  kern: AuditFacility.KERN, system: AuditFacility.KERN,
  sandbox: AuditFacility.SANDBOX, 'sandbox-service': AuditFacility.SANDBOX,
  image: AuditFacility.IMAGE, 'image-pull': AuditFacility.IMAGE,
  auth: AuditFacility.AUTH, authz: AuditFacility.AUTH,
  perm: AuditFacility.PERM, 'perm-audit': AuditFacility.PERM,
  network: AuditFacility.NETWORK, secgroup: AuditFacility.NETWORK,
  volume: AuditFacility.VOLUME,
  http: AuditFacility.HTTP,
  provider: AuditFacility.PROVIDER,
  dns: AuditFacility.DNS, 'dns-service': AuditFacility.DNS,
  queue: AuditFacility.QUEUE,
  template: AuditFacility.TEMPLATE,
  'user-service': AuditFacility.AUTH,
  sysgrp: AuditFacility.PERM,
  subnet: AuditFacility.NETWORK,
} as const satisfies Record<string, AuditFacility>;

/** Known facility name — derived from NAME_TO_FACILITY keys. Typo → compile error. */
export type FacilityName = keyof typeof NAME_TO_FACILITY;

/** Encode facility + severity into a single priority integer (0-191). */
export function encodePriority(facility: AuditFacility, level: KernLevel): number {
  return (facility << 3) | level;
}

/** Decode a priority integer back to facility and severity. */
export function decodePriority(priority: number): { facility: AuditFacility; level: KernLevel } {
  return { facility: (priority >> 3), level: (priority & 0x7) };
}

/** Look up numeric facility from a string name. Unknown facilities → LOCAL0. */
export function resolveFacility(name: string): AuditFacility {
  return (NAME_TO_FACILITY as Record<string, AuditFacility | undefined>)[name.toLowerCase()] ?? AuditFacility.LOCAL0;
}

/** Get the human-readable name of a numeric facility. */
export function facilityName(facility: AuditFacility): string {
  return FACILITY_NAMES[facility] ?? `local${String(facility - 16)}`;
}

import type { IAtomicStore } from '../store/interfaces.ts';
import type { IAuditWriter, IAuditReader, IAuditAdmin, AuditEntry, StoredAuditEntry, LogQuery } from './types.ts';
import type { LogId } from '../brand.ts';
import { generateLogId } from '../brand.ts';
import { resolveFacility, encodePriority } from './kern-level.ts';

const AUDIT_TTL_SEC = 7 * 24 * 60 * 60;
const AUDIT_PREFIX = 'audit:';
const MAX_INDEX_ENTRIES = 10_000;

export class KvAuditLogger implements IAuditWriter, IAuditReader, IAuditAdmin {
  readonly #entries: StoredAuditEntry[] = [];
  readonly #capacity: number;

  public constructor(
    private readonly atomic: IAtomicStore,
    capacity = MAX_INDEX_ENTRIES,
  ) {
    this.#capacity = capacity;
  }

  public write(entry: AuditEntry): void {
    void this.#store(entry);
  }

  async #store(entry: AuditEntry): Promise<LogId> {
    const id = generateLogId();
    const now = Date.now();
    const facilityCode = resolveFacility(entry.facility);

    await this.atomic.set(AUDIT_PREFIX + id, entry, null, AUDIT_TTL_SEC);

    const stored: StoredAuditEntry = {
      id, timestamp: now, priority: encodePriority(facilityCode, entry.level),
      level: entry.level, facility: entry.facility,
      message: entry.message, actorId: entry.actorId,
      ...(entry.metadata ? { metadata: entry.metadata } : {}),
    };
    this.#entries.push(stored);
    if (this.#entries.length > this.#capacity) this.#entries.shift();
    return id;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async query(params?: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    let f = [...this.#entries];
    if (params?.facility) f = f.filter(e => e.facility === params.facility);
    if (params?.startTs !== undefined) f = f.filter(e => e.timestamp >= params.startTs!);
    if (params?.endTs !== undefined) f = f.filter(e => e.timestamp <= params.endTs!);
    const total = f.length;
    if (params?.limit) f = f.slice(0, params.limit);
    return { entries: f, total };
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async getById(id: LogId): Promise<StoredAuditEntry | null> {
    return this.#entries.find(e => e.id === id) ?? null;
  }

  // ─── IAuditAdmin ───



  public async prune(beforeTs: number): Promise<number> {
    const idx = await this.atomic.get<string[]>(AUDIT_PREFIX + 'ids');
    if (!idx) return 0;
    let removed = 0;
    const kept: string[] = [];
    for (const id of idx.value) {
      const entry = await this.atomic.get<StoredAuditEntry>(AUDIT_PREFIX + id);
      if (entry && entry.value.timestamp < beforeTs) {
        await this.atomic.set(AUDIT_PREFIX + id, null, entry.version);
        removed++;
      } else {
        kept.push(id);
      }
    }
    if (removed > 0) await this.atomic.set(AUDIT_PREFIX + 'ids', kept, idx.version);
    return removed;
  }

  public async pruneByIds(ids: readonly string[]): Promise<number> {
    const idx = await this.atomic.get<string[]>(AUDIT_PREFIX + 'ids');
    if (!idx) return 0;
    let removed = 0;
    const idSet = new Set(ids);
    for (const id of idSet) {
      const entry = await this.atomic.get<StoredAuditEntry>(AUDIT_PREFIX + id);
      if (entry) {
        await this.atomic.set(AUDIT_PREFIX + id, null, entry.version);
        removed++;
      }
    }
    if (removed > 0) {
      await this.atomic.set(AUDIT_PREFIX + 'ids', idx.value.filter(i => !idSet.has(i)), idx.version);
    }
    return removed;
  }
}

import type { IAuditWriter, IAuditReader, IAuditAdmin, AuditEntry, StoredAuditEntry, LogQuery } from './types.ts';
import type { LogId } from '../brand.ts';
import { generateLogId } from '../brand.ts';
import { shouldLogAudit } from './log-policy.ts';
import { resolveFacility, encodePriority } from './kern-level.ts';
import { formatDmesgLine } from '../utils/dmesg.ts';

const MAX_ENTRIES = 2000;

export class LocalAuditLogger implements IAuditWriter, IAuditReader, IAuditAdmin {
  readonly #entries: StoredAuditEntry[] = [];
  readonly #capacity: number;

  public constructor(capacity = MAX_ENTRIES) {
    this.#capacity = capacity;
  }

  public write(entry: AuditEntry): void {
    void this.#store(entry);
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  async #store(entry: AuditEntry): Promise<LogId> {
    const id = generateLogId();
    const now = Date.now();
    const facilityCode = resolveFacility(entry.facility);
    const stored: StoredAuditEntry = {
      id, timestamp: now, priority: encodePriority(facilityCode, entry.level),
      level: entry.level, facility: entry.facility,
      message: entry.message, actorId: entry.actorId,
      ...(entry.metadata ? { metadata: entry.metadata } : {}),
    };
    this.#entries.push(stored);
    if (this.#entries.length > this.#capacity) this.#entries.shift();

    if (shouldLogAudit(entry.facility, entry.level)) {
      console.log(formatDmesgLine(entry.message, entry.actorId));
    }
    return id;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async query(params?: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    let f = [...this.#entries];
    if (params?.facility) f = f.filter(e => e.facility === params.facility);
    if (params?.startTs !== undefined) f = f.filter(e => e.timestamp >= params.startTs!);
    if (params?.endTs !== undefined) f = f.filter(e => e.timestamp <= params.endTs!);
    const total = f.length;
    if (params?.limit) f = f.slice(0, params.limit);
    return { entries: f, total };
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async getById(id: LogId): Promise<StoredAuditEntry | null> {
    return this.#entries.find(e => e.id === id) ?? null;
  }

  public stats(): { count: number; capacity: number } {
    return { count: this.#entries.length, capacity: this.#capacity };
  }

  // ─── IAuditAdmin ───



  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async prune(beforeTs: number): Promise<number> {
    const kept = this.#entries.filter(e => e.timestamp >= beforeTs);
    const removed = this.#entries.length - kept.length;
    this.#entries.length = 0;
    this.#entries.push(...kept);
    return removed;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async pruneByIds(ids: readonly string[]): Promise<number> {
    const idSet = new Set(ids);
    const before = this.#entries.length;
    const kept = this.#entries.filter(e => !idSet.has(e.id));
    this.#entries.length = 0;
    this.#entries.push(...kept);
    return before - kept.length;
  }
}

/**
 * Log namespace isolation — per-facility + per-sandbox query helpers.
 *
 * journald §4 model:
 *   _SYSTEMD_UNIT  → per-service isolation
 *   _SYSTEMD_CGROUP → per-container isolation
 *   SYSLOG_FACILITY → per-facility isolation
 *
 * For this project:
 *   facility       → AuditFacility (0-23)
 *   _sandbox_id    → per-sandbox log isolation
 *   _boot_id       → per-session isolation
 */

import type { IAuditReader, StoredAuditEntry, LogQuery } from './types.ts';

// ─── Namespace config ───

export interface LogNamespace {
  /** Facility filter — restricts queries to this facility. */
  readonly facility?: string;
  /** Sandbox ID filter — restricts queries to this sandbox. */
  readonly sandboxId?: string;
  /** Boot ID filter — restricts queries to this boot session. */
  readonly bootId?: string;
  /** Minimum priority level. */
  readonly minLevel?: number;
}

// ─── Namespaced reader ───

/** Create a namespaced view over an IAuditReader. */
export class NamespacedAuditReader implements IAuditReader {
  public constructor(
    private readonly reader: IAuditReader,
    private readonly ns: LogNamespace,
  ) {}

  public async query(params?: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    const merged: LogQuery = {
      ...params,
      ...(this.ns.facility ? { facility: this.ns.facility } : {}),
    };

    const result = await this.reader.query(merged);

    // Client-side filter for sandbox/boot ID (if not natively supported)
    let entries = result.entries;
    if (this.ns.sandboxId) {
      entries = entries.filter(e =>
        (e as any)._sandbox_id === this.ns.sandboxId ||
        e.metadata?.sandboxId === this.ns.sandboxId,
      );
    }
    if (this.ns.bootId) {
      entries = entries.filter(e =>
        (e as any)._boot_id === this.ns.bootId ||
        e.metadata?.bootId === this.ns.bootId,
      );
    }
    if (this.ns.minLevel !== undefined) {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-enum-comparison -- KernLevel values are numeric
      entries = entries.filter(e => e.level >= this.ns.minLevel!);
    }

    return { entries, ...(result.nextCursor ? { nextCursor: result.nextCursor } : {}), total: entries.length };
  }

  public async getById(id: any): Promise<StoredAuditEntry | null> {
    return this.reader.getById(id);
  }
}

// ─── Per-sandbox helper ───

export function sandboxLogReader(reader: IAuditReader, sandboxId: string): IAuditReader {
  return new NamespacedAuditReader(reader, { sandboxId });
}

export function facilityLogReader(reader: IAuditReader, facility: string): IAuditReader {
  return new NamespacedAuditReader(reader, { facility });
}

// ─── Query builders ───

export function buildSandboxQuery(_sandboxId: string, base?: LogQuery): LogQuery {
  return { ...base };
}

export function buildFacilityQuery(facility: string, base?: LogQuery): LogQuery {
  return { ...base, facility };
}

/**
 * Persistence policy — controls which audit entries are written to durable storage.
 *
 * Separate from log-policy.ts (console output) because storage costs real money:
 *   - R2 charges per PUT/GET operation
 *   - KV charges per read/write
 *   - DO storage is limited
 *
 * Design (mirrors journald §8 Storage=persistent vs volatile):
 *   Tier 0 — console only (DEBUG, INFO)         → console.log, no persist
 *   Tier 1 — ring buffer (NOTICE, WARNING)      → memory-only, no persist
 *   Tier 2 — durable   (ERR, CRIT, ALERT, EMERG) → write to KV/R2/DO
 *   Tier 3 — immutable (auth events, perm denials) → always persist
 *
 * ERR (3) and below are NEVER suppressed from persistence regardless of policy.
 * This matches the kernel invariant: ERRs are always recoverable from journal.
 *
 * External control: GET/PUT /api/admin/log-persistence
 */

import { KernLevel, type FacilityName } from './kern-level.ts';
import type { AuditEntry } from './types.ts';

// ─── Types ───

export interface PersistenceRule {
  /** Facility name (must be a known facility) or '*' for default. Typo → compile error. */
  facility: FacilityName | '*';
  /** Minimum KernLevel to persist. ERR and below always persist regardless. */
  minLevel: KernLevel;
  /** Sampling rate: 1 = persist all, 10 = persist ~10%. Default 1. */
  sampleRate?: number;
  /** TTL in ms — entries older than this are pruned. 0 = never. */
  ttlMs?: number;
}

export interface PersistencePolicy {
  /** Master kill-switch. When false, nothing is persisted (console still works). */
  enabled: boolean;
  /** Default rule applied when no per-facility rule matches. */
  defaultMinLevel: KernLevel;
  /** Per-facility overrides. First match wins. */
  rules: PersistenceRule[];
  /** Last update timestamp. */
  updatedAt: number;
  /** Who updated it (user ID). */
  updatedBy?: string;
}

// ─── Built-in defaults ───

/** Facilities whose entries are always persisted (Tier 3 — immutable audit trail). */
const IMMUTABLE_FACILITIES = new Set([
  'auth', 'authz', 'perm', 'perm-audit', 'perm-gate',
]);

export function buildDefaultPersistencePolicy(): PersistencePolicy {
  return {
    enabled: true,
    defaultMinLevel: KernLevel.ERR, // Only ERR+ by default
    rules: [
      // Tier 3: auth/perm facilities — persist everything WARNING+
      // (IMMUTABLE_FACILITIES are always persisted at ERR+ in code below)
      { facility: 'auth', minLevel: KernLevel.WARNING, sampleRate: 1 },
      { facility: 'perm', minLevel: KernLevel.WARNING, sampleRate: 1 },
      { facility: 'perm-audit', minLevel: KernLevel.WARNING, sampleRate: 1 },
      // Tier 2 overrides for critical infrastructure
      { facility: 'sandbox', minLevel: KernLevel.ERR, sampleRate: 1 },
      { facility: 'provider', minLevel: KernLevel.ERR, sampleRate: 1 },
      { facility: 'queue', minLevel: KernLevel.WARNING, sampleRate: 1 },
      // High-volume facilities: only persist ERR+
      { facility: 'http', minLevel: KernLevel.ERR, sampleRate: 1 },
      { facility: 'image', minLevel: KernLevel.ERR, sampleRate: 1 },
      { facility: 'network', minLevel: KernLevel.ERR, sampleRate: 1 },
      { facility: 'volume', minLevel: KernLevel.ERR, sampleRate: 1 },
    ],
    updatedAt: Date.now(),
  };
}

// ─── Runtime state ───

let _persistencePolicy = buildDefaultPersistencePolicy();

export function getPersistencePolicy(): PersistencePolicy {
  return _persistencePolicy;
}

export function setPersistencePolicy(policy: PersistencePolicy): void {
  _persistencePolicy = policy;
}

/** Reset to built-in defaults. */
export function resetPersistencePolicy(): PersistencePolicy {
  _persistencePolicy = buildDefaultPersistencePolicy();
  return _persistencePolicy;
}

// ─── Decision engine ───

/**
 * Determine whether an audit entry should be persisted to durable storage.
 *
 * Rules (in order):
 *   1. Master kill-switch: if policy.enabled === false → false
 *   2. Immutable facilities (auth/perm): ERR+ → always true
 *   3. ERR and below (EMERG/ALERT/CRIT) → always true (kernel invariant)
 *   4. Per-facility rule match → check minLevel
 *   5. Default rule → check defaultMinLevel
 *   6. Sampling: if sampleRate > 1, random subset
 */
export function shouldPersist(entry: AuditEntry): boolean {
  if (!_persistencePolicy.enabled) return false;

  const facility = entry.facility ?? 'audit';
  const level = entry.level;

  // ERR (3) and below are NEVER suppressed — kernel invariant
  if (level <= KernLevel.ERR) return true;

  // Tier 3: immutable facilities — everything WARNING+ is persisted
  if (IMMUTABLE_FACILITIES.has(facility)) {
    // ERR+ handled above; WARNING+ always persist for immutable facilities
    if (level <= KernLevel.WARNING) return true;
  }

  // Find matching rule (first match wins)
  const rule = _persistencePolicy.rules.find(r => r.facility === facility);

  const effectiveMinLevel = rule?.minLevel ?? _persistencePolicy.defaultMinLevel;

  if (level > effectiveMinLevel) return false;

  // Sampling: if sampleRate > 1, only persist 1/N entries
  const sampleRate = rule?.sampleRate ?? 1;
  if (sampleRate > 1) {
    // Deterministic sampling based on entry content (avoids random() overhead)
    // Uses a simple hash of message + timestamp to decide.
    const hash = simpleHash(entry.message + String(Date.now()));
    if (hash % sampleRate !== 0) return false;
  }

  return true;
}

/** Simple fast hash for deterministic sampling. */
function simpleHash(str: string): number {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h) + str.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h);
}

/**
 * R2-backed audit logger — production persistence for Cloudflare Workers.
 *
 * Write path:
 *   entry → shouldPersist() gate → buffer → batch flush to R2 (every 5s or 100 entries)
 *                           ↘ console.log → Workers Logs (free, Logpush-able)
 *
 * journald §9 persistent storage model:
 *   Tier 2 (durable) — ERR/CRIT/ALERT/EMERG → R2
 *   Tier 3 (immutable) — auth/perm WARNING+ → R2
 *   Tier 0 (console) — all levels → Workers Logs (free backup)
 */

import type { IAuditWriter, IAuditReader, IAuditAdmin, AuditEntry, StoredAuditEntry, LogQuery } from './types.ts';
import type { LogId } from '../brand.ts';
import { generateLogId } from '../brand.ts';
import { KernLevel, kernLevelName, resolveFacility, encodePriority } from './kern-level.ts';
import { shouldLogAudit } from './log-policy.ts';
import { shouldPersist } from './persistence-policy.ts';
import { encodeCursor, decodeCursor, cursorFromEntry, xorHash } from './types.ts';
import { getBootId } from './context.ts';

// ─── R2 abstraction ───

export interface R2Bucket {
  put(key: string, value: string | ArrayBuffer | Uint8Array): Promise<void>;
  get(key: string): Promise<{ body: ArrayBuffer; key: string } | null>;
  list(options?: { prefix?: string; limit?: number; cursor?: string }): Promise<{
    objects: { key: string; size: number; uploaded: Date }[];
    cursor?: string;
    truncated: boolean;
  }>;
  delete(key: string | string[]): Promise<void>;
}

// ─── Config ───

export interface R2LoggerConfig {
  /** Key prefix for log objects. */
  prefix: string;
  /** Max log entries per R2 object (batch writes). */
  batchSize: number;
  /** Flush interval in ms. */
  flushIntervalMs: number;
}

const DEFAULT_CONFIG: R2LoggerConfig = {
  prefix: 'audit-logs/',
  batchSize: 100,
  flushIntervalMs: 5000,
};

/** Strip _-prefixed keys to prevent trusted field forgery (journald convention). */
function sanitizeMetadata(meta: Record<string, unknown> | undefined): Record<string, unknown> | undefined {
  if (!meta) return undefined;
  const cleaned: Record<string, unknown> = {};
  let hasKeys = false;
  for (const [k, v] of Object.entries(meta)) {
    if (!k.startsWith('_')) { cleaned[k] = v; hasKeys = true; }
  }
  return hasKeys ? cleaned : undefined;
}

// ─── R2 Audit Logger ───

export class R2AuditLogger implements IAuditWriter, IAuditReader, IAuditAdmin {
  readonly #buffer: StoredAuditEntry[] = [];
  readonly #config: R2LoggerConfig;
  #flushTimer: ReturnType<typeof setInterval> | null = null;
  #seq = 0;
  readonly #bootId: string;
  readonly #machineHash: string;

  public constructor(
    private readonly bucket: R2Bucket,
    config: Partial<R2LoggerConfig> = {},
  ) {
    this.#config = { ...DEFAULT_CONFIG, ...config };
    this.#bootId = getBootId() ?? '00000000-0000-0000-0000-000000000000';
    this.#machineHash = hashBootId(this.#bootId);
  }

  // ─── IAuditWriter ───

  public write(entry: AuditEntry): void {
    void this.#process(entry);
  }

  async #process(entry: AuditEntry): Promise<LogId> {
    const id = generateLogId();
    const now = Date.now();
    const facility = entry.facility ?? 'audit';
    const facilityCode = resolveFacility(facility);

    // Strip _-prefixed keys from metadata to prevent trusted field forgery (journald convention).
    const safeMeta = sanitizeMetadata(entry.metadata);

    // Generate journald-style cursor with tamper-detection xor_hash.
    const seq = ++this.#seq;
    const cursor = encodeCursor(cursorFromEntry(
      { id, timestamp: now } as unknown as StoredAuditEntry,
      this.#bootId, seq, this.#machineHash,
    ));

    const stored: StoredAuditEntry = {
      id, timestamp: now,
      priority: encodePriority(facilityCode, entry.level),
      level: entry.level, facility,
      message: entry.message,
      actorId: entry.actorId,
      cursor,
      ...(entry.trusted ? { trusted: entry.trusted } : {}),
      ...(safeMeta ? { metadata: safeMeta } : {}),
    };

    // Gate expensive R2 writes with persistence policy.
    if (shouldPersist(entry)) {
      this.#buffer.push(stored);
      if (this.#buffer.length >= this.#config.batchSize) {
        await this.flush().catch(() => { /* noop */ });
      }
    }

    // Always write to console — Workers Logs is free, acts as backup via Logpush.
    if (shouldLogAudit(facility, entry.level)) {
      this.#consoleOut(entry, stored);
    }

    return id;
  }

  #consoleOut(entry: AuditEntry, stored: StoredAuditEntry): void {
    const ts = new Date(stored.timestamp).toISOString();
    const levelName = kernLevelName(entry.level);
    const facility = entry.facility ?? 'audit';
    const line = `[${ts}] ${levelName}: [${facility}] ${entry.message}`;
    const meta = stored.metadata ? JSON.stringify(stored.metadata) : undefined;

    if (entry.level <= KernLevel.ERR) {
      if (meta) { console.error(line, meta); } else { console.error(line); }
    } else if (entry.level === KernLevel.WARNING) {
      if (meta) { console.warn(line, meta); } else { console.warn(line); }
    } else {
      if (meta) { console.log(line, meta); } else { console.log(line); }
    }
  }

  // ─── Flush ───

  public async flush(): Promise<void> {
    if (this.#buffer.length === 0) return;
    const batch = this.#buffer.splice(0);
    const now = Date.now();
    const key = `${this.#config.prefix}${String(now)}-${batch[0]!.id}.json`;
    await this.bucket.put(key, JSON.stringify(batch));
  }

  // ─── IAuditReader ───

  public async query(params?: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    const limit = params?.limit ?? 100;
    const prefix = this.#config.prefix;
    const listResult = await this.bucket.list({
      prefix,
      limit: Math.ceil(limit / this.#config.batchSize),
      ...(params?.afterCursor ? { cursor: params.afterCursor } : {}),
    });

    const entries: StoredAuditEntry[] = [];
    for (const obj of listResult.objects) {
      const data = await this.bucket.get(obj.key);
      if (!data) continue;
      try {
        const batch: StoredAuditEntry[] = JSON.parse(new TextDecoder().decode(data.body));
        let filtered = batch;
        if (params?.facility) filtered = filtered.filter(e => e.facility === params.facility);
        if (params?.startTs !== undefined) filtered = filtered.filter(e => e.timestamp >= params.startTs!);
        if (params?.endTs !== undefined) filtered = filtered.filter(e => e.timestamp <= params.endTs!);
        entries.push(...filtered);
      } catch { /* skip corrupt files */ }
      if (entries.length >= limit) break;
    }

    // Include unflushed buffer entries that might be relevant
    if (this.#buffer.length > 0) {
      let buf = [...this.#buffer];
      if (params?.facility) buf = buf.filter(e => e.facility === params.facility);
      if (params?.startTs !== undefined) buf = buf.filter(e => e.timestamp >= params.startTs!);
      if (params?.endTs !== undefined) buf = buf.filter(e => e.timestamp <= params.endTs!);
      entries.push(...buf);
    }

    // Apply afterCursor filter with tamper validation.
    if (params?.afterCursor) {
      const cursor = decodeCursor(params.afterCursor);
      if (cursor && this.#validateCursor(cursor)) {
        const filtered = entries.filter(e => {
          if (!e.cursor) return true;
          const ec = decodeCursor(e.cursor);
          return ec ? ec.i > cursor.i : true;
        });
        const total = filtered.length;
        const sliced = params?.offset ? filtered.slice(params.offset) : filtered;
        const page = params?.limit ? sliced.slice(0, params.limit) : sliced;
        const lastCursor: string | undefined = page.at(-1)?.cursor;
        return { entries: page, total, ...(lastCursor ? { nextCursor: lastCursor } : {}) };
      }
    }

    const total = entries.length;
    const sliced = params?.offset ? entries.slice(params.offset) : entries;
    const page = params?.limit ? sliced.slice(0, params.limit) : sliced;
    return { entries: page, total };
  }

  public async getById(id: LogId): Promise<StoredAuditEntry | null> {
    const buf = this.#buffer.find(e => e.id === id);
    if (buf) return buf;

    const result = await this.bucket.list({ prefix: this.#config.prefix, limit: 100 });
    for (const obj of result.objects) {
      const data = await this.bucket.get(obj.key);
      if (!data) continue;
      try {
        const batch: StoredAuditEntry[] = JSON.parse(new TextDecoder().decode(data.body));
        const found = batch.find(e => e.id === id);
        if (found) return found;
      } catch { continue; }
    }
    return null;
  }

  // ─── IAuditAdmin ───


  public async prune(beforeTs: number): Promise<number> {
    const result = await this.bucket.list({ prefix: this.#config.prefix, limit: 500 });
    let removed = 0;
    for (const obj of result.objects) {
      const tsMatch = /(\d{13})-/.exec(obj.key);
      if (tsMatch && parseInt(tsMatch[1]!) < beforeTs) {
        await this.bucket.delete(obj.key);
        removed++;
      }
    }
    return removed;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async pruneByIds(_ids: readonly string[]): Promise<number> {
    return 0; // R2 delete is per-key; full implementation would need an index
  }

  // ─── Lifecycle ───

  /** Start auto-flushing the write buffer. */
  public startAutoFlush(): void {
    if (this.#flushTimer) return;
    this.#flushTimer = setInterval(() => this.flush().catch(() => { /* noop */ }), this.#config.flushIntervalMs);
  }

  public stopAutoFlush(): void {
    if (this.#flushTimer) {
      clearInterval(this.#flushTimer);
      this.#flushTimer = null;
    }
  }

  public async dispose(): Promise<void> {
    this.stopAutoFlush();
    await this.flush();
  }

  // ─── Cursor validation ───

  #validateCursor(c: { s: string; i: number; b: string; m: number; t: number; x: string }): boolean {
    const expected = xorHash({ s: c.s, i: c.i, b: c.b, m: c.m, t: c.t });
    return c.x === expected;
  }
}

/** Derive a short machine hash from a boot UUID for cursor.s field. */
function hashBootId(bootId: string): string {
  let h = 0;
  for (let i = 0; i < bootId.length; i++) h ^= bootId.charCodeAt(i) << ((i % 4) * 8);
  return (h >>> 0).toString(16).padStart(8, '0');
}

/**
 * Log rotation — journald §9 model.
 *
 * Rotation policy mirrors journald configuration:
 *   SystemMaxUse       — max total storage (bytes)
 *   SystemMaxFileSize  — max per-file size (bytes)
 *   MaxRetentionSec    — max entry age (seconds)
 *
 * The prune() function selects entries to evict based on these limits.
 * Eviction priority: oldest entries first (journald behavior).
 */

import type { StoredAuditEntry } from './types.ts';

// ─── Configuration ───

export interface LogRotationConfig {
  /** Maximum total bytes used by all log entries. 0 = unlimited. */
  readonly maxTotalBytes: number;
  /** Maximum bytes per log file/shard. 0 = unlimited. */
  readonly maxFileBytes: number;
  /** Maximum age in milliseconds. 0 = unlimited. */
  readonly maxAgeMs: number;
  /** Minimum entries to keep regardless of limits. */
  readonly minEntries: number;
}

export const DEFAULT_ROTATION: LogRotationConfig = {
  maxTotalBytes: 100 * 1024 * 1024,  // 100 MB
  maxFileBytes: 16 * 1024 * 1024,   // 16 MB per shard
  maxAgeMs: 7 * 24 * 60 * 60 * 1000, // 7 days
  minEntries: 1000,                   // keep at least 1000 entries
};

/** journald-style defaults for production. */
export const PRODUCTION_ROTATION: LogRotationConfig = {
  maxTotalBytes: 4 * 1024 * 1024 * 1024, // 4 GB (journald default cap)
  maxFileBytes: 512 * 1024 * 1024,       // 512 MB (SystemMaxUse / 8)
  maxAgeMs: 30 * 24 * 60 * 60 * 1000,   // 30 days
  minEntries: 10000,
};

// ─── Prune logic ───

export interface PruneResult {
  readonly removed: number;
  readonly freedBytes: number;
  readonly remaining: number;
}

/**
 * Select entries to remove based on rotation policy.
 * Returns the IDs of entries to delete.
 * Entries are sorted oldest-first (journald behavior).
 */
export function selectEntriesToPrune(
  entries: readonly StoredAuditEntry[],
  config: LogRotationConfig,
): readonly string[] {
  if (entries.length <= config.minEntries) return [];

  // Sort by timestamp ascending (oldest first)
  const sorted = [...entries].sort((a, b) => a.timestamp - b.timestamp);
  const toRemove: string[] = [];
  let totalSize: number;
  const now = Date.now();

  // Apply age-based eviction
  if (config.maxAgeMs > 0) {
    const cutoff = now - config.maxAgeMs;
    for (const entry of sorted) {
      if (toRemove.length + config.minEntries >= sorted.length) break;
      if (entry.timestamp < cutoff) {
        toRemove.push(entry.id);
      }
    }
  }

  // Remove already-marked entries from remaining
  const remainingAfterAge = sorted.filter(e => !toRemove.includes(e.id));
  totalSize = estimateTotalSize(remainingAfterAge);

  // Apply size-based eviction (oldest first)
  if (config.maxTotalBytes > 0 && totalSize > config.maxTotalBytes) {
    for (const entry of remainingAfterAge) {
      if (toRemove.length + config.minEntries >= sorted.length) break;
      if (totalSize <= config.maxTotalBytes) break;
      toRemove.push(entry.id);
      totalSize -= estimateEntrySize(entry);
    }
  }

  return toRemove;
}

/** Estimate the storage footprint of a single entry. */
export function estimateEntrySize(entry: StoredAuditEntry): number {
  // Rough estimate: JSON serialized size
  const textLen = entry.message?.length ?? 0;
  const metaLen = entry.metadata ? JSON.stringify(entry.metadata).length : 0;
  return textLen + metaLen + 200; // 200 bytes overhead
}

function estimateTotalSize(entries: readonly StoredAuditEntry[]): number {
  return entries.reduce((sum, e) => sum + estimateEntrySize(e), 0);
}

// ─── Prune via IAuditAdmin ───

import type { IAuditAdmin, IAuditReader } from './types.ts';

/**
 * Execute a prune pass on an audit backend.
 * Needs both IAuditReader (to list entries) and IAuditAdmin (to delete).
 */
export async function pruneBackend(
  reader: IAuditReader,
  admin: IAuditAdmin,
  config: LogRotationConfig = DEFAULT_ROTATION,
): Promise<PruneResult> {
  // Query all entries (with limit to avoid OOM)
  const allEntries: StoredAuditEntry[] = [];
  let cursor: string | undefined;
  const batchSize = 500;

  while (true) {
    const result = await reader.query({ limit: batchSize, ...(cursor ? { afterCursor: cursor } : {}) });
    allEntries.push(...(result.entries));
    if (!result.nextCursor || result.entries.length < batchSize) break;
    cursor = result.nextCursor;
  }

  const toRemove = selectEntriesToPrune(allEntries, config);

  if (toRemove.length > 0) {
    await admin.pruneByIds(toRemove);
  }

  return {
    removed: toRemove.length,
    freedBytes: toRemove.reduce((sum, id) => {
      const entry = allEntries.find(e => e.id === id);
      return sum + (entry ? estimateEntrySize(entry) : 0);
    }, 0),
    remaining: allEntries.length - toRemove.length,
  };
}

/**
 * Real-time log tail — journalctl -f model.
 *
 * Provides cursor-based incremental log streaming via:
 *   - WebSocket push (active connection)
 *   - Poll mode (HTTP long-poll with cursor)
 *
 * The consumer stores the last consumed cursor and resumes from that point.
 * This mirrors journald's `--after-cursor` + `--cursor-file` pattern (§5).
 */

import type { IAuditReader, StoredAuditEntry } from './types.ts';

// ─── Tail session ───

export interface TailSession {
  /** Last consumed cursor position. */
  cursor: string;
  /** Poll interval in ms. */
  intervalMs: number;
  /** Max entries per poll. */
  batchSize: number;
  /** Subscribers that receive each batch. */
  subscribers: Set<(entries: readonly StoredAuditEntry[]) => void>;
  /** Timer handle for cleanup. */
  timer?: ReturnType<typeof setInterval>;
}

export function createTailSession(intervalMs = 2000, batchSize = 50): TailSession {
  return {
    cursor: '',
    intervalMs,
    batchSize,
    subscribers: new Set(),
  };
}

// ─── Poll-based tail ───

export interface TailOptions {
  /** Facility filter (optional). */
  facility?: string;
  /** Minimum severity level (0-7). */
  minLevel?: number;
}

export async function pollTail(
  reader: IAuditReader,
  session: TailSession,
  options: TailOptions = {},
): Promise<{ entries: readonly StoredAuditEntry[]; newCursor: string }> {
  const params: any = {
    limit: session.batchSize,
    ...(options.facility ? { facility: options.facility } : {}),
    ...(session.cursor ? { afterCursor: session.cursor } : {}),
  };

  const result = await reader.query(params);
  const entries = result.entries;
  const newCursor = result.nextCursor ?? session.cursor;

  if (entries.length > 0) {
    session.cursor = newCursor;
    for (const sub of session.subscribers) {
      try { sub(entries); } catch { /* subscriber error */ }
    }
  }

  return { entries, newCursor };
}

/** Start a tail session that polls at regular intervals. */
export function startTail(
  reader: IAuditReader,
  session: TailSession,
  options: TailOptions = {},
): () => void {
  const timer = setInterval(() => {
    pollTail(reader, session, options).catch(() => { /* noop */ });
  }, session.intervalMs);
  session.timer = timer;
  return () => { clearInterval(timer); };
}

/** Stop a tail session. */
export function stopTail(session: TailSession): void {
  if (session.timer) clearInterval(session.timer);
  session.subscribers.clear();
}

// ─── WebSocket message format ───

export interface TailWsMessage {
  type: 'tail:batch' | 'tail:error' | 'tail:ping';
  cursor?: string;
  entries?: StoredAuditEntry[];
  error?: string;
}

/** Create a WebSocket tail handler that pushes log batches to connected clients. */
export function createWsTailHandler(
  reader: IAuditReader,
  options: TailOptions = {},
): { handle(send: (msg: TailWsMessage) => void, close: () => void, pollIntervalMs?: number): Promise<void> } {
  return {
    /** Upgrade an HTTP request to a WebSocket tail session. */
    async handle(
      send: (msg: TailWsMessage) => void,
      close: () => void,
      pollIntervalMs = 2000,
    ) {
      const session = createTailSession(pollIntervalMs);
      session.subscribers.add((entries) => {
        send({ type: 'tail:batch', cursor: session.cursor, entries: [...entries] });
      });

      // Send initial batch
      const { entries, newCursor } = await pollTail(reader, session, options);
      if (entries.length > 0) {
        send({ type: 'tail:batch', cursor: newCursor, entries: [...entries] });
      }

      // Start polling
      const stop = startTail(reader, session, options);

      // Ping every 30s
      const pingTimer = setInterval(() => { send({ type: 'tail:ping' }); }, 30000);

      return () => {
        stop();
        clearInterval(pingTimer);
        close();
      };
    },
  };
}

import type { KernLevel } from './kern-level.ts';
import type { LogId, Facility, SerializedBody } from '../brand.ts';
import { formatDmesgLine } from '../utils/dmesg.ts';

// ═══════════════════════════════════════════════════════════
// Core entry types (unified audit + logger)
// ═══════════════════════════════════════════════════════════

/**
 * Trusted fields — auto-injected by the logging framework.
 * Prefixed with _ to distinguish from caller-provided fields (journald convention).
 * These fields CANNOT be set by business code — only the middleware/log framework sets them.
 */
export interface TrustedFields {
  _request_id?: string;
  _user_id?: string;
  _source_ip?: string;
  _boot_id?: string;
  _sandbox_id?: string;
}

/** Input for writing an audit/log entry. */
export interface AuditEntry {
  level: KernLevel;
  facility: string;
  message: string;
  actorId?: string | undefined;
  metadata?: Record<string, unknown>;
  /** Computed priority = facility × 8 + level. Set by logger, not caller. */
  priority?: number;
  /** Auto-injected trusted fields. Set by the logging framework. */
  trusted?: TrustedFields;
}

/** Persisted entry (what gets stored). */
export interface StoredAuditEntry {
  id: string;
  timestamp: number;
  level: KernLevel;
  facility: string;
  message: string;
  actorId?: string | undefined;
  metadata?: Record<string, unknown>;
  priority?: number;
  trusted?: TrustedFields;
  /** Journald-style cursor for incremental consumption with tamper detection. */
  cursor?: string;
}

/**
 * Cursor for incremental log consumption (journald-style).
 * Format: "s=<machine>;i=<seq>;b=<boot>;m=<mono>;t=<real>;x=<xor>"
 */
export interface LogCursor {
  s: string;  // machine hash
  i: number;  // sequence number
  b: string;  // boot ID
  m: number;  // monotonic timestamp (performance.now ms)
  t: number;  // wall clock timestamp (Date.now ms)
  x: string;  // xor hash of above fields (tamper detection)
}

/** Result of a log query with cursor for incremental consumption. */
export interface LogQueryResult {
  entries: StoredAuditEntry[];
  /** Cursor pointing to the last entry in this batch. Pass as `afterCursor` for next page. */
  nextCursor?: string;
  /** Total count matching the query (may be approximate). */
  total?: number;
}

/** Query parameters for log retrieval. */
export interface LogQuery {
  facility?: string;
  startTs?: number;
  endTs?: number;
  limit?: number;
  /** Skip first N entries (for page-based pagination). */
  offset?: number;
  /** Resume from after this cursor (exclusive). Use nextCursor from previous LogQueryResult. */
  afterCursor?: string;
  /** Filter by priority range (inclusive). priorityMin=16 → SANDBOX.EMERG and above. */
  priorityMin?: number;
  priorityMax?: number;
}

/** Encode a LogCursor to its string representation. */
export function encodeCursor(c: LogCursor): string {
  return `s=${c.s};i=${String(c.i)};b=${c.b};m=${String(c.m)};t=${String(c.t)};x=${c.x}`;
}

/** Decode a cursor string back to LogCursor. Returns null if format is invalid. */
export function decodeCursor(raw: string): LogCursor | null {
  try {
    const map = new Map(raw.split(';').map(p => p.split('=', 2) as [string, string]));
    return {
      s: map.get('s') ?? '', i: Number(map.get('i')), b: map.get('b') ?? '',
      m: Number(map.get('m')), t: Number(map.get('t')), x: map.get('x') ?? '',
    };
  } catch { return null; }
}

/** Build a cursor from a StoredAuditEntry. */
export function cursorFromEntry(entry: StoredAuditEntry, bootId: string, seq: number, machineHash: string): LogCursor {
  const cursor: LogCursor = {
    s: machineHash, i: seq, b: bootId,
    m: Math.round(performance.now()), t: entry.timestamp,
    x: '',
  };
  cursor.x = xorHash(cursor);
  return cursor;
}

export function xorHash(c: { s: string; i: number; b: string; m: number; t: number }): string {
  const parts = [c.s, String(c.i), c.b, String(c.m), String(c.t)];
  let h = 0;
  for (const p of parts) { for (let i = 0; i < p.length; i++) h ^= p.charCodeAt(i) << ((i % 4) * 8); }
  return (h >>> 0).toString(16).padStart(8, '0');
}

/** Query parameters for log retrieval. */
export interface LogQuery {
  facility?: string;
  startTs?: number;
  endTs?: number;
  limit?: number;
  cursor?: string;
}

/** Pre-serialized storage entry. */
export interface StorageEntry {
  facility: string;
  id: string;
  timestamp: number;
  body: SerializedBody;
}

/** Filter rules for querying audit logs. */
export interface AuditFilter {
  levelMin?: KernLevel;
  levelMax?: KernLevel;
  facility?: string;
  search?: string;
  since?: number;
  until?: number;
  page?: number;
  limit?: number;
}

export interface AuditQueryResult {
  lines: string[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

// ═══════════════════════════════════════════════════════════
// Interfaces (unified writer / reader / admin)
// ═══════════════════════════════════════════════════════════

export enum AuditTier {
  AUDITABLE = 'auditable',
  BEST_EFFORT = 'best-effort',
}

/** Write interface — fire-and-forget. Compiler-enforced: void is not awaitable. */
export interface IAuditWriter {
  write(entry: AuditEntry): void;
}

/** Read interface. */
export interface IAuditReader {
  query(params?: LogQuery): Promise<LogQueryResult>;
  getById(id: LogId): Promise<StoredAuditEntry | null>;
}

/** Admin interface for recovery / archival. */
export interface IAuditAdmin {
  /** Remove entries older than the given timestamp. */
  prune(beforeTs: number): Promise<number>;
  /** Remove specific entries by ID. Returns count removed. */
  pruneByIds(ids: readonly string[]): Promise<number>;
}

/** Format an audit entry as a dmesg-style log line. */
export function formatAuditLine(_timestamp: number, entry: AuditEntry): string {
  const actorId = entry.actorId ?? (entry.metadata?.actorId as string | undefined);
  return formatDmesgLine(entry.message, actorId);
}

import type { IAuditWriter, IAuditReader, IAuditAdmin, AuditEntry, StoredAuditEntry, LogQuery } from './types.ts';
import type { LogId } from '../brand.ts';
import { generateLogId } from '../brand.ts';
import { KernLevel, kernLevelName, resolveFacility, encodePriority } from './kern-level.ts';
import { shouldLogAudit } from './log-policy.ts';
import { encodeCursor, decodeCursor, cursorFromEntry, xorHash } from './types.ts';
import { getBootId } from './context.ts';

const MAX_IN_MEMORY = 500;

/** Strip _-prefixed keys to prevent trusted field forgery (journald convention). */
function sanitizeMetadata(meta: Record<string, unknown> | undefined): Record<string, unknown> | undefined {
  if (!meta) return undefined;
  const cleaned: Record<string, unknown> = {};
  let hasKeys = false;
  for (const [k, v] of Object.entries(meta)) {
    if (!k.startsWith('_')) { cleaned[k] = v; hasKeys = true; }
  }
  return hasKeys ? cleaned : undefined;
}

/**
 * Cloudflare Workers audit logger.
 *
 * Write: console.log/warn/error → Workers Logs (platform-level, free)
 * Query: in-memory ring buffer (last 500 entries) — no persistent storage.
 *
 * Workers Logs has no historical query API on the platform.
 * For persistent queryable audit, use AUDIT_BACKEND=hybrid (DO/KV) instead.
 */
export class WorkersAuditLogger implements IAuditWriter, IAuditReader, IAuditAdmin {
  readonly #memory: StoredAuditEntry[] = [];
  #seq = 0;
  readonly #bootId: string;
  readonly #machineHash: string;

  public constructor() {
    this.#bootId = getBootId() ?? '00000000-0000-0000-0000-000000000000';
    this.#machineHash = hashBootIdStr(this.#bootId);
  }

  public write(entry: AuditEntry): void {
    this.#output(entry);
  }

  #output(entry: AuditEntry): void {
    const ts = new Date().toISOString();
    const facility = entry.facility ?? 'audit';
    const levelName = kernLevelName(entry.level);

    if (!shouldLogAudit(facility, entry.level)) return;

    // Platform log line
    const line = `[${ts}] ${levelName}: [${facility}] ${entry.message}`;
    // Strip _-prefixed keys from metadata to prevent trusted field forgery (journald convention).
    const safeMeta = sanitizeMetadata(entry.metadata);
    const meta = safeMeta ? JSON.stringify(safeMeta) : undefined;

    if (entry.level <= KernLevel.ERR) {
      if (meta) { console.error(line, meta); } else { console.error(line); }
    } else if (entry.level === KernLevel.WARNING) {
      if (meta) { console.warn(line, meta); } else { console.warn(line); }
    } else {
      if (meta) { console.log(line, meta); } else { console.log(line); }
    }

    // Keep in-memory ring buffer for recent query
    const seq = ++this.#seq;
    const id = generateLogId();
    const now = Date.now();
    const cursor = encodeCursor(cursorFromEntry(
      { id, timestamp: now } as unknown as StoredAuditEntry,
      this.#bootId,
      seq,
      this.#machineHash,
    ));
    const stored: StoredAuditEntry = {
      id,
      timestamp: now,
      priority: encodePriority(resolveFacility(facility), entry.level),
      level: entry.level,
      facility,
      message: entry.message,
      actorId: entry.actorId,
      cursor,
      ...(entry.trusted ? { trusted: entry.trusted } : {}),
      ...(safeMeta ? { metadata: safeMeta } : {}),
    };
    this.#memory.push(stored);
    if (this.#memory.length > MAX_IN_MEMORY) this.#memory.shift();
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async query(params?: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    let f = [...this.#memory].reverse(); // newest first
    if (params?.facility) f = f.filter(e => e.facility === params.facility);
    if (params?.startTs !== undefined) f = f.filter(e => e.timestamp >= params.startTs!);
    if (params?.endTs !== undefined) f = f.filter(e => e.timestamp <= params.endTs!);
    // Apply afterCursor filter with tamper validation.
    if (params?.afterCursor) {
      const cursor = decodeCursor(params.afterCursor);
      if (cursor && validateCursor(cursor)) {
        f = f.filter(e => {
          if (!e.cursor) return true;
          const ec = decodeCursor(e.cursor);
          return ec ? ec.i > cursor.i : true;
        });
      }
    }
    // Compute total BEFORE slicing (SPEC: total = full matching count, not page size).
    const total = f.length;
    // Apply offset + limit for page-based pagination.
    if (params?.offset) f = f.slice(params.offset);
    if (params?.limit) f = f.slice(0, params.limit);
    const lastCursor: string | undefined = f.at(-1)?.cursor;
    return { entries: f, total, ...(lastCursor ? { nextCursor: lastCursor } : {}) };
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async getById(id: LogId): Promise<StoredAuditEntry | null> {
    return this.#memory.find(e => e.id === id) ?? null;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async prune(_beforeTs: number): Promise<number> { return 0; }
  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async pruneByIds(_ids: readonly string[]): Promise<number> { return 0; }
}

/** Validate cursor integrity via xor_hash. Returns false if tampered. */
function validateCursor(c: { s: string; i: number; b: string; m: number; t: number; x: string }): boolean {
  const expected = xorHash({ s: c.s, i: c.i, b: c.b, m: c.m, t: c.t });
  return c.x === expected;
}

/** Derive a short machine hash from a boot UUID for cursor.s field. */
function hashBootIdStr(bootId: string): string {
  let h = 0;
  for (let i = 0; i < bootId.length; i++) h ^= bootId.charCodeAt(i) << ((i % 4) * 8);
  return (h >>> 0).toString(16).padStart(8, '0');
}

import type { IAtomicStore } from '../store/interfaces.ts';
import type { Platform } from '../region/types.ts';
import { AppError } from '../types.ts';
import type { SecretEncryption } from './secret-encryption.ts';

// ─── Credential type ───

export type CredentialType = 'aksk' | 'token' | 'password';

// ─── Brand type ───

declare const CREDENTIAL_ID_BRAND: unique symbol;
export type CredentialId = string & { readonly [CREDENTIAL_ID_BRAND]: true };

export function generateCredentialId(): CredentialId {
  return `cred_${crypto.randomUUID()}` as CredentialId;
}

// ─── Entity ───

export interface RegistryCredential {
  readonly server: string;
  readonly userName: string;
  readonly password: string;
}

export interface ManagedCredential {
  readonly id: CredentialId;
  readonly name: string;
  readonly type: CredentialType;
  readonly platform: Platform;
  /** aksk: access key */
  readonly accessKeyId?: string | undefined;
  /** aksk: access secret */
  readonly accessKeySecret?: string | undefined;
  /** token: single bearer/API token */
  readonly token?: string | undefined;
  /** password: login username */
  readonly username?: string | undefined;
  /** password: login password */
  readonly password?: string | undefined;
  /** registry mirror credentials */
  readonly registryCredentials?: readonly RegistryCredential[] | undefined;
  readonly instanceId?: string | undefined;
  readonly status: 'active' | 'inactive';
  readonly createdAt: number;
  readonly updatedAt: number;
}

/** 对外展示的凭证（secret masked）。读接口统一用此类型。 */
export interface MaskedCredential {
  readonly id: CredentialId;
  readonly name: string;
  readonly type: CredentialType;
  readonly platform: Platform;
  readonly accessKeyId?: string | undefined;
  readonly accessKeySecret?: string | undefined; // masked
  readonly token?: string | undefined;           // masked
  readonly username?: string | undefined;
  readonly password?: string | undefined;         // masked
  readonly registryCredentials?: readonly RegistryCredential[] | undefined;
  readonly instanceId?: string | undefined;
  readonly status: 'active' | 'inactive';
  readonly createdAt: number;
  readonly updatedAt: number;
}

export function maskSecret(secret: string): string {
  return secret.slice(0, 6) + '***';
}

export function toMasked(cred: ManagedCredential): MaskedCredential {
  const masked: MaskedCredential = {
    id: cred.id,
    name: cred.name,
    type: cred.type,
    platform: cred.platform,
    ...(cred.accessKeyId ? { accessKeyId: cred.accessKeyId } : {}),
    ...(cred.accessKeySecret ? { accessKeySecret: maskSecret(cred.accessKeySecret) } : {}),
    ...(cred.token ? { token: maskSecret(cred.token) } : {}),
    ...(cred.username ? { username: cred.username } : {}),
    ...(cred.password ? { password: maskSecret(cred.password) } : {}),
    ...(cred.registryCredentials?.length ? { registryCredentials: cred.registryCredentials.map(rc => ({ ...rc, password: maskSecret(rc.password) })) } : {}),
    ...(cred.instanceId ? { instanceId: cred.instanceId } : {}),
    status: cred.status,
    createdAt: cred.createdAt,
    updatedAt: cred.updatedAt,
  };
  return masked;
}

export interface CreateCredentialInput {
  name: string;
  type: CredentialType;
  platform: Platform;
  accessKeyId?: string | undefined;
  accessKeySecret?: string | undefined;
  token?: string | undefined;
  username?: string | undefined;
  password?: string | undefined;
  registryCredentials?: RegistryCredential[] | undefined;
  instanceId?: string | undefined;
}

export interface UpdateCredentialInput {
  name?: string | undefined;
  type?: CredentialType | undefined;
  accessKeyId?: string | undefined;
  accessKeySecret?: string | undefined;
  token?: string | undefined;
  username?: string | undefined;
  password?: string | undefined;
  registryCredentials?: RegistryCredential[] | null | undefined;
  instanceId?: string | null | undefined;
  status?: 'active' | 'inactive' | undefined;
}

// ─── Constants ───

const PREFIX = 'cred:';
const INDEX_KEY = 'cred:ids';

// ─── Service ───

export class CredentialService {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly encryption?: SecretEncryption,
  ) {}

  /** Encrypt sensitive fields before storage. */
  async #encryptFields(cred: ManagedCredential): Promise<ManagedCredential> {
    const enc = this.encryption;
    if (!enc) return cred;
    return {
      ...cred,
      ...(cred.accessKeySecret ? { accessKeySecret: await enc.encrypt(cred.accessKeySecret) } : {}),
      ...(cred.token ? { token: await enc.encrypt(cred.token) } : {}),
      ...(cred.password ? { password: await enc.encrypt(cred.password) } : {}),
      ...(cred.registryCredentials?.length ? {
        registryCredentials: await Promise.all(cred.registryCredentials.map(async rc => ({
          ...rc,
          password: await enc.encrypt(rc.password),
        }))),
      } : {}),
    };
  }

  /** Decrypt sensitive fields after read.  Plaintext fields pass through. */
  async #decryptFields(cred: ManagedCredential): Promise<ManagedCredential> {
    const enc = this.encryption;
    if (!enc) return cred;
    return {
      ...cred,
      ...(cred.accessKeySecret ? { accessKeySecret: await enc.decrypt(cred.accessKeySecret) } : {}),
      ...(cred.token ? { token: await enc.decrypt(cred.token) } : {}),
      ...(cred.password ? { password: await enc.decrypt(cred.password) } : {}),
      ...(cred.registryCredentials?.length ? {
        registryCredentials: await Promise.all(cred.registryCredentials.map(async rc => ({
          ...rc,
          password: await enc.decrypt(rc.password),
        }))),
      } : {}),
    };
  }

  public async create(input: CreateCredentialInput): Promise<ManagedCredential> {
    const id = generateCredentialId();
    const now = Date.now();

    const cred: ManagedCredential = {
      id,
      name: input.name,
      type: input.type,
      platform: input.platform,
      ...(input.accessKeyId ? { accessKeyId: input.accessKeyId } : {}),
      ...(input.accessKeySecret ? { accessKeySecret: input.accessKeySecret } : {}),
      ...(input.token ? { token: input.token } : {}),
      ...(input.username ? { username: input.username } : {}),
      ...(input.password ? { password: input.password } : {}),
      ...(input.registryCredentials?.length ? { registryCredentials: [...input.registryCredentials] } : {}),
      ...(input.instanceId ? { instanceId: input.instanceId } : {}),
      status: 'active',
      createdAt: now,
      updatedAt: now,
    };

    const toStore = await this.#encryptFields(cred);
    await this.atomic.set(PREFIX + id, toStore, null);
    await this.#addToIndex(id);
    return cred; // return plaintext
  }

  public async get(id: CredentialId): Promise<ManagedCredential | null> {
    const entry = await this.atomic.get<ManagedCredential>(PREFIX + id);
    if (!entry) return null;
    return this.#decryptFields(entry.value);
  }

  /** 按 name 查找凭证（provider resolver 用）。可传 instanceId 精确匹配。 */
  public async findByName(name: string, instanceId?: string): Promise<ManagedCredential | null> {
    const all = await this.#listAll();
    const decrypted = await Promise.all(all.map(c => this.#decryptFields(c)));
    // 先找 name + instanceId 精确匹配
    if (instanceId) {
      const matched = decrypted.find(c => c.name === name && c.instanceId === instanceId);
      if (matched) return matched;
    }
    // 回退到仅 name 匹配
    return decrypted.find(c => c.name === name) ?? null;
  }

  public async list(filter?: { platform?: string | undefined }): Promise<ManagedCredential[]> {
    const all = await this.#listAll();
    const decrypted = await Promise.all(all.map(c => this.#decryptFields(c)));
    if (!filter?.platform) return decrypted;
    return decrypted.filter(c => c.platform === filter.platform);
  }

  public async update(id: CredentialId, input: UpdateCredentialInput): Promise<ManagedCredential> {
    const entry = await this.atomic.get<ManagedCredential>(PREFIX + id);
    if (!entry) throw new AppError(404, 'CREDENTIAL_NOT_FOUND', 'Credential not found');

    // Decrypt existing so merge + re-encrypt stays consistent
    const existing = await this.#decryptFields(entry.value);

    const updated: ManagedCredential = {
      ...existing,
      ...(input.name !== undefined ? { name: input.name } : {}),
      ...(input.type !== undefined ? { type: input.type } : {}),
      ...(input.accessKeyId !== undefined ? { accessKeyId: input.accessKeyId } : {}),
      ...(input.accessKeySecret !== undefined ? { accessKeySecret: input.accessKeySecret } : {}),
      ...(input.token !== undefined ? { token: input.token } : {}),
      ...(input.username !== undefined ? { username: input.username } : {}),
      ...(input.password !== undefined ? { password: input.password } : {}),
      ...(input.registryCredentials !== undefined ? { registryCredentials: input.registryCredentials ?? undefined } : {}),
      ...(input.instanceId !== undefined ? { instanceId: input.instanceId ?? undefined } : {}),
      ...(input.status !== undefined ? { status: input.status } : {}),
      updatedAt: Date.now(),
    };

    const toStore = await this.#encryptFields(updated);
    const newVersion = await this.atomic.set(PREFIX + id, toStore, entry.version);
    if (!newVersion) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');
    return updated; // plaintext
  }

  public async delete(id: CredentialId): Promise<void> {
    const entry = await this.atomic.get<ManagedCredential>(PREFIX + id);
    if (!entry) throw new AppError(404, 'CREDENTIAL_NOT_FOUND', 'Credential not found');
    await this.atomic.set(PREFIX + id, null, entry.version);
    await this.#removeFromIndex(id);
  }

  // ─── Internal ───

  async #listAll(): Promise<ManagedCredential[]> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return [];
    const entries = await Promise.all(idx.value.map(id => this.atomic.get<ManagedCredential>(PREFIX + id)));
    return entries.filter(e => e).map(e => e!.value);
  }

  async #addToIndex(id: CredentialId): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    await this.atomic.set(INDEX_KEY, [...(idx?.value ?? []), id], idx?.version ?? null);
  }

  async #removeFromIndex(id: CredentialId): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return;
    await this.atomic.set(INDEX_KEY, idx.value.filter((i: string) => i !== id), idx.version);
  }
}

import type { IAuthProvider, AuthRequest, SignResult } from './interfaces.ts';

// ─── No-auth (local Podman, stub) ───

export class NoAuthProvider implements IAuthProvider {
  public readonly type = 'none';
  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async sign(_req: AuthRequest): Promise<SignResult> {
    return { headers: {} };
  }
  public isExpired(): boolean { return false; }
}

// ─── Bearer token (Cloudflare, OAuth2) ───

export class BearerTokenProvider implements IAuthProvider {
  public readonly type = 'bearer';
  private token: string;
  private expiresAt = 0;
  private readonly _tokenUrl: string | undefined;
  private readonly _clientId: string | undefined;
  private readonly _clientSecret: string | undefined;

  public constructor(token: string, opts?: { tokenUrl?: string; clientId?: string; clientSecret?: string }) {
    this.token = token;
    this._tokenUrl = opts?.tokenUrl;
    this._clientId = opts?.clientId;
    this._clientSecret = opts?.clientSecret;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async sign(req: AuthRequest): Promise<SignResult> {
    return { headers: { ...req.headers, Authorization: `Bearer ${this.token}` } };
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async getToken(): Promise<{ token: string; expiresAt?: number | undefined } | null> {
    return { token: this.token, expiresAt: this.expiresAt || undefined };
  }

  public isExpired(): boolean {
    return this.expiresAt > 0 && Date.now() >= this.expiresAt;
  }

  public async refresh(): Promise<void> {
    if (!this._tokenUrl || !this._clientId) return;
    const resp = await fetch(this._tokenUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        grant_type: 'client_credentials',
        client_id: this._clientId,
        ...(this._clientSecret ? { client_secret: this._clientSecret } : {}),
      }),
    });
    if (!resp.ok) throw new Error(`Token refresh failed: ${String(resp.status)}`);
    const data = await resp.json() as any;
    this.token = data.access_token ?? data.token ?? data.accessToken ?? '';
    this.expiresAt = data.expires_in ? Date.now() + data.expires_in * 1000 : 0;
  }
}

// ─── Shared HMAC helpers (Alibaba Cloud RPC + OSS) ───

function b64(buf: ArrayBuffer): string {
  return btoa(String.fromCharCode(...new Uint8Array(buf)));
}

export function percentEncode(s: string): string {
  return encodeURIComponent(s)
    .replace(/!/g, '%21').replace(/'/g, '%27')
    .replace(/\(/g, '%28').replace(/\)/g, '%29').replace(/\*/g, '%2A');
}

export async function hmacSha1(key: string, data: string): Promise<string> {
  const alg = { name: 'HMAC', hash: 'SHA-1' };
  const enc = new TextEncoder();
  const k = await crypto.subtle.importKey('raw', enc.encode(key), alg, false, ['sign']);
  return b64(await crypto.subtle.sign(alg, k, enc.encode(data)));
}

/** HMAC-SHA1 → base64 (for OSS Authorization header). Key is the raw accessKeySecret. */
export async function hmacSha1Base64(key: string, data: string): Promise<string> {
  return hmacSha1(key, data);
}

// ─── AK/SK for Alibaba Cloud RPC (HMAC-SHA1, signature in query params) ───

async function signAlibabaRpc(
  params: Record<string, string>,
  _accessKeyId: string,
  accessKeySecret: string,
): Promise<Record<string, string>> {
  const sortedKeys = Object.keys(params).sort();
  const canonicalized = sortedKeys
    .map(k => `${percentEncode(k)}=${percentEncode(params[k]!)}`)
    .join('&');
  const stringToSign = `POST&${percentEncode('/')}&${percentEncode(canonicalized)}`;
  const signature = await hmacSha1(accessKeySecret + '&', stringToSign);
  return { ...params, Signature: signature };
}

export class AkSkProvider implements IAuthProvider {
  public readonly type = 'aksk';

  /** Cache of stateless AkSkProvider instances, keyed by accessKeyId. */
  static #cache = new Map<string, AkSkProvider>();

  /** Get or create a cached instance. AkSkProvider is effectively stateless — reuse is safe. */
  public static getOrCreate(accessKeyId: string, accessKeySecret: string, region?: string, endpoint?: string): AkSkProvider {
    let p = AkSkProvider.#cache.get(accessKeyId);
    if (!p) {
      p = new AkSkProvider(accessKeyId, accessKeySecret, region, endpoint);
      AkSkProvider.#cache.set(accessKeyId, p);
    }
    return p;
  }

  public constructor(
    public readonly _accessKeyId: string,
    public readonly _accessKeySecret: string,
    /** Region for endpoint resolution (e.g. 'cn-hangzhou'). */
    public readonly _region?: string | undefined,
    /** Custom endpoint override. */
    public readonly _endpoint?: string | undefined,
  ) {}

  public isExpired(): boolean { return false; }

  /**
   * Sign an Alibaba Cloud RPC request.
   * Embeds the signature into the query string (URL override).
   * For non-Alibaba requests, returns headers as-is.
   */
  public async sign(req: AuthRequest): Promise<SignResult> {
    // Parse existing query params from URL
    const urlObj = new URL(req.url);
    const existingParams: Record<string, string> = {};
    urlObj.searchParams.forEach((v, k) => { existingParams[k] = v; });

    // Build common RPC params
    const rpcParams: Record<string, string> = {
      ...existingParams,
      Format: 'JSON',
      AccessKeyId: this._accessKeyId,
      SignatureMethod: 'HMAC-SHA1',
      SignatureVersion: '1.0',
      SignatureNonce: `${String(Date.now())}${Math.random().toString(36).slice(2)}`,
      Timestamp: new Date().toISOString().replace(/\.\d+Z$/, 'Z'),
    };

    const signed = await signAlibabaRpc(rpcParams, this._accessKeyId, this._accessKeySecret);
    const signedUrl = `${urlObj.origin}${urlObj.pathname}?${Object.entries(signed).map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`).join('&')}`;

    return { headers: req.headers, url: signedUrl };
  }
}

// ─── Factory ───

export function createAuthProvider(creds: any): IAuthProvider {
  if (!creds || creds.type === 'none') return new NoAuthProvider();
  if (creds.type === 'bearer') return new BearerTokenProvider(creds.token, creds);
  if (creds.type === 'aksk') return new AkSkProvider(creds.accessKeyId, creds.accessKeySecret, creds.region, creds.endpoint);
  return new NoAuthProvider();
}

/**
 * NaCl SealedBox — public-key sealed encryption (GitHub Secret model).
 *
 * Implements the same pattern as libsodium crypto_box_seal:
 *   1. Generate ephemeral ECDH keypair
 *   2. Derive shared secret from ephemeral private key + recipient public key
 *   3. Encrypt plaintext with AES-256-GCM using the shared secret
 *   4. Prepend ephemeral public key to ciphertext
 *
 * Web Crypto compatible — no external dependencies.
 */

const KEY_ALGO = { name: 'ECDH', namedCurve: 'P-256' } as const;
const ENC_ALGO = 'AES-GCM';
const IV_LENGTH = 12;
const TAG_LENGTH = 16; // AES-GCM auth tag

function bufToB64(buf: Uint8Array): string {
  return btoa(String.fromCharCode(...buf));
}

function b64ToBuf(b64: string): Uint8Array<ArrayBuffer> {
  const bin = atob(b64);
  const buf = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
  return buf;
}

function concat(...arrays: Uint8Array[]): Uint8Array {
  const total = arrays.reduce((s, a) => s + a.byteLength, 0);
  const out = new Uint8Array(total);
  let offset = 0;
  for (const a of arrays) { out.set(a, offset); offset += a.byteLength; }
  return out;
}

export interface KeyPair {
  publicKey: string;   // base64 raw public key
  privateKey: string;  // base64 raw private key
}

export class SealedBox {
  /** Generate a new ECDH P-256 keypair. */
  public static async generateKeyPair(): Promise<KeyPair> {
    const kp = await crypto.subtle.generateKey(KEY_ALGO, true, ['deriveBits']);
    const pubRaw = await crypto.subtle.exportKey('raw', kp.publicKey);
    const privRaw = await crypto.subtle.exportKey('pkcs8', kp.privateKey);
    return {
      publicKey: bufToB64(new Uint8Array(pubRaw)),
      privateKey: bufToB64(new Uint8Array(privRaw)),
    };
  }

  /** Export public key from raw base64. */
  public static async importPublicKey(rawB64: string): Promise<CryptoKey> {
    return crypto.subtle.importKey('raw', b64ToBuf(rawB64), KEY_ALGO, false, []);
  }

  /** Import private key from PKCS8 base64. */
  public static async importPrivateKey(rawB64: string): Promise<CryptoKey> {
    return crypto.subtle.importKey('pkcs8', b64ToBuf(rawB64), KEY_ALGO, false, ['deriveBits']);
  }

  /**
   * Seal plaintext to a recipient's public key.
   * Returns base64(ephemeralPublicKey || IV || ciphertext).
   */
  public static async seal(recipientPubKeyB64: string, plaintext: string): Promise<string> {
    const recipientKey = await SealedBox.importPublicKey(recipientPubKeyB64);

    // Generate ephemeral keypair
    const ephemeral = await crypto.subtle.generateKey(KEY_ALGO, true, ['deriveBits']);

    // Derive shared secret
    const sharedBits = await crypto.subtle.deriveBits(
      { name: 'ECDH', public: recipientKey },
      ephemeral.privateKey,
      256,
    );

    // Encrypt with AES-GCM
    const sharedKey = await crypto.subtle.importKey('raw', sharedBits, { name: ENC_ALGO }, false, ['encrypt']);
    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
    const encoded = new TextEncoder().encode(plaintext);
    const ciphertext = await crypto.subtle.encrypt({ name: ENC_ALGO, iv }, sharedKey, encoded);

    // Export ephemeral public key
    const ephemPubRaw = await crypto.subtle.exportKey('raw', ephemeral.publicKey);

    // Format: ephemeral_pub || iv || ciphertext
    const sealed = concat(new Uint8Array(ephemPubRaw), iv, new Uint8Array(ciphertext));
    return bufToB64(sealed);
  }

  /**
   * Open a sealed message using the recipient's private key.
   * Expects input as base64(ephemeralPublicKey || IV || ciphertext).
   */
  public static async open(recipientPrivKeyB64: string, sealedB64: string): Promise<string> {
    const privKey = await SealedBox.importPrivateKey(recipientPrivKeyB64);
    const sealed = b64ToBuf(sealedB64);

    // Parse: ephemeral_pub (65 bytes for P-256 uncompressed) || IV (12) || ciphertext
    const PUB_KEY_LEN = 65;
    if (sealed.byteLength < PUB_KEY_LEN + IV_LENGTH + TAG_LENGTH) {
      throw new Error('SealedBox: ciphertext too short');
    }

    const ephemPub = sealed.slice(0, PUB_KEY_LEN);
    const iv = sealed.slice(PUB_KEY_LEN, PUB_KEY_LEN + IV_LENGTH);
    const ciphertext = sealed.slice(PUB_KEY_LEN + IV_LENGTH);

    // Import ephemeral public key
    const ephemKey = await crypto.subtle.importKey('raw', ephemPub, KEY_ALGO, false, []);

    // Derive shared secret
    const sharedBits = await crypto.subtle.deriveBits(
      { name: 'ECDH', public: ephemKey },
      privKey,
      256,
    );

    // Decrypt
    const sharedKey = await crypto.subtle.importKey('raw', sharedBits, { name: ENC_ALGO }, false, ['decrypt']);
    const decrypted = await crypto.subtle.decrypt({ name: ENC_ALGO, iv }, sharedKey, ciphertext);
    return new TextDecoder().decode(decrypted);
  }
}

import type { CircularQueueOptions } from './interfaces.ts';

/**
 * Generic circular queue (ring buffer) base class with round-robin rotation.
 *
 * Supports two modes:
 * - **Fixed capacity** — `enqueue` returns `false` when full. Ideal for
 *   deterministic scheduling with a known maximum number of slots.
 * - **Auto-growing** (`capacity` omitted / 0) — starts at 16 and doubles
 *   when full. Indices still wrap around internally.
 *
 * The `rotate()` method moves the current head element to the tail,
 * implementing the core time-slice round-robin (RR) scheduling primitive.
 *
 * @example
 * ```ts
 * // Time-slice round-robin scheduler
 * class TimeSliceQueue extends CircularQueue<() => Promise<void>> {
 *   readonly quantumMs: number;
 *
 *   constructor(tasks: (() => Promise<void>)[], quantumMs: number) {
 *     super({ capacity: tasks.length });
 *     for (const t of tasks) this.enqueue(t);
 *     this.quantumMs = quantumMs;
 *   }
 *
 *   async tick(): Promise<void> {
 *     const task = this.current;
 *     if (task) await task();
 *     this.rotate();
 *   }
 * }
 * ```
 */
export class CircularQueue<T> {
  protected buffer: (T | undefined)[];
  protected _capacity: number;
  protected _size = 0;
  protected head = 0;
  protected tail = 0;
  protected readonly fixed: boolean;

  public constructor(options?: CircularQueueOptions) {
    const cap = options?.capacity ?? 0;
    this.fixed = cap > 0;
    this._capacity = this.fixed ? cap : 16;
    this.buffer = new Array(this._capacity);
  }

  // ─── Standard queue mutation ───

  /**
   * Insert a value at the tail of the queue.
   * @returns `false` if the queue has a fixed capacity and is full.
   */
  public enqueue(value: T): boolean {
    if (this._size === this._capacity) {
      if (this.fixed) return false;
      this.#resize();
    }
    this.buffer[this.tail] = value;
    this.tail = (this.tail + 1) % this._capacity;
    this._size++;
    return true;
  }

  /**
   * Remove and return the value at the head (the oldest element).
   * Returns `undefined` if the queue is empty.
   */
  public dequeue(): T | undefined {
    if (this._size === 0) return undefined;
    const value = this.buffer[this.head];
    this.buffer[this.head] = undefined;
    this.head = (this.head + 1) % this._capacity;
    this._size--;
    return value;
  }

  /**
   * Return the value at the head without removing it.
   * Returns `undefined` if the queue is empty.
   */
  public peek(): T | undefined {
    return this.buffer[this.head];
  }

  /**
   * Current element in a round-robin scheduling context.
   * Alias for {@link peek}.
   */
  public get current(): T | undefined {
    return this.peek();
  }

  /**
   * Round-robin rotation: move the current head element to the tail
   * and advance the head to the next element.
   *
   * This is the central primitive for time-slice round-robin scheduling:
   * after a task's time quantum expires, call `rotate()` to yield the CPU
   * to the next ready task.
   *
   * @returns The new head (the "current" for the next time slice), or
   *   `undefined` if the queue is empty.
   */
  public rotate(): T | undefined {
    if (this._size <= 1) return this.peek();
    const value = this.dequeue()!;
    this.enqueue(value);
    return this.buffer[this.head];
  }

  /**
   * Remove and return the element at the tail (the most recently enqueued).
   * Useful for preemption or cancellation of the last-arrived task.
   */
  public dequeueTail(): T | undefined {
    if (this._size === 0) return undefined;
    this.tail = (this.tail - 1 + this._capacity) % this._capacity;
    const value = this.buffer[this.tail];
    this.buffer[this.tail] = undefined;
    this._size--;
    return value;
  }

  /** Remove all elements. */
  public clear(): void {
    this.buffer.fill(undefined);
    this.head = 0;
    this.tail = 0;
    this._size = 0;
  }

  // ─── Queries ───

  /**
   * Access the element at a logical index (0 = head, 1 = second element, etc.).
   * Negative indices count from the tail (-1 = last element).
   * Returns `undefined` for out-of-range indices.
   */
  public at(index: number): T | undefined {
    if (index < 0) index = this._size + index;
    if (index < 0 || index >= this._size) return undefined;
    return this.buffer[(this.head + index) % this._capacity];
  }

  /** Check if `value` is in the queue (by reference equality). */
  public includes(value: T): boolean {
    for (let i = 0; i < this._size; i++) {
      if (this.buffer[(this.head + i) % this._capacity] === value) return true;
    }
    return false;
  }

  /** Return all elements as an array, head to tail. */
  public toArray(): T[] {
    const result: T[] = new Array(this._size);
    for (let i = 0; i < this._size; i++) {
      result[i] = this.buffer[(this.head + i) % this._capacity]!;
    }
    return result;
  }

  // ─── Iteration ───

  /** Iterate values from head to tail. */
  public *values(): IterableIterator<T> {
    for (let i = 0; i < this._size; i++) {
      yield this.buffer[(this.head + i) % this._capacity]!;
    }
  }

  /** Iterate `[index, value]` pairs, where index is the logical position. */
  public *entries(): IterableIterator<[number, T]> {
    for (let i = 0; i < this._size; i++) {
      yield [i, this.buffer[(this.head + i) % this._capacity]!];
    }
  }

  public [Symbol.iterator](): IterableIterator<T> {
    return this.values();
  }

  // ─── Properties ───

  /** Number of elements currently in the queue. */
  public get size(): number {
    return this._size;
  }

  /**
   * Maximum number of elements.
   * - In fixed-capacity mode: the configured capacity.
   * - In auto-grow mode: the current underlying array length (may increase).
   */
  public get capacity(): number {
    return this._capacity;
  }

  /** `true` when the queue contains no elements. */
  public get isEmpty(): boolean {
    return this._size === 0;
  }

  /**
   * `true` when `size` equals the current capacity.
   * In fixed-capacity mode this means `enqueue` will return `false`.
   */
  public get isFull(): boolean {
    return this._size === this._capacity;
  }

  // ─── Internal ───

  #resize(): void {
    const newCap = this._capacity * 2;
    const newBuf: (T | undefined)[] = new Array(newCap);
    for (let i = 0; i < this._size; i++) {
      newBuf[i] = this.buffer[(this.head + i) % this._capacity];
    }
    this.buffer = newBuf;
    this.head = 0;
    this.tail = this._size;
    this._capacity = newCap;
  }
}

import type { PaginatedResult } from './types.ts';

/**
 * Reference CRUD service contract.
 *
 * Services with standard CRUD semantics should structurally satisfy this
 * interface. For nominal enforcement, extend it:
 *
 *   export interface IVolumeService extends ICrudService<Volume, CreateInput, UpdateInput> {}
 *
 * Services with extra methods (uploadBlob, resolveData, etc.) extend and
 * add their own methods — the base interface guarantees create/get/list/
 * update/delete are all present.
 */
export interface ICrudService<
  TEntity,
  TCreate = Partial<TEntity>,
  TUpdate = Partial<TEntity>,
  TId = string,
> {
  create(input: TCreate): Promise<TEntity>;
  get(id: TId): Promise<TEntity | null>;
  list(page?: number, limit?: number): Promise<PaginatedResult<TEntity>>;
  update(id: TId, input: TUpdate): Promise<TEntity>;
  delete(id: TId): Promise<void>;
}

import type { Hono } from 'hono';
import type { CrudAction } from './types.ts';

/**
 * Map each CrudAction to a route registration callback.
 *
 * Record<CrudAction, …> enforces at compile time that every CRUD action
 * has a handler. Omit one → "Property X is missing" tsc error.
 *
 * @example
 * const handlers: CrudHandlerMap = {
 *   create: (r) => r.post('/', createHandler),
 *   list:   (r) => r.get('/', listHandler),
 *   get:    (r) => r.get('/:id', getHandler),
 *   update: (r) => r.put('/:id', updateHandler),
 *   delete: (r) => r.delete('/:id', deleteHandler),
 * };
 * registerCrudRoutes(router, handlers);
 */
export type CrudHandlerMap = Record<CrudAction, (router: Hono<any>) => void>;

/** Register all CRUD routes from a handler map. Returns the router for chaining. */
export function registerCrudRoutes(router: Hono<any>, handlers: CrudHandlerMap): Hono<any> {
  for (const register of Object.values(handlers)) {
    register(router);
  }
  return router;
}

import type { TopoSortResult, DagBuildError } from './interfaces.ts';

/**
 * Generic directed acyclic graph base class.
 *
 * Nodes are identified by `TId`. The key function `getId` is provided at construction
 * and is called for each node to extract its identity. Edges are directed `from` → `to`.
 * In topological sort, nodes with in-degree 0 are emitted first.
 *
 * Extend this class to add domain-specific query methods, custom validation, or
 * persistence logic. Subclasses have `protected` access to the internal maps.
 *
 * @example
 * ```ts
 * class TaskDag extends Dag<string, { id: string; deps: string[] }> {
 *   constructor() {
 *     super(n => n.id);
 *   }
 *
 *   addWithDependencies(task: { id: string; deps: string[] }): void {
 *     this.addNode(task);
 *     for (const dep of task.deps) {
 *       this.addEdge(task.id, dep);
 *     }
 *   }
 * }
 * ```
 */
export class Dag<TId, TNode> {
  /** Key extractor — subclasses may access to build custom queries. */
  protected readonly getId: (node: TNode) => TId;
  /** Node storage: id → node. */
  protected readonly nodes = new Map<TId, TNode>();
  /** Forward edges: from → Set{to}. */
  protected readonly outgoing = new Map<TId, Set<TId>>();
  /** Reverse edges: to → Set{from}. */
  protected readonly incoming = new Map<TId, Set<TId>>();

  public constructor(getId: (node: TNode) => TId) {
    this.getId = getId;
  }

  // ─── Mutation ───

  /** Add a node. Replaces any existing node with the same id. */
  public addNode(node: TNode): void {
    const id = this.getId(node);
    this.nodes.set(id, node);
    if (!this.outgoing.has(id)) this.outgoing.set(id, new Set());
    if (!this.incoming.has(id)) this.incoming.set(id, new Set());
  }

  /**
   * Add a directed edge `from` → `to`.
   * Both nodes must already exist (call `addNode` first).
   */
  public addEdge(from: TId, to: TId): void {
    if (!this.nodes.has(from)) throw new TypeError(`Dag.addEdge: source node "${String(from)}" does not exist`);
    if (!this.nodes.has(to)) throw new TypeError(`Dag.addEdge: target node "${String(to)}" does not exist`);

    this.outgoing.get(from)!.add(to);
    this.incoming.get(to)!.add(from);
  }

  // ─── Queries ───

  public hasNode(id: TId): boolean {
    return this.nodes.has(id);
  }

  public getNode(id: TId): TNode | undefined {
    return this.nodes.get(id);
  }

  /** Returns all nodes. Order is undefined. */
  public getAllNodes(): readonly TNode[] {
    return [...this.nodes.values()];
  }

  /** Number of nodes in the graph. */
  public get size(): number {
    return this.nodes.size;
  }

  /** Nodes that have a direct edge TO `id` (incoming neighbours). */
  public predecessorsOf(id: TId): readonly TNode[] {
    const result: TNode[] = [];
    for (const from of this.incoming.get(id) ?? []) {
      const node = this.nodes.get(from);
      if (node) result.push(node);
    }
    return result;
  }

  /** Nodes that `id` has a direct edge TO (outgoing neighbours). */
  public successorsOf(id: TId): readonly TNode[] {
    const result: TNode[] = [];
    for (const to of this.outgoing.get(id) ?? []) {
      const node = this.nodes.get(to);
      if (node) result.push(node);
    }
    return result;
  }

  /** Nodes with in-degree 0 — no edges point TO them. */
  public sources(): readonly TNode[] {
    const result: TNode[] = [];
    for (const [id] of this.nodes) {
      const inc = this.incoming.get(id);
      if (!inc || inc.size === 0) {
        result.push(this.nodes.get(id)!);
      }
    }
    return result;
  }

  /** Nodes with out-degree 0 — no edges point FROM them. */
  public sinks(): readonly TNode[] {
    const result: TNode[] = [];
    for (const [id] of this.nodes) {
      const out = this.outgoing.get(id);
      if (!out || out.size === 0) {
        result.push(this.nodes.get(id)!);
      }
    }
    return result;
  }

  // ─── Algorithms ───

  /**
   * Topological sort via Kahn's algorithm.
   * Returns nodes sorted so that every node appears before the nodes that depend on it
   * (i.e. if A → B, A appears before B).
   *
   * On success: `{ success: true, sorted: [...] }`
   * On cycle:  `{ success: false, sorted: [...partial...], error: "..." }`
   */
  public topologicalSort(): TopoSortResult<TNode> {
    const inDegree = new Map<TId, number>();

    // initialise in-degree for every node
    for (const id of this.nodes.keys()) {
      inDegree.set(id, 0);
    }

    // count incoming edges
    for (const [, targets] of this.outgoing) {
      for (const to of targets) {
        inDegree.set(to, (inDegree.get(to) ?? 0) + 1);
      }
    }

    // seed queue with zero in-degree nodes
    const queue: TId[] = [];
    for (const [id, degree] of inDegree) {
      if (degree === 0) queue.push(id);
    }

    const sorted: TNode[] = [];
    while (queue.length > 0) {
      const id = queue.shift()!;
      sorted.push(this.nodes.get(id)!);

      for (const to of this.outgoing.get(id) ?? []) {
        const newDegree = (inDegree.get(to) ?? 1) - 1;
        inDegree.set(to, newDegree);
        if (newDegree === 0) queue.push(to);
      }
    }

    if (sorted.length < this.nodes.size) {
      const remaining = [...this.nodes.keys()].filter(id => (inDegree.get(id) ?? 0) > 0);
      return {
        success: false,
        sorted,
        error: `Cycle detected: could not sort ${String(remaining.length)} node(s) [${remaining.join(', ')}]`,
      };
    }

    return { success: true, sorted };
  }

  /**
   * Extract the subgraph reachable from `root` using depth-first search.
   * Follows outgoing edges from root to find all transitive successors.
   *
   * Returns a discriminated union:
   * - `{ success: true, dag }` on success
   * - `{ success: false, error }` when the root is missing or a cycle is detected
   */
  public reachableSubgraph(root: TId):
    | { readonly success: true; readonly dag: Dag<TId, TNode> }
    | { readonly success: false; readonly error: string } {
    const subgraph = new Dag<TId, TNode>(this.getId);
    const path = new Set<TId>();
    const visited = new Set<TId>();

    const visit = (id: TId): string | undefined => {
      if (!this.nodes.has(id)) return `Node "${String(id)}" not found`;
      if (path.has(id)) return `Cycle detected: "${String(id)}" is visited twice on the same path`;
      if (visited.has(id)) return;

      path.add(id);
      visited.add(id);
      subgraph.addNode(this.nodes.get(id)!);

      for (const to of this.outgoing.get(id) ?? []) {
        const err = visit(to);
        if (err) return err;
        subgraph.addEdge(id, to);
      }

      path.delete(id);
    };

    const error = visit(root);
    if (error) return { success: false as const, error };
    return { success: true as const, dag: subgraph };
  }
}

/**
 * Build a DAG by traversing a key-value store using DFS starting from `rootId`.
 *
 * For each visited node, `getReferences` returns the IDs of downstream nodes.
 * The DAG edges are set as `parent → child` (the node that lists the reference
 * points TO the referenced node).
 *
 * Cycle detection uses path tracking: if a node is encountered twice on the
 * current DFS path a `DagBuildError` is recorded and that branch is not
 * traversed further.
 *
 * @param rootId      — Starting node ID.
 * @param lookup      — Resolve an ID to a node (return `undefined` if missing).
 * @param getReferences — Return the IDs this node references (outgoing edges).
 * @param getId       — Extract a node's identity (passed to the Dag constructor).
 */
export function buildDag<TId, TNode>(
  rootId: TId,
  lookup: (id: TId) => TNode | undefined,
  getReferences: (node: TNode) => readonly TId[],
  getId: (node: TNode) => TId,
): { dag: Dag<TId, TNode>; errors: readonly DagBuildError<TId>[] } {
  const dag = new Dag<TId, TNode>(getId);
  const errors: DagBuildError<TId>[] = [];
  const visited = new Set<TId>();
  const path = new Set<TId>();

  function visit(id: TId): void {
    if (path.has(id)) {
      errors.push({ id, message: `Circular dependency: ${[...path, id].join(' -> ')}` });
      return;
    }
    if (visited.has(id)) return;

    const node = lookup(id);
    if (!node) {
      errors.push({ id, message: `Node not found` });
      return;
    }

    visited.add(id);
    dag.addNode(node);

    const refs = getReferences(node);
    if (refs.length > 0) {
      path.add(id);
      for (const ref of refs) {
        visit(ref);
        if (dag.hasNode(ref)) {
          dag.addEdge(id, ref);
        }
      }
      path.delete(id);
    }
  }

  visit(rootId);
  return { dag, errors };
}

import { Dag } from './graph.ts';

/** Minimum contract a task must satisfy to participate in DAG orchestration. */
export interface OrchestratedTask {
  readonly id: string;
  readonly dependsOn: readonly string[];
}

/** Result of executing a single task. */
export interface OrchestratedTaskResult {
  readonly id: string;
  readonly success: boolean;
  readonly error?: string | undefined;
}

/** Final result of orchestrating all tasks. */
export interface OrchestrationResult {
  readonly success: boolean;
  readonly results: readonly OrchestratedTaskResult[];
}

/**
 * Generic DAG-based task orchestrator.
 *
 * Takes a list of tasks with dependency declarations, topologically sorts them
 * into batches (all tasks whose dependencies are met), and executes each batch
 * concurrently via the caller-supplied executor function.
 *
 * Failures are collected per-task — one failed task does not cancel its batch
 * siblings, but dependent tasks in later batches are skipped.
 *
 * @example
 * ```ts
 * const orchestrator = new DagOrchestrator();
 * const result = await orchestrator.execute(tasks, async (task) => {
 *   await containerProvider.create(task.spec);
 * });
 * ```
 */
export class DagOrchestrator<T extends OrchestratedTask> {
  /**
   * Execute a set of tasks in DAG order.
   *
   * @param tasks  - All tasks to execute.
   * @param executor - Async function that performs the actual work for a task.
   *                   If it throws, the task is marked as failed.
   */
  public async execute(
    tasks: readonly T[],
    executor: (task: T) => Promise<void>,
  ): Promise<OrchestrationResult> {
    if (tasks.length === 0) return { success: true, results: [] };

    // 1. Build DAG
    const dag = new Dag<string, T>(t => t.id);
    for (const task of tasks) dag.addNode(task);
    for (const task of tasks) {
      for (const dep of task.dependsOn) {
        dag.addEdge(task.id, dep);
      }
    }

    // 2. Topological sort — produces batches implicitly (all in-degree-0 nodes
    //    at each iteration form a batch).
    const sorted = dag.topologicalSort();
    if (!sorted.success) {
      return {
        success: false,
        results: sorted.sorted.map(n => ({ id: n.id, success: false, error: `Cycle detected: ${sorted.error}` })),
      };
    }

    // 3. Execute batch-by-batch using Kahn's algorithm semantics.
    //    We track completed nodes and, each iteration, pick nodes whose
    //    dependencies have all been satisfied.
    const results: OrchestratedTaskResult[] = [];
    const completed = new Set<string>();
    const pending = new Set(sorted.sorted.map(t => t.id));

    while (pending.size > 0) {
      const batch = [...pending].filter(id => {
        const node = dag.getNode(id);
        return node && node.dependsOn.every(d => completed.has(d));
      });

      if (batch.length === 0) {
        // Remaining tasks have unsatisfied deps (shouldn't happen since topo
        // sort succeeded, but guard against logic errors).
        for (const id of pending) {
          results.push({ id, success: false, error: 'Unsatisfied dependency' });
        }
        break;
      }

      const batchResults = await Promise.allSettled(
        batch.map(async (id) => {
          const task = dag.getNode(id)!;
          try {
            await executor(task);
            return { id: task.id, success: true };
          } catch (e) {
            return { id: task.id, success: false, error: e instanceof Error ? e.message : String(e) };
          }
        }),
      );

      for (const r of batchResults) {
        const result = r.status === 'fulfilled'
          ? r.value
          : { id: '(unknown)', success: false, error: r.reason?.message ?? String(r.reason) };
        results.push(result);
        if (result.success) {
          completed.add(result.id);
        }
        pending.delete(result.id);
      }
    }

    return {
      success: results.every(r => r.success),
      results,
    };
  }
}

/**
 * Unified DAG scheduling domain types.
 *
 * Merges:
 *   - Airflow: TaskInstance 12-state, TriggerRule, Pool, DagRun
 *   - GitHub Actions: WorkflowDef → DagDefinition, JobDef → Task, JobRun → TaskInstance
 *
 * The existing `Dag<TId, TNode>` (graph.ts) provides Kahn topological sort.
 * This file defines the *domain* layer: what tasks are, how they run, and what
 * states they transition through.
 */

import type { VersionId } from '../brand.ts';

// ─── Brand types ───

declare const DAG_ID_BRAND: unique symbol;
declare const DAG_RUN_ID_BRAND: unique symbol;
declare const TASK_ID_BRAND: unique symbol;
declare const TASK_INSTANCE_ID_BRAND: unique symbol;

export type DagId = string & { readonly [DAG_ID_BRAND]: true };
export type DagRunId = string & { readonly [DAG_RUN_ID_BRAND]: true };
export type TaskId = string & { readonly [TASK_ID_BRAND]: true };
export type TaskInstanceId = string & { readonly [TASK_INSTANCE_ID_BRAND]: true };

export function createDagId(raw: string): DagId { return raw as DagId; }
export function createDagRunId(raw: string): DagRunId { return raw as DagRunId; }
export function createTaskId(raw: string): TaskId { return raw as TaskId; }
export function createTaskInstanceId(raw: string): TaskInstanceId { return raw as TaskInstanceId; }

// ─── Trigger rule (Airflow 9) ───

export type TriggerRule =
  | 'all_success'
  | 'all_failed'
  | 'all_done'
  | 'one_success'
  | 'one_failed'
  | 'none_failed'
  | 'none_skipped'
  | 'none_failed_min_one_success'
  | 'always';

export const DEFAULT_TRIGGER_RULE: TriggerRule = 'all_success';

// ─── Operator type (extensible) ───

export type OperatorType =
  | 'run'        // shell command inside container
  | 'uses'       // reusable action reference (container image or JS)
  | 'dns'        // DNS record upsert/delete
  | 'sandbox'    // provision a full container group
  | 'noop';      // no-op (placeholder / passthrough)

// ─── Task definition ───

export interface Task {
  readonly id: TaskId;
  readonly name: string;
  readonly operatorType: OperatorType;
  /** Operator-specific configuration (arbitrary JSON). */
  readonly config: Record<string, unknown>;
  /** Task IDs this task depends on (upstream edges). */
  readonly dependsOn: readonly TaskId[];
  readonly triggerRule: TriggerRule;
  readonly retries: number;
  readonly retryDelayMs: number;
  readonly timeoutMs?: number;
  /** Pool name for slot-based concurrency. */
  readonly pool?: string;
  /** Priority within the pool (higher = more important). */
  readonly priorityWeight?: number;
  /** Maximum active TaskInstances for this task across all DagRuns. */
  readonly maxActiveTisPerDag?: number;
  /** Target compute instance / runner label. */
  readonly executorKey?: string;
  /** Arbitrary metadata for extensions. */
  readonly metadata?: Record<string, unknown>;
}

// ─── TaskInstance state machine ───

/**
 * Unified 12-state machine merging Airflow 13 + GHA 6.
 *
 *   NONE → SCHEDULED → QUEUED → RUNNING → SUCCESS | FAILED
 *                                        ├── UP_FOR_RETRY → (back to QUEUED)
 *                                        ├── DEFERRED     → (back to SCHEDULED)
 *                                        └── RESTARTING   → (back to QUEUED)
 *   SCHEDULED → SKIPPED | UPSTREAM_FAILED
 *   Any non-terminal state → REMOVED
 */
export type TaskInstanceState =
  | 'NONE'
  | 'SCHEDULED'
  | 'QUEUED'
  | 'RUNNING'
  | 'SUCCESS'
  | 'FAILED'
  | 'UP_FOR_RETRY'
  | 'SKIPPED'
  | 'UPSTREAM_FAILED'
  | 'DEFERRED'
  | 'RESTARTING'
  | 'REMOVED';

export const TERMINAL_TASK_STATES: ReadonlySet<TaskInstanceState> = new Set([
  'SUCCESS', 'FAILED', 'SKIPPED', 'UPSTREAM_FAILED', 'REMOVED',
]);

export function isTaskTerminal(state: TaskInstanceState): boolean {
  return TERMINAL_TASK_STATES.has(state);
}

export const TASK_VALID_TRANSITIONS: Readonly<Record<TaskInstanceState, readonly TaskInstanceState[]>> = {
  NONE:              ['SCHEDULED', 'REMOVED'],
  SCHEDULED:         ['QUEUED', 'SKIPPED', 'UPSTREAM_FAILED', 'REMOVED'],
  QUEUED:            ['RUNNING', 'REMOVED'],
  RUNNING:           ['SUCCESS', 'FAILED', 'UP_FOR_RETRY', 'DEFERRED', 'RESTARTING', 'REMOVED'],
  UP_FOR_RETRY:      ['QUEUED', 'FAILED'],
  DEFERRED:          ['SCHEDULED', 'REMOVED'],
  RESTARTING:        ['QUEUED', 'REMOVED'],
  SUCCESS:           [],
  FAILED:            [],
  SKIPPED:           [],
  UPSTREAM_FAILED:   [],
  REMOVED:           [],
};

export function isValidTaskTransition(from: TaskInstanceState, to: TaskInstanceState): boolean {
  return TASK_VALID_TRANSITIONS[from]?.includes(to) ?? false;
}

// ─── TaskInstance (runtime) ───

export interface TaskInstance {
  readonly id: TaskInstanceId;
  readonly taskId: TaskId;
  readonly dagRunId: DagRunId;
  state: TaskInstanceState;
  tryNumber: number;
  startedAt?: number | undefined;
  completedAt?: number | undefined;
  exitCode?: number | undefined;
  error?: string | undefined;
  output?: unknown;
  version: VersionId;
}

// ─── DagDefinition ───

export interface DagDef {
  readonly id: DagId;
  readonly name: string;
  readonly description?: string;
  /** Tasks that form the DAG. */
  readonly tasks: readonly Task[];
  /** Maximum active TaskInstances across all DagRuns for this DAG. */
  readonly maxActiveTasks?: number;
  /** Maximum active DagRuns for this DAG. */
  readonly maxActiveRuns?: number;
  /** Cron schedule expression. */
  readonly schedule?: string;
  /** Allow catchup of missed intervals. */
  readonly catchup?: boolean;
  readonly createdAt: number;
  readonly updatedAt: number;
  readonly version: VersionId;
}

// ─── DagRun ───

export type DagRunStatus = 'QUEUED' | 'RUNNING' | 'SUCCESS' | 'FAILED';

export interface DagRun {
  readonly id: DagRunId;
  readonly dagId: DagId;
  readonly status: DagRunStatus;
  /** Scheduled execution time (logical date in Airflow terms). */
  readonly executionDate: number;
  readonly startedAt?: number;
  readonly completedAt?: number;
  readonly trigger: 'manual' | 'cron' | 'backfill' | 'http' | 'webhook' | 'shared_link';
  readonly triggerPayload?: unknown;
  /** Environment variables merged across the DAG. */
  readonly env: Record<string, string>;
  /** User who triggered this run. */
  readonly ownerId?: string;
  readonly error?: string;
  readonly version: VersionId;
}

// ─── Pool ───

export interface Pool {
  readonly name: string;
  readonly slots: number;
  occupiedSlots: number;
  readonly description?: string | undefined;
}

export function openSlots(pool: Pool): number {
  return Math.max(0, pool.slots - pool.occupiedSlots);
}

// ─── Executor interface ───

export interface TaskExecutionResult {
  readonly success: boolean;
  readonly exitCode?: number;
  readonly error?: string;
  readonly output?: unknown;
}

export interface ITaskExecutor {
  readonly key: string;
  execute(task: Task, ti: TaskInstance): Promise<TaskExecutionResult>;
}

// ─── Scheduler context ───

export interface SchedulerContext {
  /** Resolve a DagDef by ID. */
  getDagDef(dagId: DagId): Promise<{ value: DagDef; version: VersionId } | null>;
  /** Get all active DagRuns. */
  getActiveDagRuns(): Promise<DagRun[]>;
  /** Get a specific DagRun. */
  getDagRun(dagRunId: DagRunId): Promise<{ value: DagRun; version: VersionId } | null>;
  /** Persist a DagRun update. */
  updateDagRun(dagRun: DagRun, version: VersionId): Promise<boolean>;
  /** Get all TaskInstances for a DagRun. */
  getTaskInstances(dagRunId: DagRunId): Promise<TaskInstance[]>;
  /** Persist a TaskInstance. */
  saveTaskInstance(ti: TaskInstance, version?: VersionId | null): Promise<boolean>;
  /** Get a pool by name. */
  getPool(name: string): Promise<Pool | null>;
  /** Update pool slot occupancy. */
  updatePool(pool: Pool): Promise<boolean>;
  /** Resolve an executor by key. */
  getExecutor(key: string): Promise<ITaskExecutor | null>;
}

import type { Event, EventHandler, EventBusConfig } from './types.ts';

/**
 * In-process pub/sub event bus.
 *
 * Handlers are registered per event type. When an {@link Event} is dispatched
 * all matching handlers are invoked in registration order. Async handlers are
 * awaited; exceptions are routed to the configurable `onError` callback.
 *
 * @example
 * ```ts
 * const bus = new EventBus();
 * bus.on('sandbox.create', async (e) => {
 *   await createSandbox(e.payload);
 * });
 * await bus.dispatch(createEvent('sandbox.create', { name: 'game-01' }));
 * ```
 */
export class EventBus {
  readonly #handlers = new Map<string, Set<EventHandler>>();
  readonly #onError: (error: unknown, event: Event) => void;

  public constructor(config?: EventBusConfig) {
    this.#onError = config?.onError ?? ((err, _event) => { throw err; });
  }

  // ─── Registration ───

  /**
   * Register a handler for a specific event type.
   *
   * Multiple handlers for the same type are invoked in registration order.
   * The same handler reference can be safely re-registered (it is a no-op).
   */
  public on<T>(type: string, handler: EventHandler<T>): void {
    let set = this.#handlers.get(type);
    if (!set) {
      set = new Set();
      this.#handlers.set(type, set);
    }
    set.add(handler as EventHandler);
  }

  /**
   * Remove a previously registered handler.
   * @returns `true` if the handler was found and removed.
   */
  public off<T>(type: string, handler: EventHandler<T>): boolean {
    return this.#handlers.get(type)?.delete(handler as EventHandler) ?? false;
  }

  /**
   * Remove all handlers for an event type, or all handlers across all types.
   */
  public removeAll(type?: string): void {
    if (type) {
      this.#handlers.delete(type);
    } else {
      this.#handlers.clear();
    }
  }

  // ─── Dispatch ───

  /**
   * Dispatch an event to all registered handlers for its type.
   *
   * All handlers are awaited. If any handler throws, the error is forwarded
   * to the configured `onError` callback, and remaining handlers still run.
   */
  public async dispatch(event: Event): Promise<void> {
    const handlers = this.#handlers.get(event.type);
    if (!handlers || handlers.size === 0) return;

    // Fast path: single handler — no array / allSettled allocation
    if (handlers.size === 1) {

      const handler: EventHandler | undefined = handlers.values().next().value;
      if (handler) {
        try {
          const r = handler(event);
          if (r instanceof Promise) await r;
        } catch (err) {
          this.#onError(err, event);
        }
      }
      return;
    }

    const results: Promise<void>[] = [];
    for (const handler of handlers) {
      try {
        const r = handler(event);
        if (r instanceof Promise) results.push(r);
      } catch (err) {
        try { this.#onError(err, event); } catch { /* onError must not abort the loop */ }
      }
    }
    if (results.length > 0) {
      const settled = await Promise.allSettled(results);
      for (const s of settled) {
        if (s.status === 'rejected') {
          try { this.#onError(s.reason, event); } catch { /* onError must not abort */ }
        }
      }
    }
  }

  /** Number of registered event types. */
  public get registeredTypes(): number {
    return this.#handlers.size;
  }

  /** Check if any handlers exist for a given event type. */
  public hasHandlers(type: string): boolean {
    return (this.#handlers.get(type)?.size ?? 0) > 0;
  }
}

import { CircularQueue } from '../circular-queue/queue.ts';
import type { IAtomicStore } from '../store/interfaces.ts';
import type { ITimerBackend, TimerHandle } from '../scheduler/interfaces.ts';
import { SetIntervalBackend } from '../scheduler/set-interval-backend.ts';
import type { EventBus } from './bus.ts';
import type {
  Event,
  TriggerEventInput,
  EventLoopConfig,
  EventLoopStatus,
} from './types.ts';
import { eventFromTrigger, DEFAULT_EVENT_LOOP_CONFIG } from './types.ts';

// ─── Store keys ───

const KEY_PENDING = 'events:pending';

/**
 * Public control surface for the event loop.
 *
 * Designed to be easily wrapped by Hono routes — every method either
 * returns `void` or a JSON-serialisable value so Worker endpoints can
 * delegate directly through.
 *
 * @example
 * ```ts
 * // POST /api/events/loop/start
 * loop.start();
 *
 * // POST /api/events/loop/configure
 * loop.configure({ intervalMs: 30000 });
 *
 * // GET /api/events/loop/status
 * return c.json(loop.status());
 * ```
 */
export interface IEventLoopControl {
  /** Start processing queued events. No-op if already running. */
  start(): void;
  /** Stop processing. No-op if not running. */
  stop(): void;
  /** Pause processing; events continue to accumulate. */
  pause(): void;
  /** Resume processing after a pause. */
  resume(): void;
  /**
   * Update runtime configuration.
   * @returns the merged config after applying changes.
   */
  configure(config: Partial<EventLoopConfig>): EventLoopConfig;
  /** Snapshot of current state. */
  status(): EventLoopStatus;

  /** Enqueue an event for processing. */
  enqueue(event: Event): void;
  /**
   * Convenience: create an Event from a public TriggerEventInput and enqueue it.
   * This is the method external HTTP callers route through.
   */
  public enqueueTrigger<T>(input: TriggerEventInput<T>): Event;

  /**
   * Enqueue a system event that bypasses the maxQueueSize limit.
   * Use for critical internal events (health:check, etc.) that must
   * never be dropped due to queue pressure.
   */
  public enqueuePriority<T>(input: TriggerEventInput<T>): Event;

  /** List pending events in the queue (type + id, no payload). */
  pendingEvents(): { type: string; id: string }[];

  /** Current number of pending events. */
  readonly size: number;

  /**
   * Manually trigger a tick, bypassing the timer backend.
   *
   * Useful for:
   * - DO Alarm callbacks (DO fires → calls `triggerTick()` via HTTP)
   * - `wrangler dev --test-scheduled` endpoint
   * - Manual API-driven dispatch
   */
  triggerTick(): Promise<void>;
}

/**
 * Round-robin event loop built on {@link CircularQueue}.
 *
 * Queues incoming events and dispatches them via an {@link EventBus} on a
 * configurable timer. Supports start/stop/pause/resume lifecycle and
 * runtime configuration changes — all exposed through {@link IEventLoopControl}
 * for easy HTTP API wrapping.
 *
 * The timing backend is injectable (defaults to {@link SetIntervalBackend}),
 * making the loop testable without wall-clock dependencies and deployable
 * with Workers-native {@link import('../scheduler/interfaces.ts').ITimerBackend
 * ITimerBackend} implementations.
 *
 * When an {@link IAtomicStore} is provided (4th constructor param), events
 * are persisted atomically — they survive Worker restarts and are recovered
 * on the next construction. The store bridges through the existing DO / KV
 * abstraction layer so it works with any backend.
 *
 * @example
 * ```ts
 * // In-memory only
 * const loop = new EventLoop(bus, { intervalMs: 60000 });
 *
 * // Persistent (survives restarts via DO / KV)
 * const loop = new EventLoop(bus, { intervalMs: 60000 }, undefined, stores.atomic);
 *
 * // Wire up a Hono route:
 * app.post('/api/events', async (c) => {
 *   const input = await c.req.json<TriggerEventInput>();
 *   const event = loop.enqueueTrigger(input);
 *   return c.json({ id: event.id }, 202);
 * });
 *
 * app.get('/api/events/loop/status', (c) => c.json(loop.status()));
 * ```
 */
export class EventLoop implements IEventLoopControl {
  readonly #queue: CircularQueue<Event>;
  readonly #bus: EventBus;
  readonly #timerBackend: ITimerBackend;
  readonly #store: IAtomicStore | undefined;
  #timerHandle: TimerHandle | null = null;
  #paused = false;
  #ticking = false;
  #processedCount = 0;
  #startTime = 0;
  #config: EventLoopConfig;

  public constructor(
    bus: EventBus,
    config?: Partial<EventLoopConfig>,
    timerBackend?: ITimerBackend,
    store?: IAtomicStore,
  ) {
    this.#bus = bus;
    this.#timerBackend = timerBackend ?? new SetIntervalBackend();
    this.#queue = new CircularQueue<Event>({ capacity: 0 }); // auto-grow
    this.#config = { ...DEFAULT_EVENT_LOOP_CONFIG, ...config };
    this.#store = store;
    if (this.#store) this.#recover().catch(err => { this.#reportError(err, 'recover'); });
    if (this.#config.autoStart) this.start();
  }

  // ─── IEventLoopControl ───

  public start(): void {
    if (this.#timerHandle !== null) return;
    this.#paused = false;
    this.#startTime = this.#startTime === 0 ? Date.now() : this.#startTime;
    this.#timerHandle = this.#timerBackend.start(
      () => { this.#tick().catch(err => { this.#reportError(err, 'tick'); }); },
      this.#config.intervalMs,
    );
  }

  public stop(): void {
    if (this.#timerHandle === null) return;
    this.#timerHandle.clear();
    this.#timerHandle = null;
    this.#paused = false;
    this.#startTime = 0;
  }

  public pause(): void {
    this.#paused = true;
  }

  public resume(): void {
    this.#paused = false;
  }

  public configure(config: Partial<EventLoopConfig>): EventLoopConfig {
    let restart = false;

    if (config.intervalMs !== undefined && config.intervalMs > 0) {
      this.#config.intervalMs = config.intervalMs;
      if (this.#timerHandle !== null) restart = true;
    }
    if (config.batchSize !== undefined) {
      this.#config.batchSize = config.batchSize;
    }
    if (config.maxQueueSize !== undefined) {
      this.#config.maxQueueSize = config.maxQueueSize;
    }
    if (config.onError !== undefined) {
      this.#config.onError = config.onError;
    }

    if (restart) {
      this.#timerHandle!.clear();
      this.#timerHandle = this.#timerBackend.start(
        () => { this.#tick().catch(err => { this.#reportError(err, 'tick'); }); },
        this.#config.intervalMs,
      );
    }

    return { ...this.#config };
  }

  public status(): EventLoopStatus {
    return {
      running: this.#timerHandle !== null,
      paused: this.#paused,
      queueSize: this.#queue.size,
      processedCount: this.#processedCount,
      uptimeMs: this.#startTime > 0 ? Date.now() - this.#startTime : 0,
      config: { ...this.#config },
    };
  }

  public enqueue(event: Event): void {
    if (this.#config.maxQueueSize > 0 && this.#queue.size >= this.#config.maxQueueSize) {
      this.#reportError(
        new Error(`Queue full (${this.#queue.size} >= ${this.#config.maxQueueSize})`),
        'enqueue',
      );
      return;
    }
    // Persist BEFORE memory enqueue to close the crash window.
    // If persist is in-flight when crash occurs, the event is in the store
    // and will be recovered on restart (at-least-once delivery).
    if (this.#store) this.#persistEnqueue(event).catch(err => { this.#reportError(err, 'persist-enqueue'); });
    this.#queue.enqueue(event);
  }

  public enqueueTrigger<T>(input: TriggerEventInput<T>): Event {
    const event = eventFromTrigger(input);
    if (this.#config.maxQueueSize > 0 && this.#queue.size >= this.#config.maxQueueSize) {
      this.#reportError(
        new Error(`Queue full (${this.#queue.size} >= ${this.#config.maxQueueSize})`),
        'enqueue',
      );
      return event;
    }
    if (this.#store) this.#persistEnqueue(event).catch(err => { this.#reportError(err, 'persist-enqueue'); });
    this.#queue.enqueue(event);
    return event;
  }

  public enqueuePriority<T>(input: TriggerEventInput<T>): Event {
    const event = eventFromTrigger(input);
    if (this.#store) this.#persistEnqueue(event).catch(err => { this.#reportError(err, 'persist-enqueue'); });
    this.#queue.enqueue(event);
    return event;
  }

  public pendingEvents(): { type: string; id: string }[] {
    return this.#queue.toArray().map(e => ({ type: e.type, id: e.id }));
  }

  public get size(): number {
    return this.#queue.size;
  }

  public async triggerTick(): Promise<void> {
    if (this.#ticking) return;
    this.#ticking = true;
    try {
      await this.#tick();
    } catch (err) {
      this.#reportError(err, 'tick');
    } finally {
      this.#ticking = false;
    }
  }

  // ─── Internal ───

  #reportError(err: unknown, context: string): void {
    this.#config.onError?.(err, context);
  }

  async #tick(): Promise<void> {
    if (this.#paused || this.#queue.isEmpty) return;

    const limit = this.#config.batchSize > 0
      ? Math.min(this.#config.batchSize, this.#queue.size)
      : this.#queue.size;

    // Dequeue batch first so the queue is drained before we await I/O.
    const dispatched: Event[] = [];
    for (let i = 0; i < limit; i++) {
      const event = this.#queue.dequeue();
      if (!event) break;
      dispatched.push(event);
      this.#processedCount++;
    }

    // Await batch dispatch — provides backpressure so only one batch
    // processes at a time.  Prevents unbounded queue growth when dispatch
    // handlers are slower than the tick interval.
    const results = await Promise.allSettled(dispatched.map(e => this.#bus.dispatch(e)));
    for (const r of results) {
      if (r.status === 'rejected') this.#reportError(r.reason, 'dispatch');
    }

    if (this.#store && dispatched.length > 0) {
      try {
        await this.#persistDequeue(dispatched);
      } catch (err) {
        this.#reportError(err, 'persist-dequeue');
      }
    }
  }

  // ─── Store persistence ───

  /** Recover pending events from store after construction. */
  async #recover(): Promise<void> {
    try {
      await this.#store!.transact(async (txn) => {
        const pending = await txn.get<Event[]>(KEY_PENDING);
        if (!pending) return;
        for (const event of pending) {
          if (event.type === 'health:check') continue;
          this.#queue.enqueue(event);
        }
        txn.set(KEY_PENDING, []);
      });
    } catch (err) {
      this.#reportError(err, 'recover');
    }
  }

  /** Event types that should survive Worker restarts (image.pull, user events). */
  static #PERSISTED_TYPES = new Set(['image.pull']);

  /** Append one event to the persisted queue (transient events skipped). */
  async #persistEnqueue(event: Event): Promise<void> {
    if (!EventLoop.#PERSISTED_TYPES.has(event.type)) return;
    await this.#store!.transact(async (txn) => {
      const pending = (await txn.get<Event[]>(KEY_PENDING)) ?? [];
      pending.push(event);
      txn.set(KEY_PENDING, pending);
    });
  }

  /** Remove dispatched events from the persisted queue. */
  async #persistDequeue(events: Event[]): Promise<void> {
    const dispatched = new Set(events.map(e => e.id));
    await this.#store!.transact(async (txn) => {
      const pending = (await txn.get<Event[]>(KEY_PENDING)) ?? [];
      txn.set(KEY_PENDING, pending.filter(e => !dispatched.has(e.id)));
    });
  }
}

import { z } from 'zod';
import type { EventBus } from '../event-bus/bus.ts';
import type { EventLoop } from '../event-bus/loop.ts';
import type { IAtomicStore } from '../store/interfaces.ts';
import type { IProviderRegistry } from '../provider/interfaces.ts';
import type { IAuditWriter } from '../audit/types.ts';
import type { IMessageQueue } from '../../queue/interfaces.ts';
import type { Sandbox } from '../../features/sandbox/types.ts';
import { SandboxStatus } from '../../features/sandbox/types.ts';
import { createRegionId } from '../region/types.ts';
import { createInstanceId } from '../region/instance.ts';
import { runtimeToNetwork, runtimeToContainers, runtimeToEvents } from '../../features/sandbox/runtime-mapper.ts';
import { formatDmesgLine } from '../utils/dmesg.ts';

export interface HealthCheckDeps {
  stores: { atomic: IAtomicStore };
  providers: Pick<IProviderRegistry, 'resolveContainer'>;
  eventBus: EventBus;
  eventLoop: EventLoop;
  audit: IAuditWriter;
  queueProducer: IMessageQueue;
}

/** Marker key prefix for GC dedup. Value: { expiresAt: number }. */
const GC_MARKER_PREFIX = 'gc:queued:';

/** Marker TTL — if consumer hasn't processed the GC within this window,
 *  the tick re-enqueues (self-healing).  Must be > 2× tick interval. */
const GC_MARKER_TTL_MS = 120_000;

/**
 * Register the health:check handler on the event bus.
 *
 * GC strategy (marker-gated, Queue-first):
 *   tick → check marker → if valid & unexpired → skip (already queued)
 *                       → if expired/missing → enqueue + write marker
 *                       → if Queue unavailable → inline fallback + clear marker
 *
 * The Queue consumer clears the marker on success; if the consumer never runs
 * (Miniflare dev), the marker expires after GC_MARKER_TTL_MS and the tick
 * re-enqueues → self-healing loop.  No inline provider.delete blocks the tick
 * unless Queue is entirely unavailable (e.g. `npm run dev` without wrangler).
 */
export function registerHealthCheck(deps: HealthCheckDeps): void {
  const { stores, providers, eventBus, eventLoop, audit, queueProducer } = deps;

  /** Track last stable updatedAt per sandbox to skip redundant provider.getStatus() calls. */
  const stableSince = new Map<string, number>();

  eventBus.on('health:check', async () => {
    try {
      const idx = await stores.atomic.get<string[]>('sandbox:ids');
      if (!idx) return;
      for (const sid of idx.value) {
        try {
          const entry = await stores.atomic.get<Sandbox>(`sandbox:${sid}`);
          if (!entry || entry.value.status === SandboxStatus.Deleted) continue;

          const instanceId = entry.value.config.instanceId;

          // Succeeded (stopped manually) > 60s → GC
          if (entry.value.status === SandboxStatus.Succeeded) {
            const stoppedDuration = Date.now() - entry.value.updatedAt;
            if (stoppedDuration > 60_000) {
              await dispatchGc(stores.atomic, queueProducer, providers, audit, {
                sandboxId: sid, reason: 'stopped-gc',
                providerId: entry.value.providerId ?? sid,
                region: entry.value.config.region,
                ...(instanceId ? { instanceId } : {}),
                containerCount: entry.value.containers.length,
                sandboxName: entry.value.name, createdAt: entry.value.createdAt,
              });
            }
            continue;
          }
          // Failed/Terminating ≥ 60s → GC
          if (entry.value.status === SandboxStatus.Failed || entry.value.status === SandboxStatus.Terminating) {
            const duration = Date.now() - entry.value.updatedAt;
            if (duration > 60_000) {
              await dispatchGc(stores.atomic, queueProducer, providers, audit, {
                sandboxId: sid, reason: `${entry.value.status.toLowerCase()}-gc`,
                providerId: entry.value.providerId ?? sid,
                region: entry.value.config.region,
                ...(instanceId ? { instanceId } : {}),
                containerCount: entry.value.containers.length,
                sandboxName: entry.value.name, createdAt: entry.value.createdAt,
              });
            }
            continue;
          }

          // ── Hard terminal states (no cloud resources) ──
          // ScheduleFailed and Expired have no provider resources (never
          // created, or already reclaimed).  Auto-clean after a long window
          // to prevent index bloat while preserving audit metadata.
          if (
            entry.value.status === SandboxStatus.ScheduleFailed ||
            entry.value.status === SandboxStatus.Expired
          ) {
            const TERMINAL_CLEANUP_MS = 24 * 60 * 60 * 1000; // 24h — preserve for audit
            const duration = Date.now() - entry.value.updatedAt;
            if (duration > TERMINAL_CLEANUP_MS) {
              await dispatchGc(stores.atomic, queueProducer, providers, audit, {
                sandboxId: sid, reason: 'expired-gc',
                providerId: entry.value.providerId ?? sid,
                region: entry.value.config.region,
                ...(instanceId ? { instanceId } : {}),
                containerCount: entry.value.containers.length,
                sandboxName: entry.value.name, createdAt: entry.value.createdAt,
              });
            }
            continue;
          }

          // ── Transient states with cloud resources ──
          // Scheduling, Pending, Restarting, Updating — the sandbox has a
          // provider resource that may disappear externally (user deletes ECI
          // from Alibaba console).  Check provider liveness + timeout fallback
          // so we don't leak orphaned sandbox records.
          if (
            entry.value.status === SandboxStatus.Scheduling ||
            entry.value.status === SandboxStatus.Pending ||
            entry.value.status === SandboxStatus.Restarting ||
            entry.value.status === SandboxStatus.Updating
          ) {
            const TRANSIENT_TIMEOUT_MS = 10 * 60 * 1000; // 10 min — generous for ECI scheduling + image pull
            const duration = Date.now() - entry.value.updatedAt;
            const providerIdentity = (entry.value.config as unknown as Record<string, unknown>).providerIdentity;
            const resolvedInstanceId = instanceId ?? (providerIdentity as Record<string, unknown> | undefined)?.instanceId as string | undefined;

            // Try provider status check (only if we have instance routing info)
            if (resolvedInstanceId) {
              try {
                const p = resolvedInstanceId ? await providers.resolveContainer?.(createInstanceId(resolvedInstanceId)) : undefined;
                if (p?.getStatus) {
                  const rt = await p.getStatus(entry.value.providerId ?? sid);
                  if (!rt) {
                    // Provider resource is gone — cloud resource deleted externally
                    await dispatchGc(stores.atomic, queueProducer, providers, audit, {
                      sandboxId: sid, reason: 'provider-gone',
                      providerId: entry.value.providerId ?? sid,
                      region: entry.value.config.region,
                      ...(instanceId ? { instanceId } : {}),
                      containerCount: entry.value.containers.length,
                      sandboxName: entry.value.name, createdAt: entry.value.createdAt,
                    });
                    continue;
                  }
                  // Scheduling auto-promotion: provider says Running → promote locally
                  // eslint-disable-next-line @typescript-eslint/no-unsafe-enum-comparison -- rt.status is provider-level string, not SandboxStatus enum
                  if (entry.value.status === SandboxStatus.Scheduling && rt.status === 'Running') {
                    const latest = await stores.atomic.get<Sandbox>(`sandbox:${sid}`);
                    if (latest?.value.status === SandboxStatus.Scheduling) {
                      await stores.atomic.set(`sandbox:${sid}`, {
                        ...latest.value,
                        status: SandboxStatus.Running,
                        network: runtimeToNetwork(rt.network, rt.associatedResources),
                        containers: runtimeToContainers(rt),
                        events: runtimeToEvents(rt),
                        updatedAt: Date.now(),
                      }, latest.version);
                    }
                    continue;
                  }
                }
              } catch (e) {
                console.error(`[health-check] provider check failed for ${sid} (${entry.value.status}): ${e instanceof Error ? e.message : String(e)}`);
              }
            }

            // Timeout fallback — if we can't reach the provider or it's stuck,
            // GC after the timeout window to prevent permanent orphans.
            if (duration > TRANSIENT_TIMEOUT_MS) {
              await dispatchGc(stores.atomic, queueProducer, providers, audit, {
                sandboxId: sid, reason: 'stuck-gc',
                providerId: entry.value.providerId ?? sid,
                region: entry.value.config.region,
                ...(instanceId ? { instanceId } : {}),
                containerCount: entry.value.containers.length,
                sandboxName: entry.value.name, createdAt: entry.value.createdAt,
              });
            }
            continue;
          }

          if (entry.value.status !== SandboxStatus.Running) continue;

          const maxRetries = entry.value.config.healthMaxRetries ?? 3;
          if (maxRetries === -1) { stableSince.delete(sid); continue; }

          // Skip provider check if sandbox hasn't changed since last healthy check
          const lastStableAt = stableSince.get(sid);
          if (lastStableAt !== undefined && entry.value.updatedAt <= lastStableAt) continue;

          if (!instanceId || !providers.resolveContainer) continue;
          const provider = await providers.resolveContainer(instanceId);
          if (!provider?.getStatus) continue;

          const runtime = await provider.getStatus(entry.value.providerId ?? sid);
          if (!runtime) {
            stableSince.delete(sid);
            await dispatchGc(stores.atomic, queueProducer, providers, audit, {
              sandboxId: sid, reason: 'provider-gone',
              providerId: entry.value.providerId ?? sid,
              region: entry.value.config.region,
              ...(instanceId ? { instanceId } : {}),
              containerCount: entry.value.containers.length,
              sandboxName: entry.value.name, createdAt: entry.value.createdAt,
            });
            continue;
          }

          const allHealthy = runtime.containers.every(cc => cc.alive);
          const anyRunning = runtime.containers.some(cc => cc.alive);
          const failKey = `health:fails:${sid}`;

          if (!anyRunning) {
            // Use fail counter — only GC after maxRetries consecutive failures.
            // This gives asyncInit providers (ECI) time to start containers.
            stableSince.delete(sid);
            const failEntry = await stores.atomic.get<number>(failKey);
            const fails = (failEntry?.value ?? 0) + 1;
            await stores.atomic.set(failKey, fails, failEntry?.version ?? null);
            if (fails >= maxRetries) {
              await dispatchGc(stores.atomic, queueProducer, providers, audit, {
                sandboxId: sid, reason: 'exited-gc',
                providerId: entry.value.providerId ?? sid,
                region: entry.value.config.region,
                ...(instanceId ? { instanceId } : {}),
                containerCount: entry.value.containers.length,
                sandboxName: entry.value.name, createdAt: entry.value.createdAt,
              });
            }
            continue;
          }

          if (allHealthy) {
            const failEntry = await stores.atomic.get<number>(failKey);
            if (failEntry) await stores.atomic.set(failKey, 0, failEntry.version);
            // Mark as stable — skip provider check next tick if unchanged
            stableSince.set(sid, entry.value.updatedAt);
          } else {
            stableSince.delete(sid); // unhealthy — re-check next tick
            const failEntry = await stores.atomic.get<number>(failKey);
            const fails = (failEntry?.value ?? 0) + 1;
            await stores.atomic.set(failKey, fails, failEntry?.version ?? null);
            if (fails >= maxRetries) {
              stableSince.delete(sid);
              await dispatchGc(stores.atomic, queueProducer, providers, audit, {
                sandboxId: sid, reason: 'unhealthy-gc',
                providerId: entry.value.providerId ?? sid,
                region: entry.value.config.region,
                ...(instanceId ? { instanceId } : {}),
                containerCount: entry.value.containers.length,
                sandboxName: entry.value.name, createdAt: entry.value.createdAt,
              });
            }
          }
        } catch (e) { console.error(`[health] check error ${sid}:`, e instanceof Error ? e.message : e); }
      }

      // Instance heartbeat timeout — 120s no heartbeat → offline (lightweight, stays inline)
      const instIdx = await stores.atomic.get<string[]>('instance:ids');
      if (instIdx) {
        const now = Date.now();
        for (const iid of instIdx.value) {
          try {
            const instEntry = await stores.atomic.get<Record<string, unknown>>('instance:' + iid);
            if (!instEntry?.value) continue;
            const instValue = z.object({ status: z.string().optional(), updatedAt: z.number().optional() }).passthrough().parse(instEntry.value);
            if (instValue.status !== 'online') continue;
            if (instValue.updatedAt !== undefined && (now - instValue.updatedAt > 120_000)) {
              await stores.atomic.set('instance:' + iid, { ...instValue, status: 'offline', updatedAt: now }, instEntry.version);
            }
          } catch { /* skip */ }
        }
      }

      // Bucket key rotation — scan + enqueue (heavy work runs in Queue consumer)
      const BINDING_INDEX_KEY = 'bucket-key:ids';
      const BINDING_PREFIX = 'bucket-key:';
      const bIdx = await stores.atomic.get<string[]>(BINDING_INDEX_KEY);
      if (bIdx) {
        for (const sid of bIdx.value) {
          try {
            const entry = await stores.atomic.get<Record<string, unknown>>(BINDING_PREFIX + sid);
            if (!entry?.value) continue;
            const bindingSchema = z.object({ expiresAt: z.number(), accessKeyId: z.string(), version: z.number(), rotationIntervalMs: z.number().optional() }).passthrough();
            const parsed = bindingSchema.parse(entry.value);
            if (parsed.expiresAt > Date.now()) continue;
            const qSent = await queueProducer.sendBucketKeyRotate({ bindingId: sid });
            if (qSent) continue;
            const sk = Array.from(crypto.getRandomValues(new Uint8Array(32)))
              .map((b: number) => b.toString(16).padStart(2, '0')).join('');
            const updated = {
              ...parsed,
              secretValue: `${parsed.accessKeyId}:${sk}`,
              version: parsed.version + 1,
              expiresAt: Date.now() + (parsed.rotationIntervalMs ?? 24 * 60 * 60 * 1000),
            };
            await stores.atomic.set(BINDING_PREFIX + sid, updated, entry.version);
          } catch { /* skip */ }
        }
      }
    } finally {
      eventLoop.enqueuePriority({ type: 'health:check', payload: {} });
    }
  });

  // Trigger first health check
  eventLoop.enqueuePriority({ type: 'health:check', payload: {} });
}

// ─── Marker-gated GC dispatch ───

interface GcParams {
  sandboxId: string;
  reason: string;
  providerId: string;
  region: string;
  instanceId?: string | undefined;
  containerCount: number;
  sandboxName: string;
  createdAt: number;
}

/**
 * Marker-gated GC dispatch.
 *
 * 1. Check marker — if valid & unexpired, skip (already queued).
 * 2. Try Queue → write marker → if accepted, done (consumer handles rest).
 * 3. Queue unavailable → inline fallback → clear marker on success.
 */
async function dispatchGc(
  atomic: IAtomicStore,
  queueProducer: IMessageQueue,
  providers: Pick<IProviderRegistry, 'resolveContainer'>,
  audit: IAuditWriter | undefined,
  params: GcParams,
): Promise<void> {
  const markerKey = GC_MARKER_PREFIX + params.sandboxId;
  const now = Date.now();

  // 1. Check existing marker
  const marker = await atomic.get<{ expiresAt: number }>(markerKey);
  if (marker && marker.value.expiresAt > now) {
    // Already queued, marker still fresh — consumer will handle it
    return;
  }

  // 2. Try Queue dispatch
  const qSent = await queueProducer.sendSandboxGc({
    sandboxId: params.sandboxId, reason: params.reason as 'stopped-gc' | 'provider-gone' | 'exited-gc' | 'unhealthy-gc' | 'manual' | 'failed-gc' | 'expired-gc' | 'stuck-gc',
    providerId: params.providerId, region: params.region,
    ...(params.instanceId ? { instanceId: params.instanceId } : {}),
    containerCount: params.containerCount,
    sandboxName: params.sandboxName, createdAt: params.createdAt,
  });

  // 3. Write marker (prevents other ticks from re-enqueuing)
  //    Use the expired marker's version if it existed, null otherwise.
  await atomic.set(markerKey, { expiresAt: now + GC_MARKER_TTL_MS }, marker?.version ?? null);

  if (qSent) return; // Queue accepted — consumer will process

  // 4. Queue unavailable — inline fallback. Resolve per-instance provider.
  if (params.instanceId && providers.resolveContainer) {
    try {
      const resolved = await providers.resolveContainer(createInstanceId(params.instanceId));
      await resolved.delete({ region: createRegionId(params.region), providerId: params.providerId });
    } catch { /* best-effort */ }
  }

  await gcUpdateState(atomic, audit, params.sandboxId, params.reason,
    params.sandboxName, params.providerId, params.containerCount, params.createdAt);

  // 5. Clear marker (we handled it inline)
  const m2 = await atomic.get<{ expiresAt: number }>(markerKey);
  if (m2) await atomic.set<Record<string, unknown> | null>(markerKey, null, m2.version);
}

// ═══════════════════════════════════════════════════════════════
// Pod GC — PodPhase-based health check
// ═══════════════════════════════════════════════════════════════

import type { PodService } from '../pod/service.ts';
import type { PodEntity } from '../pod/types.ts';
import { createPodId } from '../pod/types.ts';
import { ContainerGroupState } from '../provider/container-lifecycle.ts';
import type { InstanceId } from '../region/instance.ts';

export interface PodHealthCheckDeps {
  podService: PodService;
  stores: { atomic: IAtomicStore };
  providers: Pick<IProviderRegistry, 'resolveContainer'>;
  eventBus: EventBus;
  eventLoop: EventLoop;
  audit: IAuditWriter;
  queueProducer: IMessageQueue;
}

const POD_GC_MARKER_PREFIX = 'gc:pod:queued:';
const POD_GC_MARKER_TTL_MS = 120_000;

/**
 * Register the Pod health:check handler.
 *
 * GC strategy (PodPhase-based, Queue-first):
 *   Pending   → provider check + timeout → provider-gone / stuck-gc
 *   Running   → health check + retries → exited-gc / unhealthy-gc / provider-gone
 *   Succeeded → timeout → stopped-gc
 *   Failed    → timeout → failed-gc (long window for audit preservation)
 *
 * Uses PodPhase (5 states) instead of SandboxStatus (11 states).
 * Finer differentiation within a phase is done via provider status checks.
 */
export function registerPodHealthCheck(deps: PodHealthCheckDeps): void {
  const { podService, stores, providers, eventBus, eventLoop, audit, queueProducer } = deps;

  /** Track last stable updatedAt per pod to skip redundant provider checks. */
  const stableSince = new Map<string, number>();

  eventBus.on('health:pod:check', async () => {
    try {
      const podIds = await podService.getAllIds();
      for (const pid of podIds) {
        try {
          const pod = await podService.getById(createPodId(pid));
          if (!pod) continue;

          const phase = pod.phase;
          const providerId = pod.providerId;
          const instanceId = (pod.spec.providerOverrides)?.instanceId as string | undefined;

          // ── Succeeded > 60s → stopped-gc ──
          if (phase === 'Succeeded') {
            if (Date.now() - pod.updatedAt > 60_000) {
              await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                podId: pid, reason: 'stopped-gc', providerId: providerId ?? pid,
                podName: pod.name, createdAt: pod.createdAt,
                ...(instanceId ? { instanceId } : {}),
              });
            }
            continue;
          }

          // ── Failed > 24h → failed-gc (long window for audit) ──
          if (phase === 'Failed') {
            if (Date.now() - pod.updatedAt > 24 * 60 * 60 * 1000) {
              await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                podId: pid, reason: 'failed-gc', providerId: providerId ?? pid,
                podName: pod.name, createdAt: pod.createdAt,
                ...(instanceId ? { instanceId } : {}),
              });
            }
            continue;
          }

          // ── Pending — transient state with provider resource ──
          if (phase === 'Pending') {
            const TRANSIENT_TIMEOUT_MS = 10 * 60 * 1000;
            const duration = Date.now() - pod.updatedAt;

            if (providerId && instanceId) {
              try {
                const rt = await podService.checkProviderStatus(createPodId(pid));
                if (!rt) {
                  await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                    podId: pid, reason: 'provider-gone', providerId,
                    podName: pod.name, createdAt: pod.createdAt,
                    ...(instanceId ? { instanceId } : {}),
                  });
                  continue;
                }
                // Scheduling → Running auto-promotion
                if (rt.status === ContainerGroupState.Running) {
                  try { await podService.syncRuntime(createPodId(pid)); } catch { /* best-effort */ }
                  continue;
                }
              } catch { /* provider unreachable — fall through to timeout */ }
            }

            if (duration > TRANSIENT_TIMEOUT_MS) {
              await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                podId: pid, reason: 'stuck-gc', providerId: providerId ?? pid,
                podName: pod.name, createdAt: pod.createdAt,
                ...(instanceId ? { instanceId } : {}),
              });
            }
            continue;
          }

          // ── Running — active monitoring ──
          if (phase === 'Running') {
            // Skip if unchanged since last stable check
            const lastStableAt = stableSince.get(pid);
            if (lastStableAt !== undefined && pod.updatedAt <= lastStableAt) continue;

            if (!providerId || !instanceId) continue;

            const maxRetries = 3;
            let runtime;
            try {
              runtime = await podService.checkProviderStatus(createPodId(pid));
            } catch {
              stableSince.delete(pid);
              continue;
            }

            if (!runtime) {
              stableSince.delete(pid);
              await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                podId: pid, reason: 'provider-gone', providerId,
                podName: pod.name, createdAt: pod.createdAt,
                ...(instanceId ? { instanceId } : {}),
              });
              continue;
            }

            const allHealthy = runtime.containers.every(cc => cc.alive);
            const anyRunning = runtime.containers.some(cc => cc.alive);
            const failKey = `pod:health:fails:${pid}`;

            if (!anyRunning) {
              stableSince.delete(pid);
              const failEntry = await stores.atomic.get<number>(failKey);
              const fails = (failEntry?.value ?? 0) + 1;
              await stores.atomic.set(failKey, fails, failEntry?.version ?? null);
              if (fails >= maxRetries) {
                await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                  podId: pid, reason: 'exited-gc', providerId,
                  podName: pod.name, createdAt: pod.createdAt,
                  ...(instanceId ? { instanceId } : {}),
                });
              }
              continue;
            }

            if (allHealthy) {
              const failEntry = await stores.atomic.get<number>(failKey);
              if (failEntry) await stores.atomic.set(failKey, 0, failEntry.version);
              stableSince.set(pid, pod.updatedAt);
            } else {
              stableSince.delete(pid);
              const failEntry = await stores.atomic.get<number>(failKey);
              const fails = (failEntry?.value ?? 0) + 1;
              await stores.atomic.set(failKey, fails, failEntry?.version ?? null);
              if (fails >= maxRetries) {
                await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                  podId: pid, reason: 'unhealthy-gc', providerId,
                  podName: pod.name, createdAt: pod.createdAt,
                  ...(instanceId ? { instanceId } : {}),
                });
              }
            }
            continue;
          }

          // ── Unknown — unexpected phase, GC after long timeout ──
          if (phase === 'Unknown') {
            if (Date.now() - pod.updatedAt > 24 * 60 * 60 * 1000) {
              await dispatchPodGc(stores.atomic, queueProducer, providers, audit, {
                podId: pid, reason: 'stuck-gc', providerId: providerId ?? pid,
                podName: pod.name, createdAt: pod.createdAt,
                ...(instanceId ? { instanceId } : {}),
              });
            }
            continue;
          }
        } catch { /* skip individual pod errors */ }
      }
    } finally {
      eventLoop.enqueuePriority({ type: 'health:pod:check', payload: {} });
    }
  });

  // Trigger first pod health check
  eventLoop.enqueuePriority({ type: 'health:pod:check', payload: {} });
}

// ─── Pod GC dispatch (marker-gated, Queue-first) ───

interface PodGcParams {
  podId: string;
  reason: string;
  providerId: string;
  podName: string;
  createdAt: number;
  instanceId?: string | undefined;
}

function resolvePodGcInstanceId(raw: string | undefined): InstanceId | undefined {
  if (!raw) return undefined;
  try { return createInstanceId(raw); } catch { return undefined; }
}

async function dispatchPodGc(
  atomic: IAtomicStore,
  queueProducer: IMessageQueue,
  providers: Pick<IProviderRegistry, 'resolveContainer'>,
  audit: IAuditWriter | undefined,
  params: PodGcParams,
): Promise<void> {
  const markerKey = POD_GC_MARKER_PREFIX + params.podId;
  const now = Date.now();

  const marker = await atomic.get<{ expiresAt: number }>(markerKey);
  if (marker && marker.value.expiresAt > now) return;

  // Queue dispatch — reuses sandbox:gc queue but with pod-scoped markers
  const qSent = await queueProducer.sendSandboxGc({
    sandboxId: params.podId, reason: params.reason as 'stopped-gc' | 'provider-gone' | 'exited-gc' | 'unhealthy-gc' | 'manual' | 'failed-gc' | 'expired-gc' | 'stuck-gc',
    providerId: params.providerId, region: 'cn-hangzhou',
    ...(params.instanceId ? { instanceId: params.instanceId } : {}),
    containerCount: 0,
    sandboxName: params.podName, createdAt: params.createdAt,
  });

  await atomic.set(markerKey, { expiresAt: now + POD_GC_MARKER_TTL_MS }, marker?.version ?? null);

  if (qSent) return;

  // Queue unavailable — inline fallback
  const instId = resolvePodGcInstanceId(params.instanceId);
  if (instId && providers.resolveContainer) {
    try {
      const resolved = await providers.resolveContainer(instId);
      await resolved.delete({ region: createRegionId('cn-hangzhou'), providerId: params.providerId });
    } catch { /* best-effort */ }
  }

  await gcUpdatePodState(atomic, audit, params.podId, params.reason, params.podName, params.providerId, params.createdAt);

  const m2 = await atomic.get<{ expiresAt: number }>(markerKey);
  if (m2) await atomic.set<Record<string, unknown> | null>(markerKey, null, m2.version);
}

async function gcUpdatePodState(
  atomic: IAtomicStore,
  audit: IAuditWriter | undefined,
  pid: string,
  reason: string,
  name: string,
  providerId: string,
  createdAt: number,
): Promise<void> {
  for (let attempt = 0; attempt < 3; attempt++) {
    const latest = await atomic.get<PodEntity>('pod:' + pid);
    if (!latest) break;
    const ver = await atomic.set('pod:' + pid, {
      ...latest.value, phase: 'Failed', updatedAt: Date.now(),
    }, latest.version);
    if (!ver) continue;

    const idxEntry = await atomic.get<string[]>('pod:ids');
    if (idxEntry) await atomic.set('pod:ids', idxEntry.value.filter((i: string) => i !== pid), idxEntry.version);

    console.log(formatDmesgLine(`pod DELETED (${reason}) id=${pid} name=${name} provider=${providerId} uptime=${String(Date.now() - createdAt)}ms`));
    audit?.write({
      level: 4, facility: 'pod-service',
      message: `Pod auto-deleted (${reason}) — ${pid}`,
      metadata: { eventType: 'pod.auto-deleted', podId: pid, reason },
    });
    break;
  }
}

// ─── Inline GC state update (OCC retry + audit) ───

/** OCC state update + audit log for sandbox GC (inline fallback path). */
async function gcUpdateState(
  atomic: IAtomicStore,
  audit: IAuditWriter | undefined,
  sid: string,
  reason: string,
  name: string,
  providerId: string,
  containerCount: number,
  createdAt: number,
): Promise<void> {
  for (let attempt = 0; attempt < 3; attempt++) {
    const latest = await atomic.get<any>('sandbox:' + sid);
    if (!latest || latest.value.status === SandboxStatus.Deleted) break;
    const ver = await atomic.set('sandbox:' + sid, {
      ...latest.value, status: SandboxStatus.Deleted, updatedAt: Date.now(),
    }, latest.version);
    if (!ver) continue;
    const idxEntry = await atomic.get<string[]>('sandbox:ids');
    if (idxEntry) await atomic.set('sandbox:ids', idxEntry.value.filter((i: string) => i !== sid), idxEntry.version);
    console.log(formatDmesgLine(`sandbox DELETED (${reason}) id=${sid} name=${name} provider=${providerId} containers=${String(containerCount)} uptime=${String(Date.now() - createdAt)}ms`));
    audit?.write({
      level: 4, facility: 'sandbox-service',
      message: `Sandbox auto-deleted (${reason}) — ${sid}`,
      metadata: { eventType: 'sandbox.auto-deleted', sandboxId: sid, reason },
    });
    break;
  }
}

import type { EventBus } from '../event-bus/bus.ts';
import type { IAtomicStore } from '../store/interfaces.ts';
import type { IProviderRegistry } from '../provider/interfaces.ts';
import type { IMessageQueue } from '../../queue/interfaces.ts';
import type { SecretEncryption } from '../auth/secret-encryption.ts';
import { CredentialService } from '../auth/credential.ts';

export interface ImagePullDeps {
  atomic: IAtomicStore;
  providers: IProviderRegistry;
  eventBus: EventBus;
  queueProducer: IMessageQueue;
  secretEncryption?: SecretEncryption;
}

/**
 * Register the image.pull handler on the event bus.
 *
 * Pulls are dispatched to Queue first; falls back to inline execution
 * when the Queue binding is unavailable.
 */
export function registerImagePullHandler(deps: ImagePullDeps): void {
  const { atomic, providers, eventBus, queueProducer, secretEncryption } = deps;

  eventBus.on('image.pull', async (event: { type: string; payload?: unknown }) => {
    const payload = event.payload as Record<string, unknown> | undefined;
    if (!payload) return;
    const { taskId, image, instanceId, clusterId, credentialRef, registryCredential } = payload as {
      taskId?: string; image?: string; instanceId?: string; clusterId?: string;
      credentialRef?: string; registryCredential?: { server: string; userName: string; password: string };
    };
    if (!taskId || !image) return;

    const entry = await atomic.get<any>('pull-task:' + taskId);
    if (!entry) return;
    const taskBase = { id: taskId, repositoryId: entry.value.repositoryId, image, createdAt: entry.value.createdAt };

    // Try queue dispatch first
    const qSent = await queueProducer.sendImagePull({
      taskId, image,
      ...(instanceId ? { instanceId } : {}),
      ...(clusterId ? { clusterId } : {}),
      ...(credentialRef ? { credentialRef } : {}),
      ...(registryCredential ? { registryCredential } : {}),
    });
    if (qSent) {
      await atomic.set('pull-task:' + taskId, {
        ...taskBase, status: 'queued', queuedAt: Date.now(),
      }, entry.version);
      return;
    }

    // Queue unavailable — inline pull
    try {
      const imgProvider = instanceId ? await providers.resolveImage(instanceId as any) : providers.image;
      let credArg: string | { server: string; userName: string; password: string } | undefined = clusterId;
      if (credentialRef) {
        const credSvc = new CredentialService(atomic, secretEncryption);
        const managed = await credSvc.findByName(credentialRef);
        if (managed?.registryCredentials?.length) {
          credArg = { server: managed.registryCredentials[0]!.server, userName: managed.registryCredentials[0]!.userName, password: managed.registryCredentials[0]!.password };
        }
      } else if (registryCredential) {
        credArg = registryCredential;
      }
      const info = await imgProvider.pull(image, credArg as any);
      await atomic.set('pull-task:' + taskId, {
        ...taskBase, status: 'completed', result: { id: info.id, tags: [...info.tags] }, completedAt: Date.now(),
      }, entry.version);
    } catch (e: any) {
      console.error(`[pull-task] ${taskId} failed:`, e.message);
      await atomic.set('pull-task:' + taskId, {
        ...taskBase, status: 'failed', error: e.message, failedAt: Date.now(),
      }, entry.version);
    }
  });
}

/**
 * Log fetch event handler — async container logs via EventBus.
 *
 * ECI DescribeContainerLog is a synchronous snapshot API (no streaming).
 * Instead of blocking the HTTP response or simulating a stream, this handler:
 * 1. Listens for `log:fetch` events on the EventBus
 * 2. Calls the provider's getLogs() asynchronously
 * 3. Caches the result in the atomic store under `log:cache:{sandboxId}:{containerName}`
 *
 * Frontend flow:
 *   POST /api/sandboxes/:id/logs → dispatches log:fetch → returns cached (possibly stale) immediately
 *   GET  /api/sandboxes/:id/logs → returns latest cached content
 *
 * This gives eventual consistency with no WebSocket/DO dependency.
 */

import type { EventBus } from '../event-bus/bus.ts';
import type { IAtomicStore } from '../store/interfaces.ts';
import type { IProviderRegistry } from '../provider/interfaces.ts';

export interface LogFetchDeps {
  atomic: IAtomicStore;
  providers: IProviderRegistry;
  eventBus: EventBus;
}

export interface LogFetchPayload {
  readonly sandboxId: string;
  readonly providerId: string;
  readonly region: string;
  readonly containerName: string;
  readonly instanceId?: string;
  readonly tail?: number;
  readonly sinceSeconds?: number;
}

const LOG_CACHE_PREFIX = 'log:cache:';

function cacheKey(sandboxId: string, containerName: string): string {
  return `${LOG_CACHE_PREFIX}${sandboxId}:${containerName}`;
}

export function registerLogFetchHandler(deps: LogFetchDeps): void {
  const { atomic, providers, eventBus } = deps;

  eventBus.on('log:fetch', async (event: { type: string; payload?: unknown }) => {
    const payload = event.payload as LogFetchPayload | undefined;
    if (!payload?.sandboxId || !payload?.containerName) return;
    const { sandboxId, providerId, region, containerName, tail, sinceSeconds } = payload;

    try {
      // Check cache marker so concurrent refreshes don't pile up
      const markerKey = `log:fetching:${sandboxId}:${containerName}`;
      const marker = await atomic.get<{ startedAt: number }>(markerKey);
      if (marker && Date.now() - marker.value.startedAt < 10_000) return; // dedup within 10s

      await atomic.set(markerKey, { startedAt: Date.now() }, marker?.version ?? null);

      // Fetch logs from provider — resolve per-instance for correct credential binding
      const resolved = payload.instanceId
        ? await providers.resolveContainer?.(payload.instanceId as any)
        : undefined;
      if (!resolved) return;
      const containerProvider = resolved;
      if (!containerProvider.getLogs) return;

      const result = await containerProvider.getLogs({
        region: region as any,
        providerId,
        containerName,
        ...(tail !== undefined ? { limitBytes: tail } : {}),
        ...(sinceSeconds !== undefined ? { sinceSeconds } : {}),
      });

      // Cache the result with metadata
      const existing = await atomic.get<any>(cacheKey(sandboxId, containerName));
      await atomic.set(cacheKey(sandboxId, containerName), {
        content: result.content,
        containerName: result.containerName,
        timestamp: result.timestamp,
        fetchedAt: Date.now(),
      }, existing?.version ?? null);

      // Clear marker
      const m2 = await atomic.get(markerKey);
      if (m2) await atomic.set(markerKey, null as any, m2.version).catch(() => { /* noop */ });
    } catch (e: any) {
      console.error(`[log:fetch] ${sandboxId}/${containerName} failed:`, e.message);
    }
  });
}

export async function getCachedLogs(
  atomic: IAtomicStore,
  sandboxId: string,
  containerName: string,
): Promise<{ content: string; containerName?: string; timestamp?: string; fetchedAt?: number } | null> {
  const entry = await atomic.get<any>(cacheKey(sandboxId, containerName));
  return entry?.value ?? null;
}

import type { HashTableOptions } from './interfaces.ts';

const DEFAULT_CAPACITY = 16;
const DEFAULT_LOAD_FACTOR = 0.75;

/** Internal bucket entry for separate chaining. */
interface BucketEntry<K, V> {
  key: K;
  value: V;
}

/**
 * Generic hash table base class with separate-chaining collision resolution.
 *
 * Automatically resizes when the load factor is exceeded. The hash function
 * is based on `String(key)`. Subclasses can override `_hash` to provide a
 * custom hash strategy.
 *
 * @example
 * ```ts
 * class CaseInsensitiveMap extends HashTable<string, number> {
 *   protected _hash(key: string): number {
 *     return super._hash(key.toLowerCase());
 *   }
 * }
 * ```
 */
export class HashTable<K, V> {
  protected buckets: BucketEntry<K, V>[][];
  protected _size = 0;
  protected readonly _initialCapacity: number;
  protected readonly _loadFactor: number;

  public constructor(options?: HashTableOptions) {
    this._initialCapacity = options?.initialCapacity ?? DEFAULT_CAPACITY;
    this._loadFactor = options?.loadFactor ?? DEFAULT_LOAD_FACTOR;
    this.buckets = Array.from({ length: this._initialCapacity }, () => []);
  }

  // ─── Mutation ───

  /** Insert or update a key-value pair. */
  public set(key: K, value: V): void {
    const bucket = this.#bucket(key);
    const existing = bucket.find(e => e.key === key);
    if (existing) {
      existing.value = value;
    } else {
      bucket.push({ key, value });
      this._size++;
      if (this._size > this.buckets.length * this._loadFactor) {
        this.#resize();
      }
    }
  }

  /** Remove a key. Returns true if the key existed. */
  public delete(key: K): boolean {
    const bucket = this.#bucket(key);
    const idx = bucket.findIndex(e => e.key === key);
    if (idx === -1) return false;
    bucket.splice(idx, 1);
    this._size--;
    return true;
  }

  /** Remove all entries. */
  public clear(): void {
    for (const bucket of this.buckets) {
      bucket.length = 0;
    }
    this._size = 0;
  }

  // ─── Queries ───

  /** Get the value for a key, or undefined if not found. */
  public get(key: K): V | undefined {
    return this.#bucket(key).find(e => e.key === key)?.value;
  }

  /** Check if a key exists in the table. */
  public has(key: K): boolean {
    return this.#bucket(key).some(e => e.key === key);
  }

  /** Return all entries as an array of [key, value] pairs. */
  public entries(): [K, V][] {
    const result: [K, V][] = [];
    for (const bucket of this.buckets) {
      for (const entry of bucket) {
        result.push([entry.key, entry.value]);
      }
    }
    return result;
  }

  /** Return all keys. */
  public keys(): K[] {
    const result: K[] = [];
    for (const bucket of this.buckets) {
      for (const entry of bucket) {
        result.push(entry.key);
      }
    }
    return result;
  }

  /** Return all values. */
  public values(): V[] {
    const result: V[] = [];
    for (const bucket of this.buckets) {
      for (const entry of bucket) {
        result.push(entry.value);
      }
    }
    return result;
  }

  // ─── Properties ───

  public get size(): number {
    return this._size;
  }

  public get isEmpty(): boolean {
    return this._size === 0;
  }

  /** Current number of buckets (capacity). */
  public get capacity(): number {
    return this.buckets.length;
  }

  // ─── Hooks for subclasses ───

  /**
   * Hash function. Uses DJB2 on the stringified key.
   * Override to provide a custom hash strategy.
   */
  protected _hash(key: K): number {
    const str = String(key);
    let hash = 5381;
    for (let i = 0; i < str.length; i++) {
      hash = (hash << 5) + hash + str.charCodeAt(i);
      hash = hash & hash; // force 32-bit integer
    }
    return Math.abs(hash);
  }

  // ─── Internal ───

  #bucket(key: K): BucketEntry<K, V>[] {
    const index = this._hash(key) % this.buckets.length;
    return this.buckets[index]!;
  }

  #resize(): void {
    const oldBuckets = this.buckets;
    const newCapacity = this.buckets.length * 2;
    this.buckets = Array.from({ length: newCapacity }, () => []);
    this._size = 0;

    for (const bucket of oldBuckets) {
      for (const entry of bucket) {
        this.set(entry.key, entry.value);
      }
    }
  }
}

/**
 * Image cache LRU eviction — GitHub Cache model.
 *
 * Per-repo cap (maxTotalBytes) + LRU eviction + 7-day TTL on unaccessed images.
 * Mirrors GitHub Actions cache: 10GB repo cap, LRU eviction, 7-day stale cleanup.
 *
 * Registry credentials: delegates to ContainerSecret (Phase 5.2) for
 * registry auth — no separate credential store needed.
 */

import type { IAtomicStore } from '../store/interfaces.ts';

const CACHE_ENTRY_PREFIX = 'imgcache:';
const CACHE_INDEX_KEY = 'imgcache:ids';
const CACHE_TOTAL_SIZE_KEY = 'imgcache:totalSize';

// Defaults (GitHub Cache model: 10GB cap, 7-day stale)
const DEFAULT_MAX_TOTAL_BYTES = 10 * 1024 * 1024 * 1024; // 10 GB
const DEFAULT_MAX_AGE_MS = 7 * 24 * 3_600_000; // 7 days

export interface ImageCacheEntry {
  imageId: string; // provider image ID (sha256:...)
  tags: string[];
  sizeBytes: number;
  pullCount: number;
  lastAccessedAt: number;
  createdAt: number;
}

export interface ImageCacheConfig {
  maxTotalBytes: number;
  maxAgeMs: number;
}

export const DEFAULT_IMAGE_CACHE_CONFIG: ImageCacheConfig = {
  maxTotalBytes: DEFAULT_MAX_TOTAL_BYTES,
  maxAgeMs: DEFAULT_MAX_AGE_MS,
};

export interface EvictionResult {
  evicted: string[];
  reclaimedBytes: number;
}

export class ImageCacheTracker {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly config: ImageCacheConfig = DEFAULT_IMAGE_CACHE_CONFIG,
  ) {}

  #key(imageId: string): string { return CACHE_ENTRY_PREFIX + imageId; }

  /** Record an image pull or access. Creates or updates the cache entry. */
  public async recordAccess(imageId: string, tags: string[], sizeBytes: number): Promise<void> {
    const now = Date.now();
    const existing = await this.atomic.get<ImageCacheEntry>(this.#key(imageId));

    if (existing) {
      const entry = existing.value;
      const sizeDelta = sizeBytes - entry.sizeBytes;
      const updated: ImageCacheEntry = {
        ...entry,
        tags: [...new Set([...entry.tags, ...tags])],
        sizeBytes,
        pullCount: entry.pullCount + 1,
        lastAccessedAt: now,
      };
      await this.atomic.set(this.#key(imageId), updated, existing.version);
      if (sizeDelta !== 0) {
        await this.#addToTotalSize(sizeDelta);
      }
    } else {
      const entry: ImageCacheEntry = {
        imageId, tags, sizeBytes,
        pullCount: 1,
        lastAccessedAt: now,
        createdAt: now,
      };
      await this.atomic.set(this.#key(imageId), entry, null);
      await this.#addToIndex(imageId);
      await this.#addToTotalSize(sizeBytes);
    }
  }

  /** Record an image removal. Removes the cache entry. */
  public async recordRemoval(imageId: string): Promise<void> {
    const existing = await this.atomic.get<ImageCacheEntry>(this.#key(imageId));
    if (!existing) return;
    await this.#addToTotalSize(-existing.value.sizeBytes);
    await this.atomic.set(this.#key(imageId), null, existing.version);
    await this.#removeFromIndex(imageId);
  }

  /** Touch access time without changing other fields. */
  public async touch(imageId: string): Promise<void> {
    const existing = await this.atomic.get<ImageCacheEntry>(this.#key(imageId));
    if (!existing) return;
    const updated = { ...existing.value, lastAccessedAt: Date.now() };
    await this.atomic.set(this.#key(imageId), updated, existing.version);
  }

  /** Get the current total cached size in bytes. */
  public async totalSize(): Promise<number> {
    const entry = await this.atomic.get<number>(CACHE_TOTAL_SIZE_KEY);
    return entry?.value ?? 0;
  }

  /** List all cache entries sorted by lastAccessedAt (oldest first). */
  public async listByLastAccess(): Promise<ImageCacheEntry[]> {
    const idx = await this.atomic.get<string[]>(CACHE_INDEX_KEY);
    if (!idx) return [];
    const entries = await Promise.all(
      idx.value.map(id => this.atomic.get<ImageCacheEntry>(CACHE_ENTRY_PREFIX + id)),
    );
    return entries
      .filter(e => e)
      .map(e => e!.value)
      .sort((a, b) => a.lastAccessedAt - b.lastAccessedAt);
  }

  /**
   * Evict images to stay under the total byte limit (LRU) and remove stale entries.
   * Returns the list of evicted image IDs and total bytes reclaimed.
   * Does NOT perform the actual image removal — caller must call provider.remove().
   */
  public async computeEvictions(): Promise<EvictionResult> {
    const now = Date.now();
    const staleThreshold = now - this.config.maxAgeMs;
    const entries = await this.listByLastAccess();
    let currentTotal = await this.totalSize();

    const evicted: string[] = [];
    let reclaimedBytes = 0;

    for (const entry of entries) {
      // Evict if stale (7 days unaccessed) or over capacity
      const isStale = entry.lastAccessedAt < staleThreshold;
      const overCapacity = currentTotal > this.config.maxTotalBytes;

      if (isStale || overCapacity) {
        evicted.push(entry.imageId);
        reclaimedBytes += entry.sizeBytes;
        currentTotal -= entry.sizeBytes;
      }
    }

    return { evicted, reclaimedBytes };
  }

  /** Get a single cache entry. */
  public async get(imageId: string): Promise<ImageCacheEntry | null> {
    const entry = await this.atomic.get<ImageCacheEntry>(this.#key(imageId));
    return entry?.value ?? null;
  }

  // ─── Index helpers ───

  async #addToIndex(id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(CACHE_INDEX_KEY);
    await this.atomic.set(CACHE_INDEX_KEY, [...(idx?.value ?? []), id], idx?.version ?? null);
  }

  async #removeFromIndex(id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(CACHE_INDEX_KEY);
    if (!idx) return;
    await this.atomic.set(CACHE_INDEX_KEY, idx.value.filter(i => i !== id), idx.version);
  }

  async #addToTotalSize(delta: number): Promise<void> {
    for (let attempt = 0; attempt < 3; attempt++) {
      const entry = await this.atomic.get<number>(CACHE_TOTAL_SIZE_KEY);
      const cur = entry?.value ?? 0;
      const next = Math.max(0, cur + delta);
      const ver = await this.atomic.set(CACHE_TOTAL_SIZE_KEY, next, entry?.version ?? null);
      if (ver) return;
    }
  }
}

import type { IAtomicStore } from '../store/interfaces.ts';
import type { MiddlewareHandler } from 'hono';
import type { AppContext } from '../deps.ts';
import type { IAuditWriter } from '../audit/types.ts';
import { KernLevel } from '../audit/kern-level.ts';

// ─── Context variable ───

export interface CurrentUser {
  id: string;
  role: string;
  email: string;
}

declare module '../deps.ts' {
  interface AppContext {
    currentUser?: CurrentUser;
  }
}

// ─── Config ───

export interface AuthzConfig {
  /**
   * Atomic store for session/user lookups.
   * Should be wrapped with RequestCachedAtomicStore for per-request dedup.
   * Set to 'auto' to read from c.var.stores.atomic at request time.
   */
  store: IAtomicStore | 'auto';
  /** Route access check function: (method, path, userId) → boolean. */
  checkRouteAccess?: (method: string, path: string, userId: string) => Promise<boolean>;
  /** Path prefixes that skip auth entirely. */
  publicPaths: string[];
  /** Audit writer for security events. */
  audit?: IAuditWriter | undefined;
}

// ─── Constants ───

const TOKEN_PREFIX = 'session:';
const USER_PREFIX = 'user:';
const SESSION_TTL_MS = 2 * 60 * 60 * 1000;

// ─── Middleware ───

/**
 * Token auth + route ACL middleware.
 *
 * 1. Skips public paths (register/login etc).
 * 2. Reads `Authorization: Bearer <token>`, validates the session.
 * 3. Sets `c.var.currentUser`.
 * 4. If `checkRouteAccess` is configured, checks route ACLs.
 */
export function authz(config: AuthzConfig): MiddlewareHandler<{ Variables: AppContext }> {
  return async (c, next) => {
    // Resolve store: use request-cached version from context when configured as 'auto'
    const store: IAtomicStore = config.store === 'auto' ? c.var.stores.atomic : config.store;

    const path = c.req.path;
    const method = c.req.method;
    const ip = c.req.header('x-forwarded-for')?.split(',')[0]?.trim();

    function secAudit(ev: string, level: KernLevel, fields: Record<string, unknown>): void {
      config.audit?.write({ level, facility: 'authz', message: ev, metadata: { eventType: ev, method, path, ip, ...fields, timestamp: Date.now() } });
    }

    // 1. Skip public paths
    // Exact/startsWith matches: skip auth for all methods (register, login, etc.)
    // Wildcard (*) matches: skip auth only for GET requests (e.g. avatar display)
    if (config.publicPaths.some(p => {
      if (p.includes('*')) {
        if (method !== 'GET') return false;
        const star = p.indexOf('*');
        const prefix = p.slice(0, star);
        const suffix = p.slice(star + 1);
        if (!suffix || !path.startsWith(prefix) || !path.endsWith(suffix)) return false;
        const middle = path.slice(prefix.length, path.length - suffix.length);
        return !middle.includes('/');
      }
      return path.startsWith(p);
    })) {
      await next();
      return;
    }

    // 2. Extract Bearer token (Authorization header, or ?token= for WebSocket)
    let token = '';
    const auth = c.req.header('authorization');
    if (auth?.startsWith('Bearer ')) {
      token = auth.slice(7);
    } else if (c.req.header('upgrade')?.toLowerCase() === 'websocket') {
      // WebSocket API can't set custom headers — fallback to query param
      token = c.req.query('token') ?? '';
      if (!token) {
        secAudit('perm.unauthorized', KernLevel.WARNING, { reason: 'missing_ws_token' });
        return c.json({ success: false, data: null, error: { code: 'UNAUTHORIZED', message: 'WebSocket requires ?token=' } }, 401);
      }
    }
    if (!token) {
      secAudit('perm.unauthorized', KernLevel.WARNING, { reason: 'missing_auth_header' });
      return c.json({ success: false, data: null, error: { code: 'UNAUTHORIZED', message: 'Missing or invalid Authorization header' } }, 401);
    }
    if (!token) {
      secAudit('perm.unauthorized', KernLevel.WARNING, { reason: 'empty_token' });
      return c.json({ success: false, data: null, error: { code: 'UNAUTHORIZED', message: 'Empty token' } }, 401);
    }

    // 3. Validate session
    const sessionEntry = await store.get<{ userId: string; createdAt: number; expiresAt?: number }>(TOKEN_PREFIX + token).catch(() => null);
    if (!sessionEntry) {
      secAudit('perm.unauthorized', KernLevel.WARNING, { reason: 'invalid_token' });
      return c.json({ success: false, data: null, error: { code: 'UNAUTHORIZED', message: 'Invalid or expired token' } }, 401);
    }
    const expiresAt = sessionEntry.value.expiresAt ?? (sessionEntry.value.createdAt + SESSION_TTL_MS);
    if (Date.now() >= expiresAt) {
      secAudit('perm.unauthorized', KernLevel.WARNING, { reason: 'token_expired' });
      return c.json({ success: false, data: null, error: { code: 'UNAUTHORIZED', message: 'Token expired' } }, 401);
    }

    // 4. Get user
    const uid = sessionEntry.value.userId;
    const userEntry = await store.get<any>(USER_PREFIX + uid).catch(() => null);
    if (!userEntry) {
      secAudit('perm.unauthorized', KernLevel.WARNING, { reason: 'user_not_found', userId: uid });
      return c.json({ success: false, data: null, error: { code: 'UNAUTHORIZED', message: 'User not found' } }, 401);
    }

    // 5. Set user context
    c.set('currentUser', { id: uid, role: userEntry.value.role ?? '', email: userEntry.value.email ?? '' });

    // 6. Route ACL check
    const email = userEntry.value.email ?? '';
    if (config.checkRouteAccess) {
      const allowed = await config.checkRouteAccess(method, path, uid);
      if (!allowed) {
        secAudit('perm.forbidden', KernLevel.NOTICE, { userId: uid, email, reason: 'no_matching_acl' });
        return c.json({ success: false, data: null, error: { code: 'FORBIDDEN', message: 'You do not have access to this resource' } }, 403);
      }
      // perm.routeAccess 不在审计日志记录（每个成功的 API 请求都记录一次，噪音太大）
      // 可通过 log-policy 动态开启 DEBUG 级别观察
    }

    await next();
  };
}

import type { ErrorHandler } from 'hono';
import { ZodError } from 'zod';
import { AppError } from '../types.ts';
import { fail } from '../response.ts';
import type { IAuditWriter } from '../audit/types.ts';
import { KernLevel } from '../audit/kern-level.ts';

const ERROR_FACILITY = 'http';

/**
 * Global error handler.
 *
 * - ZodError: return 400 with validation issue messages.
 * - AppError: return structured error response at the error's status code.
 * - 5xx unhandled errors: record as KERN_ERR audit log, then return 500.
 */
export const globalErrorHandler: ErrorHandler = (err, c) => {
  if (err instanceof ZodError) {
    return c.json(fail('VALIDATION_ERROR', err.issues.map(i => i.message).join('; ')), 400);
  }

  if (err instanceof AppError) {
    return c.json(fail(err.code, err.message), err.statusCode as any);
  }

  const method = c.req.method;
  const url = c.req.url;
  const message = `Unhandled ${err.name}: ${err.message}`;
  const status = 500;

  // Fire-and-forget audit log (not awaited — must not block the error response)
  const audit = c.get('audit') as IAuditWriter | undefined;
  if (audit) {
    audit.write({
      level: KernLevel.ERR,
      facility: ERROR_FACILITY,
      message: `5xx ${method} ${url} — ${message}`,
    });
  }

  // Always also write to console.error (surfaces in wrangler dev/tail)
  console.error(`[${String(KernLevel.ERR)}] ${message}`);

  return c.json(fail('INTERNAL_ERROR', 'Internal server error'), status);
};

import type { MiddlewareHandler } from 'hono';
import type { ContentfulStatusCode } from 'hono/utils/http-status';
import type { IAtomicStore } from '../store/interfaces.ts';

const { parse: parseJson } = JSON;

/** Env shape this middleware requires on `c.var`. */
interface IdempotencyEnv { Variables: { stores: { atomic: IAtomicStore } } }

/**
 * Idempotency middleware — requires `IAtomicStore` bound to `c.var.stores`.
 * The client provides `Idempotency-Key` header.
 * On first request: stores the response. On replay: returns the stored response.
 */
export function idempotency(): MiddlewareHandler<IdempotencyEnv> {
  return async (c, next) => {
    const key = c.req.header('Idempotency-Key');
    if (!key) {
      await next();
      return;
    }

    const stores = c.var.stores.atomic;

    const storageKey = `idempotency:${key}`;

    const existing = await stores.get<string>(storageKey);
    if (existing) {
      try {
        const cached = parseJson(existing.value) as { status: number; body: unknown };
        return c.json(cached.body, cached.status as ContentfulStatusCode);
      } catch { /* corrupted data — fall through to re-execute */ }
    }

    await next();

    if (c.res.status >= 200 && c.res.status < 500) {
      try {
        const clone = (await c.res.clone().json());
        await stores.set(
          storageKey,
          JSON.stringify({ status: c.res.status, body: clone }),
          null,
        );
      } catch { /* non-JSON response — skip caching */ }
    }
  };
}

/**
 * Permission gate middleware — 3-layer security check (RHEL-aligned).
 *
 * This middleware is installed at FILTER.INPUT and enforces:
 *   Layer 1 (DAC):        user existence + resource ownership
 *   Layer 2 (Capability):  capability bitfield check
 *   Layer 3 (MAC):         DAG-based deny-override policies
 *
 * Each rejection logs an audit event with the correct audit type:
 *   DAC → SYSCALL, Capability → CAPABILITIES, MAC → AVC
 *
 * The PermissionChecker holds an in-memory cache (TTL 5s) of policies,
 * user groups, and permission groups — no per-request DB fetch overhead.
 */

import type { MiddlewareHandler } from 'hono';
import type { IPermissionChecker } from '../permission/interfaces.ts';

export interface PermissionGateOptions {
  /** Skip permission check for these paths (e.g. health, login). */
  readonly skipPaths?: readonly string[];
  /** Skip permission check for these methods (e.g. OPTIONS). */
  readonly skipMethods?: readonly string[];
}

export function createPermissionGate(
  checker: IPermissionChecker,
  options: PermissionGateOptions = {},
): MiddlewareHandler {
  const skipPaths = new Set(options.skipPaths ?? [
    '/api/auth/login',
    '/api/auth/register',
    '/api/info',
    '/health',
    '/__tick',
  ]);
  const skipMethods = new Set(options.skipMethods ?? ['OPTIONS', 'HEAD']);

  return async (c, next) => {
    const method = c.req.method;
    const path = c.req.path;

    // Skip non-guarded paths
    if (skipMethods.has(method)) return next();
    for (const p of skipPaths) {
      if (path === p || path.startsWith(p + '/') || path.startsWith(p + '?')) return next();
    }

    const userId = c.get?.('userId');
    // No user context — let the auth middleware handle rejection
    if (!userId) return next();

    const action = methodToAction(method);
    const resource = pathToResource(path);
    const ip = c.req.header?.('CF-Connecting-IP') ?? c.req.header?.('x-forwarded-for')?.split(',')[0]?.trim();

    const result = await checker.check({
      actor: userId,
      action,
      resource,
      resourceId: '',
      context: { ip, method, path },
    });

    if (result.allowed) return next();

    // Audit is auto-written by PermissionChecker on denial (SPEC: denial → record invariant).
    // HTTP context (path, method, ip) is passed in PermissionCheck.context.

    return c.json({
      error: 'FORBIDDEN',
      message: result.reason,
      ...(result.layer ? { layer: result.layer } : {}),
    }, 403);
  };
}

/** Map HTTP method to a CRUD action for permission checking. */
function methodToAction(method: string): string {
  switch (method) {
    case 'GET': return 'read';
    case 'POST': return 'create';
    case 'PUT': case 'PATCH': return 'update';
    case 'DELETE': return 'delete';
    default: return method.toLowerCase();
  }
}

/** Extract a stable resource name from the URL path. */
function pathToResource(path: string): string {
  // Strip /api/ prefix and take the first segment
  const clean = path.replace(/^\/api\//, '');
  const seg = clean.split('/')[0] ?? '';
  // Map known routes to permission resources
  const mapping: Record<string, string> = {
    'actions': 'action:workflow',
    'sandboxes': 'sandbox',
    'users': 'user',
    'permissions': 'permission',
    'templates': 'template',
    'images': 'image',
    'volumes': 'volume',
    'networks': 'network',
    'subnets': 'subnet',
    'dns': 'dns',
    'secrets': 'secret',
    'topology': 'topology',
    'platforms': 'platform',
  };
  return mapping[seg] ?? seg;
}

/**
 * Token bucket rate limiter (inspired by Linux printk_ratelimit).
 *
 * burst + interval model: allows `burst` requests initially, then
 * replenishes at rate of 1 token per `intervalMs / burst`.
 * This replaces the old windowMs+maxRequests sliding window with
 * a more predictable token bucket algorithm.
 */
import type { MiddlewareHandler } from 'hono';
import { AppError } from '../types.ts';

export interface RateLimitConfig {
  /** Maximum tokens in the bucket (initial burst capacity). Default 10. */
  burst: number;
  /** Interval in ms over which tokens replenish. Default 5000 (5s). */
  intervalMs: number;
  /** Master kill switch. Default: true. */
  enabled?: boolean;
  /** IPs or CIDRs exempt from rate limiting. */
  bypassIps?: readonly string[];
  /** Shared secret for header-based bypass. */
  bypassToken?: string;
}

interface TokenBucket {
  tokens: number;
  lastRefill: number;
}

function resolveIp(c: any): string {
  return c.req.header('cf-connecting-ip') ?? c.req.header('x-forwarded-for')?.split(',')[0]?.trim() ?? 'unknown';
}

function ipMatchesCidr(ip: string, cidr: string): boolean {
  if (ip === cidr) return true;
  const slashIdx = cidr.indexOf('/');
  if (slashIdx === -1) return ip === cidr;
  const prefixBits = parseInt(cidr.slice(slashIdx + 1), 10);
  if (isNaN(prefixBits)) return false;
  const baseIp = cidr.slice(0, slashIdx);
  if (ip.includes(':')) return ipv6InCidr(ip, baseIp, prefixBits);
  return ipv4InCidr(ip, baseIp, prefixBits);
}

function ipv4InCidr(ip: string, base: string, bits: number): boolean {
  const ipN = ipv4ToNumber(ip);
  const baseN = ipv4ToNumber(base);
  if (ipN === null || baseN === null) return false;
  const mask = bits === 0 ? 0 : (~0 >>> 0) << (32 - bits);
  return (ipN & mask) === (baseN & mask);
}

function ipv4ToNumber(ip: string): number | null {
  const parts = ip.split('.');
  if (parts.length !== 4) return null;
  let n = 0;
  for (let i = 0; i < 4; i++) {
    const octet = parseInt(parts[i]!, 10);
    if (isNaN(octet) || octet < 0 || octet > 255) return null;
    n = (n << 8) | octet;
  }
  return n >>> 0;
}

function ipv6InCidr(ip: string, base: string, bits: number): boolean {
  const ipBytes = ipv6ToBytes(ip);
  const baseBytes = ipv6ToBytes(base);
  if (!ipBytes || !baseBytes) return false;
  const fullBytes = Math.min(Math.ceil(bits / 8), 16);
  for (let i = 0; i < fullBytes; i++) {
    const byteBits = (i < Math.floor(bits / 8)) ? 8 : bits % 8;
    if (byteBits === 0) break;
    const mask = (0xff << (8 - byteBits)) & 0xff;
    if ((ipBytes[i]! & mask) !== (baseBytes[i]! & mask)) return false;
  }
  return true;
}

function ipv6ToBytes(ip: string): Uint8Array | null {
  const norm = ip.toLowerCase();
  const parts = norm.split('::');
  if (parts.length > 2) return null;
  const left = parts[0] ? parts[0].split(':') : [];
  const right = parts[1] ? parts[1].split(':') : [];
  if (left.length + right.length > 7) return null;
  const missing = 8 - left.length - right.length;
  const groups = [...left, ...Array<string>(missing).fill('0'), ...right];
  const bytes = new Uint8Array(16);
  for (let i = 0; i < 8; i++) {
    const val = parseInt(groups[i] || '0', 16);
    if (isNaN(val) || val < 0 || val > 0xffff) return null;
    bytes[i * 2] = (val >> 8) & 0xff;
    bytes[i * 2 + 1] = val & 0xff;
  }
  return bytes;
}

/** Token bucket rate limiter — burst + interval replenishment. */
export function rateLimit(config: RateLimitConfig): MiddlewareHandler {
  const enabled = config.enabled !== false;
  const bypassIps = config.bypassIps ?? [];
  const bypassToken = config.bypassToken;
  const burst = config.burst ?? 10;
  const intervalMs = config.intervalMs ?? 5000;
  const buckets = new Map<string, TokenBucket>();

  for (const cidr of bypassIps) {
    const slashIdx = cidr.indexOf('/');
    if (slashIdx !== -1 && isNaN(parseInt(cidr.slice(slashIdx + 1), 10))) {
      throw new AppError(500, 'BAD_RATE_LIMIT_CONFIG', `Invalid CIDR prefix: "${cidr}"`);
    }
  }

  return async (c, next) => {
    if (!enabled) return next();

    const ip = resolveIp(c);
    if (bypassIps.length > 0) {
      for (const cidr of bypassIps) {
        if (ipMatchesCidr(ip, cidr)) return next();
      }
    }
    if (bypassToken) {
      const headerToken = c.req.header('x-ratelimit-bypass');
      if (headerToken && headerToken === bypassToken) return next();
    }

    const now = Date.now();
    let bucket = buckets.get(ip);
    if (!bucket) {
      bucket = { tokens: burst, lastRefill: now };
      buckets.set(ip, bucket);
    }

    // Replenish: tokens += (elapsed / intervalMs) * burst
    const elapsed = now - bucket.lastRefill;
    bucket.tokens = Math.min(burst, bucket.tokens + (elapsed / intervalMs) * burst);
    bucket.lastRefill = now;

    if (bucket.tokens < 1) {
      throw new AppError(429, 'RATE_LIMITED', `Rate limit exceeded — ${String(burst)} req / ${String(intervalMs)}ms`);
    }

    bucket.tokens -= 1;
    await next();
  };
}

import type { MiddlewareHandler } from 'hono';
import type { AppContext } from '../deps.ts';

// ─── JSON depth limit ───

const DEFAULT_MAX_DEPTH = 10;

function checkDepth(obj: unknown, maxDepth: number, depth = 0): boolean {
  if (depth > maxDepth) return false;
  if (obj === null || typeof obj !== 'object') return true;
  if (Array.isArray(obj)) {
    for (const item of obj) {
      if (!checkDepth(item, maxDepth, depth + 1)) return false;
    }
    return true;
  }
  for (const val of Object.values(obj as Record<string, unknown>)) {
    if (!checkDepth(val, maxDepth, depth + 1)) return false;
  }
  return true;
}

class BodyDepthError extends Error {
  public constructor(maxDepth: number) {
    super(`JSON nesting depth exceeds limit of ${String(maxDepth)}`);
    this.name = 'BodyDepthError';
  }
}

/**
 * Middleware that limits JSON nesting depth.
 *
 * After the body is parsed as JSON (via c.req.json()), checks the parsed
 * value's maximum nesting depth.  If it exceeds `maxDepth`, returns a 400
 * response before the route handler runs.
 *
 * Must be placed AFTER body-limit middleware (which rejects oversized
 * payloads) and BEFORE any middleware that consumes the body.
 */
export function jsonDepthLimit(maxDepth = DEFAULT_MAX_DEPTH): MiddlewareHandler<{ Variables: AppContext }> {
  return async (c, next) => {
    const ct = c.req.header('content-type') ?? '';
    if (!ct.includes('application/json')) {
      await next();
      return;
    }

    // Replace c.req.json() with a wrapper that checks depth
    const originalJson = c.req.json.bind(c.req);
    c.req.json = async () => {
      const body = await originalJson();
      if (!checkDepth(body, maxDepth)) {
        throw new BodyDepthError(maxDepth);
      }
      return body;
    };

    try {
      await next();
    } catch (err) {
      if (err instanceof BodyDepthError) {
        return c.json(
          { success: false, data: null, error: { code: 'BODY_TOO_DEEP', message: err.message } },
          400,
        );
      }
      throw err;
    }
  };
}

/**
 * CIDR utilities for subnet pool management.
 *
 * Pure functions — no I/O, no state.
 */

export interface CidrBlock {
  readonly ip: number;  // network address as uint32 (big-endian)
  readonly bits: number; // prefix length (1-32)
}

/** Parse "10.2.3.0/24" → { ip: 0x0A020300, bits: 24 }. */
export function parseCidr(s: string): CidrBlock {
  const [addr, bitsStr] = s.split('/');
  if (!addr || !bitsStr) throw new Error(`Invalid CIDR: ${s}`);
  const octets = addr.split('.').map(Number);
  if (octets.length !== 4 || octets.some(o => isNaN(o) || o < 0 || o > 255)) {
    throw new Error(`Invalid IPv4 address: ${addr}`);
  }
  const bits = parseInt(bitsStr, 10);
  if (isNaN(bits) || bits < 1 || bits > 32) throw new Error(`Invalid prefix length: ${String(bits)}`);
  const raw = ((octets[0]! << 24) | (octets[1]! << 16) | (octets[2]! << 8) | octets[3]!) >>> 0;
  // Mask to network address — >>> 0 to keep unsigned after signed 32-bit &
  const mask = bits === 0 ? 0 : (~0 << (32 - bits)) >>> 0;
  return { ip: (raw & mask) >>> 0, bits };
}

/** Format { ip: 0x0A020300, bits: 24 } → "10.2.3.0/24". */
export function formatCidr(block: CidrBlock): string {
  const ip = block.ip >>> 0;
  const o1 = (ip >>> 24) & 0xFF;
  const o2 = (ip >>> 16) & 0xFF;
  const o3 = (ip >>> 8) & 0xFF;
  const o4 = ip & 0xFF;
  return `${[o1, o2, o3, o4].join('.')}/${String(block.bits)}`;
}

/** Get the broadcast address of a CIDR block. */
export function broadcast(block: CidrBlock): number {
  const mask = block.bits === 0 ? 0 : ((~0 >>> 0) << (32 - block.bits)) >>> 0;
  return (block.ip | ~mask) >>> 0;
}

/** Get the number of host addresses in a CIDR block (0 for /32). */
export function hostCount(block: CidrBlock): number {
  if (block.bits >= 31) return 2 ** (32 - block.bits);
  return 2 ** (32 - block.bits) - 2; // subtract network + broadcast
}

/** Check if `inner` is fully contained within `outer`. */
export function contains(outer: CidrBlock, inner: CidrBlock): boolean {
  if (outer.bits > inner.bits) return false; // outer prefix must be shorter or equal
  const mask = outer.bits === 0 ? 0 : (~0 << (32 - outer.bits)) >>> 0;
  return (outer.ip & mask) === (inner.ip & mask);
}

/**
 * Iterate all subnets of `parent` with `prefixLen`.
 * Yields each subnet CIDR block.
 */
export function* subnets(parent: CidrBlock, prefixLen: number): Generator<CidrBlock> {
  if (prefixLen <= parent.bits) throw new Error(`prefixLen (${String(prefixLen)}) must be > parent bits (${String(parent.bits)})`);
  const step = 2 ** (32 - prefixLen);
  const end = broadcast(parent) + 1;
  for (let ip = parent.ip; ip < end; ip += step) {
    yield { ip: ip >>> 0, bits: prefixLen };
  }
}

/** Get the next sequential CIDR block after `current` within `parent`. */
export function nextSubnet(parent: CidrBlock, current: CidrBlock): CidrBlock | null {
  const step = 2 ** (32 - current.bits);
  const nextIp = (current.ip + step) >>> 0;
  const next: CidrBlock = { ip: nextIp, bits: current.bits };
  if (contains(parent, next)) return next;
  return null;
}

/** Convert CIDR block to a stable string key for storage. */
export function cidrKey(block: CidrBlock): string {
  return formatCidr(block);
}

/// <reference types="@cloudflare/workers-types" />

/**
 * NotificationDO — 全局 WebSocket 广播频道
 *
 * 职责： 服务器单工推送给所有在线客户端（沙箱创建完成、节点离线、审计告警）。
 *
 * DO name: "notif:global"（单个全局实例）
 *
 * 客户端连接: GET /api/ws/notifications → Upgrade 到 NotificationDO
 * 内部桥接:   POST https://do/broadcast { type, data } → 广播给所有 WS 客户端
 *
 * 安全： /broadcast 端点只接受内部已知事件类型，并有 64KB body 上限。
 */
const MAX_BROADCAST_BYTES = 65_536;

const ALLOWED_EVENT_TYPES = new Set([
  'sandbox.provisioned',
  'sandbox.status',
]);

export class NotificationDO implements DurableObject {
  #sessions = new Set<WebSocket>();
  #filters = new Map<WebSocket, Set<string>>();

  public async fetch(request: Request): Promise<Response> {
    if (request.headers.get('Upgrade') === 'websocket') {
      return this.#handleUpgrade();
    }

    // Internal bridge: POST /broadcast { type, data }
    const url = new URL(request.url);
    if (url.pathname.endsWith('/broadcast') && request.method === 'POST') {
      // Body size limit — prevent OOM on large payloads
      const contentLength = Number(request.headers.get('content-length') ?? 0);
      if (contentLength > MAX_BROADCAST_BYTES) {
        return new Response('payload too large', { status: 413 });
      }
      const body = await request.json();
      if (!ALLOWED_EVENT_TYPES.has(body.type)) {
        return new Response('unknown event type', { status: 400 });
      }
      this.#broadcast(body.type, body.data);
      return new Response('ok', { status: 200 });
    }

    return new Response('not found', { status: 404 });
  }

  #handleUpgrade(): Response {
    const pair = new WebSocketPair();
    const client = pair[0];
    const server = pair[1];

    server.accept();
    this.#sessions.add(server);

    server.addEventListener('message', (event: MessageEvent) => {
      this.#handleMessage(server, event);
    });

    server.addEventListener('close', () => {
      this.#sessions.delete(server);
      this.#filters.delete(server);
    });

    return new Response(null, { status: 101, webSocket: client });
  }

  #handleMessage(ws: WebSocket, event: MessageEvent): void {
    try {
      const msg = JSON.parse(event.data as string);
      if (msg.type === 'subscribe' && Array.isArray(msg.channels)) {
        this.#filters.set(ws, new Set(msg.channels));
        ws.send(JSON.stringify({ type: 'subscribed', channels: msg.channels }));
      }
    } catch {
      ws.send(JSON.stringify({ type: 'error', data: { message: 'Invalid message format' } }));
    }
  }

  #broadcast(type: string, data: unknown): void {
    const ts = Date.now();
    for (const [ws, channels] of this.#filters) {
      // Skip if client has active filters and none match this event type
      if (channels.size > 0 && !this.#matches(channels, type)) continue;
      try {
        ws.send(JSON.stringify({ type, data, ts }));
      } catch {
        this.#sessions.delete(ws);
        this.#filters.delete(ws);
      }
    }
  }

  /** Check if event type matches any subscription channel (supports wildcard: "sandbox.*"). */
  #matches(channels: Set<string>, eventType: string): boolean {
    for (const ch of channels) {
      if (ch === '*' || ch === eventType) return true;
      if (ch.endsWith('.*') && eventType.startsWith(ch.slice(0, -1))) return true;
      if (ch.endsWith(':*') && eventType.startsWith(ch.slice(0, -1))) return true;
    }
    return false;
  }
}

import { Dag } from '../dag/graph.ts';
import { PermissionEffect } from './types.ts';
import type { PolicyId, PolicyNode, PermissionCheck, EvaluationResult } from './types.ts';

/**
 * Directed acyclic graph of permission policy nodes.
 *
 * Extends the generic `Dag` with domain-specific methods for building and
 * evaluating a permission policy graph. Evaluation uses **deny-overrides**:
 * if any matching policy has effect DENY, the result is immediately denied.
 * Otherwise the first matching ALLOW (in topological order) grants access.
 * If no policy matches, the result is denied by default.
 *
 * @example
 * ```ts
 * const dag = new PermissionDag();
 * dag.addPolicy({ id: p('admin'), effect: PermissionEffect.ALLOW, match: p => p.actor === 'root' });
 * dag.addPolicy({ id: p('deny-deleted'), effect: PermissionEffect.DENY, match: p => p.resourceId.startsWith('deleted-') });
 * dag.addDependency(p('deny-deleted'), p('admin'));  // deny-deleted evaluated first
 * ```
 */
export class PermissionDag extends Dag<PolicyId, PolicyNode> {
  public constructor() {
    super(node => node.id);
  }

  // ─── Building ───

  /** Register a policy node. Replaces any node with the same id. */
  public addPolicy(node: PolicyNode): void {
    this.addNode(node);
  }

  /**
   * Add a dependency edge: `from` policy must be evaluated before `to`.
   * Both policy IDs must already exist.
   */
  public addDependency(from: PolicyId, to: PolicyId): void {
    this.addEdge(from, to);
  }

  // ─── Evaluation ───

  /**
   * Evaluate all matching policies in topological order.
   *
   * Strategy (deny-overrides):
   *  1. Topological sort — respect dependency ordering.
   *  2. For each node in sort order: if it matches, check effect.
   *     - DENY → return immediately (deny overrides).
   *     - ALLOW → flag as allowed but continue (later nodes may deny).
   *  3. After all nodes: return ALLOW if any matched, else DENY.
   *
   * Returns the decision and the policy node that triggered it (if any).
   */
  public evaluate(params: PermissionCheck): EvaluationResult {
    const sortResult = this.topologicalSort();

    if (!sortResult.success) {
      return {
        allowed: false,
        reason: `Policy DAG cycle detected: ${sortResult.error}`,
      };
    }

    let allowMatched: PolicyNode | undefined;

    for (const node of sortResult.sorted) {
      if (!node.match(params)) continue;

      if (node.effect === PermissionEffect.DENY) {
        return {
          allowed: false,
          reason: `Denied by policy: ${node.description ?? node.id}`,
          matchedPolicy: node,
        };
      }

      if (!allowMatched) {
        allowMatched = node;
      }
    }

    if (allowMatched) {
      return {
        allowed: true,
        reason: `Allowed by policy: ${allowMatched.description ?? allowMatched.id}`,
        matchedPolicy: allowMatched,
      };
    }

    return { allowed: false, reason: 'No matching policy' };
  }
}

declare const AUTHZ_ID_BRAND: unique symbol;
declare const POLICY_ID_BRAND: unique symbol;
declare const ROLE_ID_BRAND: unique symbol;

export type AuthzId = string & { readonly [AUTHZ_ID_BRAND]: true };
export type PolicyId = string & { readonly [POLICY_ID_BRAND]: true };
export type RoleId = string & { readonly [ROLE_ID_BRAND]: true };

export function createAuthzId(raw: string): AuthzId {
  if (!raw) throw new TypeError('AuthzId must not be empty');
  return raw as AuthzId;
}

export function generateAuthzId(): AuthzId {
  return `authz_${crypto.randomUUID()}` as AuthzId;
}

export function createPolicyId(raw: string): PolicyId {
  if (!raw) throw new TypeError('PolicyId must not be empty');
  return raw as PolicyId;
}

export function createRoleId(raw: string): RoleId {
  if (!raw) throw new TypeError('RoleId must not be empty');
  return raw as RoleId;
}

export enum PermissionEffect {
  ALLOW = 'allow',
  DENY = 'deny',
}

export enum PermissionAction {
  CREATE = 'create',
  READ = 'read',
  UPDATE = 'update',
  DELETE = 'delete',
  ADMIN = 'admin',
}

// ═══════════════════════════════════════════════════════════
// Capability bitfield — decomposes superuser into named capabilities
// ═══════════════════════════════════════════════════════════

export const Capability = {
  NONE:                    0,
  // Sandbox
  SANDBOX_CREATE:          1 << 0,   // 1
  SANDBOX_DELETE:          1 << 1,   // 2
  SANDBOX_UPDATE:          1 << 2,   // 4
  SANDBOX_EXEC:            1 << 3,   // 8
  SANDBOX_ADMIN:           1 << 4,   // 16
  // Image
  IMAGE_PULL:              1 << 5,   // 32
  IMAGE_DELETE:            1 << 6,   // 64
  IMAGE_COMMIT:            1 << 7,   // 128
  // Volume
  VOLUME_MOUNT:            1 << 8,   // 256
  VOLUME_CREATE:           1 << 9,   // 512
  VOLUME_DELETE:           1 << 10,  // 1024
  // Network
  NETWORK_BIND:            1 << 11,  // 2048
  NETWORK_ADMIN:           1 << 12,  // 4096
  // User management
  USER_CREATE:             1 << 13,  // 8192
  USER_DELETE:             1 << 14,  // 16384
  USER_ADMIN:              1 << 15,  // 32768
  // System
  SYS_AUDIT_READ:          1 << 16,  // 65536
  SYS_AUDIT_WRITE:         1 << 17,  // 131072
  SYS_CONFIG:              1 << 18,  // 262144
  // Composite sets
  SANDBOX_CRUD:            (1 << 0) | (1 << 1) | (1 << 2) | (1 << 3),  // 15
  IMAGE_CRUD:              (1 << 5) | (1 << 6) | (1 << 7),              // 224
  VOLUME_CRUD:             (1 << 8) | (1 << 9) | (1 << 10),             // 1792
  USER_CRUD:               (1 << 13) | (1 << 14),                        // 24576
  ALL:                      0x7FFFF,  // All 19 capabilities
} as const;

export type CapabilityValue = number;

/** Map an action string to the required capability bit. */
export function actionToCapability(action: string): CapabilityValue {
  /* eslint-disable @typescript-eslint/no-unsafe-enum-comparison -- accepts both PermissionAction enum values and arbitrary strings */
  switch (action) {
    case PermissionAction.CREATE: return Capability.SANDBOX_CREATE;
    case PermissionAction.DELETE: return Capability.SANDBOX_DELETE;
    case PermissionAction.UPDATE: return Capability.SANDBOX_UPDATE;
    default: return Capability.NONE;
  }
  /* eslint-enable @typescript-eslint/no-unsafe-enum-comparison */
}

/** Check if a capability set contains the required capabilities. */
export function hasCapability(caps: CapabilityValue, required: CapabilityValue): boolean {
  return (caps & required) === required;
}

// ═══════════════════════════════════════════════════════════
// 3-layer denial tracking — DAC / Capability / MAC
// ═══════════════════════════════════════════════════════════

export const enum DenialLayer {
  DAC = 'dac',
  CAPABILITY = 'cap',
  MAC = 'mac',
}

/** Audit record type per denial layer — mirrors Linux audit types. */
export const DENIAL_AUDIT_TYPE: Record<DenialLayer, string> = {
  [DenialLayer.DAC]:        'SYSCALL',
  [DenialLayer.CAPABILITY]: 'CAPABILITIES',
  [DenialLayer.MAC]:        'AVC',
};

export interface PermissionCheck {
  readonly actor: string;
  /** Action string — accepts PermissionAction enum values or arbitrary strings for pattern matching. */
  readonly action: string;
  readonly resource: string;
  readonly resourceId: string;
  readonly context?: Record<string, unknown>;
}

export interface PermissionResult {
  readonly allowed: boolean;
  readonly reason: string;
  /** Which layer denied the request. Undefined if allowed. */
  readonly layer?: DenialLayer;
  /** Audit type for the denial event. Maps to 'SYSCALL' | 'CAPABILITIES' | 'AVC'. */
  readonly auditType?: string;
}

/**
 * A node in the permission policy DAG.
 *
 * Each node has an effect (ALLOW or DENY) and a `match()` function that
 * determines whether this policy applies to a given permission check.
 * Nodes are composed into a DAG via `PermissionDag`; edges define dependency
 * ordering for evaluation.
 *
 * @example
 * ```ts
 * const adminPolicy: PolicyNode = {
 *   id: createPolicyId('admin-rule'),
 *   effect: PermissionEffect.ALLOW,
 *   description: 'Admins can do anything',
 *   match: (p) => p.actor.startsWith('admin:'),
 * };
 * ```
 */
export interface PolicyNode {
  readonly id: PolicyId;
  readonly effect: PermissionEffect;
  readonly description?: string;
  /** Return true if this policy applies to the given check. */
  match(params: PermissionCheck): boolean;
}

/**
 * Extended result from DAG evaluation that includes which policy matched.
 */
export interface EvaluationResult extends PermissionResult {
  /** The policy node that produced the decision, if any. */
  readonly matchedPolicy?: PolicyNode;
}

export interface AuthzRecord {
  readonly id: AuthzId;
  readonly actor: string;
  readonly action: PermissionAction;
  readonly resource: string;
  readonly resourceId: string;
  readonly allowed: boolean;
  readonly reason: string;
  readonly timestamp: number;
  readonly metadata?: Record<string, unknown>;
}

/**
 * PodService — full lifecycle management for Pods.
 * Mirrors SandboxService but operates on PodSpec/PodPhase/PodEntity.
 */

import type { IAtomicStore } from '../store/interfaces.ts';
import type { IContainerProvider, IProviderRegistry, ContainerLogResult } from '../provider/interfaces.ts';
import { ProviderResolutionError } from '../provider/errors.ts';
import type { CreateContainerGroupInput, ContainerGroupRuntime } from '../provider/types.ts';
import { ContainerGroupState } from '../provider/container-lifecycle.ts';
import { createRegionId } from '../region/types.ts';
import { generateVersionId } from '../brand.ts';
import { AppError } from '../types.ts';
import { PodStore } from './store.ts';
import type { PodSpec, PodPhase, PodEntity, PodNetwork, PodId, ContainerState } from './types.ts';
import { createPodId } from './types.ts';

// ═══════════════════════════════════════════════════════════════
// Adapters (to be replaced by PodCodec injection)
// ═══════════════════════════════════════════════════════════════

function podSpecToGroupInput(spec: PodSpec): CreateContainerGroupInput {
  const containers = spec.spec.containers.map(c => {
    const cpu = c.resources?.limits?.cpu ?? 0;
    const mem = c.resources?.limits?.memory ?? 0;
    return {
      name: c.name,
      image: c.image,
      command: c.command,
      args: c.args,
      env: c.env,
      ports: c.ports,
      volumeMounts: c.volumeMounts,
      livenessProbe: c.livenessProbe,
      readinessProbe: c.readinessProbe,
      startupProbe: c.startupProbe,
      imagePullPolicy: c.imagePullPolicy ?? undefined,
      tty: c.tty ?? undefined,
      stdin: c.stdin ?? undefined,
      networkMode: c.networkMode ?? undefined,
      resources: (cpu > 0 || mem > 0) ? { limits: { cpu, memory: mem, ...(c.resources?.limits?.gpu !== undefined ? { gpu: c.resources.limits.gpu } : {}) } } : undefined,
    };
  });

  return {
    name: spec.metadata.name,
    region: createRegionId('cn-hangzhou'),
    cpu: containers.reduce((s, c) => s + (c.resources?.limits?.cpu ?? 0), 0) || 1,
    memory: containers.reduce((s, c) => s + (c.resources?.limits?.memory ?? 0), 0) || 512,
    restartPolicy: spec.spec.restartPolicy,
    containers,
    volumes: spec.spec.volumes?.map(v => ({ id: v.id, type: v.type, options: v.options })),
    tags: spec.metadata.labels ? Object.entries(spec.metadata.labels).map(([k, v]) => ({ key: k, value: v })) : undefined,
    network: { allocatePublicIp: false },
    providerOverrides: spec.providerOverrides,
  };
}

function toPodPhase(cgStatus: ContainerGroupState): PodPhase {
  switch (cgStatus) {
    case ContainerGroupState.Scheduling:
    case ContainerGroupState.ScheduleFailed:
    case ContainerGroupState.Pending:
      return 'Pending';
    case ContainerGroupState.Running:
    case ContainerGroupState.Restarting:
    case ContainerGroupState.Updating:
    case ContainerGroupState.Terminating:
      return 'Running';
    case ContainerGroupState.Succeeded:
    case ContainerGroupState.Stopped:
    case ContainerGroupState.Paused:
      return 'Succeeded';
    case ContainerGroupState.Failed:
    case ContainerGroupState.Expired:
      return 'Failed';
    case ContainerGroupState.Deleted:
      return 'Failed';
  }
}

function toContainers(cg: ContainerGroupRuntime): PodEntity['containers'] {
  return cg.containers.map(c => ({
    name: c.name,
    image: c.image,
    state: buildContainerState(c.status, c),
    env: c.env,
    ports: c.network?.ports.map(p => ({ containerPort: p.containerPort, hostPort: p.hostPort ?? undefined, protocol: p.protocol })),
    resources: c.resources ? { cpu: c.resources.cpu, memory: c.resources.memory, gpu: c.resources.gpu } : undefined,
    labels: c.labels,
    annotations: c.annotations,
    mounts: c.mounts,
  }));
}

function buildContainerState(status: string, c: { exitCode?: number | undefined; startedAt?: string | undefined; finishedAt?: string | undefined }): ContainerState {
  const s = status.toLowerCase();
  if (s === 'running') return { state: 'Running', startedAt: c.startedAt ?? '' };
  if (s === 'exited' || s === 'terminated') return { state: 'Terminated', exitCode: c.exitCode ?? 0, reason: undefined, signal: undefined, startedAt: c.startedAt, finishedAt: c.finishedAt };
  return { state: 'Waiting' };
}

// ═══════════════════════════════════════════════════════════════
// PodService
// ═══════════════════════════════════════════════════════════════

export class PodService {
  private readonly store: PodStore;

  public constructor(
    atomic: IAtomicStore,
    private readonly providerRegistry?: IProviderRegistry | undefined,
    /** Fallback provider when no registry is available. */
    private readonly fallbackProvider?: IContainerProvider | undefined,
  ) {
    this.store = new PodStore(atomic);
  }

  private async resolveProvider(): Promise<IContainerProvider> {
    if (this.providerRegistry?.resolveContainer) {
      const p = await this.providerRegistry.resolveContainer(undefined);
      if (p) return p;
    }
    if (this.fallbackProvider) return this.fallbackProvider;
    throw new ProviderResolutionError('No container provider available for PodService');
  }

  public async provision(spec: PodSpec): Promise<PodEntity> {
    const podId = createPodId(crypto.randomUUID());
    const provider = await this.resolveProvider();
    const groupInput = podSpecToGroupInput(spec);
    const { providerId } = await provider.create(groupInput);
    const initialPhase: PodPhase = provider.lifecycle.asyncInit ? 'Pending' : 'Running';

    const entity: PodEntity = {
      podId,
      name: spec.metadata.name,
      spec,
      phase: initialPhase,
      providerId,
      network: {},
      containers: [],
      conditions: [],
      events: [],
      createdAt: Date.now(),
      updatedAt: Date.now(),
      version: generateVersionId(),
      creatorId: undefined,
    };

    const written = await this.store.insert(entity);
    if (!written) throw new AppError(500, 'CREATE_FAILED', 'Failed to persist Pod');
    await this.store.addToIndex(podId);
    return entity;
  }

  public async getById(podId: PodId): Promise<PodEntity | null> {
    return this.store.getById(podId);
  }

  public async list(phase?: PodPhase, limit = 50, cursor?: string): Promise<{ items: PodEntity[]; nextCursor?: string }> {
    return this.store.list(phase, limit, cursor);
  }

  public async stop(podId: PodId): Promise<PodEntity> {
    const pod = await this.store.getById(podId);
    if (!pod) throw new AppError(404, 'POD_NOT_FOUND', `Pod ${podId} not found`);
    if (pod.providerId) {
      const provider = await this.resolveProvider();
      try { await provider.stop?.(pod.providerId); } catch { /* best-effort */ }
    }
    return this.store.transition(podId, 'Succeeded');
  }

  public async start(podId: PodId): Promise<PodEntity> {
    const pod = await this.store.getById(podId);
    if (!pod) throw new AppError(404, 'POD_NOT_FOUND', `Pod ${podId} not found`);
    if (pod.providerId) {
      const provider = await this.resolveProvider();
      try { await provider.start?.(pod.providerId); } catch { /* best-effort */ }
    }
    return this.store.transition(podId, 'Running');
  }

  public async terminate(podId: PodId): Promise<void> {
    const pod = await this.store.getById(podId);
    if (!pod) throw new AppError(404, 'POD_NOT_FOUND', `Pod ${podId} not found`);
    if (pod.providerId) {
      const provider = await this.resolveProvider();
      try { await provider.delete({ region: createRegionId('cn-hangzhou'), providerId: pod.providerId }); } catch { /* GC will retry */ }
    }
    await this.store.transition(podId, 'Failed');
    await this.store.removeFromIndex(podId);
  }

  public async getAllIds(): Promise<string[]> {
    return this.store.getAllIds();
  }

  /** GC cleanup — delete provider resource (best-effort) + remove from index. */
  public async gcCleanup(podId: PodId): Promise<void> {
    const pod = await this.store.getById(podId);
    if (!pod) return;
    if (pod.providerId) {
      const provider = await this.resolveProvider();
      try {
        await Promise.race([
          provider.delete({ region: createRegionId('cn-hangzhou'), providerId: pod.providerId }),
          new Promise<never>((_, reject) => setTimeout(() => { reject(new Error('GC delete timeout after 10s')); }, 10_000)),
        ]);
      } catch { /* best-effort */ }
    }
    for (let attempt = 0; attempt < 3; attempt++) {
      const latest = await this.store.getById(podId);
      if (!latest) break;
      try {
        await this.store.update(podId, { ...latest, phase: 'Failed', updatedAt: Date.now(), version: generateVersionId() }, latest.version);
      } catch { continue; }
      break;
    }
    await this.store.removeFromIndex(podId);
  }

  /** Lightweight provider status check — returns runtime or null if resource is gone. */
  public async checkProviderStatus(podId: PodId): Promise<ContainerGroupRuntime | null> {
    const pod = await this.store.getById(podId);
    if (!pod?.providerId) return null;
    const provider = await this.resolveProvider();
    if (!provider.getStatus) return null;
    let providerStatus: ContainerGroupRuntime | null = null;
    try {
      providerStatus = await provider.getStatus(pod.providerId);
    } catch (_e) { /* provider unreachable — treat as resource gone */ }
    return providerStatus;
  }

  public async syncRuntime(podId: PodId): Promise<PodEntity> {
    const pod = await this.store.getById(podId);
    if (!pod?.providerId) throw new AppError(404, 'POD_NOT_FOUND', `Pod ${podId} not found or has no providerId`);
    const provider = await this.resolveProvider();
    const result = await provider.describe({ region: createRegionId('cn-hangzhou'), sandboxId: pod.providerId });
    const runtime = result.sandboxes[0];
    if (!runtime) throw new AppError(404, 'RUNTIME_NOT_FOUND', `No runtime found for pod ${podId}`);

    const containers = toContainers(runtime);
    const phase = toPodPhase(runtime.status);
    const network: PodNetwork = {
      privateIp: runtime.network.privateIp,
      vpcId: runtime.network.vpcId,
      subnetId: runtime.network.subnetId,
      securityGroupId: runtime.network.securityGroupId,
    };

    const updated: PodEntity = {
      ...pod,
      phase,
      containers,
      network,
      events: runtime.events.map(e => ({ reason: e.reason, type: e.type, message: e.message, count: e.count })),
      updatedAt: Date.now(),
      version: generateVersionId(),
    };
    return this.store.update(podId, updated, pod.version);
  }

  public async getLogs(podId: PodId, containerName: string, options?: { limitBytes?: number; sinceSeconds?: number; timestamps?: boolean }): Promise<ContainerLogResult> {
    const pod = await this.store.getById(podId);
    if (!pod?.providerId) throw new AppError(404, 'POD_NOT_FOUND', `Pod ${podId} not found or has no providerId`);
    const provider = await this.resolveProvider();
    return provider.getLogs({ region: createRegionId('cn-hangzhou'), providerId: pod.providerId, containerName, ...options });
  }

  public async exec(podId: PodId, cmd: readonly string[], containerName?: string): Promise<{ execId: string; webSocketUri?: string | undefined }> {
    const pod = await this.store.getById(podId);
    if (!pod?.providerId) throw new AppError(404, 'POD_NOT_FOUND', `Pod ${podId} not found or has no providerId`);
    const provider = await this.resolveProvider();
    if (!provider.exec) throw new AppError(501, 'NOT_IMPLEMENTED', 'Provider does not support exec');
    const result = await provider.exec(pod.providerId, cmd, containerName);
    return { execId: result.execId, webSocketUri: result.webSocketUri ?? undefined };
  }

  public async update(podId: PodId, specPatch: Partial<PodSpec>): Promise<PodEntity> {
    const pod = await this.store.getById(podId);
    if (!pod) throw new AppError(404, 'POD_NOT_FOUND', `Pod ${podId} not found`);
    if (pod.providerId) {
      const provider = await this.resolveProvider();
      if (provider.update) {
        const groupInput = podSpecToGroupInput(mergePodSpec(pod.spec, specPatch));
        try { await provider.update(pod.providerId, groupInput); } catch { /* best-effort */ }
      }
    }
    const merged = mergePodSpec(pod.spec, specPatch);
    const updated: PodEntity = {
      ...pod,
      spec: merged,
      updatedAt: Date.now(),
      version: generateVersionId(),
    };
    return this.store.update(podId, updated, pod.version);
  }
}

function mergePodSpec(base: PodSpec, patch: Partial<PodSpec>): PodSpec {
  return {
    metadata: { ...base.metadata, ...patch.metadata },
    spec: {
      containers: patch.spec?.containers ?? base.spec.containers,
      restartPolicy: patch.spec?.restartPolicy ?? base.spec.restartPolicy,
      ...(base.spec.initContainers || patch.spec?.initContainers ? { initContainers: patch.spec?.initContainers ?? base.spec.initContainers } : {}),
      ...(base.spec.volumes || patch.spec?.volumes ? { volumes: patch.spec?.volumes ?? base.spec.volumes } : {}),
      ...(base.spec.priority !== undefined || patch.spec?.priority !== undefined ? { priority: patch.spec?.priority ?? base.spec.priority } : {}),
      ...(base.spec.nodeSelector || patch.spec?.nodeSelector ? { nodeSelector: patch.spec?.nodeSelector ?? base.spec.nodeSelector } : {}),
      ...(base.spec.terminationGracePeriodSeconds !== undefined || patch.spec?.terminationGracePeriodSeconds !== undefined ? { terminationGracePeriodSeconds: patch.spec?.terminationGracePeriodSeconds ?? base.spec.terminationGracePeriodSeconds } : {}),
      ...(base.spec.dnsConfig || patch.spec?.dnsConfig ? { dnsConfig: patch.spec?.dnsConfig ?? base.spec.dnsConfig } : {}),
      ...(base.spec.hostAliases || patch.spec?.hostAliases ? { hostAliases: patch.spec?.hostAliases ?? base.spec.hostAliases } : {}),
    },
    ...(base.providerOverrides || patch.providerOverrides ? { providerOverrides: { ...base.providerOverrides, ...patch.providerOverrides } } : {}),
  };
}

/**
 * Abstract Container Group Lifecycle — formal state machine derived from
 * the Alibaba ECI ContainerGroup model (SPEC/ECI_LIFECYCLE_FORMAL_MODEL.md).
 *
 * Design invariants:
 * - Pure functions only — no IO, no side effects. Trivially testable.
 * - The full state set is a superset of all provider states (ECI + Podman).
 * - Each provider declares a ContainerLifecycleProfile that is a restriction of
 *   the full model, not an ad-hoc flag set.
 * - All 5 ECI safety invariants are encoded as runtime-checkable assertions.
 * - The bridge to SandboxStatus is a pure, verified mapping.
 */

// ─── 1. Complete state set (§1 of formal model) ───

/** Full ContainerGroup state space.
 *  ECI defines 11 states. Podman adds 2: Stopped, Paused.
 *  Sorted by lifecycle phase: creation → runtime → terminal. */
export enum ContainerGroupState {
  /** ECI: Scheduling — transient, resources being allocated. */
  Scheduling = 'Scheduling',
  /** ECI: ScheduleFailed — terminal, no capacity / invalid params. */
  ScheduleFailed = 'ScheduleFailed',
  /** ECI: Pending — image pull + container init. Podman: analogous to "Created". */
  Pending = 'Pending',
  /** Steady state — all containers alive and serving. */
  Running = 'Running',
  /** ECI: Updating — UpdateContainerGroup in flight. */
  Updating = 'Updating',
  /** ECI: Restarting — RestartContainerGroup in flight. Podman: analogous. */
  Restarting = 'Restarting',
  /** Podman: Stopped — pod exists but processes are not running. Recoverable.
   *  ECI does NOT have this state (stop = delete). */
  Stopped = 'Stopped',
  /** Podman: Paused — cgroups frozen. Not in ECI model. */
  Paused = 'Paused',
  /** ECI: Terminating — DeleteContainerGroup grace period. */
  Terminating = 'Terminating',
  // ─── Terminal states (§3.2) ───
  /** ECI: Succeeded — containers exited with code 0, RestartPolicy != Always. */
  Succeeded = 'Succeeded',
  /** ECI: Failed — init/container error, or RestartPolicy=Never + non-zero exit. */
  Failed = 'Failed',
  /** ECI: Expired — preemptible instance reclaimed by platform. */
  Expired = 'Expired',
  /** ECI: Deleted — resources removed from cloud. Logical terminal. */
  Deleted = 'Deleted',
}

// ─── 2. Container-level states (§1.3) ───

export enum ContainerStateValue {
  Waiting = 'Waiting',
  Running = 'Running',
  Terminated = 'Terminated',
}

// ─── 3. Trigger taxonomy (§3) ───

/** System events — the cloud platform initiates these transitions. */
export type SystemEvent =
  | 'ScheduleSucceeded'
  | 'ScheduleFailed'
  | 'InitSucceeded'
  | 'InitFailed'
  | 'ContainerExited0'
  | 'ContainerExitedNonZero'
  | 'InstanceExpired'
  | 'RestartSucceeded'
  | 'RestartFailed'
  | 'UpdateSucceeded'
  | 'UpdateFailed'
  | 'CleanupComplete';

/** API operations — the user initiates these transitions (§4). */
export type ApiOperation =
  | 'CreateContainerGroup'
  | 'DeleteContainerGroup'
  | 'RestartContainerGroup'
  | 'UpdateContainerGroup'
  | 'StopContainerGroup'
  | 'StartContainerGroup'
  | 'PauseContainerGroup'
  | 'UnpauseContainerGroup';

/** A transition trigger: either a system event, an API call, or a RestartPolicy evaluation. */
export type TransitionTrigger =
  | { readonly kind: 'System'; readonly event: SystemEvent }
  | { readonly kind: 'Api'; readonly operation: ApiOperation }
  | { readonly kind: 'RestartPolicy'; readonly exitCode: number; readonly policy: RestartPolicy };

/** RestartPolicy values (§8). */
export type RestartPolicy = 'Always' | 'OnFailure' | 'Never';

// ─── 4. Transition function (§3.1, 18 rules) ───

/** Ordered pair of states. */
export interface Transition {
  readonly from: ContainerGroupState;
  readonly to: ContainerGroupState;
}

/** Complete transition table — all 18 ECI rules + Podman extensions.
 *  Each entry is a (from, trigger, to) triple.
 *  System transitions are always valid when the system reports the event.
 *  API transitions are only valid when canApplyOperation(from, op) is true. */
export const ECI_TRANSITIONS: readonly {
  readonly from: ContainerGroupState;
  readonly trigger: TransitionTrigger;
  readonly to: ContainerGroupState;
  readonly rule: string;
}[] = [
  // T1: Scheduling + ScheduleSucceeded → Pending
  { from: ContainerGroupState.Scheduling, trigger: { kind: 'System', event: 'ScheduleSucceeded' }, to: ContainerGroupState.Pending, rule: 'T1' },
  // T2: Scheduling + ScheduleFailed → ScheduleFailed
  { from: ContainerGroupState.Scheduling, trigger: { kind: 'System', event: 'ScheduleFailed' }, to: ContainerGroupState.ScheduleFailed, rule: 'T2' },
  // T3: Pending + InitSucceeded → Running
  { from: ContainerGroupState.Pending, trigger: { kind: 'System', event: 'InitSucceeded' }, to: ContainerGroupState.Running, rule: 'T3' },
  // T4: Pending + InitFailed → Failed
  { from: ContainerGroupState.Pending, trigger: { kind: 'System', event: 'InitFailed' }, to: ContainerGroupState.Failed, rule: 'T4' },
  // T5: Running + ContainerExited0 → Succeeded (policy-dependent, handled by RestartPolicy trigger)
  { from: ContainerGroupState.Running, trigger: { kind: 'System', event: 'ContainerExited0' }, to: ContainerGroupState.Succeeded, rule: 'T5' },
  // T6: Running + ContainerExitedNonZero → Failed (policy-dependent)
  { from: ContainerGroupState.Running, trigger: { kind: 'System', event: 'ContainerExitedNonZero' }, to: ContainerGroupState.Failed, rule: 'T6' },
  // T7: Running + RestartContainerGroup → Restarting
  { from: ContainerGroupState.Running, trigger: { kind: 'Api', operation: 'RestartContainerGroup' }, to: ContainerGroupState.Restarting, rule: 'T7' },
  // T8: Running + UpdateContainerGroup → Updating
  { from: ContainerGroupState.Running, trigger: { kind: 'Api', operation: 'UpdateContainerGroup' }, to: ContainerGroupState.Updating, rule: 'T8' },
  // T9: Running + DeleteContainerGroup → Terminating
  { from: ContainerGroupState.Running, trigger: { kind: 'Api', operation: 'DeleteContainerGroup' }, to: ContainerGroupState.Terminating, rule: 'T9' },
  // T10: Running + InstanceExpired → Expired
  { from: ContainerGroupState.Running, trigger: { kind: 'System', event: 'InstanceExpired' }, to: ContainerGroupState.Expired, rule: 'T10' },
  // T11: Restarting + RestartSucceeded → Pending
  { from: ContainerGroupState.Restarting, trigger: { kind: 'System', event: 'RestartSucceeded' }, to: ContainerGroupState.Pending, rule: 'T11' },
  // T12: Restarting + RestartFailed → Failed
  { from: ContainerGroupState.Restarting, trigger: { kind: 'System', event: 'RestartFailed' }, to: ContainerGroupState.Failed, rule: 'T12' },
  // T13: Updating + UpdateSucceeded → Running
  { from: ContainerGroupState.Updating, trigger: { kind: 'System', event: 'UpdateSucceeded' }, to: ContainerGroupState.Running, rule: 'T13' },
  // T14: Updating + UpdateFailed → Running (rollback)
  { from: ContainerGroupState.Updating, trigger: { kind: 'System', event: 'UpdateFailed' }, to: ContainerGroupState.Running, rule: 'T14' },
  // T15: Terminating + CleanupComplete → Deleted
  { from: ContainerGroupState.Terminating, trigger: { kind: 'System', event: 'CleanupComplete' }, to: ContainerGroupState.Deleted, rule: 'T15' },
  // T16: Restarting + DeleteContainerGroup → Terminating
  { from: ContainerGroupState.Restarting, trigger: { kind: 'Api', operation: 'DeleteContainerGroup' }, to: ContainerGroupState.Terminating, rule: 'T16' },
  // T17: Updating + DeleteContainerGroup → Terminating
  { from: ContainerGroupState.Updating, trigger: { kind: 'Api', operation: 'DeleteContainerGroup' }, to: ContainerGroupState.Terminating, rule: 'T17' },
  // T18: Pending + DeleteContainerGroup → Terminating
  { from: ContainerGroupState.Pending, trigger: { kind: 'Api', operation: 'DeleteContainerGroup' }, to: ContainerGroupState.Terminating, rule: 'T18' },
];

/** Podman-specific transitions (not in ECI model). */
export const PODMAN_TRANSITIONS: readonly {
  readonly from: ContainerGroupState;
  readonly trigger: TransitionTrigger;
  readonly to: ContainerGroupState;
  readonly rule: string;
}[] = [
  // P1: Running + StopContainerGroup → Stopped (reversible, unlike ECI)
  { from: ContainerGroupState.Running, trigger: { kind: 'Api', operation: 'StopContainerGroup' }, to: ContainerGroupState.Stopped, rule: 'P1' },
  // P2: Stopped + StartContainerGroup → Running
  { from: ContainerGroupState.Stopped, trigger: { kind: 'Api', operation: 'StartContainerGroup' }, to: ContainerGroupState.Running, rule: 'P2' },
  // P3: Running + PauseContainerGroup → Paused
  { from: ContainerGroupState.Running, trigger: { kind: 'Api', operation: 'PauseContainerGroup' }, to: ContainerGroupState.Paused, rule: 'P3' },
  // P4: Paused + UnpauseContainerGroup → Running
  { from: ContainerGroupState.Paused, trigger: { kind: 'Api', operation: 'UnpauseContainerGroup' }, to: ContainerGroupState.Running, rule: 'P4' },
  // P5: Stopped + DeleteContainerGroup → Terminating
  { from: ContainerGroupState.Stopped, trigger: { kind: 'Api', operation: 'DeleteContainerGroup' }, to: ContainerGroupState.Terminating, rule: 'P5' },
  // P6: Paused + StopContainerGroup → Stopped
  { from: ContainerGroupState.Paused, trigger: { kind: 'Api', operation: 'StopContainerGroup' }, to: ContainerGroupState.Stopped, rule: 'P6' },
  // P7: Paused + DeleteContainerGroup → Terminating
  { from: ContainerGroupState.Paused, trigger: { kind: 'Api', operation: 'DeleteContainerGroup' }, to: ContainerGroupState.Terminating, rule: 'P7' },
];

/** All known transitions (ECI + Podman). */
export const ALL_TRANSITIONS: readonly {
  readonly from: ContainerGroupState;
  readonly trigger: TransitionTrigger;
  readonly to: ContainerGroupState;
  readonly rule: string;
}[] = [...ECI_TRANSITIONS, ...PODMAN_TRANSITIONS];

// ─── 5. Transition function ───

/** δ: State × Trigger → State
 *  Returns the target state if the transition is known, otherwise returns the
 *  input state unchanged (terminal absorption + invalid transition handling). */
export function transition(
  state: ContainerGroupState,
  trigger: TransitionTrigger,
): ContainerGroupState {
  // RestartPolicy trigger: evaluate exit code against policy (§8)
  if (trigger.kind === 'RestartPolicy') {
    return evaluateRestartPolicy(state, trigger.exitCode, trigger.policy);
  }

  // Check all known transitions
  for (const t of ALL_TRANSITIONS) {
    if (t.from === state && triggerEquals(t.trigger, trigger)) {
      return t.to;
    }
  }

  // No matching transition — state is unchanged (invalid transition / terminal)
  return state;
}

/** Evaluate RestartPolicy-based transition from Running state (§8).
 *  - Always: exit(0) → Restarting, exit(!0) → Restarting
 *  - OnFailure: exit(0) → Succeeded, exit(!0) → Restarting
 *  - Never: exit(0) → Succeeded, exit(!0) → Failed */
export function evaluateRestartPolicy(
  state: ContainerGroupState,
  exitCode: number,
  policy: RestartPolicy,
): ContainerGroupState {
  if (state !== ContainerGroupState.Running) return state;

  if (policy === 'Always') {
    return ContainerGroupState.Restarting;
  }
  if (policy === 'OnFailure') {
    return exitCode === 0 ? ContainerGroupState.Succeeded : ContainerGroupState.Restarting;
  }
  // Never
  return exitCode === 0 ? ContainerGroupState.Succeeded : ContainerGroupState.Failed;
}

function triggerEquals(a: TransitionTrigger, b: TransitionTrigger): boolean {
  if (a.kind !== b.kind) return false;
  if (a.kind === 'System') return a.event === (b as typeof a).event;
  if (a.kind === 'Api') return a.operation === (b as typeof a).operation;
  // RestartPolicy
  return a.exitCode === (b as typeof a).exitCode && a.policy === (b as typeof a).policy;
}

// ─── 6. Terminal states (§3.2) ───

export const TERMINAL_STATES: ReadonlySet<ContainerGroupState> = new Set([
  ContainerGroupState.ScheduleFailed,
  ContainerGroupState.Succeeded,
  ContainerGroupState.Failed,
  ContainerGroupState.Expired,
  ContainerGroupState.Deleted,
]);

export function isTerminal(state: ContainerGroupState): boolean {
  return TERMINAL_STATES.has(state);
}

// ─── 7. API operation preconditions (§4) ───

/** Legal pre-states for each API operation. Derived from §4 of the formal model. */
export const API_PRECONDITIONS: Readonly<Record<ApiOperation, ReadonlySet<ContainerGroupState>>> = {
  CreateContainerGroup: new Set([]), // no pre-state — creates new resource
  DeleteContainerGroup: new Set([
    ContainerGroupState.Running,
    ContainerGroupState.Pending,
    ContainerGroupState.Restarting,
    ContainerGroupState.Updating,
    ContainerGroupState.Stopped,
    ContainerGroupState.Paused,
  ]),
  RestartContainerGroup: new Set([ContainerGroupState.Running]),
  UpdateContainerGroup: new Set([ContainerGroupState.Running]),
  StopContainerGroup: new Set([
    ContainerGroupState.Running,
    ContainerGroupState.Paused,
  ]),
  StartContainerGroup: new Set([ContainerGroupState.Stopped]),
  PauseContainerGroup: new Set([ContainerGroupState.Running]),
  UnpauseContainerGroup: new Set([ContainerGroupState.Paused]),
};

export function canApplyOperation(state: ContainerGroupState, op: ApiOperation): boolean {
  if (op === 'CreateContainerGroup') return true; // creates new, no pre-state
  const allowed = API_PRECONDITIONS[op];
  return allowed?.has(state) ?? false;
}

/** Check if a Delete can be applied — non-terminal, non-Terminating (§4 + P4). */
export function isDeleteAllowed(state: ContainerGroupState): boolean {
  return canApplyOperation(state, 'DeleteContainerGroup');
}

// ─── 8. Safety invariants (§5.1) — runtime-checkable assertions ───

/** P1: Terminal states cannot transition to any other state. */
export function checkNoResurrection(before: ContainerGroupState, after: ContainerGroupState): boolean {
  if (isTerminal(before)) {
    return before === after;
  }
  return true;
}

/** P2: Restarting can only be reached from Running. */
export function checkRestartLegality(_before: ContainerGroupState, after: ContainerGroupState): boolean {
  if (after === ContainerGroupState.Restarting) {
    return _before === ContainerGroupState.Running;
  }
  return true;
}

/** P3: Updating can only be reached from Running. */
export function checkUpdateLegality(_before: ContainerGroupState, after: ContainerGroupState): boolean {
  if (after === ContainerGroupState.Updating) {
    return _before === ContainerGroupState.Running;
  }
  return true;
}

/** P4: Terminating can only be reached from {Running, Pending, Restarting, Updating, Stopped, Paused}. */
export function checkDeleteLegality(before: ContainerGroupState): boolean {
  return isDeleteAllowed(before);
}

/** P5: Container Running implies CG Running.
 *  Returns true if the invariant holds. */
export function checkContainerCGRunning(
  cgState: ContainerGroupState,
  containerStates: readonly ContainerStateValue[],
): boolean {
  const anyContainerRunning = containerStates.some(cs => cs === ContainerStateValue.Running);
  if (anyContainerRunning) {
    return cgState === ContainerGroupState.Running;
  }
  return true; // no Running containers → no constraint
}

// ─── 9. Liveness properties (§5.2) — not runtime-checkable, but documented ───

/** Transient states that MUST eventually resolve. Used by health-check for timeout-based GC. */
export const TRANSIENT_STATES: ReadonlySet<ContainerGroupState> = new Set([
  ContainerGroupState.Scheduling,
  ContainerGroupState.Pending,
  ContainerGroupState.Restarting,
  ContainerGroupState.Updating,
  ContainerGroupState.Terminating,
]);

/** Check if a state is transient (the system guarantees eventual resolution). */
export function isTransient(state: ContainerGroupState): boolean {
  return TRANSIENT_STATES.has(state);
}

// ─── 10. Provider lifecycle profile ───

/** Each provider declares its capabilities as a restriction of the full model.
 *  Replaces the old ad-hoc ContainerLifecycle (4 booleans). */
export interface ContainerLifecycleProfile {
  /** States this provider can reach. Must be a subset of ContainerGroupState. */
  readonly reachableStates: ReadonlySet<ContainerGroupState>;
  /** Is stop() terminal (same as delete)? ECI: true, Podman: false. */
  readonly stopIsDelete: boolean;
  /** Can a stopped container be started again? */
  readonly startable: boolean;
  /** Can the provider report per-container health probe results? */
  readonly healthProbes: boolean;
  /** Does create() return before the instance reaches Running? */
  readonly asyncInit: boolean;
  /** Does the provider support RestartContainerGroup? */
  readonly supportsRestart: boolean;
  /** Does the provider support UpdateContainerGroup? */
  readonly supportsUpdate: boolean;
  /** Does the provider support ExecContainerCommand? */
  readonly supportsExec: boolean;
}

/** ECI ContainerGroup profile — matches the formal model exactly. */
export const ECI_PROFILE: ContainerLifecycleProfile = {
  reachableStates: new Set([
    ContainerGroupState.Scheduling,
    ContainerGroupState.ScheduleFailed,
    ContainerGroupState.Pending,
    ContainerGroupState.Running,
    ContainerGroupState.Updating,
    ContainerGroupState.Restarting,
    ContainerGroupState.Terminating,
    ContainerGroupState.Succeeded,
    ContainerGroupState.Failed,
    ContainerGroupState.Expired,
    ContainerGroupState.Deleted,
  ]),
  stopIsDelete: true,
  startable: false,
  healthProbes: false,
  asyncInit: true,
  supportsRestart: true,
  supportsUpdate: true,
  supportsExec: true,
};

/** Podman profile — subset of states, supports Stopped/Paused. */
export const PODMAN_PROFILE: ContainerLifecycleProfile = {
  reachableStates: new Set([
    ContainerGroupState.Pending,
    ContainerGroupState.Running,
    ContainerGroupState.Stopped,
    ContainerGroupState.Paused,
    ContainerGroupState.Terminating,
    ContainerGroupState.Deleted,
  ]),
  stopIsDelete: false,
  startable: true,
  healthProbes: true,
  asyncInit: false,
  supportsRestart: false,
  supportsUpdate: false,
  supportsExec: true,
};

/** Stub profile — minimal, sync init. */
export const STUB_PROFILE: ContainerLifecycleProfile = {
  reachableStates: new Set([
    ContainerGroupState.Running,
    ContainerGroupState.Stopped,
    ContainerGroupState.Terminating,
    ContainerGroupState.Deleted,
  ]),
  stopIsDelete: false,
  startable: true,
  healthProbes: false,
  asyncInit: false,
  supportsRestart: false,
  supportsUpdate: false,
  supportsExec: false,
};

/** Map provider platform name to its lifecycle profile. */
export function profileForPlatform(platform: string): ContainerLifecycleProfile {
  switch (platform) {
    case 'alibaba': return ECI_PROFILE;
    case 'podman': return PODMAN_PROFILE;
    case 'stub': return STUB_PROFILE;
    default: return STUB_PROFILE;
  }
}

// ─── 11. Bridge to SandboxStatus (§6, business layer mapping) ───

import { SandboxStatus } from '../../features/sandbox/types.ts';

/** Map a concrete ContainerGroupState to the business-layer SandboxStatus.
 *  This is a pure function — the mapping is verified against the formal model.
 *
 *  Mapping rationale:
 *  - Scheduling/Pending → Scheduling (business layer sees both as "not yet Running")
 *  - Running/Updating → Running (spec update is transparent to business layer)
 *  - Restarting → Scheduling (restart → re-init cycle, business layer sees as transient)
 *  - Stopped/Paused → Stopped (business layer: not running, recoverable)
 *  - Terminating → Terminated (business layer: shutdown in progress = terminal for user)
 *  - Succeeded/Failed/Expired/ScheduleFailed → Failed (all terminal errors collapse)
 *  - Deleted → Deleted
 */
/** Map provider-level ECI state to business-level SandboxStatus (11-state model). */
export function toSandboxStatus(state: ContainerGroupState): SandboxStatus {
  switch (state) {
    case ContainerGroupState.Scheduling:
    case ContainerGroupState.Pending:
    case ContainerGroupState.Restarting:
      return SandboxStatus.Scheduling;

    case ContainerGroupState.Running:
    case ContainerGroupState.Updating:
      return SandboxStatus.Running;

    case ContainerGroupState.Stopped:
    case ContainerGroupState.Paused:
      return SandboxStatus.Succeeded;

    case ContainerGroupState.Terminating:
      return SandboxStatus.Terminating;

    case ContainerGroupState.ScheduleFailed:
      return SandboxStatus.ScheduleFailed;

    case ContainerGroupState.Failed:
      return SandboxStatus.Failed;

    case ContainerGroupState.Succeeded:
      return SandboxStatus.Succeeded;

    case ContainerGroupState.Expired:
      return SandboxStatus.Expired;

    case ContainerGroupState.Deleted:
      return SandboxStatus.Deleted;
  }
}

/** Reverse mapping: which ContainerGroupStates map to a given SandboxStatus. */
export function fromSandboxStatus(status: SandboxStatus): readonly ContainerGroupState[] {
  switch (status) {
    case SandboxStatus.Scheduling:
      return [ContainerGroupState.Scheduling, ContainerGroupState.Pending, ContainerGroupState.Restarting];
    case SandboxStatus.Pending:
      return [ContainerGroupState.Scheduling, ContainerGroupState.Pending];
    case SandboxStatus.Running:
      return [ContainerGroupState.Running, ContainerGroupState.Updating];
    case SandboxStatus.Succeeded:
      return [ContainerGroupState.Stopped, ContainerGroupState.Paused, ContainerGroupState.Succeeded];
    case SandboxStatus.Failed:
      return [ContainerGroupState.Failed];
    case SandboxStatus.Restarting:
      return [ContainerGroupState.Restarting];
    case SandboxStatus.Updating:
      return [ContainerGroupState.Updating];
    case SandboxStatus.Terminating:
      return [ContainerGroupState.Terminating];
    case SandboxStatus.ScheduleFailed:
      return [ContainerGroupState.ScheduleFailed];
    case SandboxStatus.Expired:
      return [ContainerGroupState.Expired];
    case SandboxStatus.Deleted:
      return [ContainerGroupState.Deleted];
    default:
      return [];
  }
}

/** Re-export the old ContainerLifecycle for backward compat during migration.
 *  Derived from ContainerLifecycleProfile. */
export interface ContainerLifecycle {
  readonly stopIsDelete: boolean;
  readonly startable: boolean;
  readonly healthProbes: boolean;
  readonly asyncInit: boolean;
}

export function toLegacyLifecycle(profile: ContainerLifecycleProfile): ContainerLifecycle {
  return {
    stopIsDelete: profile.stopIsDelete,
    startable: profile.startable,
    healthProbes: profile.healthProbes,
    asyncInit: profile.asyncInit,
  };
}

// ─── 12. Formal verification helpers ───

/** Verify that a transition sequence respects all 5 safety invariants.
 *  Returns the first violated invariant name, or null if all pass. */
export function verifyTransitionSequence(
  steps: readonly { from: ContainerGroupState; to: ContainerGroupState }[],
): string | null {
  for (const step of steps) {
    if (!checkNoResurrection(step.from, step.to)) return 'P1: NoResurrection';
    if (!checkRestartLegality(step.from, step.to)) return 'P2: RestartLegality';
    if (!checkUpdateLegality(step.from, step.to)) return 'P3: UpdateLegality';
  }
  return null;
}

/** Check that a ContainerLifecycleProfile is internally consistent:
 *  - If stopIsDelete, Stopped must NOT be in reachableStates.
 *  - If !startable, Stopped must NOT be in reachableStates (or startable must be true).
 *  - If asyncInit, Scheduling must be in reachableStates. */
export function validateProfile(profile: ContainerLifecycleProfile): string | null {
  if (profile.stopIsDelete && profile.reachableStates.has(ContainerGroupState.Stopped)) {
    return 'stopIsDelete=true but Stopped is reachable — Stopped implies recoverable state';
  }
  if (profile.startable && !profile.reachableStates.has(ContainerGroupState.Stopped)) {
    return 'startable=true but Stopped is not reachable';
  }
  if (profile.asyncInit && !profile.reachableStates.has(ContainerGroupState.Scheduling)) {
    return 'asyncInit=true but Scheduling is not reachable';
  }
  if (profile.supportsRestart && !profile.reachableStates.has(ContainerGroupState.Restarting)) {
    return 'supportsRestart=true but Restarting is not reachable';
  }
  if (profile.supportsUpdate && !profile.reachableStates.has(ContainerGroupState.Updating)) {
    return 'supportsUpdate=true but Updating is not reachable';
  }
  return null;
}

/**
 * Provider extension field schema system.
 *
 * Each provider declares which extension parameters it supports.
 * Extension fields are provider-specific knobs that go beyond the
 * common CreateContainerGroupInput (e.g. Alibaba EIP, BGP Pro, spot).
 *
 * Two endpoints consume these schemas:
 *   GET  /api/extension-fields?instanceId=xxx  — schema for a specific instance
 *   POST /api/sandboxes                       — validated via providerOverrides
 */

// ─── Field type ───

export type ExtensionFieldType = 'string' | 'number' | 'boolean' | 'object' | 'string[]' | 'number[]';

export interface ExtensionFieldValidation {
  readonly enum?: readonly string[];
  readonly min?: number;
  readonly max?: number;
  readonly pattern?: string;
}

/** Description of a single extension parameter. */
export interface ExtensionFieldDef {
  readonly key: string;
  readonly type: ExtensionFieldType;
  readonly label: string;
  readonly description: string;
  readonly required?: boolean;
  readonly default?: unknown;
  /** Alibaba ECI API parameter name (for auto-mapping). */
  readonly eciParam?: string;
  /** Value transformation hint. */
  readonly transform?: 'boolean-string' | 'number-string' | 'json-string' | 'comma-sep';
  readonly validation?: ExtensionFieldValidation;
  /** Which level the parameter applies to. */
  readonly scope: 'sandbox' | 'container' | 'volume' | 'network';
  /** Optional category grouping for UI. */
  readonly category?: string;
}

/** Named schema for a single provider. */
export interface ProviderExtensionSchema {
  readonly provider: string;
  readonly label: string;
  readonly fields: readonly ExtensionFieldDef[];
}

// ─── Schema Registry ───

const schemas = new Map<string, ProviderExtensionSchema>();

export function registerExtensionSchema(schema: ProviderExtensionSchema): void {
  schemas.set(schema.provider, schema);
}

export function getExtensionSchema(provider: string): ProviderExtensionSchema | undefined {
  return schemas.get(provider);
}

export function getAllExtensionSchemas(): readonly ProviderExtensionSchema[] {
  return [...schemas.values()];
}

/** Map providerOverrides → ECI API params using schema eciParam hints. */
export function applyExtensionOverrides(
  provider: string,
  overrides: Record<string, unknown> | undefined,
): Record<string, string> {
  const out: Record<string, string> = {};
  if (!overrides) return out;

  const schema = schemas.get(provider);
  if (!schema) return out;

  for (const field of schema.fields) {
    const val = overrides[field.key];
    if (val === undefined || val === null) continue;
    // 'None' is the canonical sentinel for "not set" in our domain model.
    if (val === 'None') continue;
    if (!field.eciParam) continue;

    switch (field.transform) {
      case 'boolean-string':
        out[field.eciParam] = val ? 'true' : 'false';
        break;
      case 'number-string':
        out[field.eciParam] = String(val);
        break;
      case 'json-string':
        out[field.eciParam] = JSON.stringify(val);
        break;
      case 'comma-sep':
        out[field.eciParam] = Array.isArray(val) ? val.join(',') : String(val);
        break;
      default:
        out[field.eciParam] = String(val);
    }
  }

  return out;
}

/** Validate providerOverrides against the declared schema. */
export function validateExtensionOverrides(
  provider: string,
  overrides: Record<string, unknown> | undefined,
): { valid: boolean; errors: string[] } {
  const errors: string[] = [];
  if (!overrides) return { valid: true, errors };

  const schema = schemas.get(provider);
  if (!schema) return { valid: true, errors };

  for (const field of schema.fields) {
    const val = overrides[field.key];
    if (val === undefined || val === null) {
      if (field.required) errors.push(`${field.key} is required`);
      continue;
    }

    // Type check
    switch (field.type) {
      case 'number':
        if (typeof val !== 'number') errors.push(`${field.key} must be a number`);
        break;
      case 'boolean':
        if (typeof val !== 'boolean') errors.push(`${field.key} must be a boolean`);
        break;
      case 'string':
        if (typeof val !== 'string') errors.push(`${field.key} must be a string`);
        break;
      case 'string[]':
        if (!Array.isArray(val) || val.some(v => typeof v !== 'string')) errors.push(`${field.key} must be a string array`);
        break;
      case 'number[]':
        if (!Array.isArray(val) || val.some(v => typeof v !== 'number')) errors.push(`${field.key} must be a number array`);
        break;
    }

    // Enum check
    if (field.validation?.enum && typeof val === 'string') {
      if (!field.validation.enum.includes(val)) {
        errors.push(`${field.key} must be one of: ${field.validation.enum.join(', ')}`);
      }
    }

    // Range check
    if (field.validation) {
      if (field.validation.min !== undefined && typeof val === 'number' && val < field.validation.min) {
        errors.push(`${field.key} must be >= ${String(field.validation.min)}`);
      }
      if (field.validation.max !== undefined && typeof val === 'number' && val > field.validation.max) {
        errors.push(`${field.key} must be <= ${String(field.validation.max)}`);
      }
    }
  }
  return { valid: errors.length === 0, errors };
}

