/**
 * Provider factory — creates IProviderRegistry backed by ComputeInstance entities.
 *
 * Instead of creating singleton providers at startup, this factory:
 * 1. Returns a LazyProviderRegistry that instantiates providers on first access.
 * 2. Default provider (matching config.container) is eagerly resolved on first get.
 * 3. All other providers (dns, metrics, networkPolicy, group, S3, instance resolver)
 *    are instantiated lazily, reducing cold-start cost and memory in serverless.
 */

import type { ProviderConfig, S3Config, Credential } from '../../config/types.ts';
import type {
  IContainerProvider,
  IContainerGroupProvider,
  IDnsProvider,
  IImageProvider,
  IMetricsProvider,
  INetworkPolicyProvider,
  IProviderRegistry, ProviderCapabilities,
  ProviderEntry,
} from './interfaces.ts';
import type { IS3Provider } from './s3.ts';
import { createS3Providers, type S3ProviderEntry } from './s3-factory.ts';
import { secureContainerProvider, secureContainerGroupProvider } from './security.ts';
import type { IAtomicStore } from '../store/interfaces.ts';
import type { InstanceId } from '../region/instance.ts';
import type { InstanceProviderResolver } from './instance-resolver.ts';
import type { SecretEncryption } from '../auth/secret-encryption.ts';
import { StubContainerProvider } from '../../providers/stub/container.ts';
import { StubImageProvider } from '../../providers/stub/image.ts';
import { StubDnsProvider } from '../../providers/stub/dns.ts';
import { StubMetricsProvider } from '../../providers/stub/metrics.ts';
import { PodmanContainerProvider } from '../../providers/podman/podman-provider.ts';
import { PodmanImageProvider } from '../../providers/podman/podman-image.ts';
import { PodmanNetworkPolicyProvider } from '../../providers/podman/podman-network.ts';
import { PodmanContainerGroupProvider } from '../../providers/podman/podman-group-provider.ts';
import { AlibabaEciContainerProvider } from '../../providers/alibaba/eci-container.ts';
import { AlibabaEciImageProvider } from '../../providers/alibaba/eci-image.ts';
import { AlibabaEciMetricsProvider } from '../../providers/alibaba/eci-metrics.ts';
import { AlibabaEciContainerGroupProvider } from '../../providers/alibaba/eci-group-provider.ts';
import { AlibabaEciApiClient } from '../../providers/alibaba/eci-api.ts';
import { AlibabaCrApiClient } from '../../providers/alibaba/cr-api.ts';
import { AlibabaOssOpenApiClient } from '../../providers/alibaba/oss-openapi.ts';
import { CloudflareDnsProvider } from '../../providers/cloudflare/dns.ts';

// ─── Lazy provider registry ───
// Providers are instantiated on first access rather than at startup,
// reducing cold-start cost and memory in serverless environments.
// Imports are static (worker bundler includes them anyway), but the
// `new XxxProvider()` calls are deferred until first use.

class LazyProviderRegistry implements IProviderRegistry {
  private _defaultImage?: IImageProvider;
  private _networkPolicy: INetworkPolicyProvider | undefined;
  private _dns?: IDnsProvider;
  private _metrics?: IMetricsProvider;
  private _groupContainer: IContainerGroupProvider | undefined;
  private _rawEciApi: any;
  private _crApi: any;
  private _ossOpenApi: any;
  private _typeEntries?: Map<string, ProviderEntry>;
  private _s3Entries?: S3ProviderEntry[];
  private _instanceResolver?: InstanceProviderResolver;
  private _resolverPromise: Promise<void> | null = null;

  public constructor(
    private readonly config: ProviderConfig,
    private readonly s3Config: S3Config | undefined,
    private readonly atomicStore: IAtomicStore | undefined,
    private readonly secretEncryption?: SecretEncryption,
  ) {}

  /** Emit a one-time warning when the global default provider is accessed.
   *  In production, all provider operations should route through resolveContainer(instanceId). */
  #warnedDefault = false;
  #warnDefault(): void {
    if (!this.#warnedDefault) {
      this.#warnedDefault = true;
      console.warn(`[provider] Using global default container="${this.config.container}" as fallback. Per-instance resolution (resolveContainer) is preferred for production.`);
    }
  }

  /** Number of Alibaba accounts with valid credentials. */
  private get _hasAlibabaAccounts(): boolean {
    return this.config.accounts.some(a => !!(a.accessKeyId && a.accessKeySecret));
  }

  /** @deprecated Global default is disabled — use resolveContainer(instanceId) instead. */
  public get container(): IContainerProvider {
    throw new Error(
      'Global default provider is disabled. Use resolveContainer(instanceId) to route to a specific instance, ' +
      'or resolveContainer(undefined) to auto-pick the first online container-capable instance.'
    );
  }

  public get image(): IImageProvider {
    if (!this._defaultImage) {
      this.#warnDefault();
      this._defaultImage = this._resolveDefaultEntry().image;
    }
    return this._defaultImage;
  }

  public get networkPolicy(): INetworkPolicyProvider | undefined {
    if (this._networkPolicy === undefined) {
      const ep = process.env.PODMAN_ENDPOINT ?? 'http://127.0.0.1:8080';
      this._networkPolicy = this._isAlibaba ? undefined : new PodmanNetworkPolicyProvider(ep);
    }
    return this._networkPolicy;
  }

  public get dns(): IDnsProvider {
    if (!this._dns) {
      this._dns = this.config.dns === 'cloudflare' && this.config.cfApiToken
        ? new CloudflareDnsProvider(this.config.cfApiToken)
        : new StubDnsProvider();
    }
    return this._dns;
  }

  public get metrics(): IMetricsProvider {
    if (!this._metrics) {
      const defaultCreds = this.config.accounts.find(
        (a): a is Credential & { accessKeyId: string; accessKeySecret: string } => !!(a.accessKeyId && a.accessKeySecret),
      );
      this._metrics = this.config.metrics === 'alibaba' && defaultCreds
        ? new AlibabaEciMetricsProvider(defaultCreds.accessKeyId, defaultCreds.accessKeySecret)
        : new StubMetricsProvider();
    }
    return this._metrics;
  }

  public get groupContainer(): IContainerGroupProvider | undefined {
    if (!this._groupContainer) {
      this._groupContainer = this._createGroupProvider();
    }
    return this._groupContainer;
  }

  public get rawEciApi(): any {
    if (!this._rawEciApi) {
      const cred = this._firstAlibabaCred();
      if (cred) this._rawEciApi = new AlibabaEciApiClient(cred.accessKeyId, cred.accessKeySecret);
    }
    return this._rawEciApi;
  }

  public get crApi(): any {
    if (!this._crApi) {
      const cred = this._firstAlibabaCred();
      if (cred) this._crApi = new AlibabaCrApiClient(cred.accessKeyId, cred.accessKeySecret);
    }
    return this._crApi;
  }

  public get ossOpenApi(): any {
    if (!this._ossOpenApi) {
      const cred = this._firstAlibabaCred();
      if (cred) this._ossOpenApi = new AlibabaOssOpenApiClient(cred.accessKeyId, cred.accessKeySecret);
    }
    return this._ossOpenApi;
  }

  public get capabilities(): ProviderCapabilities {
    const isProd = this.config.container === 'alibaba' && this._hasAlibabaAccounts;
    return {
      spotInstances: isProd, nfsVolumes: true, publicIpAutoAssign: true,
      preemptible: isProd, maxRuntimeSeconds: isProd ? 86_400 * 7 : 0,
    };
  }

  // ─── Type-based provider lookup (lazy) ───

  private _getTypeEntries(): Map<string, ProviderEntry> {
    if (!this._typeEntries) {
      this._typeEntries = this._buildTypeEntries();
    }
    return this._typeEntries;
  }

  public provider(name: string): ProviderEntry | undefined {
    return this._getTypeEntries().get(name);
  }

  public availableProviders(): readonly ProviderEntry[] {
    return [...this._getTypeEntries().values()];
  }

  // ─── S3 (lazy) ───

  private _getS3Entries(): S3ProviderEntry[] {
    if (!this._s3Entries && this.s3Config) {
      this._s3Entries = createS3Providers(this.s3Config).entries;
    }
    return this._s3Entries ?? [];
  }

  public s3Account(name?: string): IS3Provider | undefined {
    const entries = this._getS3Entries();
    const n = name ?? this.s3Config?.defaultAccount ?? '';
    return entries.find(e => e.name === n)?.provider;
  }

  public listS3Accounts(): string[] {
    return this._getS3Entries().map(e => e.name);
  }

  // ─── Instance-based resolution (lazy) ───

  private async _ensureResolver(): Promise<void> {
    if (this._instanceResolver || !this.atomicStore) return;
    if (!this._resolverPromise) {
      this._resolverPromise = this._initResolver();
    }
    await this._resolverPromise;
  }

  private async _initResolver(): Promise<void> {
    if (!this.atomicStore) return;
    const { InstanceService } = await import('../region/instance.ts');
    const { CredentialService } = await import('../auth/credential.ts');
    const { InstanceProviderResolver } = await import('./instance-resolver.ts');
    const instanceService = new InstanceService(this.atomicStore);
    const credService = new CredentialService(this.atomicStore, this.secretEncryption);
    this._instanceResolver = new InstanceProviderResolver(instanceService, credService);
  }

  public async resolveContainer(instanceId?: InstanceId): Promise<IContainerProvider> {
    await this._ensureResolver();
    if (this._instanceResolver) {
      return this._instanceResolver.resolveContainer(instanceId);
    }
    throw new Error('InstanceProviderResolver not available — atomicStore is required for provider resolution');
  }

  public async resolveImage(instanceId?: InstanceId): Promise<IImageProvider> {
    await this._ensureResolver();
    if (this._instanceResolver) {
      return this._instanceResolver.resolveImage(instanceId);
    }
    throw new Error('InstanceProviderResolver not available — atomicStore is required for provider resolution');
  }

  public async resolveGroup(instanceId?: InstanceId): Promise<IContainerGroupProvider | undefined> {
    await this._ensureResolver();
    if (!this._instanceResolver) {
      throw new Error('InstanceProviderResolver not available — atomicStore is required for provider resolution');
    }
    return this._instanceResolver.resolveGroup(instanceId);
  }

  public async resolveRawEciApi(instanceId?: InstanceId): Promise<any> {
    await this._ensureResolver();
    if (this._instanceResolver && instanceId) {
      return this._instanceResolver.resolveRawEciApi(instanceId);
    }
    return this.rawEciApi;
  }

  public async resolveCrApi(instanceId?: InstanceId): Promise<any> {
    await this._ensureResolver();
    if (this._instanceResolver && instanceId) {
      return this._instanceResolver.resolveCrApi(instanceId);
    }
    return this.crApi;
  }

  public async resolveOssOpenApi(instanceId?: InstanceId): Promise<any> {
    await this._ensureResolver();
    if (this._instanceResolver && instanceId) {
      return this._instanceResolver.resolveOssOpenApi(instanceId);
    }
    return this.ossOpenApi;
  }

  // ─── Internal helpers ───

  private get _isAlibaba(): boolean {
    return this.config.container === 'alibaba' && this._hasAlibabaAccounts;
  }

  /** First valid Alibaba credential from config, or undefined if none configured. */
  private _firstAlibabaCred(): { accessKeyId: string; accessKeySecret: string } | undefined {
    const found = this.config.accounts.find(
      (a): a is Credential & { accessKeyId: string; accessKeySecret: string } => !!(a.accessKeyId && a.accessKeySecret),
    );
    return found ? { accessKeyId: found.accessKeyId, accessKeySecret: found.accessKeySecret } : undefined;
  }

  private _resolveDefaultEntry(): ProviderEntry {
    if (this._isAlibaba) {
      return this._buildAlibabaDefaultEntry();
    }
    if (this.config.container === 'podman') {
      return this._buildPodmanEntry();
    }
    return this._buildStubEntry();
  }

  private _buildStubEntry(): ProviderEntry {
    return {
      name: 'stub',
      container: secureContainerProvider(new StubContainerProvider()),
      image: new StubImageProvider(),
    };
  }

  private _buildPodmanEntry(): ProviderEntry {
    const ep = process.env.PODMAN_ENDPOINT ?? 'http://127.0.0.1:8080';
    return {
      name: 'podman',
      container: secureContainerProvider(new PodmanContainerProvider(ep)),
      image: new PodmanImageProvider(ep),
    };
  }

  private _buildAlibabaDefaultEntry(): ProviderEntry {
    const accounts = this._buildAlibabaAccounts();
    return {
      name: 'alibaba',
      container: accounts[0]!.container,
      image: accounts[0]!.image,
    };
  }

  private _buildAlibabaAccounts(): { name: string; container: IContainerProvider; image: IImageProvider }[] {
    return this.config.accounts
      .filter((a): a is Credential & { accessKeyId: string; accessKeySecret: string } => !!(a.accessKeyId && a.accessKeySecret))
      .map(a => ({
        name: a.name,
        container: secureContainerProvider(new AlibabaEciContainerProvider(a.accessKeyId, a.accessKeySecret, a.endpoint)),
        image: new AlibabaEciImageProvider(a.accessKeyId, a.accessKeySecret, a.endpoint,
          a.defaultRegion ?? this.config.region as string,
          a.extra?.registryCredentials as { server: string; userName: string; password: string }[] | undefined),
      }));
  }

  private _buildTypeEntries(): Map<string, ProviderEntry> {
    const entries = new Map<string, ProviderEntry>();
    entries.set('stub', this._buildStubEntry());
    entries.set('podman', this._buildPodmanEntry());
    const aliAccounts = this._buildAlibabaAccounts();
    if (aliAccounts.length > 0) {
      entries.set('alibaba', {
        name: 'alibaba' as const,
        container: aliAccounts[0]!.container,
        image: aliAccounts[0]!.image,
      });
    }
    return entries;
  }

  private _createGroupProvider(): IContainerGroupProvider | undefined {
    if (this._isAlibaba) {
      const defaultAccount = this.config.accounts.find(
        (a): a is Credential & { accessKeyId: string; accessKeySecret: string } => !!(a.accessKeyId && a.accessKeySecret),
      );
      if (defaultAccount) {
        return secureContainerGroupProvider(
          new AlibabaEciContainerGroupProvider(defaultAccount.accessKeyId, defaultAccount.accessKeySecret, defaultAccount.endpoint),
        );
      }
    }
    if (this.config.container === 'podman') {
      const ep = process.env.PODMAN_ENDPOINT ?? 'http://127.0.0.1:8080';
      return secureContainerGroupProvider(new PodmanContainerGroupProvider(ep));
    }
    return undefined;
  }
}

export function createProviderRegistry(
  config: ProviderConfig,
  s3Config?: S3Config,
  atomicStore?: IAtomicStore,
  secretEncryption?: SecretEncryption,
): IProviderRegistry {
  return new LazyProviderRegistry(config, s3Config, atomicStore, secretEncryption);
}

/**
 * InstanceProviderResolver — dynamically creates provider instances from
 * ComputeInstance entities. Replaces the old static provider singleton model.
 *
 * Flow:
 *   SandboxService.provision()
 *     → resolveContainer(clusterId)  // or instanceId
 *     → InstanceService.resolveByCluster() → picks online instance
 *     → #createContainerProvider(instance) → returns IContainerProvider
 *     → provider.create(input)
 */

import type { IContainerProvider, IContainerGroupProvider, IImageProvider, INetworkPolicyProvider } from './interfaces.ts';
import type { IS3Provider } from './s3.ts';
import type { ComputeInstance } from '../region/instance.ts';
import type { InstanceService, InstanceId } from '../region/instance.ts';
import type { CredentialService, RegistryCredential } from '../auth/credential.ts';
import { AppError } from '../types.ts';
import { CredentialResolutionError } from './errors.ts';
import { secureContainerProvider, secureContainerGroupProvider } from './security.ts';
import { PodmanContainerProvider } from '../../providers/podman/podman-provider.ts';
import { PodmanImageProvider } from '../../providers/podman/podman-image.ts';
import { PodmanContainerGroupProvider } from '../../providers/podman/podman-group-provider.ts';
import { PodmanNetworkPolicyProvider } from '../../providers/podman/podman-network.ts';
import { AlibabaEciContainerProvider } from '../../providers/alibaba/eci-container.ts';
import { AlibabaEciImageProvider } from '../../providers/alibaba/eci-image.ts';
import { AlibabaEciContainerGroupProvider } from '../../providers/alibaba/eci-group-provider.ts';
import { StubContainerProvider } from '../../providers/stub/container.ts';
import { StubImageProvider } from '../../providers/stub/image.ts';
import { AwsS3Provider } from '../../providers/s3/aws-s3.ts';
import { AlibabaOssProvider } from '../../providers/alibaba/oss.ts';
import { AlibabaEciApiClient } from '../../providers/alibaba/eci-api.ts';
import { AlibabaCrApiClient } from '../../providers/alibaba/cr-api.ts';
import { AlibabaOssOpenApiClient } from '../../providers/alibaba/oss-openapi.ts';

export class InstanceProviderResolver {
  public constructor(
    private readonly instanceService: InstanceService,
    private readonly credentialService: CredentialService,
  ) {}

  /** Resolve a container provider. If instanceId provided, uses that instance.
   *  Otherwise picks the first online instance with container capability. */
  public async resolveContainer(instanceId?: InstanceId): Promise<IContainerProvider> {
    if (instanceId) {
      const inst = await this.instanceService.get(instanceId);
      if (inst) return this.#createContainerProvider(inst);
      throw new AppError(404, 'INSTANCE_NOT_FOUND', `Container instance ${instanceId} not found`);
    }
    const all = await this.instanceService.resolveByCapability('container');
    if (all.length > 0) return this.#createContainerProvider(all[0]!);
    return secureContainerProvider(new StubContainerProvider());
  }

  /** Resolve an image provider. */
  public async resolveImage(instanceId?: InstanceId): Promise<IImageProvider> {
    if (instanceId) {
      const inst = await this.instanceService.get(instanceId);
      if (inst?.capabilities.image) return this.#createImageProvider(inst);
      throw new AppError(404, 'INSTANCE_NOT_FOUND', `Image instance ${instanceId} not found`);
    }
    const all = await this.instanceService.resolveByCapability('image');
    if (all.length > 0) return this.#createImageProvider(all[0]!);
    return new StubImageProvider();
  }

  /** Resolve a container group provider. */
  public async resolveGroup(instanceId?: InstanceId): Promise<IContainerGroupProvider | undefined> {
    if (instanceId) {
      const inst = await this.instanceService.get(instanceId);
      if (inst?.capabilities.group) return this.#createGroupProvider(inst);
      throw new AppError(404, 'INSTANCE_NOT_FOUND', `Group instance ${instanceId} not found or lacks group capability`);
    }
    const all = await this.instanceService.resolveByCapability('group');
    if (all.length > 0) return this.#createGroupProvider(all[0]!);
    return undefined;
  }

  /** Resolve a specific instance and create its container provider. */
  public async resolveContainerByInstance(instanceId: InstanceId): Promise<IContainerProvider | null> {
    const inst = await this.instanceService.get(instanceId);
    return inst ? this.#createContainerProvider(inst) : null;
  }

  /** Resolve a network policy provider for a specific instance. */
  public async resolveNetworkPolicy(instanceId: InstanceId): Promise<INetworkPolicyProvider | undefined> {
    const inst = await this.instanceService.get(instanceId);
    if (!inst?.capabilities.network) return undefined;
    return this.#createNetworkPolicyProvider(inst);
  }

  /** Resolve an S3 provider for a specific instance. */
  public async resolveS3(instanceId: InstanceId): Promise<IS3Provider | undefined> {
    const inst = await this.instanceService.get(instanceId);
    if (!inst?.capabilities.s3) return undefined;
    return this.#createS3Provider(inst);
  }

  // ─── Provider factory methods ───

  async #resolveCredential(credentialRef?: string, instanceId?: string): Promise<{
    type?: string | undefined;
    accessKeyId: string | undefined;
    accessKeySecret: string | undefined;
    token?: string | undefined;
    username?: string | undefined;
    password?: string | undefined;
    registryCredentials?: readonly RegistryCredential[] | undefined;
  }> {
    // 1. Try credential manager (preferred — per-instance, encrypted)
    if (credentialRef) {
      // credentialRef may be a credential ID (cred_xxx) or a name (eci_profile@...)
      const cred = await this.credentialService.get(credentialRef as any)
        ?? await this.credentialService.findByName(credentialRef, instanceId);
      if (cred?.accessKeyId && cred?.accessKeySecret) {
        return {
          type: cred.type,
          accessKeyId: cred.accessKeyId,
          accessKeySecret: cred.accessKeySecret,
          token: cred.token,
          username: cred.username,
          password: cred.password,
          registryCredentials: cred.registryCredentials,
        };
      }
      // credentialRef was explicitly configured but cannot be resolved — fail loudly
      throw new CredentialResolutionError(
        `Credential "${credentialRef}" not found or missing access keys for instance ${instanceId ?? 'unknown'}. Check that the credential exists and has ALIBABA_ACCESS_KEY_ID / ALIBABA_ACCESS_KEY_SECRET set.`,
        credentialRef,
        instanceId,
      );
    }
    // 2. Fallback to environment variables (backward compatible)
    const envAk = process.env.ALIBABA_ACCESS_KEY_ID;
    const envSk = process.env.ALIBABA_ACCESS_KEY_SECRET;
    if (envAk && envSk) {
      return { accessKeyId: envAk, accessKeySecret: envSk };
    }
    return { accessKeyId: undefined, accessKeySecret: undefined };
  }

  async #createContainerProvider(instance: ComputeInstance): Promise<IContainerProvider> {
    switch (instance.platform) {
      case 'podman':
        return secureContainerProvider(new PodmanContainerProvider(instance.endpoint));
      case 'alibaba': {
        const cred = await this.#resolveCredential(instance.credentialRef, instance.id);
        return secureContainerProvider(new AlibabaEciContainerProvider(
          cred.accessKeyId ?? '', cred.accessKeySecret ?? '', instance.endpoint,
        ));
      }
      case 'stub':
        return secureContainerProvider(new StubContainerProvider());
      default:
        return secureContainerProvider(new StubContainerProvider());
    }
  }

  async #createImageProvider(instance: ComputeInstance): Promise<IImageProvider> {
    switch (instance.platform) {
      case 'podman':
        return new PodmanImageProvider(instance.endpoint);
      case 'alibaba': {
        const cred = await this.#resolveCredential(instance.credentialRef, instance.id);
        return new AlibabaEciImageProvider(
          cred.accessKeyId ?? '', cred.accessKeySecret ?? '', instance.endpoint,
          instance.region,
          cred.registryCredentials as { server: string; userName: string; password: string }[] | undefined,
        );
      }
      case 'stub':
        return new StubImageProvider();
      default:
        return new StubImageProvider();
    }
  }

  async #createGroupProvider(instance: ComputeInstance): Promise<IContainerGroupProvider | undefined> {
    switch (instance.platform) {
      case 'podman':
        return secureContainerGroupProvider(new PodmanContainerGroupProvider(instance.endpoint));
      case 'alibaba': {
        const cred = await this.#resolveCredential(instance.credentialRef, instance.id);
        return secureContainerGroupProvider(new AlibabaEciContainerGroupProvider(
          cred.accessKeyId ?? '', cred.accessKeySecret ?? '', instance.endpoint,
        ));
      }
      default:
        return undefined;
    }
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  async #createNetworkPolicyProvider(instance: ComputeInstance): Promise<INetworkPolicyProvider | undefined> {
    switch (instance.platform) {
      case 'podman':
        return new PodmanNetworkPolicyProvider(instance.endpoint);
      case 'alibaba':
        // Alibaba SecurityGroup-based network policy — not yet implemented
        return undefined;
      default:
        return undefined;
    }
  }

  async #createS3Provider(instance: ComputeInstance): Promise<IS3Provider | undefined> {
    const cred = await this.#resolveCredential(instance.credentialRef, instance.id);
    switch (instance.platform) {
      case 'podman':
        // Podman has no native S3 — MinIO-compatible endpoint via AwsS3Provider
        return cred.accessKeyId && cred.accessKeySecret
          ? new AwsS3Provider({ accessKeyId: cred.accessKeyId, secretAccessKey: cred.accessKeySecret }, 'auto', instance.endpoint)
          : undefined;
      case 'alibaba':
        return cred.accessKeyId && cred.accessKeySecret
          ? new AlibabaOssProvider(cred.accessKeyId, cred.accessKeySecret, instance.endpoint)
          : undefined;
      case 'stub':
        return undefined;
      default:
        return undefined;
    }
  }

  /** Resolve a raw ECI API client for a specific instance. */
  public async resolveRawEciApi(instanceId: InstanceId): Promise<any> {
    const inst = await this.instanceService.get(instanceId);
    if (inst?.platform !== 'alibaba') return undefined;
    const cred = await this.#resolveCredential(inst.credentialRef);
    if (!cred.accessKeyId || !cred.accessKeySecret) return undefined;
    return new AlibabaEciApiClient(cred.accessKeyId, cred.accessKeySecret, inst.endpoint);
  }

  /** Resolve a CR (Container Registry) API client for a specific instance. */
  public async resolveCrApi(instanceId: InstanceId): Promise<any> {
    const inst = await this.instanceService.get(instanceId);
    if (inst?.platform !== 'alibaba') return undefined;
    const cred = await this.#resolveCredential(inst.credentialRef);
    if (!cred.accessKeyId || !cred.accessKeySecret) return undefined;
    return new AlibabaCrApiClient(cred.accessKeyId, cred.accessKeySecret);
  }

  /** Resolve an OSS management-plane API client for a specific instance. */
  public async resolveOssOpenApi(instanceId: InstanceId): Promise<any> {
    const inst = await this.instanceService.get(instanceId);
    if (inst?.platform !== 'alibaba') return undefined;
    const cred = await this.#resolveCredential(inst.credentialRef);
    if (!cred.accessKeyId || !cred.accessKeySecret) return undefined;
    return new AlibabaOssOpenApiClient(cred.accessKeyId, cred.accessKeySecret);
  }
}

// ─── Provider abstraction layer ───
// Every cloud operation goes through these interfaces.
// Concrete implementations (Alibaba, AWS, GCP, Azure) live under src/providers/.
//
// Design invariants:
// - All input/output types are provider-agnostic — no Alibaba/AWS types leak through.
// - Each provider method maps 1:1 to a remote API call from script0.
// - Provider-specific config lives in an opaque `providerConfig` bag per sandbox,
//   so the business layer never branches on provider identity.

import type {
  ContainerGroupRuntime,
  ContainerGroupStatus,
  CreateContainerGroupInput,
  MetricSnapshot,
  NodeCapacity,
  NodeCondition,
} from './types.ts';
import type { RegionId } from '../region/types.ts';
import type { InstanceId } from '../region/instance.ts';
import type { IS3Provider } from './s3.ts';

// ─── Container operations ───

export interface DescribeContainerGroupsInput {
  readonly region: RegionId;
  readonly sandboxName?: string;
  readonly sandboxId?: string;
  readonly status?: ContainerGroupStatus;
  readonly limit?: number;
  readonly nextToken?: string;
}

export interface DescribeContainerGroupsResult {
  readonly sandboxes: readonly ContainerGroupRuntime[];
  readonly nextToken?: string;
  readonly totalCount?: number;
}

export interface DeleteContainerGroupInput {
  readonly region: RegionId;
  readonly providerId: string;
}

export interface GetContainerLogInput {
  readonly region: RegionId;
  readonly providerId: string;
  readonly containerName: string;
  readonly limitBytes?: number;
  readonly sinceSeconds?: number;
  readonly timestamps?: boolean;
}

export interface ContainerLogResult {
  readonly containerName: string;
  readonly content: string;
  readonly timestamp?: string;
}

/** Provider lifecycle model — declared by each provider at construction.
 *  Callers MUST query this before making lifecycle decisions (stop/start/GC). */
export interface ContainerLifecycle {
  /** stop() is terminal (same as delete). ECI: true, Podman: false. */
  readonly stopIsDelete: boolean;
  /** Can a stopped sandbox be restarted? ECI: false, Podman: true. */
  readonly startable: boolean;
  /** Can the provider report per-container health probe results? ECI: false, Podman: true. */
  readonly healthProbes: boolean;
  /** Does create() return before the sandbox is actually Running? ECI: true, Podman/Stub: false. */
  readonly asyncInit: boolean;
}

export interface IContainerProvider {
  /** Provider lifecycle semantics — callers query this before stop/start/GC. */
  readonly lifecycle: ContainerLifecycle;

  /**
   * Create a container (or container group, depending on provider).
   *
   * Accepts CreateContainerGroupInput because all providers need the same
   * data shape (containers, resources, network). Lifecycle semantics differ:
   * - Podman: creates a single Docker container (only the first container in
   *   the input array is used; extra containers are ignored).
   * - ECI: creates a ContainerGroup — all containers in the array are included.
   *
   * Returns the provider-assigned ID.
   */
  create(input: CreateContainerGroupInput): Promise<{ providerId: string }>;

  /** Query sandboxes by filters. */
  describe(input: DescribeContainerGroupsInput): Promise<DescribeContainerGroupsResult>;

  /** Update an existing container group (spec changes). */
  update?(providerId: string, input: Partial<CreateContainerGroupInput>): Promise<void>;

  /** Get a single sandbox's runtime status by provider ID. */
  getStatus?(providerId: string): Promise<ContainerGroupRuntime | null>;

  /** Delete a sandbox by provider ID. */
  delete(input: DeleteContainerGroupInput): Promise<void>;

  /** Fetch container stdout/stderr logs. */
  getLogs(input: GetContainerLogInput): Promise<ContainerLogResult>;

  /** Gracefully stop a container with optional timeout. */
  stop?(providerId: string, timeoutSeconds?: number): Promise<void>;

  /** Start a stopped container. */
  start?(providerId: string): Promise<void>;

  /** Restart a container with optional timeout. */
  restart?(providerId: string, timeoutSeconds?: number): Promise<void>;

  /** Force-kill a container with optional signal. */
  kill?(providerId: string, signal?: string): Promise<void>;

  /** Pause a running container (freeze cgroups). */
  pause?(providerId: string): Promise<void>;

  /** Unpause a paused container. */
  unpause?(providerId: string): Promise<void>;

  /** Wait for a container to reach a specific state. */
  wait?(providerId: string, condition?: 'not-running' | 'next-exit'): Promise<{ statusCode: number }>;

  /** Execute a command inside a running container. */
  exec?(providerId: string, cmd: readonly string[], containerName?: string): Promise<{ execId: string; webSocketUri?: string | undefined }>;

  /** Rename a container. */
  rename?(providerId: string, newName: string): Promise<void>;

  /** Get live resource usage stats. */
  stats?(providerId: string): Promise<{ cpuUsage: number; memoryUsage: number; networkIO?: { rx: number; tx: number } | undefined }>;

  /** List running processes inside a container. */
  top?(providerId: string, psArgs?: string): Promise<{ processes: readonly (readonly string[])[] }>;
}

// ─── Virtual Node operations ───

export interface VirtualNodeInfo {
  readonly name: string;
  readonly provider: string;
  readonly capacity: NodeCapacity;
  readonly conditions: readonly NodeCondition[];
  readonly ready: boolean;
  readonly lastHeartbeatTime?: string;
}

export interface IVirtualNode {
  /** Register or refresh the virtual node in the cluster. */
  register(info: VirtualNodeInfo): Promise<void>;

  /** Deregister the virtual node. */
  deregister(): Promise<void>;

  /** Check node health. Returns false if the node should be marked NotReady. */
  ping(): Promise<boolean>;

  /** Report current node status (capacity, conditions). */
  status(): Promise<VirtualNodeInfo>;
}

// ─── DNS operations ───

export interface UpdateDnsRecordInput {
  readonly domain: string;
  readonly type: 'A' | 'CNAME';
  readonly value: string;
  readonly ttl: number;
  readonly proxied: boolean;
  /** Provider-specific record identifier (e.g. Cloudflare record ID). */
  readonly providerRecordId: string;
  /** Provider-specific zone identifier. */
  readonly zoneId: string;
}

export interface DeleteDnsRecordInput {
  readonly zoneId: string;
  readonly providerRecordId: string;
}

export interface IDnsProvider {
  /** Create or update a DNS record. */
  updateRecord(input: UpdateDnsRecordInput): Promise<void>;

  /** Delete a DNS record. */
  deleteRecord(input: DeleteDnsRecordInput): Promise<void>;
}

// ─── Image operations ───

export interface ImageInfo {
  readonly id: string;
  readonly tags: readonly string[];
  readonly created?: number | undefined;
  readonly size?: number | undefined;
  readonly architecture?: string | undefined;
  readonly os?: string | undefined;
  readonly layers?: number | undefined;
}

/** Optional pagination / filter params for list(). */
export interface ListImagesOptions {
  readonly limit?: number;
  readonly offset?: number;
  readonly search?: string;
}

export interface IImageProvider {
  /** Pull an image from a registry. Returns image info.
   *  If clusterId is provided, the provider may route to a cluster-specific endpoint. */
  pull(image: string, clusterId?: string): Promise<ImageInfo>;

  /** List locally available images. */
  list(options?: ListImagesOptions): Promise<readonly ImageInfo[]>;

  /** Inspect a single image by ID or tag. */
  inspect(id: string): Promise<ImageInfo | null>;

  /** Remove an image. */
  remove(id: string): Promise<void>;

  /** Push an image to a registry. Optional — provider may not support it. */
  push?(imageOrId: string, credential?: { server: string; userName: string; password: string }): Promise<ImageInfo>;

  /** Search for images on a registry. */
  search?(term: string, options?: { limit?: number | undefined }): Promise<readonly { name: string; description?: string | undefined; isOfficial?: boolean | undefined }[]>;

  /** Tag an image with a new name. */
  tag?(id: string, tag: string): Promise<void>;

  /** Get image layer history. */
  history?(id: string): Promise<readonly { id: string; created?: number | undefined; createdBy?: string | undefined; size?: number | undefined }[]>;

  /** Prune unused images. */
  prune?(options?: { dangling?: boolean | undefined }): Promise<{ reclaimed: number }>;

  /** Build an image from a Dockerfile-like context. */
  build?(context: unknown, options?: { dockerfile?: string | undefined; tag?: string | undefined }): Promise<ImageInfo>;
}

// ─── Metrics operations ───

export interface FetchMetricsInput {
  readonly region: RegionId;
  readonly providerId: string;
  readonly periodSeconds?: number;
  readonly startTime?: number;
  readonly endTime?: number;
}

export interface FetchMetricsResult {
  readonly snapshots: readonly MetricSnapshot[];
}

export interface IMetricsProvider {
  /** Fetch monitoring metrics for a sandbox. */
  fetchMetrics(input: FetchMetricsInput): Promise<FetchMetricsResult>;
}

// ─── Network policy (multi-tenant isolation) ───

export interface NetworkRule {
  readonly direction: 'ingress' | 'egress';
  readonly protocol?: 'tcp' | 'udp' | undefined;
  readonly port?: number | undefined;
  readonly cidr?: string | undefined;
  readonly action: 'allow' | 'deny';
  /** Per-rule bandwidth limit (Mbps). 0 = block, undefined = no limit. */
  readonly rateLimit?: number | undefined;
}

export interface INetworkPolicyProvider {
  /** Ensure an isolated network exists for a tenant. Returns network name/ID. */
  ensureNetwork(tenantId: string): Promise<string>;
  /** Remove a network when no longer needed. */
  removeNetwork(networkId: string): Promise<void>;
  /** Optionally apply ingress/egress rules to a network. */
  applyRules?(networkId: string, rules: readonly NetworkRule[]): Promise<void>;
}

// ─── Provider capability declaration ───

/** Each provider declares which optional capabilities it supports. */
export interface ProviderCapabilities {
  readonly spotInstances: boolean;
  readonly nfsVolumes: boolean;
  readonly publicIpAutoAssign: boolean;
  readonly preemptible: boolean;
  /** Max seconds a sandbox can run before being forcibly terminated (0 = unlimited). */
  readonly maxRuntimeSeconds: number;
}

export interface ProviderEntry {
  readonly name: string;
  readonly container: IContainerProvider;
  readonly image: IImageProvider;
}

export interface IProviderRegistry {
  /** Default container provider (resolved from first available online instance). */
  readonly container: IContainerProvider;
  readonly dns: IDnsProvider;
  readonly metrics: IMetricsProvider;
  /** Default image provider. */
  readonly image: IImageProvider;
  readonly virtualNode?: IVirtualNode | undefined;
  readonly networkPolicy?: INetworkPolicyProvider | undefined;
  readonly groupContainer?: IContainerGroupProvider | undefined;
  readonly capabilities: ProviderCapabilities;

  /** Get a provider by type name ('stub' | 'podman' | 'alibaba'). */
  provider(name: string): ProviderEntry | undefined;

  /** List available provider types. Deprecated: use /api/topology/instances. */
  availableProviders(): readonly ProviderEntry[];

  /** S3: get a named S3 provider account. */
  s3Account(name?: string): IS3Provider | undefined;

  /** S3: list all S3 account names. */
  listS3Accounts(): string[];

  /** Get raw ECI OpenAPI client for the default Alibaba account. */
  rawEciApi(): any;

  /** Get CR (Container Registry) OpenAPI client. */
  crApi(): any;

  /** Get OSS management-plane OpenAPI client (bucket CRUD, policy, etc.). */
  ossOpenApi(): any;

  // ─── ComputeInstance-aware resolution ───

  /** Resolve a container provider for a specific instance.
   *  Falls back to default container provider. */
  resolveContainer(instanceId?: InstanceId): Promise<IContainerProvider>;

  /** Resolve an image provider for a specific instance. */
  resolveImage(instanceId?: InstanceId): Promise<IImageProvider>;

  /** Resolve a container group provider for a specific instance. */
  resolveGroup(instanceId?: InstanceId): Promise<IContainerGroupProvider | undefined>;

  /** Resolve a raw ECI API client for a specific instance. */
  resolveRawEciApi(instanceId?: InstanceId): Promise<any>;

  /** Resolve a CR (Container Registry) API client for a specific instance. */
  resolveCrApi(instanceId?: InstanceId): Promise<any>;

  /** Resolve an OSS management-plane API client for a specific instance. */
  resolveOssOpenApi(instanceId?: InstanceId): Promise<any>;
}

// ─── Container group / Pod operations ───
// Separate from IContainerProvider because the lifecycle is different:
// - Podman: creates a libpod pod (pod create → share net/uts/ipc → start).
//   All containers in the spec are included in the pod.
// - ECI: creates a ContainerGroup. All containers share the same ENI.
//
// Accepts the same CreateContainerGroupInput type as IContainerProvider
// because the data shape is identical. The semantic difference is in how
// the provider groups the containers (pod vs. container group vs. individual).

import type { PodSpec } from '../pod/types.ts';

export interface IContainerGroupProvider {
  /**
   * Create a pod from the K8s-aligned PodSpec (v3, preferred).
   * Provider selects the appropriate codec internally.
   */
  createPod(spec: PodSpec): Promise<{ providerId: string }>;

  /**
   * Stop a container group.
   * - ECI: 停止即释放（terminal），等同于删除，资源不可恢复
   * - Podman: 停止进程但保留 pod 元数据，可重新 start
   */
  stopGroup(providerId: string): Promise<void>;

  /** Start a stopped container group. */
  startGroup?(providerId: string): Promise<void>;

  /** Delete a container group by provider ID (terminal). */
  deleteGroup(providerId: string): Promise<void>;

  /** Get detailed status of a container group. */
  getGroupStatus(providerId: string): Promise<ContainerGroupRuntime | null>;

  /** List container groups with optional filters. */
  describeGroups(input: DescribeContainerGroupsInput): Promise<DescribeContainerGroupsResult>;
}

/**
 * S3 客户端基类 — 抽取三套 Provider 的共享逻辑
 *
 * AwsS3Provider / CloudflareR2S3Provider / AlibabaOssProvider 都重复实现
 * 了 encodeKey、parseListResult、parseObjectInfo、toArrayBuffer。
 * 子类只需实现 #authFetch() 方法处理各自的认证签名差异。
 */
import type {
  IS3Provider, S3PutObjectInput, S3GetObjectResult, S3ObjectInfo, S3ListObjectsResult, S3ProviderType,
} from './s3.ts';
import type { S3ProviderConfig } from './s3-types.ts';
import { payloadHash } from './s3-signer.ts';

export abstract class S3ClientBase implements IS3Provider {
  public abstract readonly type: S3ProviderType;
  protected readonly config: S3ProviderConfig;

  public constructor(config?: S3ProviderConfig) {
    this.config = config ?? {};
  }

  /** Subclass implements its own auth scheme (SigV4, OSS HMAC, etc.) */
  protected abstract authFetch(url: string, method: string, path: string, queryString: string, headers: Record<string, string>, bodyHash: string, body?: BodyInit): Promise<Response>;

  /** Bucket name mapping override */
  protected bucketMapping(bucket: string): string {
    return this.config.bucketNameMapping?.[bucket] ?? bucket;
  }

  public async putObject(input: S3PutObjectInput): Promise<{ etag: string }> {
    const bodyBuf = await toArrayBuffer(input.body);
    const bodyHash = input.contentType === 'application/octet-stream' ? '' : await payloadHash(bodyBuf);
    const bucket = this.bucketMapping(input.bucket);
    const path = `/${bucket}/${encodeKey(input.key)}`;
    const url = `${this.endpointFor(bucket)}${path}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    if (input.contentType) amzHeaders['content-type'] = input.contentType;
    if (input.cacheControl) amzHeaders['cache-control'] = input.cacheControl;
    const res = await this.authFetch(url, 'PUT', path, '', amzHeaders, bodyHash, bodyBuf);
    return { etag: (res.headers.get('etag') ?? '').replace(/"/g, '') };
  }

  public async getObject(bucket: string, key: string): Promise<S3GetObjectResult | null> {
    return this.fetchObject('GET', bucket, key);
  }

  public async deleteObject(bucket: string, key: string): Promise<void> {
    const path = `/${this.bucketMapping(bucket)}/${encodeKey(key)}`;
    const url = `${this.endpointFor(bucket)}${path}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    const res = await this.authFetch(url, 'DELETE', path, '', amzHeaders, '');
    if (res.status !== 204 && res.status !== 404) {
      throw new Error(`S3 deleteObject failed: ${String(res.status)} ${await res.text()}`);
    }
  }

  public async headObject(bucket: string, key: string): Promise<S3ObjectInfo | null> {
    try {
      const path = `/${this.bucketMapping(bucket)}/${encodeKey(key)}`;
      const url = `${this.endpointFor(bucket)}${path}`;
      const amzHeaders: Record<string, string> = { host: new URL(url).host };
      const res = await this.authFetch(url, 'HEAD', path, '', amzHeaders, '');
      if (res.status === 404) return null;
      return parseObjectInfo(key, res);
    } catch { return null; }
  }

  public async listObjects(
    bucket: string,
    options?: { prefix?: string; delimiter?: string; maxKeys?: number; continuationToken?: string },
  ): Promise<S3ListObjectsResult> {
    const qs = new URLSearchParams({ 'list-type': '2' });
    if (options?.prefix) qs.set('prefix', options.prefix);
    if (options?.delimiter) qs.set('delimiter', options.delimiter);
    if (options?.maxKeys) qs.set('max-keys', String(options.maxKeys));
    if (options?.continuationToken) qs.set('continuation-token', options.continuationToken);
    const queryString = qs.toString();
    const path = `/${this.bucketMapping(bucket)}`;
    const url = `${this.endpointFor(bucket)}${path}?${queryString}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    const res = await this.authFetch(url, 'GET', path, queryString, amzHeaders, '');
    return parseListResult(await res.text());
  }

  // ─── Multi-part upload ───

  public async createMultipartUpload(input: { bucket: string; key: string; contentType?: string }): Promise<{ uploadId: string; key: string; bucket: string }> {
    const path = `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}?uploads`;
    const url = `${this.endpointFor(input.bucket)}${path}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    if (input.contentType) amzHeaders['content-type'] = input.contentType;
    const res = await this.authFetch(url, 'POST', `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}`, 'uploads', amzHeaders, '');
    const xml = await res.text();
    const uploadId = (/<UploadId>(.*?)<\/UploadId>/.exec(xml))?.[1] ?? '';
    return { uploadId, key: input.key, bucket: input.bucket };
  }

  public async uploadPart(input: { bucket: string; key: string; uploadId: string; partNumber: number }, body: Uint8Array): Promise<{ etag: string; partNumber: number }> {
    const path = `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}?partNumber=${String(input.partNumber)}&uploadId=${encodeURIComponent(input.uploadId)}`;
    const url = `${this.endpointFor(input.bucket)}${path}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    const bodyBuf = body.buffer.slice(body.byteOffset, body.byteOffset + body.byteLength) as ArrayBuffer;
    const bodyHash = await payloadHash(bodyBuf);
    const res = await this.authFetch(url, 'PUT', `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}`, `partNumber=${String(input.partNumber)}&uploadId=${encodeURIComponent(input.uploadId)}`, amzHeaders, bodyHash, bodyBuf);
    return { etag: (res.headers.get('etag') ?? '').replace(/"/g, ''), partNumber: input.partNumber };
  }

  public async completeMultipartUpload(input: { bucket: string; key: string; uploadId: string; parts: readonly { partNumber: number; etag: string }[] }): Promise<{ location?: string }> {
    const path = `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}?uploadId=${encodeURIComponent(input.uploadId)}`;
    const url = `${this.endpointFor(input.bucket)}${path}`;
    const body = buildCompleteXml(input.parts);
    const amzHeaders: Record<string, string> = { host: new URL(url).host, 'content-type': 'application/xml' };
    const res = await this.authFetch(url, 'POST', `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}`, `uploadId=${encodeURIComponent(input.uploadId)}`, amzHeaders, '', body);
    const xml = await res.text();
    const location = (/<Location>(.*?)<\/Location>/.exec(xml))?.[1];
    return { ...(location ? { location } : {}) };
  }

  public async abortMultipartUpload(input: { bucket: string; key: string; uploadId: string }): Promise<void> {
    const path = `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}?uploadId=${encodeURIComponent(input.uploadId)}`;
    const url = `${this.endpointFor(input.bucket)}${path}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    await this.authFetch(url, 'DELETE', `/${this.bucketMapping(input.bucket)}/${encodeKey(input.key)}`, `uploadId=${encodeURIComponent(input.uploadId)}`, amzHeaders, '');
  }

  public async listParts(bucket: string, key: string, uploadId: string): Promise<{ parts: readonly { partNumber: number; size: number; etag: string }[]; uploadId: string; isTruncated: boolean; nextPartNumberMarker?: number }> {
    const path = `/${this.bucketMapping(bucket)}/${encodeKey(key)}?uploadId=${encodeURIComponent(uploadId)}`;
    const url = `${this.endpointFor(bucket)}${path}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    const res = await this.authFetch(url, 'GET', `/${this.bucketMapping(bucket)}/${encodeKey(key)}`, `uploadId=${encodeURIComponent(uploadId)}`, amzHeaders, '');
    const xml = await res.text();
    const parts: { partNumber: number; size: number; etag: string }[] = [];
    for (const m of xml.matchAll(/<Part>(.*?)<\/Part>/gs)) {
      const pn = parseInt((/<PartNumber>(.*?)<\/PartNumber>/.exec((m[1]!)))?.[1] ?? '0', 10);
      const sz = parseInt((/<Size>(.*?)<\/Size>/.exec((m[1]!)))?.[1] ?? '0', 10);
      const et = ((/<ETag>(.*?)<\/ETag>/.exec((m[1]!)))?.[1] ?? '').replace(/"/g, '');
      parts.push({ partNumber: pn, size: sz, etag: et });
    }
    const truncated = xml.includes('<IsTruncated>true</IsTruncated>');
    const nextMarker = (/<NextPartNumberMarker>(.*?)<\/NextPartNumberMarker>/.exec(xml))?.[1];
    return { parts, uploadId, isTruncated: truncated, ...(nextMarker ? { nextPartNumberMarker: parseInt(nextMarker, 10) } : {}) };
  }

  /** Get the base endpoint URL for a given bucket. Override for provider-specific logic. */
  protected endpointFor(_bucket: string): string { return ''; }

  protected async fetchObject(method: string, bucket: string, key: string): Promise<S3GetObjectResult | null> {
    const path = `/${this.bucketMapping(bucket)}/${encodeKey(key)}`;
    const url = `${this.endpointFor(bucket)}${path}`;
    const amzHeaders: Record<string, string> = { host: new URL(url).host };
    const res = await this.authFetch(url, method, path, '', amzHeaders, '');
    if (res.status === 404) return null;
    return {
      body: res.body!,
      ...(res.headers.get('content-type') ? { contentType: res.headers.get('content-type')! } : {}),
      ...(res.headers.get('content-length') ? { contentLength: Number(res.headers.get('content-length')) } : {}),
      ...(res.headers.get('etag') ? { etag: (res.headers.get('etag') ?? '').replace(/"/g, '') } : {}),
      ...(res.headers.get('last-modified') ? { lastModified: new Date(res.headers.get('last-modified')!) } : {}),
    };
  }
}

// ─── 共享工具函数 ───

export function encodeKey(key: string): string {
  return key.split('/').map(encodeURIComponent).join('/');
}

export async function toArrayBuffer(body: ReadableStream | ArrayBuffer | Uint8Array): Promise<ArrayBuffer> {
  if (body instanceof ReadableStream) return new Response(body).arrayBuffer();
  if (body instanceof ArrayBuffer) return body;
  return body.buffer.slice(body.byteOffset, body.byteOffset + body.byteLength) as ArrayBuffer;
}

export function parseObjectInfo(key: string, res: Response): S3ObjectInfo {
  return {
    key,
    size: Number(res.headers.get('content-length') ?? 0),
    etag: (res.headers.get('etag') ?? '').replace(/"/g, ''),
    lastModified: res.headers.get('last-modified') ? new Date(res.headers.get('last-modified')!) : new Date(0),
    ...(res.headers.get('content-type') ? { contentType: res.headers.get('content-type')! } : {}),
  };
}

export function parseListResult(xml: string): S3ListObjectsResult {
  const objects: S3ObjectInfo[] = [];
  const commonPrefixes: string[] = [];
  let isTruncated: boolean;
  let nextToken: string | undefined;

  const contents = xml.matchAll(/<Contents>(.*?)<\/Contents>/gs);
  for (const match of contents) {
    const key = (/<Key>(.*?)<\/Key>/.exec((match[1]!)))?.[1] ?? '';
    const size = parseInt((/<Size>(.*?)<\/Size>/.exec((match[1]!)))?.[1] ?? '0', 10);
    const etag = ((/<ETag>(.*?)<\/ETag>/.exec((match[1]!)))?.[1] ?? '').replace(/"/g, '');
    const lastMod = (/<LastModified>(.*?)<\/LastModified>/.exec((match[1]!)))?.[1];
    const ct = (/<ContentType>(.*?)<\/ContentType>/.exec((match[1]!)))?.[1];
    objects.push({
      key: decodeURIComponent(key), size, etag,
      lastModified: lastMod ? new Date(lastMod) : new Date(0),
      ...(ct ? { contentType: ct } : {}),
    });
  }

  const prefixes = xml.matchAll(/<CommonPrefixes>(.*?)<\/CommonPrefixes>/gs);
  for (const match of prefixes) {
    const prefix = (/<Prefix>(.*?)<\/Prefix>/.exec((match[1]!)))?.[1] ?? '';
    commonPrefixes.push(prefix);
  }

  isTruncated = xml.includes('<IsTruncated>true</IsTruncated>');
  const tokenMatch = /<NextContinuationToken>(.*?)<\/NextContinuationToken>/.exec(xml);
  if (tokenMatch) nextToken = tokenMatch[1];

  return { objects, commonPrefixes, isTruncated, ...(nextToken ? { nextContinuationToken: nextToken } : {}) };
}

function buildCompleteXml(parts: readonly { partNumber: number; etag: string }[]): string {
  const sorted = [...parts].sort((a, b) => a.partNumber - b.partNumber);
  const partTags = sorted.map(p => `  <Part><PartNumber>${String(p.partNumber)}</PartNumber><ETag>"${p.etag}"</ETag></Part>`).join('\n');
  return `<?xml version="1.0" encoding="UTF-8"?>\n<CompleteMultipartUpload>\n${partTags}\n</CompleteMultipartUpload>`;
}

// ─── S3 provider factory ───
// Creates an IS3Provider instance from type + credentials + config.
// Auth differences are handled per-implementation:
//   aws-s3 / cloudflare-r2 / minio → SigV4 (AWS4-HMAC-SHA256)
//   alibaba-oss → OSS HMAC-SHA1

import type { IS3Provider } from './s3.ts';
import type { S3ProviderType, S3ProviderConfig } from './s3-types.ts';
import type { S3Config } from '../../config/types.ts';
import { AwsS3Provider } from '../../providers/s3/aws-s3.ts';
import { CloudflareR2S3Provider } from '../../providers/cloudflare/r2-s3.ts';
import { AlibabaOssProvider } from '../../providers/alibaba/oss.ts';
import type { SigV4Credentials } from './s3-signer.ts';

export interface S3Credentials {
  readonly sigV4?: SigV4Credentials;
  readonly oss?: { readonly accessKeyId: string; readonly accessKeySecret: string };
  readonly r2AccountId?: string;
}

export function createS3Provider(
  type: S3ProviderType,
  region: string,
  credentials: S3Credentials,
  endpoint?: string,
  config?: S3ProviderConfig,
): IS3Provider {
  switch (type) {
    case 'aws-s3': {
      if (!credentials.sigV4) throw new Error('AWS S3 requires SigV4 credentials');
      return new AwsS3Provider(credentials.sigV4, region, endpoint, config);
    }
    case 'minio': {
      if (!credentials.sigV4) throw new Error('MinIO requires SigV4 credentials');
      return new AwsS3Provider(credentials.sigV4, region, endpoint ?? 'http://localhost:9000', config);
    }
    case 'alibaba-oss': {
      if (!credentials.oss) throw new Error('Alibaba OSS requires OSS credentials');
      return new AlibabaOssProvider(credentials.oss.accessKeyId, credentials.oss.accessKeySecret, region, endpoint, config);
    }
    case 'cloudflare-r2': {
      if (!credentials.sigV4 || !credentials.r2AccountId) throw new Error('Cloudflare R2 requires SigV4 credentials + accountId');
      return new CloudflareR2S3Provider(credentials.sigV4, credentials.r2AccountId, config);
    }
  }
}

// ─── Multi-account S3 registry ───

export interface S3ProviderEntry {
  readonly name: string;
  readonly provider: IS3Provider;
  readonly bucket?: string | undefined;
}

/**
 * Create S3 providers from S3Config, supporting multi-account.
 * Each account becomes a named S3ProviderEntry in the registry.
 */
export function createS3Providers(config: S3Config): { entries: S3ProviderEntry[]; defaultName: string } {
  const type = config.backend === 'none' ? 'minio' : config.backend;
  const entries: S3ProviderEntry[] = [];

  for (const acct of config.accounts) {
    const ak = acct.accessKeyId ?? '';
    const sk = acct.accessKeySecret ?? '';
    if (!ak || !sk) continue;
    const creds: S3Credentials = type === 'alibaba-oss'
      ? { oss: { accessKeyId: ak, accessKeySecret: sk } }
      : type === 'cloudflare-r2'
        ? { sigV4: { accessKeyId: ak, secretAccessKey: sk }, r2AccountId: (acct.extra?.r2AccountId as string) ?? config.region }
        : { sigV4: { accessKeyId: ak, secretAccessKey: sk } };
    const ep = acct.endpoint ?? config.endpoint;
    entries.push({
      name: acct.name,
      provider: createS3Provider(type, acct.defaultRegion ?? config.region, creds, ep),
      bucket: acct.bucket,
    });
  }

  return {
    entries,
    defaultName: config.defaultAccount,
  };
}

// ─── AWS SigV4 signing for S3-compatible APIs ───
// Uses Web Crypto API — works in Cloudflare Workers, Node 18+, Deno, Bun.
// Used by both AWS S3 and Cloudflare R2 providers.
//
// Reference: https://docs.aws.amazon.com/AmazonS3/latest/API/sig-v4-header-based-auth.html

export interface SigV4Credentials {
  readonly accessKeyId: string;
  readonly secretAccessKey: string;
  readonly sessionToken?: string;
}

/** Hex-encoded SHA-256 digest. */
async function sha256Hex(data: string): Promise<string> {
  const enc = new TextEncoder();
  const hash = await crypto.subtle.digest('SHA-256', enc.encode(data));
  return bytesToHex(new Uint8Array(hash));
}

/** HMAC-SHA256 keyed hash, returns raw bytes. */
async function hmacRaw(key: BufferSource, data: string): Promise<ArrayBuffer> {
  const cryptoKey = await crypto.subtle.importKey(
    'raw', key, { name: 'HMAC', hash: 'SHA-256' },
    false, ['sign'],
  );
  return crypto.subtle.sign('HMAC', cryptoKey, new TextEncoder().encode(data));
}

/** HMAC-SHA256 → hex string. */
async function hmacHex(key: ArrayBuffer, data: string): Promise<string> {
  return bytesToHex(new Uint8Array(await hmacRaw(key, data)));
}

/** Derive the SigV4 signing key chain. */
async function deriveKey(
  secret: string, dateStamp: string, region: string, service: string,
): Promise<ArrayBuffer> {
  const enc = new TextEncoder();
  const kDate = await hmacRaw(enc.encode(`AWS4${secret}`), dateStamp);
  const kRegion = await hmacRaw(kDate, region);
  const kService = await hmacRaw(kRegion, service);
  return hmacRaw(kService, 'aws4_request');
}

function bytesToHex(bytes: Uint8Array): string {
  return Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
}

/**
 * Sign headers for an S3-compatible request using AWS SigV4.
 * Returns the `Authorization` header plus `x-amz-date` and optionally `x-amz-security-token`.
 */
export async function signSigV4(
  method: string,
  canonicalUri: string,
  canonicalQueryString: string,
  headers: Record<string, string>,
  payloadHash: string,
  credentials: SigV4Credentials,
  region: string,
  service: string,
  now: Date,
): Promise<Record<string, string>> {
  const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '');
  const dateStamp = amzDate.slice(0, 8);

  const signedHeaders: Record<string, string> = {
    'x-amz-date': amzDate,
    ...headers,
  };
  if (credentials.sessionToken) {
    signedHeaders['x-amz-security-token'] = credentials.sessionToken;
  }

  // Canonical headers: lowercase keys, sorted, trimmed values
  const canonicalHeaders = Object.keys(signedHeaders)
    .sort()
    .map(k => `${k.toLowerCase()}:${signedHeaders[k]!.trim()}\n`)
    .join('');

  const signedHeaderList = Object.keys(signedHeaders)
    .sort()
    .map(k => k.toLowerCase())
    .join(';');

  // Canonical request
  const canonicalRequest = [
    method,
    canonicalUri,
    canonicalQueryString,
    canonicalHeaders,
    signedHeaderList,
    payloadHash,
  ].join('\n');

  // String to sign
  const algorithm = 'AWS4-HMAC-SHA256';
  const credentialScope = `${dateStamp}/${region}/${service}/aws4_request`;
  const canonicalRequestHash = await sha256Hex(canonicalRequest);
  const stringToSign = [algorithm, amzDate, credentialScope, canonicalRequestHash].join('\n');

  // Signing key + signature
  const signingKey = await deriveKey(credentials.secretAccessKey, dateStamp, region, service);
  const signature = await hmacHex(signingKey, stringToSign);

  return {
    Authorization: `${algorithm} Credential=${credentials.accessKeyId}/${credentialScope}, SignedHeaders=${signedHeaderList}, Signature=${signature}`,
    'x-amz-date': amzDate,
    ...(credentials.sessionToken ? { 'x-amz-security-token': credentials.sessionToken } : {}),
  };
}

/** Compute the SHA-256 payload hash for an empty body (used for GET, HEAD, DELETE). */
export function emptyPayloadHash(): string {
  return 'e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855';
}

/** Compute the SHA-256 payload hash for a body. */
export async function payloadHash(body: BufferSource | string): Promise<string> {
  let enc: BufferSource;
  if (typeof body === 'string') enc = new TextEncoder().encode(body);
  else enc = body;
  const hash = await crypto.subtle.digest('SHA-256', enc);
  return bytesToHex(new Uint8Array(hash));
}

/**
 * Extract the server timestamp from an AWS S3 XML error response.
 * AWS returns a <ServerTime> element inside the <Error> body for
 * RequestTimeTooSkewed errors. Returns null if no server time is found.
 */
export function extractServerTimeFromError(body: string): Date | null {
  const match = /<ServerTime>(.+?)<\/ServerTime>/.exec(body);
  if (match) {
    const d = new Date(match[1]!);
    if (!isNaN(d.getTime())) return d;
  }
  return null;
}

/**
 * Generate a presigned URL for S3-compatible services using SigV4 query-string auth.
 *
 * The returned URL includes all required `X-Amz-*` query parameters and the
 * final `X-Amz-Signature`. The caller must use the same HTTP method as passed here.
 */
export async function signPresignedUrl(
  method: string,
  canonicalUri: string,
  credentials: SigV4Credentials,
  region: string,
  service: string,
  expiresInSeconds: number,
  now: Date,
  /** The endpoint hostname used for both signing and the final URL.
   *  Must match the actual S3-compatible service endpoint (e.g. "s3.us-east-1.amazonaws.com",
   *  "my-bucket.account.r2.cloudflarestorage.com", "192.168.1.100:9000"). */
  hostname: string,
): Promise<URL> {
  const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '');
  const dateStamp = amzDate.slice(0, 8);
  const algorithm = 'AWS4-HMAC-SHA256';
  const credentialScope = `${dateStamp}/${region}/${service}/aws4_request`;

  // Build canonical query params (sorted by key), excluding Signature
  const params = new URLSearchParams();
  params.set('X-Amz-Algorithm', algorithm);
  params.set('X-Amz-Credential', `${credentials.accessKeyId}/${credentialScope}`);
  params.set('X-Amz-Date', amzDate);
  params.set('X-Amz-Expires', String(expiresInSeconds));
  params.set('X-Amz-SignedHeaders', 'host');
  if (credentials.sessionToken) {
    params.set('X-Amz-Security-Token', credentials.sessionToken);
  }

  const canonicalQueryString = params.toString();

  // Canonical request with host-only signed headers — signed host MUST match
  // the actual endpoint the client will connect to, otherwise the service
  // rejects the signature. Caller passes the correct hostname.
  const canonicalRequest = [
    method,
    canonicalUri,
    canonicalQueryString,
    `host:${hostname}\n`,
    'host',
    'UNSIGNED-PAYLOAD',
  ].join('\n');

  // String to sign
  const canonicalRequestHash = await sha256Hex(canonicalRequest);
  const stringToSign = [algorithm, amzDate, credentialScope, canonicalRequestHash].join('\n');

  // Signing key + signature
  const signingKey = await deriveKey(credentials.secretAccessKey, dateStamp, region, service);
  const signature = await hmacHex(signingKey, stringToSign);

  params.set('X-Amz-Signature', signature);

  const url = new URL(`https://${hostname}${canonicalUri}`);
  url.search = params.toString();
  return url;
}

import type { CreateContainerGroupInput, ContainerCreateConfig, ProbeSpec } from './types.ts';
import type { IContainerProvider, IContainerGroupProvider } from './interfaces.ts';
import type { PodSpec, ContainerSpec } from '../pod/types.ts';

// ─── Probe sanitization ───

/** Shell metacharacters that should be stripped from probe arguments. */
const SHELL_META = /[;|&$()`'\n]/g;

/**
 * Sanitize a ProbeSpec to prevent command injection through shell metacharacters:
 *
 * - exec.command elements: strip shell metacharacters (already argv-safe when used
 *   with CMD instead of CMD-SHELL at the provider level, but defense-in-depth).
 * - httpGet.path: strip shell metacharacters, default to '/'. Port: coerce to number.
 * - tcpSocket: coerce port to number.
 */
export function sanitizeProbe(p: ProbeSpec): ProbeSpec {
  if (p.exec) {
    return {
      ...p,
      exec: {
        command: p.exec.command.map(s => s.replace(SHELL_META, '')),
      },
    };
  }
  if (p.httpGet) {
    return {
      ...p,
      httpGet: {
        port: p.httpGet.port,
        path: (p.httpGet.path ?? '/').replace(SHELL_META, ''),
        ...(p.httpGet.scheme !== undefined ? { scheme: p.httpGet.scheme } : {}),
      },
    };
  }
  if (p.tcpSocket) {
    return {
      ...p,
      tcpSocket: { port: p.tcpSocket.port },
    };
  }
  return p;
}

function sanitizeContainer(c: ContainerCreateConfig): ContainerCreateConfig {
  return {
    ...c,
    ...(c.livenessProbe ? { livenessProbe: sanitizeProbe(c.livenessProbe) } : {}),
    ...(c.readinessProbe ? { readinessProbe: sanitizeProbe(c.readinessProbe) } : {}),
    ...(c.startupProbe ? { startupProbe: sanitizeProbe(c.startupProbe) } : {}),
  };
}

/**
 * Sanitize a CreateContainerGroupInput in-place, cleaning all probes
 * across all containers to remove potential shell injection vectors.
 */
export function sanitizeContainerInput(input: CreateContainerGroupInput): CreateContainerGroupInput {
  return {
    ...input,
    containers: input.containers.map(sanitizeContainer),
  };
}

// ─── Provider decorators ───

/**
 * Wrap an IContainerProvider with input sanitization.
 * All containers' probes are cleaned before reaching the implementation.
 */
export function secureContainerProvider(inner: IContainerProvider): IContainerProvider {
  // Proxy intercepts create/update for sanitization, passes everything else through.
  // Class methods live on the prototype — Object.keys() can't see them, so we use Proxy.
  return new Proxy(inner, {
    get(target, prop: string | symbol, receiver) {
      if (prop === 'create') {
        return (input: CreateContainerGroupInput) => target.create(sanitizeContainerInput(input));
      }
      if (prop === 'update' && target.update) {
        return (providerId: string, input: Partial<CreateContainerGroupInput>) =>
          target.update!(providerId, sanitizeContainerInput(input as CreateContainerGroupInput));
      }
      const val = Reflect.get(target, prop, receiver);
      if (typeof val === 'function') return val.bind(target);
      return val;
    },
  });
}

/** Sanitize probes across all containers in a PodSpec (defense-in-depth). */
function sanitizePodSpec(spec: PodSpec): PodSpec {
  return {
    ...spec,
    spec: {
      ...spec.spec,
      containers: spec.spec.containers.map(sanitizePodContainer),
      ...(spec.spec.initContainers ? { initContainers: spec.spec.initContainers.map(sanitizePodContainer) } : {}),
    },
  };
}

function sanitizePodContainer(c: ContainerSpec): ContainerSpec {
  return {
    ...c,
    ...(c.livenessProbe ? { livenessProbe: sanitizeProbe(c.livenessProbe) } : {}),
    ...(c.readinessProbe ? { readinessProbe: sanitizeProbe(c.readinessProbe) } : {}),
    ...(c.startupProbe ? { startupProbe: sanitizeProbe(c.startupProbe) } : {}),
  };
}

/**
 * Wrap an IContainerGroupProvider with input sanitization.
 */
export function secureContainerGroupProvider(inner: IContainerGroupProvider): IContainerGroupProvider {
  return new Proxy(inner, {
    get(target, prop: string | symbol, receiver) {
      if (prop === 'createPod') {
        return (input: PodSpec) => target.createPod(sanitizePodSpec(input));
      }
      const val = Reflect.get(target, prop, receiver);
      if (typeof val === 'function') return val.bind(target);
      return val;
    },
  });
}

// ─── Container Group Resource Instance ───
// Represents the real-time state of a container group resource from any cloud provider.
// Derived from Alibaba ECI DescribeContainerGroups response structure (see catch/script0/).
//
// Design invariants:
// - Provider-agnostic — no Alibaba/AWS/GCP types leak through.
// - All fields map to fields from the cloud provider's "describe" API.
// - This lives in core/ so both providers/ and features/ can reference it.
//
// OCI container types live here because cloud provider instances ARE
// OCI Runtime containers (same object, different abstraction layers).

/** Real-time status from the cloud provider. */
import type { ContainerGroupState } from './container-lifecycle.ts';
/** @deprecated Use ContainerGroupState enum directly. Kept as alias for migration. */
export type ContainerGroupStatus = ContainerGroupState;

// ─── OCI Container types (core) ───

import type { RegionId, ZoneId } from '../region/types.ts';
import type { InstanceId } from '../region/instance.ts';

declare const CONTAINER_ID_BRAND: unique symbol;
export type ContainerId = string & { readonly [CONTAINER_ID_BRAND]: true };

export function createContainerId(raw: string): ContainerId {
  if (!raw) throw new TypeError('ContainerId must not be empty');
  return raw as ContainerId;
}

/** Standard OCI container states — used by both cloud provider and OCI Runtime. */
export type OciContainerStatus =
  | 'creating'
  | 'created'
  | 'running'
  | 'stopped'
  | 'paused'
  | 'error'
  | 'deleted';

export type OciHealthStatus = 'none' | 'starting' | 'healthy' | 'unhealthy';

export type OciImageRef = string;

/** A container as managed by the OCI Runtime.
 *  Cloud orchestration creates instances → these are the same objects
 *  that the OCI Runtime manages at the OS level. */
export interface OciContainer {
  readonly id: ContainerId;
  readonly name: string;
  readonly image: OciImageRef;
  readonly args: readonly string[];
  readonly env: Record<string, string>;
  readonly workingDir: string;
  readonly status: OciContainerStatus;
  /** Is the container's main process currently alive? */
  readonly alive: boolean;
  readonly createdAt: string;
  readonly startedAt?: string | undefined;
  readonly finishedAt?: string | undefined;
  readonly exitCode?: number | undefined;
  readonly labels: Record<string, string>;
  readonly annotations: Record<string, string>;
  readonly mounts: readonly {
