import { z } from 'zod';
import type { IAtomicStore } from '../store/interfaces.ts';
import type { RegionId, ZoneId, Platform } from './types.ts';
import { createZoneId } from './types.ts';
import { AppError } from '../types.ts';

// ─── Brand type ───

const instanceIdSchema = z.string().min(1).brand('InstanceId');
export type InstanceId = z.infer<typeof instanceIdSchema>;

export function generateInstanceId(): InstanceId {
  return instanceIdSchema.parse(`inst_${crypto.randomUUID()}`);
}

export function createInstanceId(raw: string): InstanceId {
  return instanceIdSchema.parse(raw);
}

// ─── Entity ───

export interface InstanceCapabilities {
  readonly container?: boolean | undefined;
  readonly image?: boolean | undefined;
  readonly group?: boolean | undefined;
  readonly metrics?: boolean | undefined;
  readonly dns?: boolean | undefined;
  readonly network?: boolean | undefined;
  readonly s3?: boolean | undefined;
}

export interface InstanceCapacity {
  readonly cpu?: number | undefined;
  readonly memory?: number | undefined;
  readonly maxPodCount?: number | undefined;
}

export type InstanceStatus = 'online' | 'offline' | 'error';

export interface ComputeInstance {
  readonly id: InstanceId;
  readonly name: string;
  readonly platform: Platform;
  readonly region: RegionId;
  readonly zone: ZoneId;
  readonly endpoint: string;
  readonly credentialRef?: string | undefined;
  readonly capabilities: InstanceCapabilities;
  readonly capacity?: InstanceCapacity | undefined;
  readonly status: InstanceStatus;
  readonly labels?: Record<string, string> | undefined;
  readonly createdAt: number;
  readonly updatedAt: number;
}

export interface CreateInstanceInput {
  name: string;
  platform: Platform;
  region: string;
  zone?: string | undefined;
  endpoint?: string | undefined;
  credentialRef?: string | undefined;
  capabilities?: InstanceCapabilities | undefined;
  capacity?: InstanceCapacity | undefined;
  labels?: Record<string, string> | undefined;
}

export interface UpdateInstanceInput {
  name?: string | undefined;
  endpoint?: string | undefined;
  credentialRef?: string | null | undefined;
  capabilities?: InstanceCapabilities | undefined;
  capacity?: InstanceCapacity | null | undefined;
  status?: InstanceStatus | undefined;
  labels?: Record<string, string> | null | undefined;
}

// ─── Constants ───

const PREFIX = 'instance:';
const INDEX_KEY = 'instance:ids';

// ─── Default endpoint helpers ───

/** Default endpoint per platform+region when not explicitly provided. */
function defaultEndpoint(platform: Platform, region: string): string {
  switch (platform) {
    case 'alibaba': return `eci.${region}.aliyuncs.com`;
    case 'podman': return 'http://127.0.0.1:8080'; // fallback — handler enforces override
    default: return region;
  }
}

// ─── Service ───

export class InstanceService {
  public constructor(private readonly atomic: IAtomicStore) {}
  #rrCounter = 0;

  public async create(input: CreateInstanceInput): Promise<ComputeInstance> {
    const id = generateInstanceId();
    // Default zone: Podman → "local", Alibaba → region+"-g" (ECI auto-schedules, suffix is metadata)
    const zoneRaw = input.zone ?? (input.platform === 'podman' ? 'local' : (input.platform === 'alibaba' ? `${input.region}-g`.replace(/--/g, '-') : 'unknown'));
    const zone = createZoneId(zoneRaw, input.platform);
    const now = Date.now();

    const instance: ComputeInstance = {
      id,
      name: input.name,
      platform: input.platform,
      region: input.region as RegionId,
      zone,
      endpoint: input.endpoint ?? defaultEndpoint(input.platform, input.region),
      ...(input.credentialRef ? { credentialRef: input.credentialRef } : {}),
      capabilities: input.capabilities ?? { container: true, image: true },
      ...(input.capacity ? { capacity: input.capacity } : {}),
      status: 'online',
      ...(input.labels ? { labels: { ...input.labels } } : {}),
      createdAt: now,
      updatedAt: now,
    };

    await this.atomic.set(PREFIX + id, instance, null);
    await this.#addToIndex(id);
    return instance;
  }

  public async get(id: InstanceId): Promise<ComputeInstance | null> {
    const entry = await this.atomic.get<ComputeInstance>(PREFIX + id);
    return entry?.value ?? null;
  }

  public async list(filter?: { region?: string | undefined; platform?: string | undefined; status?: string | undefined; zone?: string | undefined }): Promise<ComputeInstance[]> {
    const all = await this.#listAll();
    if (!filter) return all;
    return all.filter(inst => {
      if (filter.region && inst.region !== filter.region) return false;
      if (filter.platform && inst.platform !== filter.platform) return false;
      if (filter.status && inst.status !== filter.status) return false;
      if (filter.zone && inst.zone !== filter.zone) return false;
      return true;
    });
  }

  /** Paginated list — avoids loading all instances at once. */
  public async listPaginated(page = 1, limit = 50): Promise<{ items: ComputeInstance[]; total: number; page: number; limit: number }> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return { items: [], total: 0, page, limit };
    const start = (page - 1) * limit;
    const ids = idx.value.slice(start, start + limit);
    const entries = await Promise.all(ids.map(id => this.atomic.get<ComputeInstance>(PREFIX + id)));
    return { items: entries.filter(e => e?.value).map(e => e!.value), total: idx.value.length, page, limit };
  }

  public async update(id: InstanceId, input: UpdateInstanceInput): Promise<ComputeInstance> {
    const entry = await this.atomic.get<ComputeInstance>(PREFIX + id);
    if (!entry) throw new AppError(404, 'INSTANCE_NOT_FOUND', 'Compute instance not found');

    const updated: ComputeInstance = {
      ...entry.value,
      ...(input.name !== undefined ? { name: input.name } : {}),
      ...(input.endpoint !== undefined ? { endpoint: input.endpoint } : {}),
      ...(input.credentialRef !== undefined ? { credentialRef: input.credentialRef ?? undefined } : {}),
      ...(input.capabilities ? { capabilities: { ...entry.value.capabilities, ...input.capabilities } } : {}),
      ...(input.capacity !== undefined ? { capacity: input.capacity ?? undefined } : {}),
      ...(input.status !== undefined ? { status: input.status } : {}),
      ...(input.labels !== undefined ? { labels: input.labels ?? undefined } : {}),
      updatedAt: Date.now(),
    };

    const newVersion = await this.atomic.set(PREFIX + id, updated, entry.version);
    if (!newVersion) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');
    return updated;
  }

  /** Update instance capacity + status (heartbeat). Throws if instance not found. */
  public async heartbeat(id: InstanceId, capacity: InstanceCapacity, status: InstanceStatus = 'online'): Promise<void> {
    const entry = await this.atomic.get<ComputeInstance>(PREFIX + id);
    if (!entry) throw new AppError(404, 'INSTANCE_NOT_FOUND', `Instance ${id} not found`);
    await this.atomic.set(PREFIX + id, {
      ...entry.value,
      capacity,
      status,
      updatedAt: Date.now(),
    }, entry.version);
  }

  public async delete(id: InstanceId): Promise<void> {
    const entry = await this.atomic.get<ComputeInstance>(PREFIX + id);
    if (!entry) throw new AppError(404, 'INSTANCE_NOT_FOUND', 'Compute instance not found');

    // Check for running sandboxes on this instance before allowing deletion
    const sandboxIdx = await this.atomic.get<string[]>('sandbox:ids');
    if (sandboxIdx) {
      const sandboxes = await Promise.all(
        sandboxIdx.value.map(sid => this.atomic.get<any>('sandbox:' + sid))
      );
      const running = sandboxes.filter(s => s && s.value?.config?.instanceId === id && s.value?.status !== 'Deleted');
      if (running.length > 0) {
        throw new AppError(409, 'INSTANCE_HAS_SANDBOXES', `Instance ${id} has ${String(running.length)} running sandbox(es)`);
      }
    }

    await this.atomic.set(PREFIX + id, null, entry.version);
    await this.#removeFromIndex(id);
  }

  /** Find online instances with a specific capability. Round-robin across results. */
  public async resolveByCapability(capability: keyof InstanceCapabilities): Promise<ComputeInstance[]> {
    const all = await this.#listAll();
    return all.filter(inst => inst.capabilities[capability] && inst.status === 'online');
  }

  /**
   * Pick one online instance with the given capability, round-robin.
   * Returns undefined if none available.
   */
  public async pickOne(capability: keyof InstanceCapabilities): Promise<ComputeInstance | undefined> {
    const candidates = await this.resolveByCapability(capability);
    if (candidates.length === 0) return undefined;
    this.#rrCounter = (this.#rrCounter + 1) % candidates.length;
    return candidates[this.#rrCounter];
  }

  // ─── Internal helpers ───

  async #listAll(): Promise<ComputeInstance[]> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return [];
    const entries = await Promise.all(idx.value.map(id => this.atomic.get<ComputeInstance>(PREFIX + id)));
    return entries.filter(e => e).map(e => e!.value);
  }

  async #addToIndex(id: InstanceId): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    await this.atomic.set(INDEX_KEY, [...(idx?.value ?? []), id], idx?.version ?? null);
  }

  async #removeFromIndex(id: InstanceId): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return;
    await this.atomic.set(INDEX_KEY, idx.value.filter((i: string) => i !== id), idx.version);
  }
}

import type { RegionId, ZoneId, ClusterId } from './types.ts';
import { ALIBABA_REGIONS } from './types.ts';

// ─── Region-level configuration ───

export interface RegionEndpoint {
  readonly container?: string | undefined;
  readonly metrics?: string | undefined;
  readonly s3?: string | undefined;
}

export interface RegionConfig {
  readonly subnetId?: string | undefined;
  readonly securityGroupId?: string | undefined;
  readonly zoneId?: ZoneId | undefined;
  readonly endpoints?: RegionEndpoint | undefined;
}

// ─── Default endpoint builders ───

function defaultAlibabaEndpoint(region: string, service: string): string {
  return `${service}.${region}.aliyuncs.com`;
}

function buildAlibabaDefaults(): Map<string, RegionConfig> {
  const map = new Map<string, RegionConfig>();
  for (const r of ALIBABA_REGIONS) {
    map.set(r, {
      endpoints: {
        container: defaultAlibabaEndpoint(r, 'eci'),
        metrics: defaultAlibabaEndpoint(r, 'eci'),
        s3: `oss-${r}.aliyuncs.com`,
      },
    });
  }
  return map;
}

/** Known provider names accepted by getEndpoint. */
export type ProviderName = 'alibaba' | 'aws' | 'podman' | 'stub';

// ─── RegionRegistry ───

export class RegionRegistry {
  public static readonly ALIBABA = buildAlibabaDefaults();

  /** Local dev region config. */
  public static readonly LOCAL: RegionConfig = {
    endpoints: { container: 'http://127.0.0.1:8080', s3: 'http://127.0.0.1:9000' },
  };

  /** Runtime overrides applied on top of static defaults. */
  readonly #overrides = new Map<string, RegionConfig>();

  /** Cluster-specific overrides applied on top of regional config. */
  readonly #clusterOverrides = new Map<string, RegionConfig>();

  public constructor(seed?: readonly { region: string; config: RegionConfig }[]) {
    if (seed) {
      for (const { region, config } of seed) {
        this.#overrides.set(region, config);
      }
    }
  }

  /** Get the full region config (defaults + overrides merged).
   *  If clusterId is provided, cluster-level overrides are also applied. */
  public getConfig(region: RegionId, provider?: ProviderName, clusterId?: ClusterId): RegionConfig {
    // Cluster-specific override takes highest priority
    if (clusterId) {
      const co = this.#clusterOverrides.get(clusterId);
      if (co) return co;
    }

    const ov = this.#overrides.get(region);
    if (ov) return ov;

    // Route to the correct static default table based on provider hint
    if (provider === 'alibaba' || ALIBABA_REGIONS.includes(region)) {
      return RegionRegistry.ALIBABA.get(region) ?? {};
    }
    if (region === 'local') return RegionRegistry.LOCAL;

    return {};
  }

  /**
   * Resolve an API endpoint for a given provider service + region.
   *
   * RegionId is a zero-cost brand string — it does not encode which cloud
   * provider the region belongs to.  The caller supplies `provider` so
   * this method can route to the correct default table (Alibaba vs AWS).
   * Runtime overrides are checked first, then built-in defaults.
   */
  public getEndpoint(provider: ProviderName, region: RegionId, service: string, clusterId?: ClusterId): string {
    const cfg = this.getConfig(region, provider, clusterId);

    // Check region-level override first
    if (cfg.endpoints) {
      const ep = cfg.endpoints[service as keyof RegionEndpoint];
      if (ep) return ep;
    }

    // Fallback to dynamic endpoint by provider
    if (provider === 'alibaba' && ALIBABA_REGIONS.includes(region)) {
      return defaultAlibabaEndpoint(region, service);
    }

    return '';
  }

  /** Apply a runtime override for a specific cluster. */
  public setClusterOverride(clusterId: ClusterId, config: RegionConfig): void {
    this.#clusterOverrides.set(clusterId, config);
  }

  /** Remove a cluster override. */
  public removeClusterOverride(clusterId: ClusterId): void {
    this.#clusterOverrides.delete(clusterId);
  }

  /** Apply a runtime override for a specific region. */
  public setOverride(region: string, config: RegionConfig): void {
    this.#overrides.set(region, config);
  }

  /** Remove a runtime override (reverts to static default). */
  public removeOverride(region: string): void {
    this.#overrides.delete(region);
  }

  /** List all known region IDs (static + overrides). */
  public listRegions(): string[] {
    const set = new Set<string>([...ALIBABA_REGIONS, 'local', ...this.#overrides.keys()]);
    return [...set];
  }
}

// ─── Singleton for app-wide use ───

let _defaultRegistry: RegionRegistry | undefined;

export function getDefaultRegistry(): RegionRegistry {
  if (!_defaultRegistry) {
    _defaultRegistry = new RegionRegistry();
  }
  return _defaultRegistry;
}

export function setDefaultRegistry(r: RegionRegistry): void {
  _defaultRegistry = r;
}

import type { RegionId, ClusterId } from './types.ts';
import { ALIBABA_REGIONS } from './types.ts';
import { createRegionId } from './types.ts';
import { getDefaultRegistry } from './registry.ts';

export interface ScheduleRequest {
  /** Required capability type. */
  readonly capability: 'container' | 'compute';
  /** Preferred regions in order (optional). */
  readonly preferredRegions?: readonly string[] | undefined;
  /** Minimum CPU cores required. */
  readonly cpu?: number | undefined;
  /** Minimum memory in MB required. */
  readonly memory?: number | undefined;
  /** Provider hint ('alibaba' | 'podman' | 'stub'). */
  readonly provider?: string | undefined;
  /** Tenant ID for network isolation. */
  readonly tenantId?: string | undefined;
  /** Cluster ID constraint — if set, only this cluster's region is considered. */
  readonly clusterId?: ClusterId | undefined;
}

export interface ScheduleResult {
  readonly region: RegionId;
  readonly provider: string;
  readonly score: number;
  readonly reason: string;
  readonly clusterId?: ClusterId | undefined;
}

const LOCAL_REGION = createRegionId('local');

/**
 * Simple region scheduler. Evaluates available regions against the request
 * and returns the best match based on capabilities, resource availability,
 * and user preference.
 */
export function scheduleRegion(request: ScheduleRequest): ScheduleResult {
  const registry = getDefaultRegistry();

  // If clusterId is specified, constrain to that cluster's region
  let regionsToScore: string[];
  if (request.clusterId) {
    // When clusterId is set, only the cluster's region is relevant.
    // The caller is expected to have resolved the cluster already —
    // we just need to match the provider and region.
    // We still score all regions but the cluster's region gets +200.
    regionsToScore = registry.listRegions();
  } else {
    regionsToScore = registry.listRegions();
  }

  const candidates: ScheduleResult[] = [];

  for (const region of regionsToScore) {
    const provider = resolveProvider(region, request.provider);
    const score = scoreRegion(region, request);
    if (score <= 0) continue;

    candidates.push({
      region: createRegionId(region),
      provider,
      score,
      reason: score >= 200 ? 'cluster-matched' : score >= 100 ? 'preferred' : score >= 50 ? 'available' : 'fallback',
      ...(request.clusterId ? { clusterId: request.clusterId } : {}),
    });
  }

  if (candidates.length === 0) {
    return {
      region: LOCAL_REGION,
      provider: request.provider ?? 'stub',
      score: 0,
      reason: 'no region matched — using local fallback',
    };
  }

  candidates.sort((a, b) => b.score - a.score);
  return candidates[0]!;
}

function resolveProvider(region: string, preferred?: string): string {
  if (preferred) return preferred;
  if (region === 'local') return 'podman';
  if (ALIBABA_REGIONS.includes(region)) return 'alibaba';
  return 'stub';
}

/**
 * Score a region for a given request. Higher = better match.
 * Returns 0 if the region cannot satisfy the request.
 */
function scoreRegion(region: string, request: ScheduleRequest): number {
  let score = 0;

  // Preferred regions get a big boost
  if (request.preferredRegions?.includes(region)) {
    score += 100;
  }

  // Provider match
  const provider = resolveProvider(region, request.provider);
  if (request.provider && provider !== request.provider) {
    // Hard mismatch — wrong provider
    if (!request.preferredRegions?.includes(region)) return 0;
    score -= 50; // still possible but penalized
  }

  // Local gets a base score
  if (region === 'local') {
    score += 30;
  }

  // Alibaba regions get their own base score
  if (ALIBABA_REGIONS.includes(region)) {
    score += 20;
  }

  return score;
}

/**
 * Resolve a provider-aware endpoint for the scheduled region.
 */
export function getEndpointFor(region: RegionId, provider: string, service: string): string {
  if (provider === 'podman' || region === 'local') {
    return process.env.PODMAN_ENDPOINT ?? 'http://127.0.0.1:8080';
  }
  const registry = getDefaultRegistry();
  return registry.getEndpoint(provider as any, region, service);
}

import { z } from 'zod';

// ─── Platform enumeration ───

export type Platform = 'alibaba' | 'aws' | 'podman' | 'stub';

// ─── Region types ───

/** Alibaba Cloud regions as a true enum — string values for API compatibility. */
export enum AlibabaRegion {
  CnHangzhou = 'cn-hangzhou',
  CnBeijing = 'cn-beijing',
  CnShanghai = 'cn-shanghai',
  CnZhangjiakou = 'cn-zhangjiakou',
  CnHuhehaote = 'cn-huhehaote',
  CnShenzhen = 'cn-shenzhen',
  CnChengdu = 'cn-chengdu',
  CnHongkong = 'cn-hongkong',
  CnQingdao = 'cn-qingdao',
  CnHeyuan = 'cn-heyuan',
  CnWulanchabu = 'cn-wulanchabu',
  CnGuangzhou = 'cn-guangzhou',
  ApNortheast1 = 'ap-northeast-1',
  ApSoutheast1 = 'ap-southeast-1',
  ApSoutheast3 = 'ap-southeast-3',
  ApSoutheast5 = 'ap-southeast-5',
  ApSouth1 = 'ap-south-1',
  UsEast1 = 'us-east-1',
  UsWest1 = 'us-west-1',
  EuWest1 = 'eu-west-1',
  EuCentral1 = 'eu-central-1',
}

export const ALIBABA_REGIONS: readonly string[] = Object.values(AlibabaRegion);

/** AWS regions as a true enum. */
export enum AwsRegion {
  UsEast1 = 'us-east-1',
  UsEast2 = 'us-east-2',
  UsWest1 = 'us-west-1',
  UsWest2 = 'us-west-2',
  EuWest1 = 'eu-west-1',
  EuWest2 = 'eu-west-2',
  EuCentral1 = 'eu-central-1',
  EuNorth1 = 'eu-north-1',
  ApSoutheast1 = 'ap-southeast-1',
  ApSoutheast2 = 'ap-southeast-2',
  ApNortheast1 = 'ap-northeast-1',
  ApSouth1 = 'ap-south-1',
  SaEast1 = 'sa-east-1',
  CaCentral1 = 'ca-central-1',
}

export const AWS_REGIONS: readonly string[] = Object.values(AwsRegion);

/** Podman regions — local-only, but supports multiple named instances. */
export enum PodmanRegion {
  Local = 'local',
}

// ─── RegionId brand type ───

const regionIdSchema = z.string().min(1).brand('RegionId');
export type RegionId = z.infer<typeof regionIdSchema>;

export function createRegionId(raw: string): RegionId {
  if (!raw?.trim()) throw new TypeError('RegionId must not be empty');
  return regionIdSchema.parse(raw);
}

export function createAlibabaRegion(raw: string): AlibabaRegion {
  const r = Object.values(AlibabaRegion).find(r => String(r) === raw);
  if (!r) throw new TypeError(`Invalid Alibaba region: "${raw}". Valid: ${ALIBABA_REGIONS.join(', ')}`);
  return r;
}

export function createAwsRegion(raw: string): AwsRegion {
  const r = Object.values(AwsRegion).find(r => String(r) === raw);
  if (!r) throw new TypeError(`Invalid AWS region: "${raw}". Valid: ${AWS_REGIONS.join(', ')}`);
  return r;
}

/** Local / dev region constant. */
export const LOCAL_REGION = createRegionId('local');

// ─── ZoneId brand type (validated per platform, not a closed enum) ───

const zoneIdSchema = z.string().min(1).brand('ZoneId');
export type ZoneId = z.infer<typeof zoneIdSchema>;

/** Alibaba zone pattern: cn-hangzhou-g, cn-beijing-g, us-east-1-a, etc. */
const ALIBABA_ZONE_RE = /^[a-z]+(?:-[a-z0-9]+)+-[a-z]$/;

/** Podman zone: 'local' or 'local-<name>'. */
const PODMAN_ZONE_RE = /^local(?:-[a-zA-Z0-9_-]+)?$/;

export function createZoneId(raw: string, platform: Platform): ZoneId {
  if (!raw?.trim()) throw new TypeError('ZoneId must not be empty');
  switch (platform) {
    case 'alibaba':
      if (!ALIBABA_ZONE_RE.test(raw)) {
        throw new TypeError(`Invalid Alibaba zone: "${raw}". Expected format like "cn-hangzhou-a"`);
      }
      break;
    case 'podman':
      if (!PODMAN_ZONE_RE.test(raw)) {
        throw new TypeError(`Invalid Podman zone: "${raw}". Expected "local" or "local-<name>"`);
      }
      break;
    case 'stub':
      // Stub accepts any non-empty string
      break;
    case 'aws':
      // AWS zone format: us-east-1a, us-east-1b, etc.
      if (!/^[a-z]+-[a-z]+-\d+[a-z]$/.test(raw)) {
        throw new TypeError(`Invalid AWS zone: "${raw}". Expected format like "us-east-1a"`);
      }
      break;
  }
  return zoneIdSchema.parse(raw);
}

// ─── ClusterId brand type ───

const clusterIdSchema = z.string().min(1).brand('ClusterId');
export type ClusterId = z.infer<typeof clusterIdSchema>;

export function generateClusterId(): ClusterId {
  return clusterIdSchema.parse(`cluster_${crypto.randomUUID()}`);
}

import type { IAtomicStore } from '../store/interfaces.ts';
import { AppError } from '../types.ts';
import type { S3Policy, CreateS3PolicyInput, UpdateS3PolicyInput } from './types.ts';

const PREFIX = 's3-policy:';
const INDEX_KEY = 's3-policy:ids';

export class S3PolicyManager {
  public constructor(private readonly atomic: IAtomicStore) {}

  public async create(bucketId: string, input: CreateS3PolicyInput): Promise<S3Policy> {
    const id = `sp_${crypto.randomUUID()}`;
    const now = Date.now();
    const policy: S3Policy = {
      id,
      bucketId,
      name: input.name,
      description: input.description,
      effect: input.effect,
      actions: [...input.actions],
      pathPrefix: input.pathPrefix ?? '',
      applyToAutoKeys: input.applyToAutoKeys ?? true,
      priority: input.priority ?? 100,
      createdAt: now,
      updatedAt: now,
    };

    await this.atomic.set(PREFIX + id, policy, null);
    await this.#addToIndex(id);
    return policy;
  }

  public async get(id: string): Promise<S3Policy | null> {
    const entry = await this.atomic.get<S3Policy>(PREFIX + id);
    return entry?.value ?? null;
  }

  public async list(bucketId?: string): Promise<S3Policy[]> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return [];
    const entries = await Promise.all(idx.value.map(id => this.atomic.get<S3Policy>(PREFIX + id)));
    let policies = entries.filter(e => e).map(e => e!.value);
    if (bucketId) policies = policies.filter(p => p.bucketId === bucketId);
    return policies;
  }

  public async update(id: string, input: UpdateS3PolicyInput): Promise<S3Policy> {
    const entry = await this.atomic.get<S3Policy>(PREFIX + id);
    if (!entry) throw new AppError(404, 'S3_POLICY_NOT_FOUND', 'S3 policy not found');

    const updated: S3Policy = {
      ...entry.value,
      ...(input.name !== undefined ? { name: input.name } : {}),
      ...(input.description !== undefined ? { description: input.description ?? undefined } : {}),
      ...(input.effect !== undefined ? { effect: input.effect } : {}),
      ...(input.actions !== undefined ? { actions: [...input.actions] } : {}),
      ...(input.pathPrefix !== undefined ? { pathPrefix: input.pathPrefix } : {}),
      ...(input.applyToAutoKeys !== undefined ? { applyToAutoKeys: input.applyToAutoKeys } : {}),
      ...(input.priority !== undefined ? { priority: input.priority } : {}),
      updatedAt: Date.now(),
    };

    const ver = await this.atomic.set(PREFIX + id, updated, entry.version);
    if (!ver) throw new AppError(409, 'CONFLICT', 'Concurrent modification');
    return updated;
  }

  public async delete(id: string): Promise<void> {
    const entry = await this.atomic.get<S3Policy>(PREFIX + id);
    if (!entry) throw new AppError(404, 'S3_POLICY_NOT_FOUND', 'S3 policy not found');
    await this.atomic.set(PREFIX + id, null, entry.version);
    await this.#removeFromIndex(id);
  }

  /**
   * Resolve the effective policy for a bucket's auto-generated keys.
   * Collects all policies with applyToAutoKeys=true, sorts by priority (desc),
   * Deny overrides Allow.  Returns null when no policies exist (no restriction).
   */
  public async resolve(bucketId: string): Promise<{ effect: 'Allow' | 'Deny'; actions: string[]; pathPrefix: string } | null> {
    const all = await this.list(bucketId);
    const autoPolicies = all.filter(p => p.applyToAutoKeys).sort((a, b) => b.priority - a.priority);

    if (autoPolicies.length === 0) return null;

    // Deny overrides: if any Deny matches, it wins
    const deny = autoPolicies.find(p => p.effect === 'Deny');
    if (deny) return { effect: 'Deny', actions: [...deny.actions], pathPrefix: deny.pathPrefix };

    // Otherwise use the highest-priority Allow
    const allow = autoPolicies[0]!;
    return { effect: 'Allow', actions: [...allow.actions], pathPrefix: allow.pathPrefix };
  }

  async #addToIndex(id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    await this.atomic.set(INDEX_KEY, [...(idx?.value ?? []), id], idx?.version ?? null);
  }

  async #removeFromIndex(id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return;
    await this.atomic.set(INDEX_KEY, idx.value.filter((i: string) => i !== id), idx.version);
  }
}

/// <reference types="@cloudflare/workers-types" />

/**
 * Durable Object that acts as a recurring alarm timer.
 *
 * This is the **only** reliable timing source in a Workers environment —
 * DO Alarm has a single-threaded, consistent clock, unlike Worker isolates
 * where `setInterval` / `Date.now()` can diverge across instances (clock wall).
 *
 * On each alarm fire, the DO:
 * 1. Calls back to the Worker via `fetch(callbackUrl)` to trigger a tick.
 * 2. Re-schedules the next alarm using algebraic scheduling
 *    (firstAlarmAt + n * intervalMs) to prevent cumulative drift.
 *
 * Note: Uses `_`-prefixed properties instead of `#` private fields to avoid
 * a workerd crash on Windows when private fields are used in Durable Object
 * classes.
 *
 * @example
 * ```ts
 * const stub = env.ALARM_TIMER_DO.idFromName('event-loop');
 * await stub.fetch('http://do/start', {
 *   method: 'POST',
 *   body: JSON.stringify({ intervalMs: 60000, callbackUrl: 'http://localhost:8787/__scheduled' }),
 * });
 * ```
 */
export class AlarmTimerDO implements DurableObject {
  public constructor(public readonly ctx: DurableObjectState, _env: unknown) {}

  /** Minimum interval safety floor (1s). DO alarms below this risk instability. */
  public static readonly MIN_INTERVAL = 1000;

  public _intervalMs = 60000;
  public _callbackUrl = '';
  public _running = false;
  public _tickCount = 0;
  /** Absolute timestamp of the first alarm (set on /start). Used for algebraic re-scheduling. */
  public _firstAlarmAt = 0;

  public async fetch(request: Request): Promise<Response> {
    const url = new URL(request.url);

    if (url.pathname.endsWith('/start')) {
      const body = await request.json();
      this._intervalMs = Math.max(body.intervalMs, AlarmTimerDO.MIN_INTERVAL);
      this._callbackUrl = body.callbackUrl ?? '';
      this._running = true;
      this._tickCount = 0;
      // Use algebraic scheduling: record first alarm time so subsequent
      // alarms use firstAlarmAt + n * intervalMs instead of Date.now() + interval.
      // This prevents cumulative drift from DO alarm jitter.
      this._firstAlarmAt = Date.now();
      await this.ctx.storage.setAlarm(this._firstAlarmAt + this._intervalMs);
      return Response.json({
        ok: true,
        intervalMs: this._intervalMs,
        hasCallback: !!body.callbackUrl,
      });
    }

    if (url.pathname.endsWith('/stop')) {
      this._running = false;
      await this.ctx.storage.deleteAlarm();
      return Response.json({ ok: true });
    }

    if (url.pathname.endsWith('/status')) {
      const nextAlarm = await this.ctx.storage.getAlarm();
      return Response.json({
        running: this._running,
        intervalMs: this._intervalMs,
        tickCount: this._tickCount,
        hasCallback: !!this._callbackUrl,
        nextAlarm,
      });
    }

    return new Response('not found', { status: 404 });
  }

  public async alarm(): Promise<void> {
    if (!this._running) return;
    this._tickCount++;
    console.log(`[${new Date().toISOString()}] INFO: [scheduler] Tick #${String(this._tickCount)} (interval=${String(this._intervalMs)}ms)`);

    if (this._callbackUrl) {
      try {
        await fetch(this._callbackUrl, { method: 'POST' });
      } catch {
        // callback failure doesn't stop re-scheduling
      }
    }

    // Algebraic scheduling: compute next alarm from firstAlarmAt to avoid
    // accumulating DO alarm jitter. If firstAlarmAt is 0 (backward compat),
    // fall back to Date.now() + interval.
    const nextAt = this._firstAlarmAt > 0
      ? this._firstAlarmAt + this._tickCount * this._intervalMs
      : Date.now() + this._intervalMs;
    await this.ctx.storage.setAlarm(nextAt);
  }
}

import type { DagDef, DagRun } from '../dag/types.ts';
import { createDagRunId } from '../dag/types.ts';

// ─── Types ───

export interface BackfillConfig {
  /** Start of the catchup window (epoch ms). */
  startDate: number;
  /** End of the catchup window (epoch ms). Default: now. */
  endDate?: number;
  /** If true, reset existing DagRuns in the window before backfilling. */
  resetDagRuns?: boolean;
}

export interface BackfillResult {
  created: number;
  skipped: number;
  errors: string[];
}

// ─── Default cron → interval mapping ───

const DEFAULT_SCHEDULE_INTERVAL_MS = 3_600_000; // 1 hour

/**
 * Parse a simple cron expression to a millisecond interval.
 * Supports: every N minutes pattern and every minute pattern.
 * Returns null for unsupported patterns.
 */
export function cronToIntervalMs(cron: string): number | null {
  const parts = cron.trim().split(/\s+/);
  if (parts.length !== 5) return null;

  const [minute, hour, day, month, weekday] = parts;

  // */N * * * *
  if (minute?.startsWith('*/') && hour === '*' && day === '*' && month === '*' && weekday === '*') {
    const n = parseInt(minute.slice(2), 10);
    if (n > 0 && n <= 60) return n * 60_000;
  }

  // * * * * *
  if (minute === '*' && hour === '*' && day === '*' && month === '*' && weekday === '*') return 60_000;

  // N * * * * (every hour at minute N)
  const min = parseInt(minute!, 10);
  if (!isNaN(min) && min >= 0 && min < 60 && hour === '*' && day === '*' && month === '*' && weekday === '*') return 3_600_000;

  return null;
}

// ─── Backfill engine ───

/**
 * Create DagRuns for missed schedule intervals (catchup).
 *
 * Given a DagDef with `schedule` and `catchup: true`, compute the missed
 * execution dates between the last completed DagRun and now, and create
 * one DagRun per interval.
 *
 * @param dagDef  — The DAG definition with schedule info.
 * @param existingRuns — Already-created DagRuns (to avoid duplicates).
 * @param config  — Backfill window configuration.
 * @param factory — Callback that creates and persists a DagRun.
 */
export async function backfillDagRuns(
  dagDef: DagDef,
  existingRuns: readonly DagRun[],
  config: BackfillConfig,
  factory: (dagRun: Omit<DagRun, 'version'>) => Promise<boolean>,
): Promise<BackfillResult> {
  const result: BackfillResult = { created: 0, skipped: 0, errors: [] };

  if (!dagDef.schedule || !dagDef.catchup) return result;

  const intervalMs = cronToIntervalMs(dagDef.schedule);
  if (!intervalMs) {
    result.errors.push(`Unsupported schedule: ${dagDef.schedule}`);
    return result;
  }

  const endDate = config.endDate ?? Date.now();
  const existingDates = new Set(existingRuns.map(r => r.executionDate));

  // Generate execution dates for the window
  const dates: number[] = [];
  for (let d = config.startDate; d < endDate; d += intervalMs) {
    dates.push(d);
  }

  // Skip if there's less than 1 interval between runs
  if (dates.length <= 1) return result;

  for (const execDate of dates) {
    if (existingDates.has(execDate)) {
      result.skipped++;
      continue;
    }

    const dagRun: Omit<DagRun, 'version'> = {
      id: createDagRunId(`dr_${dagDef.id}_${String(execDate)}_${crypto.randomUUID()}`),
      dagId: dagDef.id,
      status: 'QUEUED',
      executionDate: execDate,
      trigger: 'backfill',
      env: {},
    };

    try {
      const ok = await factory(dagRun);
      if (ok) {
        result.created++;
      } else {
        result.errors.push(`Factory returned false for execution date ${String(execDate)}`);
      }
    } catch (err) {
      result.errors.push(
        `Failed to create DagRun for ${String(execDate)}: ${err instanceof Error ? err.message : String(err)}`,
      );
    }
  }

  return result;
}

/**
 * Compute the start date for backfill: either the DAG's createdAt, or the
 * last completed DagRun's execution date + one interval.
 */
export function computeBackfillStart(
  dagDef: DagDef,
  existingRuns: readonly DagRun[],
): number {
  const completed = existingRuns
    .filter(r => r.status === 'SUCCESS' || r.status === 'FAILED')
    .sort((a, b) => b.executionDate - a.executionDate);

  if (completed.length > 0) {
    const lastDate = completed[0]!.executionDate;
    const intervalMs = (dagDef.schedule ? cronToIntervalMs(dagDef.schedule) : null) ?? DEFAULT_SCHEDULE_INTERVAL_MS;
    return lastDate + intervalMs;
  }

  // No runs exist — start from DAG creation
  return dagDef.createdAt;
}

import type { TaskInstance } from '../dag/types.ts';

/**
 * ConcurrencyMap — O(1) lookup of active task counts.
 *
 * Maps: dag_id → { active_tis, task_id → { active_tis }, dagrun_id → { active_tis } }
 *
 * Used by the 5-step filter pipeline to enforce:
 *   - max_active_tasks (per DAG)
 *   - max_active_tis_per_dag (per Task)
 *   - max_active_tis_per_dagrun (per DagRun)
 *
 * This is a pure in-memory structure rebuilt each scheduler tick.
 */

export interface ConcurrencyCounts {
  /** Total running TaskInstances for this DAG. */
  dagActive: number;
  /** Running TaskInstances per task in this DAG. */
  taskActive: Map<string, number>;
  /** Running TaskInstances per DagRun in this DAG. */
  dagRunActive: Map<string, number>;
}

export class ConcurrencyMap {
  private readonly counts = new Map<string, ConcurrencyCounts>();

  /** Build the map from a list of active (non-terminal) TaskInstances. */
  public constructor(activeTis: readonly TaskInstance[]) {
    for (const ti of activeTis) {
      this.add(ti);
    }
  }

  private add(ti: TaskInstance): void {
    // dagRunId format: dr_<dagId>_<execDate>_<uuid> — extract second segment
    const parts = ti.dagRunId.split('_');
    const dagId = parts.length >= 3 && parts[0] === 'dr' ? parts[1]! : (parts.length >= 2 ? parts[1]! : parts[0]!);

    let c = this.counts.get(dagId);
    if (!c) {
      c = { dagActive: 0, taskActive: new Map(), dagRunActive: new Map() };
      this.counts.set(dagId, c);
    }

    c.dagActive++;
    c.taskActive.set(ti.taskId, (c.taskActive.get(ti.taskId) ?? 0) + 1);
    c.dagRunActive.set(ti.dagRunId, (c.dagRunActive.get(ti.dagRunId) ?? 0) + 1);
  }

  /** How many active TIs exist for this DAG across all DagRuns? */
  public dagActiveCount(dagId: string): number {
    return this.counts.get(dagId)?.dagActive ?? 0;
  }

  /** How many active TIs exist for this specific task? */
  public taskActiveCount(dagId: string, taskId: string): number {
    return this.counts.get(dagId)?.taskActive.get(taskId) ?? 0;
  }

  /** How many active TIs exist for this specific DagRun? */
  public dagRunActiveCount(dagId: string, dagRunId: string): number {
    return this.counts.get(dagId)?.dagRunActive.get(dagRunId) ?? 0;
  }
}

import type { ITimerBackend, SchedulerStatus } from './interfaces.ts';
import type {
  DagRun,
  TaskInstanceState,
  SchedulerContext,
  ITaskExecutor,
} from '../dag/types.ts';
import { isTaskTerminal, DEFAULT_TRIGGER_RULE } from '../dag/types.ts';
import { evaluateTriggerRule } from '../dag/trigger-rule.ts';
import {
  createTaskInstance,
  transitionState,
  shouldRetry,
  markSuccess,
  markFailed,
  markUpstreamFailed,
} from './task-instance.ts';
import { ConcurrencyMap } from './concurrency-map.ts';
import { filterScheduledTasks, type FilterContext } from './filter.ts';
import { openSlots, DEFAULT_POOL_NAME } from './pool.ts';
import { generateVersionId } from '../brand.ts';

// ─── Config ───

export interface DagSchedulerConfig {
  /** Tick interval in milliseconds. */
  intervalMs: number;
  /** Maximum concurrent executing tasks across all DAGs. */
  parallelism: number;
  /** Auto-start the scheduler loop. */
  autoStart: boolean;
}

const DEFAULT_CONFIG: DagSchedulerConfig = {
  intervalMs: 5000,
  parallelism: 8,
  autoStart: true,
};

// ─── Scheduler job ───

/**
 * DAG Scheduler — Airflow `SchedulerJobRunner` main loop.
 *
 * On each tick:
 *   1. schedule  — evaluate trigger rules, move NONE→SCHEDULED
 *   2. process   — 5-step filter, move SCHEDULED→QUEUED
 *   3. execute   — claim slots, dispatch QUEUED→RUNNING to executors
 *   4. heartbeat — check RUNNING tasks for completion/timeout
 *
 * The scheduler uses {@link SchedulerContext} for all persistence and
 * {@link ITimerBackend} for the timing loop. Executors are resolved
 * via the context's `getExecutor()` method.
 */
export class DagScheduler {
  private config: DagSchedulerConfig;
  private running = false;
  private paused = false;
  private startedAt = 0;
  private timerHandle: ReturnType<ITimerBackend['start']> | null = null;
  private tickCount = 0;
  private readonly executorCache = new Map<string, ITaskExecutor>();

  public constructor(
    private readonly ctx: SchedulerContext,
    private readonly timer: ITimerBackend,
    config: Partial<DagSchedulerConfig> = {},
  ) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  // ─── Lifecycle ───

  public start(): void {
    if (this.running) return;
    this.running = true;
    this.paused = false;
    this.startedAt = Date.now();
    this.timerHandle = this.timer.start(() => this.tick(), this.config.intervalMs);
  }

  public stop(): void {
    this.running = false;
    this.timerHandle?.clear();
    this.timerHandle = null;
  }

  public pause(): void { this.paused = true; }
  public resume(): void { this.paused = false; }

  public configure(partial: Partial<DagSchedulerConfig>): DagSchedulerConfig {
    this.config = { ...this.config, ...partial };
    // Restart timer if interval changed and running
    if (this.running) {
      this.timerHandle?.clear();
      this.timerHandle = this.timer.start(() => this.tick(), this.config.intervalMs);
    }
    return this.config;
  }

  public status(): SchedulerStatus {
    return {
      running: this.running,
      paused: this.paused,
      uptimeMs: Date.now() - this.startedAt,
      config: { intervalMs: this.config.intervalMs, autoStart: this.config.autoStart },
    };
  }

  // ─── Main tick ───

  public async tick(): Promise<void> {
    if (!this.running || this.paused) return;
    this.tickCount++;

    try {
      await this.schedule();
      await this.process();
      await this.execute();
      await this.heartbeat();
    } catch (err) {
      // Log but don't crash the scheduler
      console.error(`[DagScheduler] tick #${String(this.tickCount)} error:`, err);
    }
  }

  // ─── Phase 1: Schedule ───

  private async schedule(): Promise<void> {
    const dagRuns = await this.ctx.getActiveDagRuns();
    if (dagRuns.length === 0) return;

    for (const run of dagRuns) {
      if (run.status !== 'QUEUED' && run.status !== 'RUNNING') continue;

      // Transition to RUNNING if this is the first active tick
      let currentRun = run;
      if (currentRun.status === 'QUEUED') {
        const runEntry = await this.ctx.getDagRun(currentRun.id);
        if (!runEntry) continue;
        currentRun = { ...currentRun, status: 'RUNNING', startedAt: Date.now(), version: generateVersionId() };
        await this.ctx.updateDagRun(currentRun, runEntry.version);
      }

      const dagDefEntry = await this.ctx.getDagDef(currentRun.dagId);
      if (!dagDefEntry) continue;
      const dagDef = dagDefEntry.value;

      const tis = await this.ctx.getTaskInstances(currentRun.id);

      // Build upstream state lookup per task
      const tiMap = new Map(tis.map(ti => [ti.taskId, ti]));

      for (const task of dagDef.tasks) {
        let ti = tiMap.get(task.id);
        if (!ti) {
          // First encounter — create TaskInstance
          ti = createTaskInstance({
            id: `ti_${crypto.randomUUID()}` as any,
            taskId: task.id,
            dagRunId: currentRun.id,
          });
          await this.ctx.saveTaskInstance(ti, null);
          continue;
        }

        // Only schedule NONE and UP_FOR_RETRY tasks
        if (ti.state !== 'NONE' && ti.state !== 'UP_FOR_RETRY') continue;

        // Evaluate trigger rule
        const upstreamStates: TaskInstanceState[] = task.dependsOn.map(depId => {
          const depTi = tiMap.get(depId);
          return depTi?.state ?? 'NONE';
        });

        const rule = task.triggerRule ?? DEFAULT_TRIGGER_RULE;
        if (ti.state === 'NONE' && evaluateTriggerRule(rule, upstreamStates)) {
          ti = transitionState(ti, 'SCHEDULED');
          await this.ctx.saveTaskInstance(ti);
          tiMap.set(task.id, ti);
        }

        // UP_FOR_RETRY → QUEUED (when retry delay elapsed)
        if (ti.state === 'UP_FOR_RETRY') {
          const retryDelay = task.retryDelayMs ?? 30_000;
          if (ti.completedAt && Date.now() - ti.completedAt >= retryDelay) {
            ti = transitionState(ti, 'QUEUED');
            ti = { ...ti, tryNumber: ti.tryNumber + 1 };
            await this.ctx.saveTaskInstance(ti);
            tiMap.set(task.id, ti);
          }
        }

        // Handle upstream failures
        if (ti.state === 'NONE') {
          const anyUpstreamFailed = upstreamStates.some(
            s => s === 'FAILED' || s === 'UPSTREAM_FAILED',
          );
          if (anyUpstreamFailed && rule !== 'always') {
            ti = markUpstreamFailed(ti, 'Upstream task failed');
            await this.ctx.saveTaskInstance(ti);
            tiMap.set(task.id, ti);
          }
        }
      }

      // Check if all tasks are terminal → complete the DagRun
      const allTerminal = dagDef.tasks.every(t => {
        const ti = tiMap.get(t.id);
        return ti && isTaskTerminal(ti.state);
      });
      if (allTerminal && dagDef.tasks.length > 0) {
        const anyFailed = dagDef.tasks.some(t => {
          const ti = tiMap.get(t.id);
          return ti && (ti.state === 'FAILED' || ti.state === 'UPSTREAM_FAILED');
        });
        const runEntry = await this.ctx.getDagRun(currentRun.id);
        if (runEntry) {
          const finalRun: DagRun = {
            ...currentRun,
            status: anyFailed ? 'FAILED' : 'SUCCESS',
            completedAt: Date.now(),
            version: generateVersionId(),
          };
          await this.ctx.updateDagRun(finalRun, runEntry.version);
        }
      }
    }
  }

  // ─── Phase 2: Process (filter) ───

  private async process(): Promise<void> {
    const dagRuns = await this.ctx.getActiveDagRuns();
    if (dagRuns.length === 0) return;

    for (const run of dagRuns) {
      if (run.status !== 'RUNNING') continue;

      const dagDefEntry = await this.ctx.getDagDef(run.dagId);
      if (!dagDefEntry) continue;
      const dagDef = dagDefEntry.value;

      const tis = await this.ctx.getTaskInstances(run.id);
      const scheduled = tis.filter(ti => ti.state === 'SCHEDULED');
      if (scheduled.length === 0) continue;

      // Build context for filter
      const taskMap = new Map(dagDef.tasks.map(t => [t.id, t]));

      // Pool slots
      const poolNames = new Set(dagDef.tasks.map(t => t.pool ?? DEFAULT_POOL_NAME));
      const poolSlots = new Map<string, number>();
      for (const pn of poolNames) {
        const pool = await this.ctx.getPool(pn);
        poolSlots.set(pn, pool ? openSlots(pool) : 128);
      }

      // Dag max active
      const dagMaxActive = new Map<string, number>();
      dagMaxActive.set(dagDef.id, dagDef.maxActiveTasks ?? 16);

      const concurrencyMap = new ConcurrencyMap(
        tis.filter(ti => !isTaskTerminal(ti.state)),
      );

      const alreadyQueued = tis.filter(ti => ti.state === 'QUEUED').length;

      const filterCtx: FilterContext = {
        tasks: taskMap,
        poolSlots,
        dagMaxActive,
        concurrencyMap,
        parallelism: this.config.parallelism,
        alreadyQueued,
      };

      const result = filterScheduledTasks(scheduled, filterCtx);

      // Advance passed tasks to QUEUED
      for (const ti of result.passed) {
        const updated = transitionState(ti, 'QUEUED');
        await this.ctx.saveTaskInstance(updated);
      }
    }
  }

  // ─── Phase 3: Execute ───

  private async execute(): Promise<void> {
    const dagRuns = await this.ctx.getActiveDagRuns();
    if (dagRuns.length === 0) return;

    for (const run of dagRuns) {
      if (run.status !== 'RUNNING') continue;

      const tis = await this.ctx.getTaskInstances(run.id);
      const queued = tis.filter(ti => ti.state === 'QUEUED');
      if (queued.length === 0) continue;

      const dagDefEntry = await this.ctx.getDagDef(run.dagId);
      if (!dagDefEntry) continue;
      const dagDef = dagDefEntry.value;
      const taskMap = new Map(dagDef.tasks.map(t => [t.id, t]));

      for (const ti of queued) {
        const task = taskMap.get(ti.taskId);
        if (!task) continue;

        // Claim pool slot
        const poolName = task.pool ?? DEFAULT_POOL_NAME;
        const pool = await this.ctx.getPool(poolName);
        if (pool) {
          const open = openSlots(pool);
          if (open <= 0) continue; // pool full, try next tick
          await this.ctx.updatePool({ ...pool, occupiedSlots: pool.occupiedSlots + 1 });
        }

        // Resolve and dispatch to executor
        const executorKey = task.executorKey ?? task.operatorType;
        const executor = await this.getExecutor(executorKey);
        if (!executor) {
          // No executor — release slot and skip
          if (pool) await this.ctx.updatePool({ ...pool, occupiedSlots: Math.max(0, pool.occupiedSlots - 1) });
          continue;
        }

        // Transition to RUNNING
        let running = transitionState(ti, 'RUNNING');
        await this.ctx.saveTaskInstance(running);

        // Execute
        try {
          const result = await executor.execute(task, running);

          if (pool) {
            const p2 = await this.ctx.getPool(poolName);
            if (p2) await this.ctx.updatePool({ ...p2, occupiedSlots: Math.max(0, p2.occupiedSlots - 1) });
          }

          if (result.success) {
            running = markSuccess(running, result.output);
          } else {
            if (shouldRetry(running, task.retries)) {
              running = transitionState(running, 'UP_FOR_RETRY');
            } else {
              running = markFailed(running, result.error ?? 'Task failed', result.exitCode);
            }
          }
          await this.ctx.saveTaskInstance(running);
        } catch (err) {
          if (pool) {
            const p2 = await this.ctx.getPool(poolName);
            if (p2) await this.ctx.updatePool({ ...p2, occupiedSlots: Math.max(0, p2.occupiedSlots - 1) });
          }

          const msg = err instanceof Error ? err.message : String(err);
          if (shouldRetry(running, task.retries)) {
            running = transitionState(running, 'UP_FOR_RETRY');
          } else {
            running = markFailed(running, msg);
          }
          await this.ctx.saveTaskInstance(running);
        }
      }
    }
  }

  // ─── Phase 4: Heartbeat ───

  private async heartbeat(): Promise<void> {
    const dagRuns = await this.ctx.getActiveDagRuns();
    if (dagRuns.length === 0) return;

    for (const run of dagRuns) {
      if (run.status !== 'RUNNING') continue;

      const tis = await this.ctx.getTaskInstances(run.id);
      const running = tis.filter(ti => ti.state === 'RUNNING');
      if (running.length === 0) continue;

      const dagDefEntry = await this.ctx.getDagDef(run.dagId);
      if (!dagDefEntry) continue;

      const taskMap = new Map(dagDefEntry.value.tasks.map(t => [t.id, t]));

      for (const ti of running) {
        const task = taskMap.get(ti.taskId);
        if (!task?.timeoutMs) continue;

        const elapsed = ti.startedAt ? Date.now() - ti.startedAt : 0;
        if (elapsed > task.timeoutMs) {
          const msg = `Task timed out after ${String(task.timeoutMs)}ms`;

          if (shouldRetry(ti, task.retries)) {
            const retried = transitionState(ti, 'UP_FOR_RETRY');
            await this.ctx.saveTaskInstance({ ...retried, error: msg });
          } else {
            const failed = markFailed(ti, msg);
            await this.ctx.saveTaskInstance(failed);
          }

          // Release pool slot
          const poolName = task.pool ?? DEFAULT_POOL_NAME;
          const pool = await this.ctx.getPool(poolName);
          if (pool) {
            await this.ctx.updatePool({
              ...pool,
              occupiedSlots: Math.max(0, pool.occupiedSlots - 1),
            });
          }
        }
      }
    }
  }

  // ─── Executor cache ───

  private async getExecutor(key: string): Promise<ITaskExecutor | null> {
    const cached = this.executorCache.get(key);
    if (cached) return cached;

    const executor = await this.ctx.getExecutor(key);
    if (executor) this.executorCache.set(key, executor);
    return executor;
  }
}

import type {
  SchedulableTask,
  ResourceNode,
  ResourceSnapshot,
  Schedule,
  ScheduleEntry,
} from './types.ts';
import type { ISchedulingStrategy, IResourceAllocator } from './interfaces.ts';
import { Dag } from '../../dag/graph.ts';

/**
 * Default scheduling configuration.
 */
export interface DagSchedulerConfig {
  strategy: ISchedulingStrategy;
  allocator: IResourceAllocator;
}

/**
 * Generic DAG-based task scheduler.
 *
 * Takes tasks with resource requirements and a pool of resources,
 * and produces a Schedule that respects:
 *   1. DAG dependency order (no task starts before its dependencies finish)
 *   2. Resource capacity (no over-commit)
 *   3. Strategy-specific optimization (CPM for makespan, etc.)
 *
 * Algorithm (event-driven simulation):
 *   1. Build DAG from task dependencies
 *   2. Topological sort to verify acyclicity
 *   3. Maintain a clock, ready queue, and resource snapshots
 *   4. At each event (task completion), re-evaluate ready tasks
 *   5. Dispatch ready tasks via strategy + allocator
 *   6. Advance clock to next completion event
 *
 * Same abstraction level as src/core/dag/orchestrator.ts.
 *
 * @example
 * ```ts
 * const scheduler = new DagScheduler({
 *   strategy: new CriticalPathStrategy(tasks),
 *   allocator: new LeastRequestedAllocator(),
 * });
 * const schedule = scheduler.schedule(tasks, runners);
 * console.log('makespan:', schedule.makespan);
 * ```
 */
export class DagScheduler {
  public constructor(private readonly config: DagSchedulerConfig) {}

  public schedule(
    tasks: readonly SchedulableTask[],
    resources: readonly ResourceNode[],
  ): Schedule {
    if (tasks.length === 0) {
      return { entries: [], makespan: 0, unassigned: [] };
    }

    // 1. Build & validate DAG
    const dag = new Dag<string, SchedulableTask>(t => t.id);
    for (const t of tasks) dag.addNode(t);
    for (const t of tasks) {
      for (const dep of t.dependsOn) {
        if (dag.hasNode(dep)) dag.addEdge(t.id, dep);
      }
    }
    const topo = dag.topologicalSort();
    if (!topo.success) {
      return { entries: [], makespan: 0, unassigned: tasks.map(t => t.id) };
    }

    // 2. Initialise state
    const entries: ScheduleEntry[] = [];
    const completed = new Set<string>();
    const taskCompletionTime = new Map<string, number>(); // taskId → completionTime (0 = not started)
    let clock = 0;

    // Resource snapshots — track availableAt per resource
    const snapshots = new Map<string, ResourceSnapshot>();
    for (const r of resources) {
      snapshots.set(r.id, {
        node: r,
        available: { ...r.capacity },
        availableAt: 0,
      });
    }

    // 3. Event-driven loop
    while (completed.size < tasks.length) {
      // Collect ready tasks — all deps completed, not yet scheduled
      const ready: SchedulableTask[] = [];
      for (const t of tasks) {
        if (completed.has(t.id)) continue;
        if (taskCompletionTime.has(t.id)) continue; // already scheduled, running

        const depsDone = t.dependsOn.every(d => completed.has(d));
        if (!depsDone) continue;

        ready.push(t);
      }

      if (ready.length === 0) {
        // All remaining tasks are currently running. Advance clock to
        // the next completion event to free resources.
        const nextCompletion = findEarliestCompletion(taskCompletionTime, completed);
        if (nextCompletion === null) break;
        clock = nextCompletion;
        // Mark tasks that completed at or before the new clock
        for (const [taskId, compTime] of taskCompletionTime) {
          if (compTime <= clock && !completed.has(taskId)) {
            completed.add(taskId);
            const entry = entries.find(e => e.taskId === taskId);
            if (entry) {
              const snap = snapshots.get(entry.resourceId);
              const task = tasks.find(t => t.id === taskId);
              if (snap && task) {
                snapshots.set(entry.resourceId, {
                  ...snap,
                  available: add(snap.available, task.requirements),
                });
              }
            }
          }
        }
        continue;
      }

      // Order ready tasks by strategy
      const ordered = this.config.strategy.order(ready);

      // Try to assign each ready task to a resource
      let assignedAny = false;
      for (const task of ordered) {
        const resList = [...snapshots.values()];

        // Advance each resource's availableAt to at least clock
        for (const [rid, snap] of snapshots) {
          if (snap.availableAt < clock) {
            snapshots.set(rid, { ...snap, availableAt: clock });
          }
        }

        const chosenId = this.config.allocator.select(task, resList);
        if (chosenId === null) continue; // can't assign now, try later

        const chosen = snapshots.get(chosenId)!;
        const startTime = Math.max(clock, chosen.availableAt);
        const completionTime = startTime + task.estimatedDuration;

        // Consume capacity
        const newAvail = subtract(chosen.available, task.requirements);
        snapshots.set(chosenId, {
          ...chosen,
          available: newAvail,
          availableAt: completionTime,
        });

        entries.push({ taskId: task.id, resourceId: chosenId, startTime, completionTime });
        taskCompletionTime.set(task.id, completionTime);
        assignedAny = true;
      }

      if (!assignedAny) {
        // Resource shortage — advance clock to next completion to free capacity
        const nextCompletion = findEarliestCompletion(taskCompletionTime, completed);
        if (nextCompletion === null) break;
        clock = nextCompletion;

        // Release resources of completed tasks
        for (const [taskId, compTime] of taskCompletionTime) {
          if (compTime <= clock && !completed.has(taskId)) {
            completed.add(taskId);
            // Release capacity
            const entry = entries.find(e => e.taskId === taskId);
            if (entry) {
              const snap = snapshots.get(entry.resourceId);
              if (snap) {
                const task = tasks.find(t => t.id === taskId);
                if (task) {
                  snapshots.set(entry.resourceId, {
                    ...snap,
                    available: add(snap.available, task.requirements),
                  });
                }
              }
            }
          }
        }
        continue;
      }

      // Advance clock to next completion event
      const nextCompletion = findEarliestCompletion(taskCompletionTime, completed);
      if (nextCompletion === null) break;
      clock = nextCompletion;

      // Mark completed tasks and release resources
      for (const [taskId, compTime] of taskCompletionTime) {
        if (compTime <= clock && !completed.has(taskId)) {
          completed.add(taskId);
          const entry = entries.find(e => e.taskId === taskId);
          if (entry) {
            const snap = snapshots.get(entry.resourceId);
            const task = tasks.find(t => t.id === taskId);
            if (snap && task) {
              snapshots.set(entry.resourceId, {
                ...snap,
                available: add(snap.available, task.requirements),
              });
            }
          }
        }
      }
    }

    // Collect unassigned (tasks that never got an entry)
    const assignedIds = new Set(entries.map(e => e.taskId));
    const unassigned = tasks.filter(t => !assignedIds.has(t.id)).map(t => t.id);
    const makespan = entries.reduce((max, e) => Math.max(max, e.completionTime), 0);

    return { entries, makespan, unassigned };
  }
}

// ─── Helpers ───

function subtract(a: { cpu: number; memory: number; gpu?: number }, b: { cpu: number; memory: number; gpu?: number }): { cpu: number; memory: number; gpu?: number } {
  return {
    cpu: a.cpu - b.cpu,
    memory: a.memory - b.memory,
    ...(a.gpu !== undefined || b.gpu !== undefined ? { gpu: (a.gpu ?? 0) - (b.gpu ?? 0) } : {}),
  };
}

function add(a: { cpu: number; memory: number; gpu?: number }, b: { cpu: number; memory: number; gpu?: number }): { cpu: number; memory: number; gpu?: number } {
  return {
    cpu: a.cpu + b.cpu,
    memory: a.memory + b.memory,
    ...(a.gpu !== undefined || b.gpu !== undefined ? { gpu: (a.gpu ?? 0) + (b.gpu ?? 0) } : {}),
  };
}

function findEarliestCompletion(
  completionTimes: Map<string, number>,
  completed: Set<string>,
): number | null {
  let earliest = Infinity;
  for (const [id, t] of completionTimes) {
    if (!completed.has(id) && t < earliest) earliest = t;
  }
  return earliest === Infinity ? null : earliest;
}

import type { ITimerBackend, TimerHandle } from './interfaces.ts';

/**
 * Durable Object Alarm–backed timer.
 *
 * **Production** (with `callbackUrl`):
 * The DO Alarm is the sole timing source — no `setInterval`, no clock wall.
 * The DO fires → calls `callbackUrl` via `fetch()` → Worker route →
 * `loop.triggerTick()`. Reliable across all Worker isolates.
 *
 * **Local dev** (without `callbackUrl`):
 * Falls back to `setInterval` + DO alarm overlay for observability.
 *
 * @example
 * ```ts
 * // Production: callback drives the tick
 * const backend = new DoAlarmBackend(stub, 'http://my-worker/__scheduled');
 *
 * // Local dev: setInterval fallback
 * const backend = new DoAlarmBackend(stub);
 * ```
 */
export class DoAlarmBackend implements ITimerBackend {
  readonly #doStub: DurableObjectStub;
  readonly #callbackUrl: string | undefined;
  #localTimerId: ReturnType<typeof setInterval> | null = null;

  public constructor(doStub: DurableObjectStub, callbackUrl?: string  ) {
    this.#doStub = doStub;
    this.#callbackUrl = callbackUrl;
  }

  public start(handler: () => void, intervalMs: number): TimerHandle {
    // In production mode (callbackUrl set), the DO alarm drives the tick
    // via HTTP callback — the handler is wired through the Worker route.
    // In dev mode, use setInterval to call the handler directly.
    if (!this.#callbackUrl) {
      this.#localTimerId = setInterval(handler, intervalMs);
    }

    // Configure DO alarm in both modes (for observability / production path)
    this.#doStub.fetch('http://do/start', {
      method: 'POST',
      body: JSON.stringify({ intervalMs, callbackUrl: this.#callbackUrl }),
    }).catch(() => { /* noop */ });

    return {
      clear: () => {
        if (this.#localTimerId !== null) {
          clearInterval(this.#localTimerId);
          this.#localTimerId = null;
        }
        this.#doStub.fetch('http://do/stop', { method: 'POST' }).catch(() => { /* noop */ });
      },
    };
  }
}

import type { ITimerBackend, SchedulerBackendType } from './interfaces.ts';
import { SetIntervalBackend } from './set-interval-backend.ts';
import { ManualBackend } from './manual-backend.ts';
import { DoAlarmBackend } from './do-alarm-backend.ts';

export interface TimerBackendOptions {
  /** Required when type is `do-alarm`. */
  readonly doNamespace?: DurableObjectNamespace | undefined;
  /**
   * Callback URL the DO Alarm calls to trigger the tick.
   * In production: `https://my-worker/__scheduled`.
   * In dev (with `wrangler dev --test-scheduled`): `http://localhost:8787/__scheduled`.
   * When omitted, falls back to `setInterval` (dev mode).
   */
  readonly callbackUrl?: string | undefined;
}

/**
 * Create a timer backend from a type discriminator.
 *
 * @example
 * ```ts
 * // Worker backend (default)
 * const backend = createTimerBackend('worker');
 *
 * // DO Alarm backend with callback (production — no setInterval)
 * const backend = createTimerBackend('do-alarm', {
 *   doNamespace: env.ALARM_TIMER_DO,
 *   callbackUrl: 'https://my-worker/__scheduled',
 * });
 *
 * // DO Alarm backend without callback (dev — setInterval fallback)
 * const backend = createTimerBackend('do-alarm', {
 *   doNamespace: env.ALARM_TIMER_DO,
 * });
 * ```
 */
export function createTimerBackend(type: SchedulerBackendType, options?: TimerBackendOptions): ITimerBackend {
  // Auto-upgrade only when callbackUrl is set (production-ready).
  // In dev without WORKER_URL, keep setInterval — DO alarm in workerd
  // requires continuous I/O to fire, and stalls when the Worker is idle.
  if (type === 'worker' && options?.doNamespace && options?.callbackUrl) {
    type = 'do-alarm';
  }

  switch (type) {
    case 'worker':
      return new SetIntervalBackend();
    case 'manual':
      return new ManualBackend();
    case 'do-alarm': {
      if (!options?.doNamespace) {
        // Without DO namespace, fall back to setInterval
        return new SetIntervalBackend();
      }
      const id = options.doNamespace.idFromName('event-loop');
      const doStub = options.doNamespace.get(id);
      return new DoAlarmBackend(doStub, options.callbackUrl);
    }
  }
}

import type { TaskInstance, Task } from '../dag/types.ts';
import type { ConcurrencyMap } from './concurrency-map.ts';

/**
 * 5-step filter pipeline — Airflow `_executable_task_instances_to_queued()`.
 *
 * Given a set of SCHEDULED TaskInstances, each step filters out tasks that
 * exceed concurrency limits. Tasks that pass all 5 steps are eligible to
 * advance to QUEUED.
 *
 * Step order (matches Airflow):
 *   1. Pool slot check — pool has room?
 *   2. DAG concurrency (max_active_tasks) — too many active TIs for this DAG?
 *   3. Task concurrency (max_active_tis_per_dag) — too many instances of this task?
 *   4. DagRun concurrency (max_active_tis_per_dagrun) — too many in this specific run?
 *   5. Executor slot (parallelism) — overall system limit?
 */

export interface FilterContext {
  readonly tasks: ReadonlyMap<string, Task>;
  readonly poolSlots: ReadonlyMap<string, number>;  // pool name → open slots
  readonly dagMaxActive: ReadonlyMap<string, number>;  // dagId → max_active_tasks
  readonly concurrencyMap: ConcurrencyMap;
  readonly parallelism: number;  // max total concurrent executions
  readonly alreadyQueued: number;  // already-queued count from this tick
}

export interface FilterResult {
  /** Tasks that passed all 5 filters — can advance to QUEUED. */
  readonly passed: readonly TaskInstance[];
  /** Starvation counts per filter step (for diagnostics/audit). */
  readonly starved: StarvationCounts;
}

export interface StarvationCounts {
  pool: number;
  dag: number;
  task: number;
  dagRun: number;
  executor: number;
}

export function emptyStarvation(): StarvationCounts {
  return { pool: 0, dag: 0, task: 0, dagRun: 0, executor: 0 };
}

/**
 * Extract dagId from dagRunId.
 * Format: `dr_<dagId>_<execDate>_<uuid>` — dagId is between first and second `_`.
 */
function dagIdFromRun(dagRunId: string): string {
  const parts = dagRunId.split('_');
  // Format: dr_<dagId>_...
  if (parts.length >= 2 && parts[0] === 'dr') {
    return parts[1]!;
  }
  // Fallback: everything before second underscore
  return parts.length >= 3 ? parts[1]! : dagRunId;
}

/**
 * Run the 5-step filter on a batch of SCHEDULED TaskInstances.
 * Returns the subset that can proceed to QUEUED.
 */
export function filterScheduledTasks(
  scheduled: readonly TaskInstance[],
  ctx: FilterContext,
): FilterResult {
  const starved: StarvationCounts = emptyStarvation();

  // Track pool slot usage within this tick (local to this filter call)
  const localPoolUsage = new Map<string, number>();

  const passed: TaskInstance[] = [];

  for (const ti of scheduled) {
    const task = ctx.tasks.get(ti.taskId);
    const dagId = dagIdFromRun(ti.dagRunId);

    // Step 1: Pool slot check
    const poolName = task?.pool ?? 'default_pool';
    const poolOpenSlots = ctx.poolSlots.get(poolName) ?? 128; // default_pool → 128
    const localUsed = localPoolUsage.get(poolName) ?? 0;
    if (poolOpenSlots - localUsed <= 0) {
      starved.pool++;
      continue;
    }

    // Step 2: DAG concurrency
    const maxDagActive = ctx.dagMaxActive.get(dagId) ?? 16;
    if (ctx.concurrencyMap.dagActiveCount(dagId) >= maxDagActive) {
      starved.dag++;
      continue;
    }

    // Step 3: Task concurrency
    const maxTaskActive = task?.maxActiveTisPerDag ?? 16;
    if (ctx.concurrencyMap.taskActiveCount(dagId, ti.taskId) >= maxTaskActive) {
      starved.task++;
      continue;
    }

    // Step 4: DagRun concurrency (default: no limit = large number)
    // We check: have we exceeded the limit for this specific DagRun?
    // Default matches Airflow — max_active_tis_per_dagrun defaults to
    // dagrun's own task count.
    if (ctx.concurrencyMap.dagRunActiveCount(dagId, ti.dagRunId) >= 256) {
      starved.dagRun++;
      continue;
    }

    // Step 5: Executor slot (parallelism)
    // Count: already-running + already-queued-this-tick + about-to-queue
    const projectedActive = ctx.concurrencyMap.dagActiveCount(dagId) +
      ctx.alreadyQueued + passed.length;
    if (projectedActive >= ctx.parallelism) {
      starved.executor++;
      continue;
    }

    // All checks passed — claim local pool slot and add to passed
    localPoolUsage.set(poolName, localUsed + 1);
    passed.push(ti);
  }

  return { passed, starved };
}

// ─── Timer backend (pluggable timing strategy) ───

/**
 * Backend type discriminator, settable via `SCHEDULER_BACKEND` env var.
 *
 * - `worker` — `SetIntervalBackend`, works in Workers & Node (default).
 * - `manual` — no automatic timer; ticks must be triggered externally.
 * - `do-alarm` — `DoAlarmBackend`, DO Alarm–gated scheduling (works in
 *   Miniflare, so local dev simulates production behavior).
 */
export type SchedulerBackendType = 'worker' | 'manual' | 'do-alarm';

/** Opaque handle returned by {@link ITimerBackend.start}. */
export interface TimerHandle {
  /** Cancel the timer. No-op if already cancelled. */
  clear(): void;
}

/**
 * Pluggable timing strategy.
 *
 * Different runtimes can provide different backends:
 * - **Workers / Node**: `SetIntervalBackend` (default).
 * - **DO Alarm**: `DoAlarmBackend` — works in Miniflare and production.
 * - **Manual**: no automatic timer, explicit `tick()` calls.
 * - **Test**: `FakeTimerBackend` — no wall-clock dependency, explicit `tick()`.
 */
export interface ITimerBackend {
  /** Start a recurring timer. Returns a handle to cancel it. */
  start(handler: () => void, intervalMs: number): TimerHandle;
}

// ─── Scheduler lifecycle (common contract for all cron-like subsystems) ───

export interface SchedulerConfig {
  /** Tick interval in milliseconds. */
  intervalMs: number;
  /** Start processing immediately after construction. */
  autoStart: boolean;
}

export interface SchedulerStatus {
  running: boolean;
  paused: boolean;
  uptimeMs: number;
  config: SchedulerConfig;
}

/**
 * Common scheduler lifecycle contract.
 *
 * Implemented by {@link import('../event-bus/loop.ts').EventLoop} and designed
 * for future use by {@link import('../cleanup/interfaces.ts').ICleanupPoller}.
 *
 * @example
 * ```ts
 * function acceptAnyScheduler(s: IScheduler) {
 *   s.start();
 *   s.pause();
 *   s.resume();
 *   console.log(s.status());
 *   s.stop();
 * }
 * ```
 */
export interface IScheduler {
  start(): void;
  stop(): void;
  pause(): void;
  resume(): void;
  configure(config: Partial<SchedulerConfig>): SchedulerConfig;
  status(): SchedulerStatus;
}

/**
 * Probe evaluation — kubelet-style health check execution.
 *
 * Three probe types:
 *   livenessProbe  — container is alive?  Failure → restart
 *   readinessProbe — can serve traffic?   Failure → remove from endpoints
 *   startupProbe   — has started?          Failure → restart (liveness/readiness disabled during startup)
 *
 * Handler types:
 *   exec      — run command inside container (exit 0 = success)
 *   httpGet   — HTTP GET to container port (2xx/3xx = success)
 *   tcpSocket — TCP connect to container port (established = success)
 *
 * References:
 *   K8s Pod lifecycle: https://kubernetes.io/docs/concepts/workloads/pods/pod-lifecycle/#container-probes
 */

import type { ProbeSpec } from '../provider/types.ts';

// ─── Probe types ───

export type ProbeType = 'liveness' | 'readiness' | 'startup';

export interface ProbeResult {
  type: ProbeType;
  success: boolean;
  message?: string;
  /** If true, container should be restarted. */
  shouldRestart: boolean;
  /** If true, container should be removed from service endpoints. */
  shouldRemoveEndpoint: boolean;
}

export interface ProbeState {
  consecutiveFailures: number;
  consecutiveSuccesses: number;
  lastProbeAt: number;
  /** True when no startup probe is configured OR startup probe has succeeded. Default true. */
  startupComplete: boolean;
  /** Set to true when a startup probe is first evaluated. Enables gating. */
  hasStartupProbe: boolean;
}

// ─── Defaults (K8s-aligned) ───

const DEFAULT_INITIAL_DELAY = 0;
const DEFAULT_TIMEOUT = 1;       // seconds
const DEFAULT_PERIOD = 10;       // seconds
const DEFAULT_SUCCESS_THRESHOLD = 1;
const DEFAULT_FAILURE_THRESHOLD = 3;

// ─── Evaluation ───

/** Simulate running a probe against a container. Returns success + optional message. */
export type ProbeHandler = (spec: ProbeSpec) => Promise<{ success: boolean; message?: string }>;

/** Create a state tracker for a container's probes. */
export function createProbeState(): ProbeState {
  return { consecutiveFailures: 0, consecutiveSuccesses: 0, lastProbeAt: 0, startupComplete: true, hasStartupProbe: false };
}

/** Evaluate a probe and return the result. */
export async function evaluateProbe(
  type: ProbeType,
  spec: ProbeSpec | undefined,
  state: ProbeState,
  handler: ProbeHandler,
  now: number = Date.now(),
): Promise<ProbeResult> {
  if (!spec) {
    return { type, success: true, message: 'no probe configured', shouldRestart: false, shouldRemoveEndpoint: false };
  }

  const periodMs = (spec.periodSeconds ?? DEFAULT_PERIOD) * 1000;
  if (now - state.lastProbeAt < periodMs) {
    return { type, success: true, message: 'skipped (not due)', shouldRestart: false, shouldRemoveEndpoint: false };
  }
  state.lastProbeAt = now;

  // During startup, only run startupProbe; liveness/readiness are gated
  if (type === 'startup') {
    state.hasStartupProbe = true;
    state.startupComplete = false; // set to false first time startup probe runs
    // Will be set to true below if successThreshold met
  }
  if (!state.startupComplete && state.hasStartupProbe && type !== 'startup') {
    return { type, success: true, message: 'gated by startup probe', shouldRestart: false, shouldRemoveEndpoint: false };
  }

  const timeoutMs = (spec.timeoutSeconds ?? DEFAULT_TIMEOUT) * 1000;
  let success: boolean;
  let message: string;

  try {
    const result = await Promise.race([
      handler(spec),
      new Promise<{ success: false; message: string }>((_, reject) =>
        setTimeout(() => { reject(new Error('probe timeout')); }, timeoutMs),
      ),
    ]);
    success = result.success;
    message = result.message ?? '';
  } catch (e: any) {
    success = false;
    message = e?.message ?? 'probe error';
  }

  // Update state
  if (success) {
    state.consecutiveSuccesses++;
    state.consecutiveFailures = 0;
  } else {
    state.consecutiveFailures++;
    state.consecutiveSuccesses = 0;
  }

  // Threshold checks
  const failureThreshold = spec.failureThreshold ?? DEFAULT_FAILURE_THRESHOLD;
  const successThreshold = spec.successThreshold ?? DEFAULT_SUCCESS_THRESHOLD;

  const isFailing = state.consecutiveFailures >= failureThreshold;

  // Startup probe: on first success, mark startup complete
  if (type === 'startup' && state.consecutiveSuccesses >= successThreshold) {
    state.startupComplete = true;
  }

  if (type === 'startup' && success) {
    // Pass initialDelaySeconds after first startup success
    const initialDelayMs = (spec.initialDelaySeconds ?? DEFAULT_INITIAL_DELAY) * 1000;
    if (initialDelayMs > 0 && now - state.lastProbeAt < initialDelayMs) {
      return { type, success: true, message: 'startup probe passed', shouldRestart: false, shouldRemoveEndpoint: false };
    }
  }

  return {
    type,
    success,
    message: success ? message || 'probe passed' : message || `probe failed (${String(state.consecutiveFailures)}/${String(failureThreshold)})`,
    shouldRestart: isFailing && type !== 'readiness',  // readiness failure → don't restart
    shouldRemoveEndpoint: isFailing && type === 'readiness',
  };
}

