import { readFile, writeFile, mkdir, rm } from 'node:fs/promises';
import { join, resolve } from 'node:path';
import type { IAtomicStore, IStoreTransaction } from '../interfaces.ts';
import { TransactConflictError } from '../interfaces.ts';
import type { VersionId } from '../../brand.ts';
import { generateVersionId } from '../../brand.ts';

const { parse: parseJson } = JSON;

interface FileEntry<T = unknown> {
  value: T;
  metadata: { v: string; e?: number };
}

/**
 * Local file-based adapter for Node.js development.
 * Each key is a JSON file in `dataDir`.
 * Restart-safe — data survives across process restarts.
 *
 * Concurrency: all operations serialised via a global promise chain so
 * that read-compare-write sequences are safe from races within the same
 * process. Cross-process safety is NOT provided (adapter is for dev only).
 */
export class FileKVAtomicStore implements IAtomicStore {
  #dataDir: string;
  #lock: Promise<void> = Promise.resolve();

  public constructor(basePath: string) {
    this.#dataDir = resolve(basePath);
  }

  #serialise<T>(fn: () => Promise<T>): Promise<T> {
    const prev = this.#lock;
    let release!: () => void;
    this.#lock = new Promise(resolve => { release = resolve; });
    return prev.then(async () => {
      try {
        return await fn();
      } finally {
        release();
      }
    });
  }

  async #ensureDir(): Promise<void> {
    await mkdir(this.#dataDir, { recursive: true });
  }

  #filePath(key: string): string {
    const safe = key.replace(/[^a-zA-Z0-9._-]/g, '_');
    return join(this.#dataDir, `${safe}.json`);
  }

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters -- interface contract requires generics
  public async get<T>(key: string): Promise<{ value: T; version: VersionId } | null> {
    return this.#serialise(async () => {
      await this.#ensureDir();
      try {
        const raw = await readFile(this.#filePath(key), 'utf-8');
        const entry = parseJson(raw) as FileEntry<T>;
        if (entry.metadata.e && Date.now() > entry.metadata.e) {
          // TTL expired — delete file and return null
          try { await rm(this.#filePath(key), { force: true }); } catch { /* file may not exist */ }
          return null;
        }
        // null value = deleted — consistent with DO adapter behavior
        if (entry.value === null) return null;
        return { value: entry.value, version: entry.metadata.v as VersionId };
      } catch {
        return null;
      }
    });
  }

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters -- interface contract requires generics
  public async set<T>(key: string, value: T, expectedVersion: VersionId | null, ttlSeconds?: number): Promise<VersionId | null> {
    return this.#serialise(async () => {
      await this.#ensureDir();
      const fp = this.#filePath(key);

      let current: FileEntry | null = null;
      try {
        current = parseJson(await readFile(fp, 'utf-8')) as FileEntry;
      } catch {
        // file doesn't exist
      }

      if (expectedVersion === null && current !== null) return null;
      if (expectedVersion !== null && current?.metadata.v !== expectedVersion) return null;

      const newVersion = generateVersionId();
      const metadata: { v: string; e?: number } = { v: newVersion };
      if (ttlSeconds !== undefined) metadata.e = Date.now() + ttlSeconds * 1000;
      const entry: FileEntry = { value, metadata };
      await writeFile(fp, JSON.stringify(entry), 'utf-8');
      return newVersion;
    });
  }

  public async transact<T>(action: (txn: IStoreTransaction) => Promise<T>): Promise<T> {
    return this.#serialise(async () => {
      await this.#ensureDir();
      const readSet = new Map<string, string | null>(); // null = key didn't exist
      const deferredWrites = new Map<string, { value: unknown; version: VersionId; ttlSeconds?: number }>();

      const txn: IStoreTransaction = {
        get: async <V>(key: string) => {
          const dw = deferredWrites.get(key);
          if (dw !== undefined) return dw.value as V;

          try {
            const raw = await readFile(this.#filePath(key), 'utf-8');
            const entry = parseJson(raw) as FileEntry<V>;
            readSet.set(key, entry.metadata.v);
            return entry.value;
          } catch {
            readSet.set(key, null);
            return null;
          }
        },
        getMany: async <V>(keys: string[]) => {
          const results: (V | null)[] = [];
          for (const key of keys) {
            const dw = deferredWrites.get(key);
            if (dw !== undefined) {
              results.push(dw.value as V);
              continue;
            }
            try {
              const raw = await readFile(this.#filePath(key), 'utf-8');
              const entry = parseJson(raw) as FileEntry<V>;
              readSet.set(key, entry.metadata.v);
              results.push(entry.value);
            } catch {
              readSet.set(key, null);
              results.push(null);
            }
          }
          return results;
        },
        // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters -- interface contract requires generics
        set: <V>(key: string, value: V, ttlSeconds?: number) => {
          const newVersion = generateVersionId();
          deferredWrites.set(key, { value, version: newVersion, ...(ttlSeconds !== undefined && { ttlSeconds }) });
        },
      };

      const result = await action(txn);

      // Verify read-set versions haven't changed (excluding own writes)
      for (const [key, expectedVersion] of readSet) {
        if (deferredWrites.has(key)) continue;

        let currentVersion: string | null;
        try {
          const raw = await readFile(this.#filePath(key), 'utf-8');
          const entry = parseJson(raw) as FileEntry;
          currentVersion = entry.metadata.v;
        } catch {
          currentVersion = null;
        }

        if (currentVersion !== expectedVersion) {
          throw new TransactConflictError(
            `Transaction conflict: key "${key}" was modified concurrently.`,
          );
        }
      }

      for (const [key, { value, version, ttlSeconds }] of deferredWrites) {
        const metadata: { v: string; e?: number } = { v: version };
        if (ttlSeconds !== undefined) metadata.e = Date.now() + ttlSeconds * 1000;
        const entry: FileEntry = { value, metadata };
        await writeFile(this.#filePath(key), JSON.stringify(entry), 'utf-8');
      }

      return result;
    });
  }
}

import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { resolve, join } from 'node:path';
import type { IQueryStore, QueryParams } from '../interfaces.ts';

const { parse: parseJson } = JSON;

/**
 * Local file-based query store for Node.js development.
 * Each "table" is a JSON file containing an array of objects.
 * Supports a very limited subset of SQL — just enough for dev.
 */
export class FileQueryStore implements IQueryStore {
  #dataDir: string;

  public constructor(basePath: string) {
    this.#dataDir = resolve(basePath, 'query');
  }

  async #ensureDir(): Promise<void> {
    await mkdir(this.#dataDir, { recursive: true });
  }

  #tablePath(table: string): string {
    return join(this.#dataDir, `${table}.json`);
  }

  async #readTable(table: string): Promise<Record<string, unknown>[]> {
    try {
      const raw = await readFile(this.#tablePath(table), 'utf-8');
      return parseJson(raw) as Record<string, unknown>[];
    } catch {
      return [];
    }
  }

  async #writeTable(table: string, rows: Record<string, unknown>[]): Promise<void> {
    await writeFile(this.#tablePath(table), JSON.stringify(rows), 'utf-8');
  }

  public async execute<T = unknown>(sql: string, params?: QueryParams): Promise<T[]> {
    await this.#ensureDir();

    // Minimal SQL parser: supports SELECT * FROM <table> WHERE <col> = <val>
    const selectMatch = /SELECT\s+\*\s+FROM\s+(\w+)(?:\s+WHERE\s+(.+))?/i.exec(sql);
    if (selectMatch) {
      const table = selectMatch[1]!;
      let rows = await this.#readTable(table);

      if (selectMatch[2]) {
        const whereClause = selectMatch[2].trim();
        // Simple WHERE col = $1
        const whereMatch = /(\w+)\s*=\s*\?/.exec(whereClause);
        if (whereMatch && Array.isArray(params)) {
          const col = whereMatch[1]!;
          rows = rows.filter(r => r[col] === params[0]);
        }
      }

      return rows as T[];
    }

    // INSERT INTO <table> VALUES (...)
    const insertMatch = /INSERT\s+INTO\s+(\w+)\s+VALUES\s*\((.+)\)/i.exec(sql);
    if (insertMatch) {
      const table = insertMatch[1]!;
      const rows = await this.#readTable(table);
      // Very naive — just appends params as a row
      if (Array.isArray(params)) {
        const newRow: Record<string, unknown> = {};
        for (let i = 0; i < params.length; i++) {
          newRow[`col${String(i)}`] = params[i];
        }
        rows.push(newRow);
        await this.#writeTable(table, rows);
      }
      return [] as T[];
    }

    // Unsupported — return empty for dev
    return [] as T[];
  }
}

/// <reference types="@cloudflare/workers-types" />

import type { IBlobStore, BlobMetadata } from '../interfaces.ts';

export class R2BlobStore implements IBlobStore {
  public constructor(private readonly bucket: R2Bucket) {}

  public async put(key: string, body: ReadableStream | ArrayBuffer, metadata?: BlobMetadata): Promise<void> {
    const options: Record<string, unknown> = {};
    if (metadata?.contentType) {
      options.httpMetadata = { contentType: metadata.contentType };
    }
    if (metadata?.custom) {
      options.customMetadata = metadata.custom;
    }
    await this.bucket.put(key, body, options as R2PutOptions);
  }

  public async get(key: string): Promise<ReadableStream | null> {
    const obj = await this.bucket.get(key);
    return obj?.body ?? null;
  }

  public async delete(key: string): Promise<void> {
    await this.bucket.delete(key);
  }
}

/// <reference types="@cloudflare/workers-types" />

import type { StorageConfig } from './config.ts';
import type { IAtomicStore, IQueryStore, IBlobStore, Stores } from './interfaces.ts';

// Cloudflare adapters
import { CloudflareKVAtomicStore } from './adapters/cloudflare-kv.ts';
import { DurableObjectAtomicStore } from './adapters/durable-object.ts';
import { CachedAtomicStore } from './adapters/cached.ts';
import { D1QueryStore } from './adapters/d1.ts';
import { R2BlobStore } from './adapters/r2.ts';

// Metrics abstraction
import { AtomicStoreMetrics } from './metrics.ts';

export async function createStores(config: StorageConfig, platformBindings?: Record<string, unknown>): Promise<Stores> {
  const filePath = config.connections.filePath ?? '.data';
  const metrics = new AtomicStoreMetrics();

  return {
    atomic: await createAtomicStore(config, platformBindings, filePath, metrics),
    query: await createQueryStore(config, platformBindings, filePath),
    blob: await createBlobStore(config, platformBindings, filePath),
    metrics,
  };
}

// ══════════════════════════════════════════════
// Atomic store
// ══════════════════════════════════════════════

// eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters -- interface contract requires generics
function resolveBinding<T>(name: string, bindings?: Record<string, unknown>): T | undefined {
  return bindings?.[name] as T | undefined;
}

async function createAtomicStore(
  config: StorageConfig,
  bindings?: Record<string, unknown>,
  filePath?: string,
  metrics?: AtomicStoreMetrics,
): Promise<IAtomicStore> {
  const doNsName = config.connections.doNamespace ?? 'ATOMIC_STORE_DO';
  const kvNsName = config.connections.kvNamespace ?? 'KV_STORE';

  const doNs = resolveBinding<DurableObjectNamespace>(doNsName, bindings);
  const kvNs = resolveBinding<KVNamespace>(kvNsName, bindings);

  const doStore = doNs
    ? new DurableObjectAtomicStore(doNs)
    : null;
  const kvStore = kvNs ? new CloudflareKVAtomicStore(kvNs) : null;

  if (doStore && kvStore) {
    return new CachedAtomicStore(doStore, kvStore, 30_000, config.cacheTtlSeconds, metrics);
  }
  if (doStore) return doStore;
  if (kvStore) return kvStore;

  const { FileKVAtomicStore } = await import('./adapters/file-kv.ts');
  return new FileKVAtomicStore(filePath ?? '.data/kv');
}

// ══════════════════════════════════════════════
// Query store (D1 > file > none)
// ══════════════════════════════════════════════

async function createQueryStore(
  config: StorageConfig,
  bindings?: Record<string, unknown>,
  filePath?: string,
): Promise<IQueryStore> {
  const d1Name = config.connections.d1Binding ?? 'QUERY_DB';
  const db = resolveBinding<D1Database>(d1Name, bindings);
  if (db) return new D1QueryStore(db);

  if (config.queryBackend === 'file' || config.queryBackend === 'd1') {
    const { FileQueryStore } = await import('./adapters/file-query.ts');
    return new FileQueryStore(filePath ?? '.data');
  }

  return {
    // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
    async execute() {
      throw new Error('QueryStore not configured. Set queryBackend or bind a D1 database.');
    },
  };
}

// ══════════════════════════════════════════════
// Blob store (R2 > file > none)
// ══════════════════════════════════════════════

async function createBlobStore(
  config: StorageConfig,
  bindings?: Record<string, unknown>,
  filePath?: string,
): Promise<IBlobStore> {
  const r2Name = config.connections.r2Binding ?? 'BLOB_STORE';
  const bucket = resolveBinding<R2Bucket>(r2Name, bindings);
  if (bucket) return new R2BlobStore(bucket);

  if (config.blobBackend === 'file' || config.blobBackend === 'r2') {
    const { FileBlobStore } = await import('./adapters/file-blob.ts');
    return new FileBlobStore(filePath ?? '.data');
  }

  return {
    // eslint-disable-next-line @typescript-eslint/no-empty-function -- noop adapter
    async put() { /* noop */ },
    // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
    async get() { return null; },
    // eslint-disable-next-line @typescript-eslint/no-empty-function -- noop adapter
    async delete() { /* noop */ },
  };
}

