/**
 * Request-scoped atomic store cache.
 * Wraps IAtomicStore and caches get() results per-key within a single request.
 * Transparently eliminates duplicate reads without changing business logic.
 *
 * Use case: in authz middleware chain, the same user/perm/route-ACL key may be
 * read multiple times (auth middleware → PermissionChecker → RouteAclManager).
 * This wrapper serves the second+ read from an in-memory map.
 *
 * set() and transact() bypass cache (writes must go to the real store).
 * invalidateCache() clears the cached entry.
 */

import type { IAtomicStore, IStoreTransaction } from './interfaces.ts';
import type { VersionId } from '../brand.ts';

export class RequestCachedAtomicStore implements IAtomicStore {
  readonly #inner: IAtomicStore;
  readonly #cache = new Map<string, { value: unknown; version: VersionId } | null>();

  public constructor(inner: IAtomicStore) {
    this.#inner = inner;
  }

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters -- interface contract requires generics
  public async get<T>(key: string): Promise<{ value: T; version: VersionId } | null> {
    const cached = this.#cache.get(key);
    if (cached !== undefined) return cached as { value: T; version: VersionId } | null;

    const result = await this.#inner.get<T>(key);
    this.#cache.set(key, result);
    return result;
  }

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters -- interface contract requires generics
  public async set<T>(key: string, value: T, expectedVersion: VersionId | null, ttlSeconds?: number): Promise<VersionId | null> {
    this.#cache.delete(key);
    return this.#inner.set(key, value, expectedVersion, ttlSeconds);
  }

  public async transact<T>(action: (txn: IStoreTransaction) => Promise<T>): Promise<T> {
    const result = await this.#inner.transact(action);
    this.#cache.clear();
    return result;
  }

  public invalidateCache(key: string): Promise<void> {
    this.#cache.delete(key);
    return this.#inner.invalidateCache?.(key) ?? Promise.resolve();
  }
}

/**
 * Storage-boundary validation — ensures data read from the store
 * conforms to the expected schema before entering business logic.
 *
 * Use getValidated() instead of raw atomic.get() when the shape
 * of stored data matters for correctness. In development, a
 * schema mismatch is a hard error; in production, it logs and
 * returns null to prevent corrupt data propagation.
 *
 * Pattern:
 *   const vol = await getValidated(atomic, key, VolumeSchema);
 *   // vol is Volume | null, guaranteed to match the schema
 */

import type { ZodType } from 'zod';
import type { IAtomicStore } from './interfaces.ts';

/**
 * Read and validate an entity from the atomic store.
 *
 * Returns null if the key doesn't exist or if the stored data
 * fails schema validation (corrupted entry).
 */
export async function getValidated<T>(
  atomic: IAtomicStore,
  key: string,
  schema: ZodType<T>,
): Promise<T | null> {
  const entry = await atomic.get<unknown>(key);
  if (!entry) return null;

  const result = schema.safeParse(entry.value);
  if (!result.success) {
    const issues = result.error.issues.map(i => `${i.path.join('.')}: ${i.message}`).join('; ');
    console.error(`[store] Schema validation failed for ${key}: ${issues}`);
    // In production, return null to prevent corrupt data propagation.
    // In dev/test, this is a bug — the data should have been valid when written.
    return null;
  }
  return result.data;
}

/**
 * Validate and store an entity. Ensures the data matches the schema
 * BEFORE writing, catching bugs at the source.
 */
export async function setValidated<T>(
  atomic: IAtomicStore,
  key: string,
  value: T,
  schema: ZodType<T>,
  expectedVersion: any,
): Promise<any> {
  const result = schema.safeParse(value);
  if (!result.success) {
    const issues = result.error.issues.map(i => `${i.path.join('.')}: ${i.message}`).join('; ');
    throw new Error(`[store] Refusing to write invalid data to ${key}: ${issues}`);
  }
  return atomic.set(key, result.data, expectedVersion);
}

import type { BinaryTreeNode, BinaryTreeTraversalOrder } from './interfaces.ts';

/**
 * Generic binary tree base class.
 *
 * Each node has at most two children: `left` and `right`. Provides
 * traversal (preorder, inorder, postorder, BFS, DFS), search, and
 * mutation primitives.
 *
 * This is a general binary tree — not a BST. For a BST, extend this
 * class and enforce ordering in `setLeft`/`setRight`.
 *
 * @example
 * ```ts
 * class ExpressionTree extends BinaryTree<string> {
 *   evaluate(node?: BinaryTreeNode<string>): number {
 *     const n = node ?? this.root;
 *     if (!n) throw new Error('Empty tree');
 *     if (!n.left || !n.right) return Number(n.value);
 *     const l = this.evaluate(n.left);
 *     const r = this.evaluate(n.right);
 *     switch (n.value) {
 *       case '+': return l + r;
 *       case '-': return l - r;
 *       case '*': return l * r;
 *       case '/': return l / r;
 *       default: return Number(n.value);
 *     }
 *   }
 * }
 * ```
 */
export class BinaryTree<T> {
  protected root: BinaryTreeNode<T> | null = null;
  protected _size = 0;

  // ─── Mutation ───

  /** Set the root value. Replaces any existing tree. Returns the new root node. */
  public setRoot(value: T): BinaryTreeNode<T> {
    this.root = { value, left: null, right: null };
    this._size = 1;
    return this.root;
  }

  /** Set the left child of `parent`. Returns the new node. */
  public setLeft(parent: BinaryTreeNode<T>, value: T): BinaryTreeNode<T> {
    const child: BinaryTreeNode<T> = { value, left: null, right: null };
    if (parent.left) this.#subtractSize(parent.left);
    parent.left = child;
    this._size++;
    return child;
  }

  /** Set the right child of `parent`. Returns the new node. */
  public setRight(parent: BinaryTreeNode<T>, value: T): BinaryTreeNode<T> {
    const child: BinaryTreeNode<T> = { value, left: null, right: null };
    if (parent.right) this.#subtractSize(parent.right);
    parent.right = child;
    this._size++;
    return child;
  }

  /**
   * Remove a node and its entire subtree.
   * Returns `true` if the node was found and removed.
   */
  public remove(node: BinaryTreeNode<T>): boolean {
    if (this.root === node) {
      this.root = null;
      this._size = 0;
      return true;
    }
    const parent = this.#findParent(node);
    if (!parent) return false;

    const removed = this.#subtractSize(node);
    if (parent.left === node) {
      parent.left = null;
    } else {
      parent.right = null;
    }
    return removed;
  }

  /** Remove all nodes. */
  public clear(): void {
    this.root = null;
    this._size = 0;
  }

  // ─── Queries ───

  /**
   * Find the first node whose value satisfies `predicate`.
   * Uses preorder traversal.
   */
  public find(predicate: (value: T) => boolean): BinaryTreeNode<T> | undefined {
    if (!this.root) return undefined;
    const stack: BinaryTreeNode<T>[] = [this.root];
    while (stack.length > 0) {
      const node = stack.pop()!;
      if (predicate(node.value)) return node;
      if (node.right) stack.push(node.right);
      if (node.left) stack.push(node.left);
    }
  }

  /** Traverse the tree and collect values in the specified order. */
  public traverse(order: BinaryTreeTraversalOrder): T[] {
    const result: T[] = [];
    if (!this.root) return result;

    switch (order) {
      case 'preorder':
        this.#preorder(this.root, result);
        break;
      case 'inorder':
        this.#inorder(this.root, result);
        break;
      case 'postorder':
        this.#postorder(this.root, result);
        break;
      case 'bfs':
        this.#bfs(result);
        break;
      case 'dfs':
        this.#dfs(result);
        break;
    }
    return result;
  }

  /** Shorthand for `traverse('preorder')`. */
  public toArray(): T[] {
    return this.traverse('preorder');
  }

  /** Height of the tree (number of edges on the longest root-to-leaf path). */
  public get height(): number {
    return this.#height(this.root);
  }

  /** Number of nodes. */
  public get size(): number {
    return this._size;
  }

  public get isEmpty(): boolean {
    return this._size === 0;
  }

  public get rootNode(): BinaryTreeNode<T> | null {
    return this.root;
  }

  // ─── Internal ───

  #preorder(node: BinaryTreeNode<T>, result: T[]): void {
    result.push(node.value);
    if (node.left) this.#preorder(node.left, result);
    if (node.right) this.#preorder(node.right, result);
  }

  #inorder(node: BinaryTreeNode<T>, result: T[]): void {
    if (node.left) this.#inorder(node.left, result);
    result.push(node.value);
    if (node.right) this.#inorder(node.right, result);
  }

  #postorder(node: BinaryTreeNode<T>, result: T[]): void {
    if (node.left) this.#postorder(node.left, result);
    if (node.right) this.#postorder(node.right, result);
    result.push(node.value);
  }

  #bfs(result: T[]): void {
    if (!this.root) return;
    const queue: BinaryTreeNode<T>[] = [this.root];
    while (queue.length > 0) {
      const node = queue.shift()!;
      result.push(node.value);
      if (node.left) queue.push(node.left);
      if (node.right) queue.push(node.right);
    }
  }

  #dfs(result: T[]): void {
    if (!this.root) return;
    const stack: BinaryTreeNode<T>[] = [this.root];
    while (stack.length > 0) {
      const node = stack.pop()!;
      result.push(node.value);
      if (node.right) stack.push(node.right);
      if (node.left) stack.push(node.left);
    }
  }

  #findParent(target: BinaryTreeNode<T>): BinaryTreeNode<T> | undefined {
    if (!this.root || target === this.root) return undefined;
    const stack: BinaryTreeNode<T>[] = [this.root];
    while (stack.length > 0) {
      const node = stack.pop()!;
      if (node.left === target || node.right === target) return node;
      if (node.right) stack.push(node.right);
      if (node.left) stack.push(node.left);
    }
  }

  #subtractSize(node: BinaryTreeNode<T>): boolean {
    const stack: BinaryTreeNode<T>[] = [node];
    while (stack.length > 0) {
      const n = stack.pop()!;
      this._size--;
      if (n.right) stack.push(n.right);
      if (n.left) stack.push(n.left);
    }
    return true;
  }

  #height(node: BinaryTreeNode<T> | null): number {
    if (!node) return -1;
    return 1 + Math.max(this.#height(node.left), this.#height(node.right));
  }
}

import type { TreeNode, TreeTraversalOrder } from './interfaces.ts';

/**
 * Generic N-ary tree base class.
 *
 * Each node can hold an arbitrary number of children. Provides traversal,
 * search, and mutation primitives. Subclasses have `protected` access to
 * the root node and size counter.
 *
 * @example
 * ```ts
 * class CategoryTree extends Tree<string> {
 *   addCategory(path: string[]): TreeNode<string> {
 *     let node = this.root;
 *     if (!node) node = this.setRoot(path[0]!);
 *     for (let i = 1; i < path.length; i++) {
 *       let child = node.children.find(c => c.value === path[i]);
 *       if (!child) child = this.addChild(node, path[i]!);
 *       node = child;
 *     }
 *     return node;
 *   }
 * }
 * ```
 */
export class Tree<T> {
  protected root: TreeNode<T> | null = null;
  protected _size = 0;

  // ─── Mutation ───

  /** Set the root value. Replaces any existing tree. Returns the new root node. */
  public setRoot(value: T): TreeNode<T> {
    this.root = { value, children: [] };
    this._size = 1;
    return this.root;
  }

  /** Add a child to `parent`. Returns the new child node. */
  public addChild(parent: TreeNode<T>, value: T): TreeNode<T> {
    const child: TreeNode<T> = { value, children: [] };
    parent.children.push(child);
    this._size++;
    return child;
  }

  /**
   * Remove a node and its entire subtree from the tree.
   * Returns `true` if the node was found and removed.
   */
  public remove(node: TreeNode<T>): boolean {
    if (this.root === node) {
      this.root = null;
      this._size = 0;
      return true;
    }
    const parent = this.#findParent(node);
    if (!parent) return false;
    const idx = parent.children.indexOf(node);
    if (idx !== -1) {
      parent.children.splice(idx, 1);
      this.#subtractSize(node);
      return true;
    }
    return false;
  }

  /** Remove all nodes. */
  public clear(): void {
    this.root = null;
    this._size = 0;
  }

  // ─── Queries ───

  /** Find the first node whose value satisfies `predicate` (preorder traversal). */
  public find(predicate: (value: T) => boolean): TreeNode<T> | undefined {
    if (!this.root) return undefined;
    const stack: TreeNode<T>[] = [this.root];
    while (stack.length > 0) {
      const node = stack.pop()!;
      if (predicate(node.value)) return node;
      for (let i = node.children.length - 1; i >= 0; i--) {
        stack.push(node.children[i]!);
      }
    }
  }

  /** Traverse the tree and collect values in the specified order. */
  public traverse(order: TreeTraversalOrder): T[] {
    const result: T[] = [];
    if (!this.root) return result;

    switch (order) {
      case 'preorder':
        this.#preorder(this.root, result);
        break;
      case 'postorder':
        this.#postorder(this.root, result);
        break;
      case 'bfs':
        this.#bfs(result);
        break;
    }
    return result;
  }

  /** Shorthand for `traverse('preorder')`. */
  public toArray(): T[] {
    return this.traverse('preorder');
  }

  /** Get the depth of a node (root depth = 0). Returns -1 if not found. */
  public depthOf(node: TreeNode<T>): number {
    if (node === this.root) return 0;
    let depth = 1;
    let current: TreeNode<T> | undefined = this.#findParent(node);
    while (current) {
      if (current === this.root) return depth;
      current = this.#findParent(current);
      depth++;
    }
    return -1;
  }

  /** Number of nodes. */
  public get size(): number {
    return this._size;
  }

  public get isEmpty(): boolean {
    return this._size === 0;
  }

  public get rootNode(): TreeNode<T> | null {
    return this.root;
  }

  // ─── Internal ───

  #preorder(node: TreeNode<T>, result: T[]): void {
    result.push(node.value);
    for (const child of node.children) {
      this.#preorder(child, result);
    }
  }

  #postorder(node: TreeNode<T>, result: T[]): void {
    for (const child of node.children) {
      this.#postorder(child, result);
    }
    result.push(node.value);
  }

  #bfs(result: T[]): void {
    if (!this.root) return;
    const queue: TreeNode<T>[] = [this.root];
    while (queue.length > 0) {
      const node = queue.shift()!;
      result.push(node.value);
      for (const child of node.children) {
        queue.push(child);
      }
    }
  }

  #findParent(target: TreeNode<T>): TreeNode<T> | undefined {
    if (!this.root || target === this.root) return undefined;
    const stack: TreeNode<T>[] = [this.root];
    while (stack.length > 0) {
      const node = stack.pop()!;
      for (const child of node.children) {
        if (child === target) return node;
        stack.push(child);
      }
    }
  }

  #subtractSize(node: TreeNode<T>): void {
    const stack: TreeNode<T>[] = [node];
    while (stack.length > 0) {
      const n = stack.pop()!;
      this._size--;
      for (const child of n.children) {
        stack.push(child);
      }
    }
  }
}

/// <reference types="@cloudflare/workers-types" />

import { Hono } from 'hono';

/**
 * WebSocket 升级路由
 *
 * 根据 path 将 Upgrade 请求路由到对应的 Durable Object。
 * DO 必须在 wrangler.toml 中绑定并通过 platformBindings 传入。
 *
 * 生产环境（Workers）：  将 Upgrade 请求代理到 DO，由 DO 建立 WebSocket
 * 本地开发（npm run dev）：WebSocket 不可用，返回 501
 */
export function createWsRouter(platformBindings?: Record<string, unknown>): Hono {
  const router = new Hono();

  const notifDO = platformBindings?.NOTIFICATION_DO as DurableObjectNamespace | undefined;

  if (!notifDO) {
    // Dev mode: no DO bindings, WebSocket not available
    router.get('/notifications', (c) => {
      return c.json({
        error: 'WEBSOCKET_UNAVAILABLE',
        message: 'WebSocket notifications are not available in this environment',
      }, 501);
    });
    return router;
  }

  router.get('/notifications', async (c) => {
    const stub = notifDO.get(notifDO.idFromName('notif:global'));
    return stub.fetch(c.req.raw);
  });

  return router;
}

/**
 * Local Node.js dev server — bypasses workerd entirely.
 *
 * Workerd crashes on Windows Insider builds (libuv UV_HANDLE_CLOSING bug).
 * Run with: npm run dev
 *
 * Uses `@hono/node-server` to serve the Hono app on http://localhost:3000.
 * All DO / KV / D1 / R2 bindings are stubbed with file-based adapters.
 */

import { serve } from '@hono/node-server';
import { loadConfig } from './config/env.ts';
import { createApp } from './core/app.ts';
import { createRegionId } from './core/region/types.ts';
import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

// Load .env file manually — tsx doesn't auto-load it
const __dirname = dirname(fileURLToPath(import.meta.url));
try {
  const envPath = resolve(__dirname, '..', '.env');
  const lines = readFileSync(envPath, 'utf-8').split('\n');
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const eq = trimmed.indexOf('=');
    if (eq === -1) continue;
    const key = trimmed.slice(0, eq).trim();
    const val = trimmed.slice(eq + 1).trim();
    if (key && !(key in process.env)) {
      process.env[key] = val;
    }
  }
} catch { /* .env not found — use env vars / defaults */ }

const config = loadConfig({
  provider: {
    container: 'podman',
    region: createRegionId('local'),
    accounts: [],
    defaultAccount: 'default',
    dns: 'stub',
    metrics: 'stub',
  },
  storage: {
    stateBackend: 'file',
    queryBackend: 'none',
    blobBackend: 'file',
    connections: { filePath: '.data' },
  },
  scheduler: {
    backend: 'worker',
    intervalMs: 60000,
    batchSize: 0,
  },
});

const instance = await createApp(config);

// Run seeding synchronously in dev mode — no ctx.waitUntil() available locally.
// On first run this seeds policy lib, default instance, and templates (~100 I/O ops).
// Subsequent starts only check gate keys (negligible cost).
instance.seed().catch((err: unknown) => { console.error('[dev] seed error:', err); });

serve({ fetch: instance.app.fetch, port: config.server.port }, (info) => {

  console.log(`[${new Date().toISOString()}] INFO: [dev] Server listening on http://localhost:${String(info.port)}`);
});

process.on('SIGINT', () => {
  void instance.dispose().then(() => process.exit(0));
});

import type { DagDef, DagId, Task, DagRun } from '../../core/dag/types.ts';
import { createDagId, createTaskId, createDagRunId, DEFAULT_TRIGGER_RULE } from '../../core/dag/types.ts';
import type { WorkflowDef, JobDef } from './types.ts';
import { generateVersionId } from '../../core/brand.ts';

/**
 * Convert a GitHub Actions–style WorkflowDef into an Airflow-style DagDef.
 *
 * Mapping:
 *   WorkflowDef         → DagDef
 *   JobDef              → Task (operatorType = 'container' | 'dns')
 *   JobDef.needs        → Task.dependsOn
 *   WorkflowRun (later) → DagRun
 *   JobRun (later)      → TaskInstance
 *
 * Each JobDef becomes a single Task. Steps within the job are executed
 * sequentially by the JobOperator (ITaskExecutor implementation).
 */

export interface BuildDagOptions {
  /** Override the DAG id (defaults to wf_<workflowDef.id>). */
  readonly dagId?: DagId;
  /** Extra metadata to merge into Task configs. */
  readonly metadata?: Record<string, unknown>;
}

export function buildDagFromWorkflow(
  wf: WorkflowDef,
  options: BuildDagOptions = {},
): { dag: DagDef; taskMap: Map<string, Task> } {
  const dagId = options.dagId ?? createDagId(`wf_${wf.id}`);
  const now = Date.now();

  const tasks: Task[] = [];
  const taskMap = new Map<string, Task>();

  for (const [jobName, jobDef] of Object.entries(wf.jobs)) {
    const task = jobToTask(jobName, jobDef, wf.env, options.metadata);
    tasks.push(task);
    taskMap.set(jobName, task);
  }

  const dag: DagDef = {
    id: dagId,
    name: wf.name,
    ...(wf.description ? { description: wf.description } : {}),
    tasks,
    maxActiveTasks: 16,
    maxActiveRuns: 5,
    createdAt: now,
    updatedAt: now,
    version: generateVersionId(),
  };

  return { dag, taskMap };
}

function jobToTask(
  jobName: string,
  jobDef: JobDef,
  wfEnv: Record<string, string> = {},
  metadata?: Record<string, unknown>,
): Task {
  const taskId = createTaskId(`task_${jobName}`);

  return {
    id: taskId,
    name: jobName,
    operatorType: 'sandbox',
    config: {
      jobName,
      needs: jobDef.needs ?? [],
      steps: jobDef.steps,
      env: { ...wfEnv, ...jobDef.env },
      timeout: jobDef.timeout,
      container: jobDef.container,
      containers: jobDef.containers,
      instanceId: jobDef.instanceId,
      region: jobDef.region,
      approval: jobDef.approval,
      cache: jobDef.cache,
      ...metadata,
    },
    dependsOn: (jobDef.needs ?? []).map(n => createTaskId(`task_${n}`)),
    triggerRule: DEFAULT_TRIGGER_RULE,
    retries: 0,
    retryDelayMs: 30_000,
    ...(jobDef.timeout ? { timeoutMs: jobDef.timeout * 1000 } : {}),
  };
}

/** Create a DagRun from a WorkflowRun trigger. */
export function createDagRunFromTrigger(
  dagId: DagId,
  trigger: DagRun['trigger'],
  triggerPayload?: unknown,
  env?: Record<string, string>,
  ownerId?: string,
): Omit<DagRun, 'version'> {
  return {
    id: createDagRunId(`dr_${dagId}_${String(Date.now())}_${crypto.randomUUID()}`),
    dagId,
    status: 'QUEUED',
    executionDate: Date.now(),
    trigger,
    triggerPayload,
    env: env ?? {},
    ...(ownerId ? { ownerId } : {}),
  };
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { WorkflowRun, JobRun } from './types.ts';
import { IDX_WORKFLOW_RUN_IDS, PFX_WORKFLOW_RUN } from './types.ts';

export interface DashboardMetrics {
  totalWorkflows: number;
  totalRuns: number;
  activeRuns: number;
  successRate: number;
  avgDurationMs: number;
  runnersOnline: number;
  byTrigger: Record<string, number>;
  byStatus: Record<string, number>;
  /** 个人维度的聚类数据（仅当传入 userId 时填充）. */
  myRuns?: number;
  mySuccessRate?: number;
  myRecentRuns?: { id: string; status: string; trigger: string; startedAt: number }[];
}

export interface BillingEntry {
  runId: string;
  jobRunId: string;
  projectId?: string;
  orgId?: string;
  cpuSeconds: number;
  memoryMbSeconds: number;
  durationMs: number;
  cost: number;
  billedAt: number;
}

const BILL_PFX = 'action-billing:';
const CPU_COST_PER_SEC = 0.0001;
const MEM_COST_PER_MB_SEC = 0.000001;

export class DashboardService {
  public constructor(private readonly atomic: IAtomicStore) {}

  public async getMetrics(userId?: string): Promise<DashboardMetrics> {
    const idx = await this.atomic.get<string[]>(IDX_WORKFLOW_RUN_IDS);
    const empty = { totalWorkflows: 0, totalRuns: 0, activeRuns: 0, successRate: 0, avgDurationMs: 0, runnersOnline: 0, byTrigger: {}, byStatus: {} };
    if (!idx) return empty;

    const entries = (await Promise.all(
      idx.value.slice(-500).map(i => this.atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + i)),
    )).filter(e => e).map(e => e!.value);

    const totalRuns = entries.length;
    const activeRuns = entries.filter(r => r.status === 'Pending' || r.status === 'Running').length;
    const completed = entries.filter(r => r.completedAt);
    const successCount = completed.filter(r => r.status === 'Success').length;
    const successRate = completed.length > 0 ? successCount / completed.length : 0;
    const avgDurationMs = completed.length > 0
      ? completed.reduce((s, r) => s + (r.completedAt! - r.startedAt), 0) / completed.length
      : 0;

    const byTrigger: Record<string, number> = {};
    const byStatus: Record<string, number> = {};
    for (const r of entries) {
      byTrigger[r.trigger] = (byTrigger[r.trigger] ?? 0) + 1;
      byStatus[r.status] = (byStatus[r.status] ?? 0) + 1;
    }

    const runnerIdx = await this.atomic.get<string[]>('action-runner:ids');
    let runnersOnline = 0;
    if (runnerIdx) {
      const rs = (await Promise.all(runnerIdx.value.map(i => this.atomic.get<any>('action-runner:' + i))))
        .filter(e => e?.value.status === 'online');
      runnersOnline = rs.length;
    }

    const result: DashboardMetrics = { totalWorkflows: 0, totalRuns, activeRuns, successRate, avgDurationMs, runnersOnline, byTrigger, byStatus };

    // Personal clustering
    if (userId) {
      const mine = entries.filter(r => r.ownerId === userId);
      const myCompleted = mine.filter(r => r.completedAt);
      result.myRuns = mine.length;
      result.mySuccessRate = myCompleted.length > 0
        ? myCompleted.filter(r => r.status === 'Success').length / myCompleted.length
        : 0;
      result.myRecentRuns = mine.slice(0, 10).map(r => ({
        id: r.id, status: r.status, trigger: r.trigger, startedAt: r.startedAt,
      }));
    }

    return result;
  }

  public async recordJobBilling(jobRun: JobRun, jobDef?: { cpu?: number; memory?: number }): Promise<void> {
    if (!jobRun.startedAt || !jobRun.completedAt) return;

    const durationMs = jobRun.completedAt - jobRun.startedAt;
    const cpuCores = jobDef?.cpu ?? 1;
    const memoryMb = jobDef?.memory ?? 1024;
    const cpuSec = cpuCores * durationMs / 1000;
    const memSec = memoryMb * durationMs / 1000;
    const cost = cpuSec * CPU_COST_PER_SEC + memSec * MEM_COST_PER_MB_SEC;

    const entry = await this.atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + jobRun.workflowRunId);
    const billing: BillingEntry = {
      runId: jobRun.workflowRunId,
      jobRunId: jobRun.id,
      projectId: (entry?.value as any)?.projectId,
      orgId: (entry?.value as any)?.orgId,
      cpuSeconds: cpuSec,
      memoryMbSeconds: memSec,
      durationMs,
      cost,
      billedAt: Date.now(),
    };

    await this.atomic.set(`${BILL_PFX}${jobRun.id}`, billing, null);
  }

  public async getBilling(projectId?: string, orgId?: string): Promise<BillingEntry[]> {
    const idx = await this.atomic.get<string[]>('action:job-run:ids');
    if (!idx) return [];
    const entries = (await Promise.all(
      idx.value.map(i => this.atomic.get<BillingEntry>(BILL_PFX + i)),
    )).filter(e => e).map(e => e!.value);
    if (projectId) return entries.filter(b => b.projectId === projectId);
    if (orgId) return entries.filter(b => b.orgId === orgId);
    return entries;
  }
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import { AppError } from '../../core/types.ts';
import { generateVersionId } from '../../core/brand.ts';
import type { VersionId } from '../../core/brand.ts';

// ═══════════════════════════════════════════════════════════════
// Extension types — pluggable metadata for all Action entities
// ═══════════════════════════════════════════════════════════════

/**
 * Extensible metadata contract shared by all Action entities.
 * Every entity exposes `metadata` (arbitrary JSON) and `annotations`
 * (string key-value pairs, e.g. for label selectors).
 */
export interface ExtensibleEntity {
  readonly id: string;
  readonly metadata?: Record<string, unknown>;
  readonly annotations?: Readonly<Record<string, string>>;
}

export interface CreateOrgInput {
  readonly name: string;
  readonly displayName?: string;
  readonly metadata?: Record<string, unknown>;
}

export interface Organization {
  readonly id: string;
  readonly name: string;
  readonly displayName?: string;
  readonly ownerId: string;
  readonly memberIds: readonly string[];
  readonly adminIds: readonly string[];
  readonly projectIds: readonly string[];
  /** Resource quotas for this org. */
  readonly quotas: OrgQuota;
  readonly metadata?: Record<string, unknown>;
  readonly createdAt: number;
  readonly updatedAt: number;
  readonly version: VersionId;
}

export interface OrgQuota {
  readonly maxWorkflows: number;    // 0 = unlimited
  readonly maxRunners: number;
  readonly maxConcurrentRuns: number;
  readonly maxSharedLinks: number;
  readonly maxSecretsPerWorkflow: number;
}

export const DEFAULT_ORG_QUOTA: OrgQuota = {
  maxWorkflows: 0,
  maxRunners: 5,
  maxConcurrentRuns: 10,
  maxSharedLinks: 20,
  maxSecretsPerWorkflow: 50,
};

export interface CreateProjectInput {
  readonly orgId: string;
  readonly name: string;
  readonly displayName?: string;
  readonly metadata?: Record<string, unknown>;
}

export interface Project {
  readonly id: string;
  readonly orgId: string;
  readonly name: string;
  readonly displayName?: string;
  readonly ownerId: string;
  readonly memberIds: readonly string[];
  readonly quotas: OrgQuota; // inherits from org, can be overridden
  readonly metadata?: Record<string, unknown>;
  readonly createdAt: number;
  readonly updatedAt: number;
  readonly version: VersionId;
}

// ─── Approval node ───

export type ApprovalStatus = 'pending' | 'approved' | 'rejected';

export interface ApprovalNode {
  readonly id: string;
  readonly workflowRunId: string;
  readonly jobName: string;
  readonly approvers: readonly string[]; // userIds who can approve
  readonly status: ApprovalStatus;
  readonly reason?: string;
  readonly requestedAt: number;
  readonly decidedAt?: number;
  readonly decidedBy?: string;
  readonly version: VersionId;
}

const PFX_ORG = 'action-org:';
const PFX_PROJ = 'action-project:';
const PFX_APPROVAL = 'action-approval:';
const IDX_ORG = 'action-org:ids';
const IDX_PROJ = 'action-project:ids';
const IDX_APPROVAL = 'action-approval:ids';

// ═══════════════════════════════════════════════════════════════
// Organization service
// ═══════════════════════════════════════════════════════════════

export class OrgService {
  public constructor(private readonly atomic: IAtomicStore) {}

  public async create(ownerId: string, input: CreateOrgInput): Promise<Organization> {
    const id = `org_${crypto.randomUUID()}`;
    const now = Date.now();
    const org: Organization = {
      id, name: input.name,
      ...(input.displayName ? { displayName: input.displayName } : {}),
      ownerId, memberIds: [ownerId], adminIds: [ownerId], projectIds: [],
      quotas: DEFAULT_ORG_QUOTA,
      ...(input.metadata ? { metadata: input.metadata } : {}),
      createdAt: now, updatedAt: now, version: generateVersionId(),
    };
    await this.atomic.set(PFX_ORG + id, org, null);
    await this.#addToIdx(IDX_ORG, id);
    return org;
  }

  public async get(id: string): Promise<Organization | null> {
    const e = await this.atomic.get<Organization>(PFX_ORG + id);
    return e?.value ?? null;
  }

  public async list(memberId?: string): Promise<Organization[]> {
    const idx = await this.atomic.get<string[]>(IDX_ORG);
    if (!idx) return [];
    const entries = (await Promise.all(idx.value.map(i => this.atomic.get<Organization>(PFX_ORG + i))))
      .filter(e => e).map(e => e!.value);
    return memberId ? entries.filter(o => o.memberIds.includes(memberId)) : entries;
  }

  public async addMember(orgId: string, userId: string): Promise<void> {
    const e = await this.atomic.get<Organization>(PFX_ORG + orgId);
    if (!e) throw new AppError(404, 'ORG_NOT_FOUND', 'Organization not found');
    if (e.value.memberIds.includes(userId)) return;
    const updated: Organization = { ...e.value, memberIds: [...e.value.memberIds, userId], updatedAt: Date.now(), version: generateVersionId() };
    await this.atomic.set(PFX_ORG + orgId, updated, e.version);
  }

  public async addProject(orgId: string, projectId: string): Promise<void> {
    const e = await this.atomic.get<Organization>(PFX_ORG + orgId);
    if (!e) throw new AppError(404, 'ORG_NOT_FOUND', 'Organization not found');
    const updated: Organization = { ...e.value, projectIds: [...e.value.projectIds, projectId], updatedAt: Date.now(), version: generateVersionId() };
    await this.atomic.set(PFX_ORG + orgId, updated, e.version);
  }

  async #addToIdx(key: string, id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(key);
    await this.atomic.set(key, [...(idx?.value ?? []), id], idx?.version ?? null);
  }
}

// ═══════════════════════════════════════════════════════════════
// Project service
// ═══════════════════════════════════════════════════════════════

export class ProjectService {
  public constructor(private readonly atomic: IAtomicStore, private readonly orgService: OrgService) {}

  public async create(ownerId: string, input: CreateProjectInput): Promise<Project> {
    const org = await this.orgService.get(input.orgId);
    if (!org) throw new AppError(404, 'ORG_NOT_FOUND', 'Organization not found');

    const id = `proj_${crypto.randomUUID()}`;
    const now = Date.now();
    const proj: Project = {
      id, orgId: input.orgId, name: input.name,
      ...(input.displayName ? { displayName: input.displayName } : {}),
      ownerId, memberIds: [ownerId], quotas: org.quotas,
      ...(input.metadata ? { metadata: input.metadata } : {}),
      createdAt: now, updatedAt: now, version: generateVersionId(),
    };
    await this.atomic.set(PFX_PROJ + id, proj, null);
    await this.orgService.addProject(input.orgId, id);
    await this.#addToIdx(IDX_PROJ, id);
    return proj;
  }

  public async get(id: string): Promise<Project | null> {
    const e = await this.atomic.get<Project>(PFX_PROJ + id);
    return e?.value ?? null;
  }

  public async list(orgId: string): Promise<Project[]> {
    const idx = await this.atomic.get<string[]>(IDX_PROJ);
    if (!idx) return [];
    const entries = (await Promise.all(idx.value.map(i => this.atomic.get<Project>(PFX_PROJ + i))))
      .filter(e => e).map(e => e!.value);
    return entries.filter(p => p.orgId === orgId);
  }

  async #addToIdx(key: string, id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(key);
    await this.atomic.set(key, [...(idx?.value ?? []), id], idx?.version ?? null);
  }
}

// ═══════════════════════════════════════════════════════════════
// Approval service
// ═══════════════════════════════════════════════════════════════

export class ApprovalService {
  public constructor(private readonly atomic: IAtomicStore) {}

  public async request(runId: string, jobName: string, approvers: string[]): Promise<ApprovalNode> {
    const id = `aprv_${crypto.randomUUID()}`;
    const now = Date.now();
    const node: ApprovalNode = {
      id, workflowRunId: runId, jobName, approvers,
      status: 'pending', requestedAt: now, version: generateVersionId(),
    };
    await this.atomic.set(PFX_APPROVAL + id, node, null);
    await this.#addToIdx(IDX_APPROVAL, id);
    return node;
  }

  public async decide(id: string, userId: string, approved: boolean, reason?: string): Promise<ApprovalNode> {
    const e = await this.atomic.get<ApprovalNode>(PFX_APPROVAL + id);
    if (!e) throw new AppError(404, 'APPROVAL_NOT_FOUND', 'Approval not found');
    if (!e.value.approvers.includes(userId)) throw new AppError(403, 'NOT_APPROVER', 'You are not an approver');
    if (e.value.status !== 'pending') throw new AppError(409, 'ALREADY_DECIDED', 'Approval already decided');

    const now = Date.now();
    const updated: ApprovalNode = {
      ...e.value, status: approved ? 'approved' : 'rejected',
      ...(reason ? { reason } : {}),
      decidedAt: now, decidedBy: userId, version: generateVersionId(),
    };
    await this.atomic.set(PFX_APPROVAL + id, updated, e.version);
    return updated;
  }

  public async getForRun(runId: string): Promise<ApprovalNode[]> {
    const idx = await this.atomic.get<string[]>(IDX_APPROVAL);
    if (!idx) return [];
    const entries = (await Promise.all(idx.value.map(i => this.atomic.get<ApprovalNode>(PFX_APPROVAL + i))))
      .filter(e => e?.value.workflowRunId === runId).map(e => e!.value);
    return entries;
  }

  async #addToIdx(key: string, id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(key);
    await this.atomic.set(key, [...(idx?.value ?? []), id], idx?.version ?? null);
  }
}

import { Hono } from 'hono';
import type { FeatureDeps, AppContext } from '../../core/deps.ts';
import { AppError } from '../../core/types.ts';
import { ok } from '../../core/response.ts';
import { register as registerScheduler } from '../../core/scheduler/registry.ts';

import type { RouteMeta } from '../../core/http-docs/types.ts';
import { generateVersionId } from '../../core/brand.ts';
import { CreateWorkflowSchema, UpdateWorkflowSchema, TriggerWorkflowSchema } from './schema.ts';
import { WorkflowRunner } from './runner.ts';

const { parse: parseJson } = JSON;
import { ActionRegistry } from './registry.ts';
import type { TriggerConfig, JobDef } from './types.ts';
import { registerCronTrigger } from './triggers.ts';
import { readStepLogs } from './logs.ts';
import { WorkflowSecretService } from './secrets.ts';
import { SharedLinkService } from './shared-link.ts';
import { RunnerRegistry } from './runner-registry.ts';
import { BlobWorkspaceStore } from './workspace.ts';
import { OrgService, ProjectService, ApprovalService } from './extensions.ts';
import { DashboardService } from './dashboard.ts';
import { TEMPLATES, TEMPLATE_METAS } from './templates.generated.ts';
import {
  type WorkflowDef,
  type WorkflowRun,
  type JobRun,
  IDX_WORKFLOW_IDS,
  IDX_WORKFLOW_RUN_IDS,
  PFX_WORKFLOW_DEF,
  PFX_WORKFLOW_RUN,
  PFX_JOB_RUN,
  createWorkflowDefId,
} from './types.ts';

// ─── DAG Scheduler integration ───
import { DagScheduler } from '../../core/scheduler/dag-scheduler.ts';
import { SetIntervalBackend } from '../../core/scheduler/set-interval-backend.ts';
import { StoreSchedulerContext } from './scheduler-context.ts';
import { JobOperator } from './job-operator.ts';
import { buildDagFromWorkflow, createDagRunFromTrigger } from './dag-builder.ts';
import { PodService } from '../../core/pod/service.ts';

export function createActionsRouter(deps: FeatureDeps): Hono<any> {
  const router = new Hono<{ Variables: AppContext }>();
  const atomic = deps.stores.atomic;
  const blob = deps.stores.blob;

  const actionRegistry = new ActionRegistry(atomic);

  // Shared PodService — Actions and Template use the same instance (CEA K8s executor model)
  const podService = new PodService(deps.stores.atomic, deps.providers);

  const runner = new WorkflowRunner({
    stores: { atomic: deps.stores.atomic, blob: deps.stores.blob },
    providers: {
      dns: deps.providers.dns,
      resolveContainer: deps.providers.resolveContainer?.bind(deps.providers),
    },
    audit: deps.audit,
    queueProducer: deps.queueProducer,
    eventBus: deps.eventBus,
    actionRegistry,
    podService,
  });

  // ── DAG Scheduler setup ──
  const schedulerCtx = new StoreSchedulerContext(atomic);

  const jobOperator = new JobOperator({
    stores: { blob },
    providers: {
      dns: deps.providers.dns,
      resolveContainer: deps.providers.resolveContainer?.bind(deps.providers),
    },
    audit: deps.audit,
    eventBus: deps.eventBus,
    actionRegistry,
    podService,
  });
  schedulerCtx.registerExecutor(jobOperator);

  const dagScheduler = new DagScheduler(
    schedulerCtx,
    new SetIntervalBackend(),
    { intervalMs: 5000, parallelism: 4, autoStart: true },
  );
  dagScheduler.start();
  registerScheduler('dagScheduler', dagScheduler);

  const guard = (action: string, resource: string) =>
    async (c: any, next: () => Promise<void>) => {
      if (deps.permissionChecker) {
        const r = await deps.permissionChecker.check({
          userId: c.get?.('userId') ?? 'anonymous',
          action, resource,
          ip: c.req.header?.('CF-Connecting-IP'),
        });
        if (!r.allowed) throw new AppError(403, 'FORBIDDEN', r.reason);
      }
      await next();
    };

  // ── Cron trigger registration ──

  registerCronTrigger({
    atomic,
    eventBus: deps.eventBus,
    eventLoop: deps.eventLoop,
    audit: deps.audit,
    onTrigger: async (wf, trigger, payload) => runner.startRun(wf, trigger, payload),
  });

  // ── Workflow CRUD ──

  router.post('/workflows', guard('create', 'action:workflow'), async (c) => {
    const body = await c.req.json();
    const parsed = CreateWorkflowSchema.safeParse(body);
    if (!parsed.success) throw new AppError(400, 'INVALID_WORKFLOW', parsed.error.message);

    const input = parsed.data;
    const id = createWorkflowDefId(`wf_${crypto.randomUUID()}`);
    const now = Date.now();

    const def: WorkflowDef = {
      id,
      name: input.name,
      ...(input.description ? { description: input.description } : {}),
      on: input.on as TriggerConfig,
      ...(input.env ? { env: input.env } : {}),
      jobs: input.jobs as Record<string, JobDef>,
      ...(input.orgId ? { orgId: input.orgId } : {}),
      ...(input.projectId ? { projectId: input.projectId } : {}),
      ownerId: c.var.currentUser?.id ?? 'anonymous',
      ...(input.metadata ? { metadata: input.metadata } : {}),
      ...(input.annotations ? { annotations: input.annotations } : {}),
      createdAt: now,
      updatedAt: now,
      version: generateVersionId(),
    };

    await atomic.set(PFX_WORKFLOW_DEF + id, def, null);
    const idx = await atomic.get<string[]>(IDX_WORKFLOW_IDS);
    await atomic.set(IDX_WORKFLOW_IDS, [...(idx?.value ?? []), id], idx?.version ?? null);
    return c.json(ok(def), 201);
  });

  router.get('/workflows', async (c) => {
    const idx = await atomic.get<string[]>(IDX_WORKFLOW_IDS);
    if (!idx) return c.json(ok({ items: [], total: 0, page: 1, limit: 50 }));
    const page = Math.max(1, parseInt(c.req.query('page') ?? '') || 1);
    const limit = Math.min(Math.max(1, parseInt(c.req.query('limit') ?? '') || 50), 200);
    const total = idx.value.length;
    const start = (page - 1) * limit;
    const pageIds = idx.value.slice(start, start + limit);
    const entries = await Promise.all(
      pageIds.map(i => atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + i)),
    );
    return c.json(ok({ items: entries.filter(e => e).map(e => e!.value), total, page, limit }));
  });

  router.get('/workflows/:id', async (c) => {
    const entry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + c.req.param('id'));
    if (!entry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow not found');
    return c.json(ok(entry.value));
  });

  router.patch('/workflows/:id', guard('update', 'action:workflow'), async (c) => {
    const wid = c.req.param('id');
    const entry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + wid);
    if (!entry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow not found');

    const body = await c.req.json();
    const parsed = UpdateWorkflowSchema.safeParse(body);
    if (!parsed.success) throw new AppError(400, 'INVALID_WORKFLOW', parsed.error.message);

    const input = parsed.data;
    const updated: WorkflowDef = {
      ...entry.value,
      ...(input.name !== undefined ? { name: input.name } : {}),
      ...(input.description != null ? { description: input.description } : {}),
      ...(input.on !== undefined ? { on: input.on as TriggerConfig } : {}),
      ...(input.env !== undefined ? { env: input.env } : {}),
      ...(input.jobs !== undefined ? { jobs: input.jobs as Record<string, JobDef> } : {}),
      updatedAt: Date.now(),
      version: generateVersionId(),
    };

    const ver = await atomic.set(PFX_WORKFLOW_DEF + wid, updated, entry.version);
    if (!ver) throw new AppError(409, 'CONFLICT', 'Concurrent modification');
    return c.json(ok(updated));
  });

  router.delete('/workflows/:id', guard('delete', 'action:workflow'), async (c) => {
    const wid = c.req.param('id');
    const entry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + wid);
    if (!entry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow not found');

    await atomic.set(PFX_WORKFLOW_DEF + wid, null, entry.version);
    const idx = await atomic.get<string[]>(IDX_WORKFLOW_IDS);
    if (idx) await atomic.set(IDX_WORKFLOW_IDS, idx.value.filter(i => i !== wid), idx.version);
    return c.json(ok({ deleted: true }));
  });

  // ── Triggers ──

  router.post('/workflows/:id/trigger', guard('execute', 'action:workflow'), async (c) => {
    const wid = c.req.param('id');
    const entry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + wid);
    if (!entry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow not found');

    const body = await c.req.json().catch(() => ({}));
    const parsed = TriggerWorkflowSchema.safeParse(body);
    const inputs = parsed.success && parsed.data.inputs ? parsed.data.inputs : {};

    const run = await runner.startRun(entry.value, 'manual', undefined, inputs,
      c.var.currentUser?.id ?? 'anonymous');
    return c.json(ok(run), 201);
  });

  /** HTTP trigger: POST /api/actions/workflows/:id/http */
  router.post('/workflows/:id/http', async (c) => {
    const wid = c.req.param('id');
    const entry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + wid);
    if (!entry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow not found');
    if (!entry.value.on.http) throw new AppError(400, 'NOT_HTTP_TRIGGER', 'Workflow does not have HTTP trigger enabled');

    // Read raw body for signature verification
    const rawBody = await c.req.text();
    const secret = entry.value.on.http.signatureSecret;
    if (secret) {
      const sig = c.req.header('X-Workflow-Signature');
      if (!sig) throw new AppError(401, 'MISSING_SIGNATURE', 'X-Workflow-Signature header required');
      const { verifyHttpSignature } = await import('./triggers.ts');
      const valid = await verifyHttpSignature(secret, rawBody, sig);
      if (!valid) throw new AppError(401, 'INVALID_SIGNATURE', 'Signature verification failed');
    }

    let payload: Record<string, unknown> = {};
    try { payload = parseJson(rawBody || '{}'); } catch { /* not JSON */ }
    const inputs = payload.inputs as Record<string, string> | undefined ?? {};

    const run = await runner.startRun(entry.value, 'http', payload, inputs,
      c.var.currentUser?.id ?? 'anonymous');
    return c.json(ok(run), 201);
  });

  /** Scheduler-based trigger: POST /api/actions/workflows/:id/schedule
   *  Converts WorkflowDef → DagDef → DagRun and submits to the Airflow-style
   *  scheduler. The scheduler handles dependency resolution, concurrency, and
   *  retries via TriggerRule + 5-step filter. */
  router.post('/workflows/:id/schedule', guard('execute', 'action:workflow'), async (c) => {
    const wid = c.req.param('id');
    const entry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + wid);
    if (!entry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow not found');

    const body = await c.req.json().catch(() => ({}));
    const parsed = TriggerWorkflowSchema.safeParse(body);
    const inputs = parsed.success && parsed.data.inputs ? parsed.data.inputs : {};

    // Build DAG and persist
    const { dag } = buildDagFromWorkflow(entry.value);
    await schedulerCtx.saveDagDef(dag);

    // Create DagRun
    const dagRun = createDagRunFromTrigger(
      dag.id, 'manual', undefined, inputs,
      c.var.currentUser?.id ?? 'anonymous',
    );
    const run: any = { ...dagRun, version: generateVersionId() };
    await schedulerCtx.saveNewDagRun(run);

    deps.audit.write({
      level: 5, facility: 'dag-scheduler',
      message: `DagRun ${String(run.id)} created via scheduler for workflow ${entry.value.name}`,
      metadata: { dagId: dag.id, dagRunId: run.id, trigger: 'manual', taskCount: dag.tasks.length },
    });

    return c.json(ok({ dagRunId: run.id, dagId: dag.id, status: run.status, taskCount: dag.tasks.length }), 201);
  });

  /** Generic webhook endpoint: POST /api/actions/webhook
   *  Matches incoming webhook payloads against all workflows that have
   *  on.push configured.  Basic branch-name matching for now. */
  router.post('/webhook', async (c) => {
    const payload = await c.req.json().catch(() => ({}));
    const branch = (payload)?.ref?.replace('refs/heads/', '') ?? '';

    const idx = await atomic.get<string[]>(IDX_WORKFLOW_IDS);
    if (!idx) return c.json(ok({ triggered: [], count: 0 }));

    const triggered: string[] = [];
    for (const wid of idx.value) {
      const entry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + wid);
      if (!entry?.value.on.push) continue;

      const branches = entry.value.on.push.branches;
      if (branches && branches.length > 0) {
        if (!branches.includes(branch) && !branches.includes('*')) continue;
      }

      const run = await runner.startRun(entry.value, 'webhook', payload, undefined,
        c.var.currentUser?.id ?? 'anonymous');
      triggered.push(run.id);
    }

    return c.json(ok({ triggered, count: triggered.length }));
  });

  // ── Run management ──

  router.get('/runs', async (c) => {
    const idx = await atomic.get<string[]>(IDX_WORKFLOW_RUN_IDS);
    if (!idx) return c.json(ok({ items: [], total: 0, page: 1, limit: 50 }));
    const page = Math.max(1, parseInt(c.req.query('page') ?? '') || 1);
    const limit = Math.min(Math.max(1, parseInt(c.req.query('limit') ?? '') || 50), 200);
    const total = idx.value.length;
    const reversed = [...idx.value].reverse();
    const start = (page - 1) * limit;
    const pageIds = reversed.slice(start, start + limit);
    const entries = await Promise.all(
      pageIds.map(i => atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + i)),
    );
    return c.json(ok({ items: entries.filter(e => e).map(e => e!.value), total, page, limit }));
  });

  router.get('/runs/:id', async (c) => {
    const entry = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + c.req.param('id'));
    if (!entry) throw new AppError(404, 'RUN_NOT_FOUND', 'Workflow run not found');
    return c.json(ok(entry.value));
  });

  router.get('/runs/:id/jobs', async (c) => {
    const wfEntry = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + c.req.param('id'));
    if (!wfEntry) throw new AppError(404, 'RUN_NOT_FOUND', 'Workflow run not found');

    const jobRuns = await Promise.all(
      wfEntry.value.jobRunRefs.map(ref => atomic.get<JobRun>(PFX_JOB_RUN + ref.jobRunId)),
    );
    return c.json(ok(jobRuns.filter(j => j).map(j => j!.value)));
  });

  /** DAG endpoint — returns nodes + edges with real-time status for dependency graph rendering. */
  router.get('/runs/:id/dag', async (c) => {
    const wfEntry = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + c.req.param('id'));
    if (!wfEntry) throw new AppError(404, 'RUN_NOT_FOUND', 'Workflow run not found');
    const run = wfEntry.value;

    const wfDefEntry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + run.workflowId);
    if (!wfDefEntry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow definition not found');
    const jobs = wfDefEntry.value.jobs;

    const jobRuns = await Promise.all(
      run.jobRunRefs.map(ref => atomic.get<JobRun>(PFX_JOB_RUN + ref.jobRunId)),
    );
    const statusMap = new Map(jobRuns.filter(j => j).map(j => [j!.value.jobName, j!.value]));

    const nodes = run.jobRunRefs.map(ref => ({
      id: ref.jobName,
      label: ref.jobName,
      status: statusMap.get(ref.jobName)?.status ?? 'Queued',
      startedAt: statusMap.get(ref.jobName)?.startedAt,
      completedAt: statusMap.get(ref.jobName)?.completedAt,
      stepCount: statusMap.get(ref.jobName)?.stepRuns.length ?? 0,
      completedSteps: statusMap.get(ref.jobName)?.stepRuns.filter(s => s.status === 'Success').length ?? 0,
    }));

    const edges: { from: string; to: string }[] = [];
    for (const [name, job] of Object.entries(jobs)) {
      for (const dep of job.needs ?? []) {
        edges.push({ from: dep, to: name });
      }
    }

    return c.json(ok({
      workflowName: wfDefEntry.value.name,
      status: run.status,
      trigger: run.trigger,
      startedAt: run.startedAt,
      completedAt: run.completedAt,
      nodes,
      edges,
    }));
  });

  router.get('/jobs/:id', async (c) => {
    const entry = await atomic.get<JobRun>(PFX_JOB_RUN + c.req.param('id'));
    if (!entry) throw new AppError(404, 'JOB_NOT_FOUND', 'Job run not found');
    return c.json(ok(entry.value));
  });

  // ── Step logs ──

  router.get('/jobs/:id/logs', async (c) => {
    const jobId = c.req.param('id');
    const entry = await atomic.get<JobRun>(PFX_JOB_RUN + jobId);
    if (!entry) throw new AppError(404, 'JOB_NOT_FOUND', 'Job run not found');

    const step = c.req.query('step') || 'all';
    const offset = Math.max(0, parseInt(c.req.query('offset') ?? '') || 0);
    const limit = Math.min(parseInt(c.req.query('limit') ?? '') || 500, 10000);

    const result = await readStepLogs(blob, jobId, step, offset, limit);
    return c.json(ok(result));
  });

  // ── Action registry ──

  router.post('/actions', async (c) => {
    const body = await c.req.json();
    if (!body.name || !body.version || !body.runs) {
      throw new AppError(400, 'INVALID_ACTION', 'name, version, and runs are required');
    }
    const def = await actionRegistry.register(body);
    return c.json(ok(def), 201);
  });

  router.get('/actions', async (c) => {
    const list = await actionRegistry.list();
    const page = Math.max(1, parseInt(c.req.query('page') ?? '') || 1);
    const limit = Math.min(Math.max(1, parseInt(c.req.query('limit') ?? '') || 50), 200);
    const total = list.length;
    const start = (page - 1) * limit;
    return c.json(ok({ items: list.slice(start, start + limit), total, page, limit }));
  });

  // ── Organizations & Projects ──

  const orgService = new OrgService(atomic);
  const projectService = new ProjectService(atomic, orgService);

  router.post('/orgs', async (c) => {
    const body = await c.req.json();
    const ownerId = c.var.currentUser?.id ?? 'anonymous';
    const org = await orgService.create(ownerId, body);
    return c.json(ok(org), 201);
  });

  router.get('/orgs', async (c) => {
    const memberId = c.req.query('member');
    const list = await orgService.list(memberId);
    return c.json(ok(list));
  });

  router.get('/orgs/:id', async (c) => {
    const o = await orgService.get(c.req.param('id'));
    if (!o) throw new AppError(404, 'ORG_NOT_FOUND', 'Organization not found');
    return c.json(ok(o));
  });

  router.post('/orgs/:id/members', async (c) => {
    const { userId } = await c.req.json();
    await orgService.addMember(c.req.param('id'), userId);
    return c.json(ok({ ok: true }));
  });

  router.post('/projects', async (c) => {
    const body = await c.req.json();
    const ownerId = c.var.currentUser?.id ?? 'anonymous';
    const proj = await projectService.create(ownerId, body);
    return c.json(ok(proj), 201);
  });

  router.get('/projects', async (c) => {
    const orgId = c.req.query('orgId');
    if (!orgId) throw new AppError(400, 'MISSING_ORG', 'orgId query param required');
    const list = await projectService.list(orgId);
    return c.json(ok(list));
  });

  // ── Approval ──

  const approvalService = new ApprovalService(atomic);

  router.post('/runs/:id/approvals', async (c) => {
    const { jobName, approvers } = await c.req.json();
    const node = await approvalService.request(c.req.param('id'), jobName, approvers);
    return c.json(ok(node), 201);
  });

  router.post('/approvals/:id/decide', async (c) => {
    const { approved, reason } = await c.req.json();
    const userId = c.var.currentUser?.id ?? 'anonymous';
    const node = await approvalService.decide(c.req.param('id'), userId, approved, reason);
    return c.json(ok(node));
  });

  router.get('/runs/:id/approvals', async (c) => {
    const list = await approvalService.getForRun(c.req.param('id'));
    return c.json(ok(list));
  });

  // ── Secrets ──

  const secretService = new WorkflowSecretService(atomic, deps.secretEncryption);

  router.post('/workflows/:id/secrets', async (c) => {
    const wid = c.req.param('id');
    const wfEntry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + wid);
    if (!wfEntry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Workflow not found');

    const { key, value } = await c.req.json();
    if (!key || value === undefined) throw new AppError(400, 'INVALID_SECRET', 'key and value required');

    const secret = await secretService.set(wid, key, value);
    return c.json(ok({ id: secret.id, key: secret.key, createdAt: secret.createdAt }), 201);
  });

  router.get('/workflows/:id/secrets', async (c) => {
    const wid = c.req.param('id');
    const list = await secretService.list(wid);
    return c.json(ok(list));
  });

  router.delete('/secrets/:id', async (c) => {
    await secretService.delete(c.req.param('id'));
    return c.json(ok({ deleted: true }));
  });

  // ── Shared links ──

  const sharedLinkService = new SharedLinkService(atomic, deps.audit);

  router.post('/shared-links', async (c) => {
    const body = await c.req.json();
    // Extract owner from auth context if available
    const ownerId = c.var.currentUser?.id ?? 'anonymous';
    const link = await sharedLinkService.create(ownerId, body);
    const { passwordHash: _passwordHash, ...safe } = link;
    return c.json(ok(safe), 201);
  });

  router.get('/shared-links', async (c) => {
    const ownerId = c.var.currentUser?.id ?? 'anonymous';
    const links = await sharedLinkService.list(ownerId);
    return c.json(ok(links.map(({ passwordHash: _passwordHash, ...safe }) => safe)));
  });

  router.get('/shared-links/:id', async (c) => {
    const link = await sharedLinkService.get(c.req.param('id'));
    if (!link) throw new AppError(404, 'LINK_NOT_FOUND', 'Shared link not found');
    const { passwordHash: _passwordHash, ...safe } = link;
    return c.json(ok(safe));
  });

  /** Guest access: validate and trigger. No auth required. */
  router.post('/shared-links/:id/launch', async (c) => {
    const body = await c.req.json().catch(() => ({}));
    const password = body.password as string | undefined;

    const link = await sharedLinkService.validate(c.req.param('id'), password);

    // Load the workflow and trigger it
    const wfEntry = await atomic.get<WorkflowDef>(PFX_WORKFLOW_DEF + link.workflowId);
    if (!wfEntry) throw new AppError(404, 'WORKFLOW_NOT_FOUND', 'Target workflow not found');

    await sharedLinkService.recordUse(link.id);

    const run = await runner.startRun(wfEntry.value, 'shared_link', { linkId: link.id, defaultTtl: link.defaultTtlSeconds });
    return c.json(ok({ runId: run.id, status: run.status }), 201);
  });

  router.post('/shared-links/:id/disable', async (c) => {
    const ownerId = c.var.currentUser?.id ?? 'anonymous';
    await sharedLinkService.disable(c.req.param('id'), ownerId);
    return c.json(ok({ disabled: true }));
  });

  // ── Runner registry ──

  const runnerRegistry = new RunnerRegistry(atomic, deps.audit);

  /** Runner heartbeat: POST /api/actions/runners/heartbeat */
  router.post('/runners/heartbeat', async (c) => {
    const body = await c.req.json();
    const runner = await runnerRegistry.heartbeat(body);
    return c.json(ok(runner));
  });

  router.get('/runners', async (c) => {
    const labels = c.req.query('labels') ? parseJson(c.req.query('labels')!) : undefined;
    const runners = await runnerRegistry.listOnline(labels);
    return c.json(ok(runners));
  });

  router.get('/runners/:id', async (c) => {
    const r = await runnerRegistry.get(c.req.param('id'));
    if (!r) throw new AppError(404, 'RUNNER_NOT_FOUND', 'Runner not found');
    return c.json(ok(r));
  });

  router.post('/runners/:id/drain', async (c) => {
    await runnerRegistry.drain(c.req.param('id'));
    return c.json(ok({ draining: true }));
  });

  // Register stale-runner cleanup tick
  deps.eventBus.on('runner:heartbeat:check', async () => {
    const marked = await runnerRegistry.markStale();
    if (marked > 0) {
      deps.audit.write({
        level: 4, facility: 'runner-registry',
        message: `Marked ${String(marked)} stale runner(s) offline`,
        metadata: { count: marked },
      });
    }
  });
  deps.eventLoop.enqueuePriority({ type: 'runner:heartbeat:check', payload: {} });

  // ── Workspace ──

  const workspaceStore = new BlobWorkspaceStore(blob);

  router.get('/workspace/:workflowRunId/:jobName', async (c) => {
    const result = await workspaceStore.load(
      c.req.param('workflowRunId'),
      c.req.param('jobName'),
    );
    if (!result) throw new AppError(404, 'WORKSPACE_NOT_FOUND', 'Workspace not found');
    // Return metadata + base64 data for API consumers
    const b64 = btoa(String.fromCharCode(...result.data));
    return c.json(ok({ meta: result.meta, data: b64 }));
  });

  // ── Dashboard ──

  const dashboard = new DashboardService(atomic);

  router.get('/dashboard', async (c) => {
    const userId = c.var.currentUser?.id ?? 'anonymous';
    const metrics = await dashboard.getMetrics(userId);
    return c.json(ok(metrics));
  });

  // ── Templates ──

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  router.get('/templates', async (c) => {
    const category = c.req.query('category');
    const items = category
      ? TEMPLATE_METAS.filter(t => t.category === category)
      : TEMPLATE_METAS;
    return c.json(ok({ items, total: items.length }));
  });

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  router.get('/templates/:id', async (c) => {
    const t = TEMPLATES.find(tpl => tpl.id === c.req.param('id'));
    if (!t) throw new AppError(404, 'TEMPLATE_NOT_FOUND', 'Template not found');
    return c.json(ok(t));
  });

  return router;
}

