import type { Hono } from 'hono';
import type { FeatureDeps } from '../../core/deps.ts';
import { createActionsRouter } from './handler.ts';

export function createRouter(deps: FeatureDeps): Hono<any> {
  return createActionsRouter(deps);
}

import type { ITaskExecutor, Task, TaskInstance, TaskExecutionResult } from '../../core/dag/types.ts';
import type { IBlobStore } from '../../core/store/interfaces.ts';
import type { IProviderRegistry } from '../../core/provider/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import type { EventBus } from '../../core/event-bus/bus.ts';
import type { RunStepDef, UsesStepDef, StepDef, ActionContainerConfig } from './types.ts';
import { executeDnsStep } from './step-dns.ts';
import { appendStepLog } from './logs.ts';
import type { ActionRegistry } from './registry.ts';
import { createEvent } from '../../core/event-bus/types.ts';
import type { PodService } from '../../core/pod/service.ts';
import type { PodSpec } from '../../core/pod/types.ts';

/**
 * JobOperator — executes a GitHub Actions–style Job as a single Task.
 *
 * This is the bridge between the Airflow scheduler and the existing
 * step-execution infrastructure. It provisions a sandbox and runs
 * the job's steps inside it.
 */
export class JobOperator implements ITaskExecutor {
  public readonly key = 'sandbox';

  public constructor(
    private readonly deps: {
      stores: { blob: IBlobStore };
      providers: Pick<IProviderRegistry, 'resolveContainer' | 'dns'>;
      audit: IAuditWriter;
      eventBus?: EventBus;
      actionRegistry?: ActionRegistry;
      podService?: PodService;
    },
  ) {}

  public async execute(_task: Task, ti: TaskInstance): Promise<TaskExecutionResult> {
    const config = _task.config as {
      jobName: string;
      needs: string[];
      steps: StepDef[];
      env: Record<string, string>;
      timeout?: number;
      container?: ActionContainerConfig;
      containers?: readonly (ActionContainerConfig & { name: string })[];
      instanceId?: string;
      region?: string;
      approval?: { approvers: readonly string[]; message?: string };
    };

    const jobName = config.jobName;
    const steps = config.steps;

    try {
      // Provision sandbox
      const sandboxId = await this.provisionSandbox(config);

      // Execute steps sequentially
      for (const step of steps) {
        const name = step.name ?? this.stepLabel(step);
        await appendStepLog(this.deps.stores.blob, ti.id, name, `Step started: ${name}`);
        this.deps.audit.write({
          level: 6, facility: 'job-operator',
          message: `Step ${name} started for ${jobName}`,
          metadata: { taskInstanceId: ti.id, stepName: name },
        });

        try {
          if ('run' in step) {
            await this.executeRunStep(step, config.env, sandboxId);
          } else if ('dns' in step) {
            await executeDnsStep(step, this.deps.providers.dns, this.deps.audit);
          } else if ('uses' in step) {
            await this.executeUsesStep(step, config.env, sandboxId);
          }
          await appendStepLog(this.deps.stores.blob, ti.id, name, `Step completed: ${name}`);
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          await appendStepLog(this.deps.stores.blob, ti.id, name, `Step FAILED: ${msg}`);
          this.deps.audit.write({
            level: 3, facility: 'job-operator',
            message: `Step ${name} failed: ${msg}`,
            metadata: { taskInstanceId: ti.id, stepName: name, error: msg },
          });

          if (step.continueOnError) continue;
          return { success: false, error: msg, exitCode: 1 };
        }
      }

      // Emit completion event
      if (this.deps.eventBus) {
        const evt = createEvent('workflow:job:status', {
          jobRunId: ti.id, jobName,
          workflowRunId: ti.dagRunId,
          status: 'Success',
        });
        await this.deps.eventBus.dispatch(evt);
      }

      return { success: true };
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      return { success: false, error: msg, exitCode: 1 };
    }
  }

  private stepLabel(step: StepDef): string {
    if ('run' in step) return step.run.slice(0, 60);
    if ('dns' in step) return `dns:${step.dns.name}`;
    return step.uses ?? 'unknown';
  }

  private async provisionSandbox(config: any): Promise<string> {
    const mainContainer: ActionContainerConfig | undefined = config.containers?.[0] ?? config.container;
    if (!mainContainer) throw new Error('Job has no container defined');

    const env = config.env ?? {};
    const envList = Object.entries(env).map(([name, value]) => ({ name, value: String(value) }));

    // v3 path: PodService.provision() → PodEntity with lifecycle tracking
    if (this.deps.podService) {
      const podSpec: PodSpec = {
        metadata: {
          name: `action-${String(config.jobName)}-${String(Date.now())}`,
          labels: { job: config.jobName, owner: 'actions' },
        },
        spec: {
          containers: [{
            name: config.jobName,
            image: mainContainer.image,
            command: mainContainer.command ? [...mainContainer.command] : undefined,
            args: mainContainer.args ? [...mainContainer.args] : undefined,
            env: envList.length > 0 ? envList : undefined,
            ports: mainContainer.ports ? [...mainContainer.ports] : undefined,
            resources: mainContainer.resources ? {
              limits: {
                cpu: mainContainer.resources.cpu ?? 1,
                memory: mainContainer.resources.memory ?? 1024,
              },
            } : undefined,
          }],
          restartPolicy: 'Never',
        },
      };
      const pod = await this.deps.podService.provision(podSpec);
      return pod.providerId ?? pod.podId;
    }

    // v2 fallback: direct provider.create()
    const instanceId = config.instanceId;
    if (!instanceId || !this.deps.providers.resolveContainer) {
      throw new Error('Job requires an instanceId to resolve a container provider');
    }

    const provider: any = await this.deps.providers.resolveContainer(instanceId);
    const region = config.region ?? 'local';

    const result = await provider.create({
      name: `action-${String(config.jobName)}-${String(Date.now())}`,
      region,
      ...(instanceId ? { instanceId } : {}),
      cpu: mainContainer.resources?.cpu ?? 1,
      memory: mainContainer.resources?.memory ?? 1024,
      restartPolicy: 'Never',
      containers: [{
        name: config.jobName,
        image: mainContainer.image,
        command: mainContainer.command ? [...mainContainer.command] : undefined,
        args: mainContainer.args ? [...mainContainer.args] : undefined,
        env: envList,
        ports: mainContainer.ports ? [...mainContainer.ports] : undefined,
        workingDir: mainContainer.workingDir,
        resources: mainContainer.resources ? { cpu: mainContainer.resources.cpu ?? 1, memory: mainContainer.resources.memory ?? 1024 } : { cpu: 1, memory: 2048 },
      }],
      network: { allocatePublicIp: false },
    });

    return result.providerId;
  }

  private async executeRunStep(
    step: RunStepDef,
    env: Record<string, string>,
    sandboxId: string,
  ): Promise<void> {
    const provider = await this.deps.providers.resolveContainer?.(undefined) as any;
    if (typeof provider?.exec !== 'function') return;

    const shell = step.shell ?? '/bin/sh';
    const mergedEnv = Object.entries({ ...env, ...step.env }).map(([k, v]) => `${k}=${v}`);

    const result = await provider.exec({
      providerId: sandboxId,
      command: [shell, '-c', step.run],
      env: mergedEnv,
      timeout: step.timeout ? step.timeout * 1000 : undefined,
    });

    if (result?.exitCode !== 0) {
      throw new Error(`Command exited with ${String(result?.exitCode ?? -1)}: ${step.run.slice(0, 200)}`);
    }
  }

  private async executeUsesStep(
    step: UsesStepDef,
    env: Record<string, string>,
    sandboxId: string,
  ): Promise<void> {
    const registry = this.deps.actionRegistry;
    const provider = await this.deps.providers.resolveContainer?.(undefined) as any;

    if (!registry && typeof provider?.exec !== 'function') {
      throw new Error(`Cannot execute uses: step — no action registry or provider exec`);
    }

    const resolved = registry ? await registry.resolve(step.uses) : null;
    if (resolved && typeof provider?.exec === 'function') {
      const mergedEnv = { ...env, ...step.env, ...step.with };
      const envList = Object.entries(mergedEnv).map(([k, v]) => `${k}=${v}`);
      const cmd = resolved.entrypoint ?? ['/bin/sh', '-c', `echo 'Action: ${step.uses}'`];
      const result = await provider.exec({
        providerId: sandboxId,
        command: cmd,
        env: envList,
        timeout: step.timeout ? step.timeout * 1000 : undefined,
      });
      if (result?.exitCode !== 0) {
        throw new Error(`Action ${String(step.uses)} failed with exit ${String(result?.exitCode)}`);
      }
    } else if (typeof provider?.exec === 'function') {
      const mergedEnv = { ...env, ...step.env, ...step.with };
      const envList = Object.entries(mergedEnv).map(([k, v]) => `${k}=${v}`);
      const result = await provider.exec({
        providerId: sandboxId,
        command: ['/bin/sh', '-c', `echo 'Running action: ${step.uses}'`],
        env: envList,
        timeout: step.timeout ? step.timeout * 1000 : undefined,
      });
      if (result?.exitCode !== 0) {
        throw new Error(`Action ${String(step.uses)} failed with exit ${String(result?.exitCode)}`);
      }
    } else {
      throw new Error(`Action not found: ${step.uses}`);
    }
  }
}

import type { IBlobStore } from '../../core/store/interfaces.ts';
import { formatDmesgLine } from '../../core/utils/dmesg.ts';

const LOG_PREFIX = 'action:logs:';

/**
 * Append a log line to a job run's log stream.
 *
 * Logs are stored as segments in IBlobStore (R2), one per step per job.
 * This keeps the atomic store clean and allows large log volumes.
 *
 * Uses dmesg format for consistency with the rest of the system:
 *   [uptime.usecs] facility: message
 */
export async function appendStepLog(
  blob: IBlobStore,
  jobRunId: string,
  stepName: string,
  line: string,
): Promise<void> {
  const segKey = `${LOG_PREFIX}${jobRunId}/${sanitizeSegment(stepName)}`;
  const ts = formatDmesgLine(line);

  // Append to existing segment
  const existing = await blob.get(segKey);
  const encoder = new TextEncoder();
  const newLine = encoder.encode(ts + '\n');

  if (existing) {
    // Merge: read existing + new line
    const chunks: Uint8Array[] = [];
    const reader = existing.getReader();
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      chunks.push(value);
    }
    const merged = new Uint8Array(
      chunks.reduce((s, c) => s + c.byteLength, 0) + newLine.byteLength,
    );
    let offset = 0;
    for (const c of chunks) { merged.set(c, offset); offset += c.byteLength; }
    merged.set(newLine, offset);
    await blob.put(segKey, merged.buffer, {
      contentType: 'text/plain; charset=utf-8',
      contentLength: merged.byteLength,
    });
  } else {
    await blob.put(segKey, newLine.buffer, {
      contentType: 'text/plain; charset=utf-8',
      contentLength: newLine.byteLength,
    });
  }
}

/**
 * Read log segments for a job run.
 * Returns concatenated log text with optional offset/limit for pagination.
 */
export async function readStepLogs(
  blob: IBlobStore,
  jobRunId: string,
  stepName: string,
  offset = 0,
  limit?: number,
): Promise<{ text: string; totalBytes: number; offset: number; limit: number }> {
  const segKey = `${LOG_PREFIX}${jobRunId}/${sanitizeSegment(stepName)}`;
  const existing = await blob.get(segKey);

  if (!existing) {
    return { text: '', totalBytes: 0, offset: 0, limit: limit ?? 0 };
  }

  // Read full content
  const chunks: Uint8Array[] = [];
  const reader = existing.getReader();
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    chunks.push(value);
  }

  const totalSize = chunks.reduce((s, c) => s + c.byteLength, 0);
  const merged = new Uint8Array(totalSize);
  let pos = 0;
  for (const c of chunks) { merged.set(c, pos); pos += c.byteLength; }

  const decoder = new TextDecoder();
  const full = decoder.decode(merged);

  // Apply offset/limit
  const lines = full.split('\n');
  const actualLimit = limit ?? lines.length;
  const sliced = lines.slice(offset, offset + actualLimit);

  return {
    text: sliced.join('\n'),
    totalBytes: totalSize,
    offset,
    limit: actualLimit,
  };
}

/**
 * List all step log segments for a job run.
 */
/** @internal — enumerate step segments from known step names (used by API). */
export function listJobLogSegments(
  stepNames: readonly string[],
): { stepName: string; sizeBytes: number }[] {
  return stepNames.map(s => ({ stepName: s, sizeBytes: 0 }));
}

function sanitizeSegment(name: string): string {
  return name.replace(/[^a-zA-Z0-9._-]/g, '_').slice(0, 128);
}

import type { JobDef } from './types.ts';

/**
 * Matrix strategy configuration.
 *
 * @example
 * ```yaml
 * strategy:
 *   matrix:
 *     os: [ubuntu, alpine]
 *     node: [18, 20]
 *   exclude:
 *     - { os: alpine, node: 20 }
 *   maxParallel: 4
 * ```
 *
 * Extensibility: additional combinators (include, failFast, etc.)
 * can be added to the StrategyConfig union.
 */
export interface MatrixConfig {
  /** Variable → values mapping. Each combination produces one Job variant. */
  readonly matrix: Record<string, readonly (string | number | boolean)[]>;
  /** Combinations to exclude (exact match on subset of variables). */
  readonly exclude?: readonly Record<string, string | number | boolean>[];
  /** Maximum concurrent instances of expanded jobs. 0 = unlimited. */
  readonly maxParallel?: number;
  /** If true, cancel all remaining jobs when one fails. */
  readonly failFast?: boolean;
}

/** A single expanded job variant with its variable bindings. */
export interface JobVariant {
  /** Unique name for this variant, e.g. "test (os=ubuntu, node=18)". */
  readonly name: string;
  /** Variable bindings for use in ${{ matrix.os }} resolution. */
  readonly matrixVars: Record<string, string | number | boolean>;
  /** The job template (shared reference, not cloned). */
  readonly jobDef: JobDef;
}

/**
 * Expand a matrix strategy into individual job variants.
 *
 * Pure function — no side effects, no I/O.  Input: strategy config + job
 * template.  Output: list of JobVariant with variable bindings.
 *
 * Extensibility: the MatrixExpander class can be extended with additional
 * combinator strategies (e.g. weighted matrix, conditional include).
 */
export class MatrixExpander {
  /**
   * Expand a matrix configuration into individual job variants.
   * Returns an empty array if no matrix strategy is configured.
   */
  public expand(jobName: string, jobDef: JobDef): JobVariant[] {
    const matrix = (jobDef as any).strategy?.matrix as MatrixConfig['matrix'] | undefined;
    if (!matrix) return [{ name: jobName, matrixVars: {}, jobDef }];

    const exclude = (jobDef as any).strategy?.exclude as MatrixConfig['exclude'] | undefined;
    const failFast = (jobDef as any).strategy?.failFast as boolean | undefined;
    const maxParallel = (jobDef as any).strategy?.maxParallel as number | undefined;

    const variables = Object.entries(matrix);
    if (variables.length === 0) return [{ name: jobName, matrixVars: {}, jobDef }];

    // Cartesian product of all variable values
    const combinations = this.#cartesian(variables);

    // Apply excludes
    const filtered = exclude
      ? combinations.filter(combo =>
          !exclude.some(ex => this.#matchesExclude(combo, ex)),
        )
      : combinations;

    return filtered.map((vars, _i) => {
      const labelParts = Object.entries(vars).map(([k, v]) => `${k}=${String(v)}`);
      return {
        name: `${jobName} (${labelParts.join(', ')})`,
        matrixVars: vars,
        jobDef: {
          ...jobDef,
          // Remove strategy from expanded job to prevent infinite recursion
          strategy: undefined as any,
          // Inject matrix variables into env
          env: {
            ...jobDef.env,
            ...Object.fromEntries(
              Object.entries(vars).map(([k, v]) => [`MATRIX_${k.toUpperCase()}`, String(v)]),
            ),
          },
          // Inject maxParallel / failFast metadata
          ...(maxParallel !== undefined ? { maxParallel } : {}),
          ...(failFast !== undefined ? { failFast } : {}),
        },
      };
    });
  }

  // ─── Helpers ───

  #cartesian(
    variables: [string, readonly (string | number | boolean)[]][],
  ): Record<string, string | number | boolean>[] {
    if (variables.length === 0) return [{}];

    const [head, ...tail] = variables;
    const [key, values] = head!;
    const rest = this.#cartesian(tail);

    const result: Record<string, string | number | boolean>[] = [];
    for (const value of values) {
      for (const r of rest) {
        result.push({ [key]: value, ...r });
      }
    }
    return result;
  }

  #matchesExclude(
    vars: Record<string, string | number | boolean>,
    exclude: Record<string, string | number | boolean>,
  ): boolean {
    return Object.entries(exclude).every(([k, v]) => vars[k] === v);
  }
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { VersionId } from '../../core/brand.ts';
import { generateVersionId } from '../../core/brand.ts';

const PFX = 'action-def:';
const IDX = 'action-def:ids';

export interface ActionDef {
  readonly id: string;
  readonly name: string;
  readonly version: string;
  readonly description?: string;
  /** Input parameters the action accepts. */
  readonly inputs?: Record<string, {
    readonly description?: string;
    readonly required?: boolean;
    readonly default?: string;
  }>;
  /** Outputs the action produces. */
  readonly outputs?: Record<string, { readonly description?: string }>;
  /** How the action runs: 'container' for Docker image, 'node' for JS. */
  readonly runs: {
    readonly using: 'container' | 'node';
    readonly main?: string;   // JS entrypoint file
    readonly image?: string;  // Container image reference
  };
  readonly createdAt: number;
  readonly updatedAt: number;
  readonly versionId: VersionId;
}

export interface CreateActionInput {
  readonly name: string;
  readonly version: string;
  readonly description?: string;
  readonly inputs?: Record<string, { description?: string; required?: boolean; default?: string }>;
  readonly outputs?: Record<string, { description?: string }>;
  readonly runs: { using: 'container' | 'node'; main?: string; image?: string };
}

/**
 * Resolve a `uses:` reference like "docker/build-push@v1" or "my-action@1.0.0"
 * to a concrete ActionDef (image reference or JS entrypoint).
 *
 * Lookup strategy:
 *   1. Exact match: name@version in action-def registry
 *   2. Container fallback: if name contains '/', treat as image reference directly
 */
export class ActionRegistry {
  public constructor(private readonly atomic: IAtomicStore) {}

  public async register(input: CreateActionInput): Promise<ActionDef> {
    const id = `act_${crypto.randomUUID()}`;
    const def: ActionDef = {
      id,
      name: input.name,
      version: input.version,
      ...(input.description ? { description: input.description } : {}),
      ...(input.inputs ? { inputs: input.inputs } : {}),
      ...(input.outputs ? { outputs: input.outputs } : {}),
      runs: input.runs,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      versionId: generateVersionId(),
    };

    await this.atomic.set(PFX + id, def, null);
    const idx = await this.atomic.get<string[]>(IDX);
    await this.atomic.set(IDX, [...(idx?.value ?? []), id], idx?.version ?? null);
    return def;
  }

  public async get(id: string): Promise<ActionDef | null> {
    const entry = await this.atomic.get<ActionDef>(PFX + id);
    return entry?.value ?? null;
  }

  public async list(): Promise<ActionDef[]> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return [];
    const entries = await Promise.all(
      idx.value.map(i => this.atomic.get<ActionDef>(PFX + i)),
    );
    return entries.filter(e => e).map(e => e!.value);
  }

  /**
   * Resolve a `uses:` string to a concrete run configuration.
   *
   * @returns { image, entrypoint } for container actions, or null if not found.
   */
  public async resolve(uses: string): Promise<{
    image: string;
    entrypoint?: string[];
    env?: Record<string, string>;
  } | null> {
    // Try exact match: name@version
    const idx = await this.atomic.get<string[]>(IDX);
    if (idx) {
      for (const id of idx.value) {
        const entry = await this.atomic.get<ActionDef>(PFX + id);
        if (!entry) continue;
        const fullRef = `${entry.value.name}@${entry.value.version}`;
        if (fullRef === uses) {
          if (entry.value.runs.using === 'container' && entry.value.runs.image) {
            const ep = entry.value.runs.main ? { entrypoint: [entry.value.runs.main] } : {};
            return { image: entry.value.runs.image, ...ep };
          }
          // node actions not supported in P1
          return null;
        }
      }
    }

    // Container image fallback: docker.io/library/node:20, etc.
    if (uses.includes('/') || uses.includes(':')) {
      const [image, tag] = uses.includes(':') ? uses.split(':') : [uses, 'latest'];
      return { image: `${String(image)}:${String(tag)}` };
    }

    return null;
  }
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import { AppError } from '../../core/types.ts';
import { generateVersionId } from '../../core/brand.ts';
import type { VersionId } from '../../core/brand.ts';
import type { ResourceNode } from '../../core/scheduler/dag/types.ts';

const PFX = 'action-runner:';
const IDX = 'action-runner:ids';
/** Heartbeat timeout: runners not seen within this window are marked offline. */
const HEARTBEAT_TIMEOUT_MS = 30_000;

export interface RunnerRegistration {
  readonly id: string;
  readonly name: string;
  /** Backing compute instance ID. Maps to IProviderRegistry.resolveContainer(). */
  readonly instanceId?: string;
  /** Labels for job matching (runs-on). e.g. { os: "linux", arch: "amd64" }. */
  readonly labels: Readonly<Record<string, string>>;
  /** Total resource capacity of this runner. */
  readonly capacity: {
    readonly cpu: number;
    readonly memory: number;   // MB
    readonly gpu?: number;
  };
  /** Current status. */
  readonly status: 'online' | 'offline' | 'draining';
  /** Version of the runner software. */
  readonly version: string;
  /** Last heartbeat timestamp (unix ms). */
  readonly lastHeartbeat: number;
  readonly createdAt: number;
  readonly updatedAt: number;
  readonly storeVersion: VersionId;
}

/** Input for registration or heartbeat update. */
export interface RunnerHeartbeatInput {
  readonly name: string;
  readonly instanceId?: string;
  readonly labels: Record<string, string>;
  readonly capacity: { cpu: number; memory: number; gpu?: number };
  readonly version?: string;
}

/**
 * Runner Registry — manages runner lifecycle.
 *
 * Extensibility: pluggable health policies (graceful drain, auto-scale signals,
 * custom health checks) can be added via IHealthPolicy interface without
 * modifying this class.
 */
export class RunnerRegistry {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly audit: IAuditWriter,
  ) {}

  /** Register a new runner or update heartbeat for an existing one. */
  public async heartbeat(input: RunnerHeartbeatInput): Promise<RunnerRegistration> {
    // Find existing runner by name
    const existing = await this.#findByName(input.name);

    if (existing) {
      const updated: RunnerRegistration = {
        ...existing,
        ...(input.instanceId ? { instanceId: input.instanceId } : {}),
        labels: input.labels,
        capacity: input.capacity,
        status: 'online',
        version: input.version ?? existing.version,
        lastHeartbeat: Date.now(),
        updatedAt: Date.now(),
        storeVersion: generateVersionId(),
      };
      const ver = await this.atomic.set(PFX + existing.id, updated, existing.storeVersion);
      if (!ver) throw new AppError(409, 'CONFLICT', 'Concurrent heartbeat update');
      return updated;
    }

    // New runner
    const id = `runner_${crypto.randomUUID()}`;
    const now = Date.now();
    const runner: RunnerRegistration = {
      id, name: input.name,
      ...(input.instanceId ? { instanceId: input.instanceId } : {}),
      labels: input.labels,
      capacity: input.capacity,
      status: 'online',
      version: input.version ?? '1.0.0',
      lastHeartbeat: now,
      createdAt: now, updatedAt: now,
      storeVersion: generateVersionId(),
    };

    await this.atomic.set(PFX + id, runner, null);
    const idx = await this.atomic.get<string[]>(IDX);
    await this.atomic.set(IDX, [...(idx?.value ?? []), id], idx?.version ?? null);

    this.audit.write({
      level: 5, facility: 'runner-registry',
      message: `Runner registered: ${input.name} (${id})`,
      metadata: { runnerId: id, labels: input.labels },
    });

    return runner;
  }

  /** Mark runners that haven't sent a heartbeat recently as offline. */
  public async markStale(): Promise<number> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return 0;
    const now = Date.now();
    let marked = 0;

    for (const id of idx.value) {
      const entry = await this.atomic.get<RunnerRegistration>(PFX + id);
      if (entry?.value.status !== 'online') continue;
      if (now - entry.value.lastHeartbeat < HEARTBEAT_TIMEOUT_MS) continue;

      const updated: RunnerRegistration = {
        ...entry.value,
        status: 'offline',
        updatedAt: now,
        storeVersion: generateVersionId(),
      };
      const ver = await this.atomic.set(PFX + id, updated, entry.version);
      if (ver) marked++;
    }
    return marked;
  }

  /** List online runners, optionally filtered by label requirements. */
  public async listOnline(requiredLabels?: Record<string, string>): Promise<RunnerRegistration[]> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return [];

    const entries = await Promise.all(
      idx.value.map(i => this.atomic.get<RunnerRegistration>(PFX + i)),
    );
    let runners = entries.filter(e => e?.value.status === 'online').map(e => e!.value);

    if (requiredLabels) {
      runners = runners.filter(r =>
        Object.entries(requiredLabels).every(([k, v]) => r.labels[k] === v),
      );
    }

    return runners;
  }

  /** Convert online runners to ResourceNode[] for the DagScheduler. */
  public async toResourceNodes(requiredLabels?: Record<string, string>): Promise<ResourceNode[]> {
    const runners = await this.listOnline(requiredLabels);
    return runners.map(r => ({
      id: r.id,
      capacity: r.capacity,
      labels: r.labels,
    }));
  }

  /** Set a runner to draining (stop accepting new jobs). */
  public async drain(id: string): Promise<void> {
    const entry = await this.atomic.get<RunnerRegistration>(PFX + id);
    if (!entry) throw new AppError(404, 'RUNNER_NOT_FOUND', 'Runner not found');
    const updated: RunnerRegistration = {
      ...entry.value, status: 'draining', updatedAt: Date.now(), storeVersion: generateVersionId(),
    };
    await this.atomic.set(PFX + id, updated, entry.version);
  }

  public async get(id: string): Promise<RunnerRegistration | null> {
    const entry = await this.atomic.get<RunnerRegistration>(PFX + id);
    return entry?.value ?? null;
  }

  public async list(): Promise<RunnerRegistration[]> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return [];
    const entries = await Promise.all(
      idx.value.map(i => this.atomic.get<RunnerRegistration>(PFX + i)),
    );
    return entries.filter(e => e).map(e => e!.value);
  }

  async #findByName(name: string): Promise<RunnerRegistration | null> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return null;
    for (const id of idx.value) {
      const entry = await this.atomic.get<RunnerRegistration>(PFX + id);
      if (entry?.value.name === name) return entry.value;
    }
    return null;
  }
}

import type { IAtomicStore, IBlobStore } from '../../core/store/interfaces.ts';
import type { IProviderRegistry } from '../../core/provider/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import type { IMessageQueue } from '../../queue/interfaces.ts';
import { createEvent } from '../../core/event-bus/types.ts';
import type { EventBus } from '../../core/event-bus/bus.ts';
import {
  type WorkflowDef,
  type WorkflowRun,
  type JobRun,
  type JobDef,
  type StepDef,
  type RunStepDef,
  type UsesStepDef,
  type WorkflowRunId,
  type JobRunId,
  type StepRun,
  type ActionContainerConfig,
  type JobRunStatus,
  IDX_WORKFLOW_RUN_IDS,
  IDX_JOB_RUN_IDS,
  PFX_WORKFLOW_RUN,
  PFX_JOB_RUN,
  createWorkflowRunId,
  createJobRunId,
} from './types.ts';
import { executeDnsStep } from './step-dns.ts';
import { appendStepLog } from './logs.ts';
import type { ActionRegistry } from './registry.ts';
import { MatrixExpander } from './matrix.ts';
import { DashboardService } from './dashboard.ts';
import { generateVersionId } from '../../core/brand.ts';
import type { PodService } from '../../core/pod/service.ts';
import type { PodSpec } from '../../core/pod/types.ts';
import { createRegionId } from '../../core/region/types.ts';
import { createInstanceId } from '../../core/region/instance.ts';

function runId(): WorkflowRunId { return createWorkflowRunId(`wfr_${crypto.randomUUID()}`); }
function jId(): JobRunId { return createJobRunId(`jr_${crypto.randomUUID()}`); }

export interface WorkflowRunnerDeps {
  stores: { atomic: IAtomicStore; blob: IBlobStore };
  providers: Pick<IProviderRegistry, 'resolveContainer' | 'dns'>;
  audit: IAuditWriter;
  queueProducer?: IMessageQueue;
  eventBus?: EventBus;
  actionRegistry?: ActionRegistry;
  podService?: PodService;
}

export class WorkflowRunner {
  public constructor(private readonly deps: WorkflowRunnerDeps) {}

  public async startRun(
    workflowDef: WorkflowDef,
    trigger: WorkflowRun['trigger'],
    triggerPayload?: unknown,
    extraEnv?: Record<string, string>,
    actorId?: string,
  ): Promise<WorkflowRun> {
    const id = runId();
    const now = Date.now();
    const env = { ...workflowDef.env, ...extraEnv };

    const run: WorkflowRun = {
      id,
      workflowId: workflowDef.id,
      status: 'Pending',
      trigger,
      triggerPayload,
      ...(actorId ? { ownerId: actorId } : {}),
      env,
      jobRunRefs: [],
      startedAt: now,
      version: generateVersionId(),
    };

    const { atomic } = this.deps.stores;
    await atomic.set(PFX_WORKFLOW_RUN + id, run, null);
    await this.#addToIndex(IDX_WORKFLOW_RUN_IDS, id);

    const jobRefs = await this.#createJobRuns(workflowDef, id);

    const entry = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + id);
    const updated: WorkflowRun = { ...run, jobRunRefs: jobRefs };
    if (entry) {
      const ver = await atomic.set(PFX_WORKFLOW_RUN + id, updated, entry.version);
      if (!ver) {
        // OCC conflict — re-read and retry once
        const entry2 = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + id);
        if (entry2) await atomic.set(PFX_WORKFLOW_RUN + id, updated, entry2.version);
      }
    }

    await this.#enqueueReadyJobs(workflowDef, updated);

    this.deps.audit.write({
      level: 5, facility: 'workflow-runner',
      message: `WorkflowRun ${id} started: ${workflowDef.name} (trigger=${trigger})`,
      metadata: { workflowRunId: id, workflowId: workflowDef.id, trigger },
    });

    return updated;
  }

  public async executeJob(jobRunId: JobRunId): Promise<JobRun> {
    const { atomic } = this.deps.stores;
    const entry = await atomic.get<JobRun>(PFX_JOB_RUN + jobRunId);
    if (!entry) throw new Error(`JobRun ${jobRunId} not found`);
    const jobRun = entry.value;
    if (jobRun.status !== 'Queued') return jobRun;

    const started = Date.now();
    let current: JobRun = { ...jobRun, status: 'Running', startedAt: started, attempts: jobRun.attempts + 1, version: generateVersionId() };
    const ver1 = await atomic.set(PFX_JOB_RUN + jobRunId, current, entry.version);
    if (!ver1) return current; // OCC conflict

    // Push status via EventBus → DoBridge → WebSocket
    if (this.deps.eventBus && current.workflowRunId) {
      const evt = createEvent('workflow:job:status', {
        jobRunId, jobName: jobRun.jobName,
        workflowRunId: jobRun.workflowRunId, status: 'Running',
      });
      await this.deps.eventBus.dispatch(evt);
    }

    const wfEntry = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + jobRun.workflowRunId);
    if (!wfEntry) throw new Error(`WorkflowRun ${jobRun.workflowRunId} not found`);

    const wfDefEntry = await atomic.get<WorkflowDef>(`workflow-def:${wfEntry.value.workflowId}`);
    if (!wfDefEntry) throw new Error(`WorkflowDef not found`);
    const jobDef = wfDefEntry.value.jobs[jobRun.jobName];
    if (!jobDef) throw new Error(`Job ${jobRun.jobName} not in workflow`);

    // ── Approval gating ──
    if (jobDef.approval) {
      const { ApprovalService } = await import('./extensions.ts');
      const approvalSvc = new ApprovalService(atomic);
      const existing = await approvalSvc.getForRun(jobRun.workflowRunId);
      const jobApproval = existing.find(a => a.jobName === jobRun.jobName);

      if (!jobApproval || jobApproval.status === 'pending') {
        if (!jobApproval) {
          await approvalSvc.request(jobRun.workflowRunId, jobRun.jobName, [...jobDef.approval.approvers]);
        }
        // Mark as Queued — will be re-triggered when approved
        return current;
      }
      if (jobApproval.status === 'rejected') {
        const finalEntry = await atomic.get<JobRun>(PFX_JOB_RUN + jobRunId);
        if (finalEntry) {
          current = { ...current, status: 'Failure', error: `Approval rejected: ${jobApproval.reason ?? 'no reason'}`, completedAt: Date.now(), version: generateVersionId() };
          await atomic.set(PFX_JOB_RUN + jobRunId, current, finalEntry.version);
        }
        return current;
      }
      // approved — proceed
    }

    try {
      const { sandboxId, podId } = await this.#provisionJobSandbox(jobDef, wfEntry.value.env, jobRun.jobName);

      const sEntry = await atomic.get<JobRun>(PFX_JOB_RUN + jobRunId);
      if (sEntry) {
        current = { ...current, sandboxId, ...(podId ? { podId } : {}), version: generateVersionId() };
        await atomic.set(PFX_JOB_RUN + jobRunId, current, sEntry.version);
      }

      const stepRuns = await this.#executeSteps(jobDef.steps, wfEntry.value.env, sandboxId, jobRunId);

      const allOk = stepRuns.every(s => s.status !== 'Failure');
      const finalEntry = await atomic.get<JobRun>(PFX_JOB_RUN + jobRunId);
      if (finalEntry) {
        current = {
          ...current,
          status: allOk ? 'Success' : 'Failure',
          stepRuns,
          completedAt: Date.now(),
          version: generateVersionId(),
        };
        await atomic.set(PFX_JOB_RUN + jobRunId, current, finalEntry.version);
      }
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      const finalEntry = await atomic.get<JobRun>(PFX_JOB_RUN + jobRunId);
      if (finalEntry) {
        current = {
          ...current,
          status: 'Failure',
          error: msg,
          completedAt: Date.now(),
          version: generateVersionId(),
        };
        await atomic.set(PFX_JOB_RUN + jobRunId, current, finalEntry.version);
      }
    }

    // Push final status via EventBus
    if (this.deps.eventBus && current.workflowRunId) {
      const evt = createEvent('workflow:job:status', {
        jobRunId, jobName: jobRun.jobName,
        workflowRunId: jobRun.workflowRunId,
        status: current.status,
        ...(current.error ? { error: current.error } : {}),
      });
      await this.deps.eventBus.dispatch(evt);
    }

    // Record billing for completed job
    const billing = new DashboardService(atomic);
    const cpu = jobDef.container?.resources?.cpu ?? jobDef.containers?.[0]?.resources?.cpu;
    const memory = jobDef.container?.resources?.memory ?? jobDef.containers?.[0]?.resources?.memory;
    await billing.recordJobBilling(current, { ...(cpu ? { cpu } : {}), ...(memory ? { memory } : {}) });

    // Enqueue downstream jobs
    const wfEntry2 = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + jobRun.workflowRunId);
    const wfDefEntry2 = wfEntry2
      ? await atomic.get<WorkflowDef>(`workflow-def:${wfEntry2.value.workflowId}`)
      : null;
    if (wfEntry2 && wfDefEntry2 && current.status === 'Success') {
      await this.#enqueueReadyJobs(wfDefEntry2.value, wfEntry2.value);
    }

    if (wfEntry2) {
      await this.#checkWorkflowCompletion(wfEntry2.value);
    }

    return current;
  }

  // ─── Private ───

  async #createJobRuns(wf: WorkflowDef, wfRunId: WorkflowRunId): Promise<WorkflowRun['jobRunRefs']> {
    const refs: { jobName: string; jobRunId: JobRunId }[] = [];
    const expander = new MatrixExpander();

    for (const [jobName, jobDef] of Object.entries(wf.jobs)) {
      // Expand matrix strategy → one JobRun per variant
      const variants = expander.expand(jobName, jobDef);
      const failFast = (jobDef as any).strategy?.failFast === true;

      for (const variant of variants) {
        // Resolve ${{ matrix.xxx }} in env and container fields
        const resolvedEnv = this.#resolveMatrixVars(variant.jobDef.env ?? {}, variant.matrixVars);
        const resolvedContainer = variant.jobDef.container
          ? this.#resolveMatrixInContainer(variant.jobDef.container, variant.matrixVars)
          : undefined;

        const resolvedJob: typeof jobDef = {
          ...variant.jobDef,
          env: resolvedEnv,
          ...(resolvedContainer ? { container: resolvedContainer } : {}),
          // Inject failFast from matrix strategy
          ...(failFast ? { failFast: true } as any : {}),
        };

        const id = jId();
        const jobRun: JobRun = {
          id,
          workflowRunId: wfRunId,
          jobName: variant.name,
          status: 'Queued',
          attempts: 0,
          stepRuns: resolvedJob.steps.map(s => this.#defToStepRun(s)),
          version: generateVersionId(),
        };
        await this.deps.stores.atomic.set(PFX_JOB_RUN + id, jobRun, null);
        await this.#addToIndex(IDX_JOB_RUN_IDS, id);
        refs.push({ jobName: variant.name, jobRunId: id });
      }

      // failFast: if any variant of this job failed, cancel remaining variants
      // (checked in #checkWorkflowCompletion when one fails)
    }
    return refs;
  }

  /** Resolve ${{ matrix.KEY }} placeholders in env vars. */
  #resolveMatrixVars(
    env: Record<string, string>,
    matrixVars: Record<string, string | number | boolean>,
  ): Record<string, string> {
    const pattern = /\$\{\{\s*matrix\.(\w+)\s*\}\}/g;
    const result: Record<string, string> = {};
    for (const [k, v] of Object.entries(env)) {
      let resolved = v;
      for (const match of v.matchAll(pattern)) {
        const varName = match[1]!;
        const val = matrixVars[varName];
        resolved = resolved.replace(match[0], val !== undefined ? String(val) : '');
      }
      result[k] = resolved;
    }
    return result;
  }

  /** Resolve ${{ matrix.KEY }} in container config fields. */
  #resolveMatrixInContainer(container: any, vars: Record<string, string | number | boolean>): any {
    const pattern = /\$\{\{\s*matrix\.(\w+)\s*\}\}/g;
    const resolve = (s: string): string => {
      let r = s;
      for (const m of s.matchAll(pattern)) {
        r = r.replace(m[0], String(vars[m[1]!] ?? ''));
      }
      return r;
    };
    return {
      ...container,
      image: container.image ? resolve(container.image) : container.image,
    };
  }

  async #enqueueReadyJobs(wf: WorkflowDef, run: WorkflowRun): Promise<void> {
    const { atomic } = this.deps.stores;

    for (const ref of run.jobRunRefs) {
      const jEntry = await atomic.get<JobRun>(PFX_JOB_RUN + ref.jobRunId);
      if (jEntry?.value.status !== 'Queued') continue;

      const jobDef = wf.jobs[ref.jobName];
      if (!jobDef) continue;

      // Resolve dependency statuses
      const needs = jobDef.needs ?? [];
      if (needs.length > 0) {
        const depStatuses = await Promise.all(
          needs.map(async (needName) => {
            const depRef = run.jobRunRefs.find(r => r.jobName === needName);
            if (!depRef) return { name: needName, status: 'Queued' as const };
            const depEntry = await atomic.get<JobRun>(PFX_JOB_RUN + depRef.jobRunId);
            return { name: needName, status: (depEntry?.value.status ?? 'Queued') };
          }),
        );

        // failFast: if any dep failed, skip this job
        const failed = depStatuses.filter(d => d.status === 'Failure' || d.status === 'Cancelled');
        if (failed.length > 0) {
          const jEntry2 = await atomic.get<JobRun>(PFX_JOB_RUN + ref.jobRunId);
          if (jEntry2) {
            await atomic.set(PFX_JOB_RUN + ref.jobRunId, {
              ...jEntry2.value, status: 'Skipped',
              error: `Upstream dependency failed: ${failed.map(d => d.name).join(', ')}`,
              completedAt: Date.now(), version: generateVersionId(),
            }, jEntry2.version);
          }
          continue;
        }

        // All deps must be Success
        if (!depStatuses.every(s => s.status === 'Success')) continue;
      }

      // Schedule via Queue, or inline fallback
      const qp = this.deps.queueProducer;
      const qSent = qp
        ? await qp.send({ type: 'workflow:job:run', payload: { jobRunId: ref.jobRunId, workflowRunId: run.id }, timestamp: Date.now(), id: `wfj_${crypto.randomUUID()}` } as any)
        : false;

      if (!qSent) {
        await this.executeJob(ref.jobRunId);
      }
    }
  }

  async #checkWorkflowCompletion(run: WorkflowRun): Promise<void> {
    const { atomic } = this.deps.stores;
    const statuses: JobRunStatus[] = [];
    for (const ref of run.jobRunRefs) {
      const jEntry = await atomic.get<JobRun>(PFX_JOB_RUN + ref.jobRunId);
      if (jEntry) statuses.push(jEntry.value.status);
    }

    const pending = statuses.filter(s => s === 'Queued' || s === 'Running');
    if (pending.length > 0) return;

    const anyFailed = statuses.some(s => s === 'Failure' || s === 'Cancelled');
    const newStatus = anyFailed ? 'Failure' : 'Success';

    const entry = await atomic.get<WorkflowRun>(PFX_WORKFLOW_RUN + run.id);
    if (!entry || entry.value.status !== 'Pending' && entry.value.status !== 'Running') return;

    const updated: WorkflowRun = {
      ...entry.value,
      status: newStatus,
      completedAt: Date.now(),
      version: generateVersionId(),
    };
    await atomic.set(PFX_WORKFLOW_RUN + run.id, updated, entry.version);

    if (this.deps.eventBus) {
      const evt = createEvent('workflow:completed', { workflowRunId: run.id, status: newStatus });
      await this.deps.eventBus.dispatch(evt);
    }
  }

  async #provisionJobSandbox(
    jobDef: JobDef,
    env: Record<string, string>,
    jobName: string,
  ): Promise<{ sandboxId: string; podId?: string }> {
    const instanceId = jobDef.instanceId;
    const region = jobDef.region ?? 'local';
    const mergedEnv = { ...env, ...jobDef.env };
    const container = jobDef.containers?.[0] ?? jobDef.container;
    if (!container) throw new Error(`Job ${jobName} has no container defined`);

    // v3 path: PodService.provision() → PodEntity with lifecycle tracking
    if (this.deps.podService) {
      const podSpec = this.#jobToPodSpec(jobName, container, mergedEnv, jobDef);
      const pod = await this.deps.podService.provision(podSpec);
      return { sandboxId: pod.providerId ?? pod.podId, podId: pod.podId };
    }

    // v2 fallback: direct provider.create()
    if (!instanceId || !this.deps.providers.resolveContainer) {
      throw new Error('Workflow job requires an instanceId to resolve a container provider');
    }
    const provider = await this.deps.providers.resolveContainer(createInstanceId(instanceId));

    const result = await provider.create({
      name: `action-${jobName}-${String(Date.now())}`,
      region: createRegionId(region),
      ...(instanceId ? { instanceId: createInstanceId(instanceId) } : {}),
      cpu: container.resources?.cpu ?? 1,
      memory: container.resources?.memory ?? 1024,
      restartPolicy: 'Never',
      containers: [{
        name: jobName,
        image: container.image,
        command: container.command ? [...container.command] : undefined,
        args: container.args ? [...container.args] : undefined,
        env: Object.entries(mergedEnv).map(([k, v]) => ({ name: k, value: v })),
        ports: container.ports ? [...container.ports] : undefined,
        resources: container.resources ? { limits: { cpu: container.resources.cpu ?? 1, memory: container.resources.memory ?? 1024 } } : undefined,
      }],
      network: { allocatePublicIp: false },
    });

    return { sandboxId: result.providerId };
  }

  /** Build a PodSpec from a job definition for PodService.provision(). */
  #jobToPodSpec(
    jobName: string,
    container: ActionContainerConfig,
    env: Record<string, string>,
    jobDef: JobDef,
  ): PodSpec {
    const envList = Object.entries(env).map(([name, value]) => ({ name, value }));
    return {
      metadata: {
        name: `action-${jobName}-${String(Date.now())}`,
        labels: { job: jobName, owner: 'actions' },
      },
      spec: {
        containers: [{
          name: jobName,
          image: container.image,
          command: container.command ? [...container.command] : undefined,
          args: container.args ? [...container.args] : undefined,
          env: envList.length > 0 ? envList : undefined,
          ports: container.ports ? [...container.ports] : undefined,
          resources: container.resources ? {
            limits: {
              cpu: container.resources.cpu ?? 1,
              memory: container.resources.memory ?? 1024,
            },
          } : undefined,
        }],
        restartPolicy: 'Never',
      },
      ...(jobDef.region ? { providerOverrides: { region: jobDef.region, ...(jobDef.instanceId ? { instanceId: jobDef.instanceId } : {}) } } : {}),
    };
  }

  async #executeSteps(
    steps: readonly StepDef[],
    env: Record<string, string>,
    sandboxId: string,
    jobRunId: string,
  ): Promise<StepRun[]> {
    const stepRuns: StepRun[] = [];
    const provider = await this.deps.providers.resolveContainer?.(undefined) as any;

    for (const step of steps) {
      const name = step.name ?? (('run' in step) ? step.run.slice(0, 60) : ('dns' in step) ? `dns:${step.dns.name}` : step.uses ?? 'unknown');
      const startedAt = Date.now();

      // Log step start
      await appendStepLog(this.deps.stores.blob, jobRunId, name, `Step started: ${name}`);
      this.deps.audit.write({
        level: 6, facility: 'step-executor',
        message: `Step started: ${name}`,
        metadata: { jobRunId, stepName: name },
      });

      try {
        if ('run' in step) {
          await this.#executeRunStep(step, env, sandboxId, provider);
          await appendStepLog(this.deps.stores.blob, jobRunId, name,
            `Step completed: ${name} (exit 0)`);
          stepRuns.push({ name, status: 'Success', startedAt, completedAt: Date.now(), exitCode: 0 });

        } else if ('dns' in step) {
          await executeDnsStep(step, this.deps.providers.dns, this.deps.audit);
          await appendStepLog(this.deps.stores.blob, jobRunId, name,
            `DNS ${(step).dns.action} ${(step).dns.name}`);
          stepRuns.push({ name, status: 'Success', startedAt, completedAt: Date.now() });

        } else if ('uses' in step) {
          await this.#executeUsesStep(step, env, sandboxId, provider);
          await appendStepLog(this.deps.stores.blob, jobRunId, name,
            `Action completed: ${(step).uses}`);
          stepRuns.push({ name, status: 'Success', startedAt, completedAt: Date.now(), exitCode: 0 });
        }

      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        await appendStepLog(this.deps.stores.blob, jobRunId, name,
          `Step FAILED: ${msg}`);
        this.deps.audit.write({
          level: 3, facility: 'step-executor',
          message: `Step failed: ${name} — ${msg}`,
          metadata: { jobRunId, stepName: name, error: msg },
        });

        if (step.continueOnError) {
          stepRuns.push({ name, status: 'Success', startedAt, completedAt: Date.now(), error: msg });
        } else {
          stepRuns.push({ name, status: 'Failure', startedAt, completedAt: Date.now(), exitCode: 1, error: msg });
          break;
        }
      }
    }

    return stepRuns;
  }

  /** Execute a `run:` step inside the container via provider.exec(). */
  async #executeRunStep(
    step: RunStepDef,
    env: Record<string, string>,
    sandboxId: string,
    provider: any,
  ): Promise<void> {
    const shell = step.shell ?? '/bin/sh';
    const script = step.run;

    if (typeof provider.exec !== 'function') {
      // Provider doesn't support exec — mark as success
      // (the container's entrypoint handles execution)
      return;
    }

    const envList = Object.entries({ ...env, ...step.env }).map(
      ([k, v]) => `${k}=${v}`,
    );

    const result = await provider.exec({
      providerId: sandboxId,
      command: [shell, '-c', script],
      env: envList,
      timeout: step.timeout ? step.timeout * 1000 : undefined,
    });

    if (result?.exitCode !== 0) {
      throw new Error(
        `Command exited with code ${String(result?.exitCode ?? -1)}: ${script.slice(0, 200)}`,
      );
    }
  }

  /** Execute a `uses:` step by resolving the action reference and running it. */
  async #executeUsesStep(
    step: UsesStepDef,
    env: Record<string, string>,
    sandboxId: string,
    provider: any,
  ): Promise<void> {
    const registry = this.deps.actionRegistry;
    if (!registry) {
      // No registry configured — try container image fallback
      if (typeof provider.exec === 'function') {
        const mergedEnv = { ...env, ...step.env, ...step.with };
        const envList = Object.entries(mergedEnv).map(([k, v]) => `${k}=${v}`);
        const result = await provider.exec({
          providerId: sandboxId,
          command: ['/bin/sh', '-c', `echo 'Running action: ${step.uses}'`],
          env: envList,
          timeout: step.timeout ? step.timeout * 1000 : undefined,
        });
        if (result?.exitCode !== 0) {
          throw new Error(`Action ${String(step.uses)} failed with exit ${String(result?.exitCode)}`);
        }
        return;
      }
      throw new Error(`Action registry not available and provider has no exec — cannot run ${step.uses}`);
    }

    const resolved = await registry.resolve(step.uses);
    if (!resolved) {
      throw new Error(`Action not found: ${step.uses}. Register it via POST /api/actions/actions or use a container image reference (e.g. docker.io/library/node:20).`);
    }

    // For container-based actions, exec the entrypoint inside the sandbox
    if (typeof provider.exec === 'function') {
      const mergedEnv = { ...env, ...step.env, ...step.with };
      const envList = Object.entries(mergedEnv).map(([k, v]) => `${k}=${v}`);
      const cmd = resolved.entrypoint ?? ['/bin/sh', '-c', `echo 'Action: ${step.uses}'`];
      const result = await provider.exec({
        providerId: sandboxId,
        command: cmd,
        env: envList,
        timeout: step.timeout ? step.timeout * 1000 : undefined,
      });
      if (result?.exitCode !== 0) {
        throw new Error(`Action ${String(step.uses)} failed with exit ${String(result?.exitCode)}`);
      }
    }
  }

  #defToStepRun(step: StepDef): StepRun {
    const name = step.name ?? (('run' in step) ? step.run.slice(0, 60) : ('dns' in step) ? `dns:${step.dns.name}` : step.uses ?? 'unknown');
    return { name, status: 'Queued' };
  }

  async #addToIndex(indexKey: string, id: string): Promise<void> {
    const { atomic } = this.deps.stores;
    const idx = await atomic.get<string[]>(indexKey);
    await atomic.set(indexKey, [...(idx?.value ?? []), id], idx?.version ?? null);
  }
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { SecretEncryption } from '../../core/auth/secret-encryption.ts';
import { AppError } from '../../core/types.ts';
import { generateVersionId } from '../../core/brand.ts';
import type { VersionId } from '../../core/brand.ts';

const PFX = 'action-secret:';
const IDX = 'action-secret:ids';

export interface WorkflowSecret {
  readonly id: string;
  readonly workflowId: string;
  readonly key: string;           // e.g. "DOCKER_PASSWORD"
  readonly encryptedValue: string; // AES-256-GCM ciphertext (or plaintext if no key configured)
  readonly createdAt: number;
  readonly updatedAt: number;
  readonly version: VersionId;
}

export class WorkflowSecretService {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly encryption?: SecretEncryption,
  ) {}

  public async set(workflowId: string, key: string, value: string): Promise<WorkflowSecret> {
    const id = `ws_${crypto.randomUUID()}`;
    const now = Date.now();
    const encrypted = this.encryption
      ? await this.encryption.encrypt(value)
      : value;

    const secret: WorkflowSecret = {
      id, workflowId, key, encryptedValue: encrypted,
      createdAt: now, updatedAt: now, version: generateVersionId(),
    };

    // Upsert: if a secret with the same workflowId + key exists, replace it
    const existing = await this.#findByKey(workflowId, key);
    if (existing) {
      const updated: WorkflowSecret = { ...existing, encryptedValue: encrypted, updatedAt: now, version: generateVersionId() };
      await this.atomic.set(PFX + existing.id, updated, existing.version);
      return updated;
    }

    await this.atomic.set(PFX + id, secret, null);
    const idx = await this.atomic.get<string[]>(IDX);
    await this.atomic.set(IDX, [...(idx?.value ?? []), id], idx?.version ?? null);
    return secret;
  }

  public async get(workflowId: string, key: string): Promise<string | null> {
    const secret = await this.#findByKey(workflowId, key);
    if (!secret) return null;
    return this.encryption
      ? this.encryption.decrypt(secret.encryptedValue)
      : secret.encryptedValue;
  }

  public async list(workflowId: string): Promise<{ key: string; id: string }[]> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return [];
    const entries = await Promise.all(
      idx.value.map(i => this.atomic.get<WorkflowSecret>(PFX + i)),
    );
    return entries
      .filter(e => e?.value.workflowId === workflowId)
      .map(e => ({ key: e!.value.key, id: e!.value.id }));
  }

  public async delete(id: string): Promise<void> {
    const entry = await this.atomic.get<WorkflowSecret>(PFX + id);
    if (!entry) throw new AppError(404, 'SECRET_NOT_FOUND', 'Secret not found');
    await this.atomic.set(PFX + id, null, entry.version);
    const idx = await this.atomic.get<string[]>(IDX);
    if (idx) await this.atomic.set(IDX, idx.value.filter(i => i !== id), idx.version);
  }

  /**
   * Resolve `${{ secrets.KEY }}` placeholders in a values object.
   */
  public async resolveSecrets(
    workflowId: string,
    values: Record<string, string>,
  ): Promise<Record<string, string>> {
    const result: Record<string, string> = {};
    for (const [k, v] of Object.entries(values)) {
      result[k] = await this.#resolveValue(workflowId, v);
    }
    return result;
  }

  async #resolveValue(workflowId: string, value: string): Promise<string> {
    const pattern = /\$\{\{\s*secrets\.(\w+)\s*\}\}/g;
    let resolved = value;
    for (const match of value.matchAll(pattern)) {
      const key = match[1]!;
      const secretVal = await this.get(workflowId, key);
      if (secretVal === null) throw new AppError(400, 'SECRET_NOT_FOUND', `Secret "${key}" not found for workflow`);
      resolved = resolved.replace(match[0], secretVal);
    }
    return resolved;
  }

  async #findByKey(workflowId: string, key: string): Promise<WorkflowSecret | null> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return null;
    for (const id of idx.value) {
      const entry = await this.atomic.get<WorkflowSecret>(PFX + id);
      if (entry?.value.workflowId === workflowId && entry.value.key === key) {
        return entry.value;
      }
    }
    return null;
  }
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import { AppError } from '../../core/types.ts';
import { generateVersionId } from '../../core/brand.ts';
import type { VersionId } from '../../core/brand.ts';

const PFX = 'shared-link:';
const IDX = 'shared-link:ids';

export interface SharedLink {
  readonly id: string;
  readonly ownerId: string;
  readonly workflowId: string;
  readonly name: string;
  /** bcrypt-style password hash. Empty string = no password required. */
  readonly passwordHash: string;
  readonly expiresAt: number;          // unix ms
  readonly maxUses: number;           // 0 = unlimited
  readonly useCount: number;
  readonly concurrentMax: number;     // 0 = unlimited
  readonly defaultTtlSeconds: number; // container lifetime after start
  readonly enabled: boolean;
  readonly createdAt: number;
  readonly updatedAt: number;
  readonly version: VersionId;
}

export interface CreateSharedLinkInput {
  readonly workflowId: string;
  readonly name: string;
  readonly password?: string;
  readonly expiresAt: number;
  readonly maxUses?: number;
  readonly concurrentMax?: number;
  readonly defaultTtlSeconds?: number;
}

export class SharedLinkService {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly audit: IAuditWriter,
  ) {}

  public async create(ownerId: string, input: CreateSharedLinkInput): Promise<SharedLink> {
    const id = `sl_${crypto.randomUUID()}`;
    const now = Date.now();

    if (input.expiresAt <= now) throw new AppError(400, 'INVALID_EXPIRY', 'expiresAt must be in the future');

    const passwordHash = input.password
      ? await this.#hashPassword(input.password)
      : '';

    const link: SharedLink = {
      id,
      ownerId,
      workflowId: input.workflowId,
      name: input.name,
      passwordHash,
      expiresAt: input.expiresAt,
      maxUses: input.maxUses ?? 0,
      useCount: 0,
      concurrentMax: input.concurrentMax ?? 0,
      defaultTtlSeconds: input.defaultTtlSeconds ?? 3600,
      enabled: true,
      createdAt: now,
      updatedAt: now,
      version: generateVersionId(),
    };

    await this.atomic.set(PFX + id, link, null);
    const idx = await this.atomic.get<string[]>(IDX);
    await this.atomic.set(IDX, [...(idx?.value ?? []), id], idx?.version ?? null);

    this.audit.write({
      level: 5, facility: 'shared-link',
      message: `SharedLink created: ${input.name} (${id})`,
      metadata: { linkId: id, ownerId, workflowId: input.workflowId },
    });

    return link;
  }

  /**
   * Validate access to a shared link.
   * Checks: enabled, expiry, maxUses, password.
   * Returns the link if access is granted, throws otherwise.
   */
  public async validate(id: string, password?: string): Promise<SharedLink> {
    const entry = await this.atomic.get<SharedLink>(PFX + id);
    if (!entry) throw new AppError(404, 'LINK_NOT_FOUND', 'Shared link not found');

    const link = entry.value;
    const now = Date.now();

    if (!link.enabled) throw new AppError(403, 'LINK_DISABLED', 'This shared link has been disabled');
    if (now > link.expiresAt) throw new AppError(403, 'LINK_EXPIRED', 'This shared link has expired');
    if (link.maxUses > 0 && link.useCount >= link.maxUses) {
      throw new AppError(403, 'LINK_EXHAUSTED', 'This shared link has reached its maximum uses');
    }

    if (link.passwordHash) {
      if (!password) throw new AppError(401, 'PASSWORD_REQUIRED', 'Password required');
      const valid = await this.#verifyPassword(password, link.passwordHash);
      if (!valid) throw new AppError(401, 'INVALID_PASSWORD', 'Invalid password');
    }

    return link;
  }

  /** Record a use of the shared link (increment useCount). */
  public async recordUse(id: string): Promise<void> {
    for (let attempt = 0; attempt < 3; attempt++) {
      const entry = await this.atomic.get<SharedLink>(PFX + id);
      if (!entry) return;

      const updated: SharedLink = {
        ...entry.value,
        useCount: entry.value.useCount + 1,
        updatedAt: Date.now(),
        version: generateVersionId(),
      };
      const ver = await this.atomic.set(PFX + id, updated, entry.version);
      if (ver) return;
    }
  }

  public async disable(id: string, ownerId: string): Promise<void> {
    const entry = await this.atomic.get<SharedLink>(PFX + id);
    if (!entry) throw new AppError(404, 'LINK_NOT_FOUND', 'Shared link not found');
    if (entry.value.ownerId !== ownerId) throw new AppError(403, 'FORBIDDEN', 'Not the owner');

    const updated: SharedLink = { ...entry.value, enabled: false, updatedAt: Date.now(), version: generateVersionId() };
    const ver = await this.atomic.set(PFX + id, updated, entry.version);
    if (!ver) throw new AppError(409, 'CONFLICT', 'Concurrent modification');
  }

  public async list(ownerId: string): Promise<SharedLink[]> {
    const idx = await this.atomic.get<string[]>(IDX);
    if (!idx) return [];
    const entries = await Promise.all(
      idx.value.map(i => this.atomic.get<SharedLink>(PFX + i)),
    );
    return entries.filter(e => e?.value.ownerId === ownerId).map(e => e!.value);
  }

  public async get(id: string): Promise<SharedLink | null> {
    const entry = await this.atomic.get<SharedLink>(PFX + id);
    return entry?.value ?? null;
  }

  // ─── Password helpers ───

  async #hashPassword(password: string): Promise<string> {
    const encoder = new TextEncoder();
    const salt = crypto.getRandomValues(new Uint8Array(16));
    const key = await crypto.subtle.importKey('raw', encoder.encode(password), 'PBKDF2', false, ['deriveBits']);
    const hash = await crypto.subtle.deriveBits(
      { name: 'PBKDF2', salt, iterations: 100000, hash: 'SHA-256' },
      key, 256,
    );
    const saltB64 = btoa(String.fromCharCode(...salt));
    const hashB64 = btoa(String.fromCharCode(...new Uint8Array(hash)));
    return `$pbkdf2$${saltB64}$${hashB64}`;
  }

  async #verifyPassword(password: string, stored: string): Promise<boolean> {
    const parts = stored.split('$');
    if (parts.length !== 4 || parts[1] !== 'pbkdf2') return false;
    const salt = Uint8Array.from(atob(parts[2]!), c => c.charCodeAt(0));
    const expectedHash = parts[3]!;

    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey('raw', encoder.encode(password), 'PBKDF2', false, ['deriveBits']);
    const hash = await crypto.subtle.deriveBits(
      { name: 'PBKDF2', salt, iterations: 100000, hash: 'SHA-256' },
      key, 256,
    );
    const hashB64 = btoa(String.fromCharCode(...new Uint8Array(hash)));
    return hashB64 === expectedHash;
  }
}

import type { IDnsProvider } from '../../core/provider/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import type { DnsStepDef } from './types.ts';

/**
 * Execute a DNS step — uses the IDnsProvider directly.
 *
 * DNS is an Action-internal capability, not routed through the
 * /api/dns feature.  This means:
 *  - No pre-existing DnsRecord entity required
 *  - DNS lifecycle is tied to the Workflow Run (cleanup on teardown)
 *  - zoneId is explicit in the step config (no external lookup)
 */
export async function executeDnsStep(
  step: DnsStepDef,
  provider: IDnsProvider,
  audit?: IAuditWriter,
): Promise<void> {
  const dns = step.dns;
  const ttl = dns.ttl ?? 300;
  const proxied = dns.proxied ?? false;

  if (dns.action === 'upsert') {
    // providerRecordId is optional for upsert — the provider will create or
    // update the record. We use the fqdn as a stable identifier.
    const recordId = `${dns.type}:${dns.name}:${dns.zoneId}`;
    await provider.updateRecord({
      domain: dns.name,
      type: dns.type as 'A' | 'CNAME',
      value: dns.value,
      ttl,
      proxied,
      providerRecordId: recordId,
      zoneId: dns.zoneId,
    });
  } else {
    const recordId = `${dns.type}:${dns.name}:${dns.zoneId}`;
    await provider.deleteRecord({
      zoneId: dns.zoneId,
      providerRecordId: recordId,
    });
  }

  audit?.write({
    level: 6,
    facility: 'action-dns',
    message: `DNS ${dns.action} ${dns.type} ${dns.name} → ${dns.value}`,
    metadata: { stepType: 'dns', ...dns },
  });
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { EventBus } from '../../core/event-bus/bus.ts';
import type { EventLoop } from '../../core/event-bus/loop.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
