import type { IBlobStore } from '../../core/store/interfaces.ts';

const { parse: parseJson } = JSON;
const WS_PREFIX = 'action:workspace:';

/**
 * Workspace metadata stored alongside the archive.
 *
 * Extensibility: the ArchiveFormat type allows adding new compression
 * or transfer methods without changing the API.
 */
export type ArchiveFormat = 'tar' | 'tar.gz' | 'raw';

export interface WorkspaceMeta {
  readonly workflowRunId: string;
  readonly jobName: string;
  readonly format: ArchiveFormat;
  readonly sizeBytes: number;
  readonly fileCount: number;
  readonly createdAt: number;
}

/**
 * Workspace sharing service — transfers working directories between
 * jobs in the same workflow via IBlobStore (R2 / file-blob).
 *
 * Pattern:
 *   Job A: share → snapshot working dir → upload to R2
 *   Job B: restore → download from R2 → extract to working dir
 *
 * Extensibility: the IWorkspaceStore interface allows swapping R2
 * for NFS, S3, or local filesystem without changing consumers.
 */
export interface IWorkspaceStore {
  save(workflowRunId: string, jobName: string, data: Uint8Array, meta: Omit<WorkspaceMeta, 'workflowRunId' | 'jobName' | 'sizeBytes' | 'createdAt'>): Promise<WorkspaceMeta>;
  load(workflowRunId: string, jobName: string): Promise<{ data: Uint8Array; meta: WorkspaceMeta } | null>;
  list(workflowRunId: string): Promise<WorkspaceMeta[]>;
}

export class BlobWorkspaceStore implements IWorkspaceStore {
  public constructor(private readonly blob: IBlobStore) {}

  public async save(
    workflowRunId: string,
    jobName: string,
    data: Uint8Array,
    meta: Omit<WorkspaceMeta, 'workflowRunId' | 'jobName' | 'sizeBytes' | 'createdAt'>,
  ): Promise<WorkspaceMeta> {
    const key = `${WS_PREFIX}${workflowRunId}/${jobName}`;
    const now = Date.now();
    const wsMeta: WorkspaceMeta = {
      workflowRunId, jobName,
      format: meta.format,
      sizeBytes: data.byteLength,
      fileCount: meta.fileCount,
      createdAt: now,
    };

    // Store data + metadata as a JSON envelope
    const envelope = JSON.stringify({ meta: wsMeta, data: Array.from(data) });
    const encoded = new TextEncoder().encode(envelope);

    await this.blob.put(key, encoded.buffer, {
      contentType: 'application/json',
      contentLength: encoded.byteLength,
    });

    return wsMeta;
  }

  public async load(workflowRunId: string, jobName: string): Promise<{ data: Uint8Array; meta: WorkspaceMeta } | null> {
    const key = `${WS_PREFIX}${workflowRunId}/${jobName}`;
    const stream = await this.blob.get(key);
    if (!stream) return null;

    const chunks: Uint8Array[] = [];
    const reader = stream.getReader();
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      chunks.push(value);
    }

    const totalSize = chunks.reduce((s, c) => s + c.byteLength, 0);
    const merged = new Uint8Array(totalSize);
    let offset = 0;
    for (const c of chunks) { merged.set(c, offset); offset += c.byteLength; }

    const text = new TextDecoder().decode(merged);
    const envelope = parseJson(text);
    return {
      data: new Uint8Array(envelope.data as number[]),
      meta: envelope.meta as WorkspaceMeta,
    };
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async list(_workflowRunId: string): Promise<WorkspaceMeta[]> {
    // IBlobStore has no list — callers track workspace keys via metadata
    return [];
  }
}

import { Hono } from 'hono';
import type { IContainerSecretService } from './service.ts';
import { CreateContainerSecretSchema, UpdateContainerSecretSchema } from './schema.ts';
import { ok, fail } from '../../core/response.ts';
import type { RouteMeta } from '../../core/http-docs/types.ts';
import { z } from 'zod';
import type { CrudHandlerMap } from '../../core/crud/router.ts';
import { registerCrudRoutes } from '../../core/crud/router.ts';

export function createContainerSecretRouter(svc: IContainerSecretService): Hono<any> {
  const router = new Hono<any>();

  const crud: CrudHandlerMap = {
    create: (r) => r.post('/', async (c) => {
      const body: unknown = await c.req.json();
      const parsed = CreateContainerSecretSchema.safeParse(body);
      if (!parsed.success) {
        return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      }
      const secret = await svc.create(parsed.data);
      return c.json(ok(redact(secret)), 201);
    }),

    list: (r) => r.get('/', async (c) => {
      const scopeId = c.req.query('scopeId');
      const items = await svc.list(scopeId);
      return c.json(ok({ items: items.map(redact), total: items.length }));
    }),

    get: (r) => r.get('/:id', async (c) => {
      const secret = await svc.get(c.req.param('id'));
      if (!secret) return c.json(fail('SECRET_NOT_FOUND', 'Container secret not found'), 404);
      return c.json(ok(redact(secret)));
    }),

    update: (r) => r.put('/:id', async (c) => {
      const body: unknown = await c.req.json();
      const parsed = UpdateContainerSecretSchema.safeParse(body);
      if (!parsed.success) {
        return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      }
      const secret = await svc.update(c.req.param('id'), parsed.data);
      return c.json(ok(redact(secret)));
    }),

    delete: (r) => r.delete('/:id', async (c) => {
      await svc.delete(c.req.param('id'));
      return c.json(ok(null));
    }),
  };

  registerCrudRoutes(router, crud);

  // ─── Extra routes (beyond CRUD) ───

  router.post('/:id/upload', async (c) => {
    const body = await c.req.parseBody();
    const file = body.file as File | undefined;
    if (!file) return c.json(fail('VALIDATION_ERROR', 'file is required'), 400);
    const secret = await svc.uploadBlob(
      c.req.param('id'),
      file.name,
      await file.arrayBuffer(),
      file.type,
    );
    return c.json(ok(redact(secret)));
  });

  router.get('/:id/download', async (c) => {
    const data = await svc.resolveData(c.req.param('id'));
    return c.body(data, 200, { 'Content-Type': 'application/octet-stream' });
  });

  router.get('/public-key/:userId', async (c) => {
    const pk = await svc.getPublicKey(c.req.param('userId'));
    if (!pk) return c.json(fail('PUBLIC_KEY_NOT_FOUND', 'No SealedBox keypair for this user. Generate one first.'), 404);
    return c.json(ok({ userId: c.req.param('userId'), publicKey: pk, keyType: 'sealed-box' }));
  });

  router.get('/:id/scopes', async (c) => {
    const secret = await svc.get(c.req.param('id'));
    if (!secret) return c.json(fail('SECRET_NOT_FOUND', 'Container secret not found'), 404);
    return c.json(ok(secret.selectedScopeIds));
  });

  router.put('/:id/scopes', async (c) => {
    const body: unknown = await c.req.json();
    const parsed = z.array(z.string()).safeParse(body);
    if (!parsed.success) {
      return c.json(fail('VALIDATION_ERROR', 'Expected array of scope IDs'), 400);
    }
    const secret = await svc.update(c.req.param('id'), { selectedScopeIds: parsed.data });
    return c.json(ok(redact(secret)));
  });

  router.get('/:id/check-access', async (c) => {
    const scopeId = c.req.query('scopeId');
    if (!scopeId) return c.json(fail('VALIDATION_ERROR', 'scopeId query parameter is required'), 400);
    const allowed = await svc.canAccess(c.req.param('id'), scopeId);
    return c.json(ok({ allowed }));
  });

  return router;
}

function redact(s: any): any {
  if (!s) return s;
  const r = { ...s };
  if (r.value) r.value = '[REDACTED]';
  return r;
}

