/* eslint-disable @typescript-eslint/restrict-template-expressions -- stub implementation */

// ─── Stub OCI Runtime — Container Simulator ───
// Models five dimensions: container info, network, storage, logs, health check.
// Cloud orchestration creates instances → OCI Runtime manages them.
//
// Container info: name, image, args, env, workingDir, labels, annotations
// Network:        IP (172.17.0.x), gateway, port mappings
// Storage:        volume/directory mounts
// Logs:           image-aware startup + console output
// Health check:   simulated probe with starting → healthy/unhealthy transitions

/* eslint-disable @typescript-eslint/require-await -- stub/noop implementation */
import type { IOCIRuntime } from './interfaces.ts';
import type {
  ContainerId,
  OciContainer,
  OciContainerStatus,
  OciHealthStatus,
} from '../../core/provider/types.ts';
import { createContainerId } from '../../core/provider/types.ts';
import type {
  OciImageRef,
  OciImageInfo,
  OciCreateSpec,
  OciLogOptions,
} from './types.ts';

// ─── Internal state ───

interface MutableContainer {
  id: ContainerId;
  name: string;
  image: OciImageRef;
  args: readonly string[];
  env: Record<string, string>;
  workingDir: string;
  status: OciContainerStatus;
  alive: boolean;
  createdAt: string;
  startedAt?: string | undefined;
  finishedAt?: string | undefined;
  exitCode?: number | undefined;
  labels: Record<string, string>;
  annotations: Record<string, string>;
  mounts: readonly { source: string; destination: string; type?: string | undefined; options?: readonly string[] | undefined }[];
  ports: readonly { containerPort: number; hostPort?: number | undefined; protocol: 'tcp' | 'udp' }[];
  resources?: { cpu?: number | undefined; memory?: number | undefined; pids?: number | undefined } | undefined;
  healthSpec: { test: readonly string[]; intervalSeconds: number; timeoutSeconds: number; retries: number; startPeriodSeconds: number } | null;
  ipAddress?: string;
  logLines: string[];
}

let nextIp = 2;
let nextId = 1;

function allocateIp(): string { return `172.17.0.${nextIp++}`; }

/** Build the frozen view returned to callers. */
function snapshot(c: MutableContainer): OciContainer {
  const running = c.status === 'running';
  const health = computeHealth(c);

  return {
    id: c.id,
    name: c.name,
    image: c.image,
    args: c.args,
    env: c.env,
    workingDir: c.workingDir,
    status: c.status,
    alive: c.alive,
    createdAt: c.createdAt,
    startedAt: c.startedAt,
    finishedAt: c.finishedAt,
    exitCode: c.exitCode,
    labels: c.labels,
    annotations: c.annotations,
    mounts: c.mounts,
    ...(c.ipAddress || c.ports.length > 0 ? {
      network: {
        ipAddress: c.ipAddress ?? '0.0.0.0',
        gateway: '172.17.0.1',
        ports: c.ports.map(p => ({ containerPort: p.containerPort, hostPort: p.hostPort, protocol: p.protocol })),
      },
    } : {}),
    ...(running && c.resources ? {
      resources: {
        cpu: c.resources.cpu ?? 2,
        memory: c.resources.memory ?? 512,
        cpuUsagePercent: +(5 + Math.random() * 40).toFixed(1),
        memoryUsageBytes: c.resources.memory
          ? Math.floor(c.resources.memory * 1024 * 1024 * (0.1 + Math.random() * 0.6))
          : Math.floor(32 * 1024 * 1024 + Math.random() * 64 * 1024 * 1024),
        memoryLimitBytes: c.resources.memory ? c.resources.memory * 1024 * 1024 : 256 * 1024 * 1024,
        pidsCurrent: Math.floor(5 + Math.random() * 20),
      },
    } : {}),
    health,
  };
}

function computeHealth(c: MutableContainer): { status: OciHealthStatus; lastCheckedAt?: string; message?: string; failingSince?: string } {
  if (!c.healthSpec) return { status: 'none' };
  if (c.status !== 'running') return { status: 'none' };

  const uptime = c.startedAt ? Date.now() - new Date(c.startedAt).getTime() : 0;
  const startPeriodMs = c.healthSpec.startPeriodSeconds * 1000;

  // Still in start period
  if (uptime < startPeriodMs) {
    return { status: 'starting', lastCheckedAt: new Date().toISOString(), message: 'Container starting, health check not yet active' };
  }

  // Running + past start period → healthy
  const sinceHealthy = Math.floor((uptime - startPeriodMs) / 1000 / c.healthSpec.intervalSeconds);
  if (sinceHealthy < 2) {
    return { status: 'starting', lastCheckedAt: new Date().toISOString(), message: `Probe "${c.healthSpec.test.join(' ')}" waiting for stabilisation` };
  }

  return {
    status: 'healthy',
    lastCheckedAt: new Date().toISOString(),
    message: `Probe "${c.healthSpec.test.join(' ')}" succeeded`,
  };
}

// ─── Image-aware log generators ───

const logGenerators = new Map<string, (name: string, image: string, ip: string | undefined, ports: readonly { containerPort: number }[], args: readonly string[]) => string[]>();

function reg(pattern: string, fn: typeof logGenerators extends Map<string, infer V> ? V : never): void {
  logGenerators.set(pattern.toLowerCase(), fn);
}

reg('nginx', (name) => [
  `[boot] ${name}: nginx ${Math.floor(1 + Math.random() * 26)}.${Math.floor(Math.random() * 99)} started`,
  `[boot] ${name}: worker process running`,
  `[boot] ${name}: accepting connections on port 80`,
]);

reg('node', (name, _img, _ip, ports) => [
  `[boot] ${name}: Node.js server starting...`,
  `[boot] ${name}: listening on port ${ports[0]?.containerPort ?? 3000}`,
  `[boot] ${name}: worker online`,
]);

reg('redis', (name) => [
  `[boot] ${name}: Redis ${Math.floor(6 + Math.random() * 2)}.${Math.floor(Math.random() * 99)} starting`,
  `[boot] ${name}: running in standalone mode on port 6379`,
  `[boot] ${name}: ready to accept connections`,
]);

reg('postgres', (name) => [
  `[boot] ${name}: PostgreSQL ${Math.floor(13 + Math.random() * 5)}.${Math.floor(Math.random() * 10)} starting`,
  `[boot] ${name}: database system was shut down at ${new Date().toUTCString()}`,
  `[boot] ${name}: database system is ready to accept connections`,
]);

reg('steamcmd', (name, _img, ip, ports) => [
  `[boot] ${name}: Steam Console Client (c) Valve Corporation`,
  `[boot] ${name}: logging directory /home/container/.local/share/Steam/logs`,
  `[boot] ${name}: game server ready on ${ip ?? '0.0.0.0'}:${ports[0]?.containerPort ?? 27015}`,
]);

reg('l4d2', (name, _img, ip, ports) => [
  `[boot] ============ Left 4 Dead 2 ============`,
  `[boot] ${name}: version ${Math.floor(2 + Math.random())}.${Math.floor(Math.random() * 10)}.${Math.floor(Math.random() * 10)}`,
  `[boot] ${name}: server IP ${ip ?? '0.0.0.0'}:${ports[0]?.containerPort ?? 27015}`,
  `[boot] ${name}: connection to Steam servers successful`,
  `[boot] ${name}: ready`,
]);

reg('ftp', (name, _img, _ip, ports) => [
  `[boot] ${name}: FTP server starting on port ${ports[0]?.containerPort ?? 21}`,
  `[boot] ${name}: anonymous access ${Math.random() > 0.5 ? 'enabled' : 'disabled'}`,
  `[boot] ${name}: FTP server ready`,
]);

function genLogs(c: MutableContainer): string[] {
  const lower = c.image.toLowerCase();
  for (const [pattern, gen] of logGenerators) {
    if (lower.includes(pattern)) {
      return gen(c.name, c.image, c.ipAddress, c.ports, c.args);
    }
  }
  return [
    `[boot] ${c.name}: container started (image: ${c.image.split('/').pop()})`,
    `[boot] ${c.name}: process running entrypoint`,
    ...(c.args.length > 0 ? [`[boot] ${c.name}: args: ${c.args.join(' ')}`] : []),
    ...(c.ports.length > 0 ? [`[boot] ${c.name}: listening on 0.0.0.0:${c.ports[0]!.containerPort}`] : []),
  ];
}

// ─── Implementation ───

export class StubOciRuntime implements IOCIRuntime {
  #containers = new Map<string, MutableContainer>();
  #images = new Map<string, OciImageInfo>();

  public async pullImage(image: OciImageRef): Promise<OciImageInfo> {
    const existing = this.#images.get(image);
    if (existing) return existing;

    const isGameServer = image.includes('l4d2') || image.includes('steamcmd');
    const size = isGameServer ? 2_500_000_000 : image.includes('node') ? 950_000_000 : image.includes('nginx') ? 180_000_000 : 100_000_000;

    const info: OciImageInfo = { ref: image, digest: `sha256:${'f'.repeat(64)}`, size, pulledAt: new Date().toISOString() };
    this.#images.set(image, info);
    return info;
  }

  public async listImages(): Promise<readonly OciImageInfo[]> {
    return [...this.#images.values()];
  }

  public async removeImage(image: OciImageRef): Promise<void> {
    this.#images.delete(image);
  }

  public async createContainer(spec: OciCreateSpec): Promise<OciContainer> {
    if (!this.#images.has(spec.image)) await this.pullImage(spec.image);

    const id = createContainerId(`oci-${nextId++}`);
    const now = new Date().toISOString();

    const c: MutableContainer = {
      id, name: spec.name, image: spec.image, args: spec.args ?? [], env: spec.env ?? {},
      workingDir: spec.workingDir ?? '/', status: 'created', alive: false, createdAt: now,
      labels: spec.labels ?? {}, annotations: spec.annotations ?? {},
      mounts: spec.mounts ?? [],
      ports: spec.ports ?? [],
      ...(spec.resources ? {
        resources: {
          ...(spec.resources.cpu !== undefined ? { cpu: spec.resources.cpu } : {}),
          ...(spec.resources.memory !== undefined ? { memory: spec.resources.memory } : {}),
          ...(spec.resources.pids !== undefined ? { pids: spec.resources.pids } : {}),
        },
      } : {}),
      healthSpec: spec.healthCheck ? {
        test: spec.healthCheck.test,
        intervalSeconds: spec.healthCheck.intervalSeconds ?? 30,
        timeoutSeconds: spec.healthCheck.timeoutSeconds ?? 30,
        retries: spec.healthCheck.retries ?? 3,
        startPeriodSeconds: spec.healthCheck.startPeriodSeconds ?? 0,
      } : null,
      logLines: [],
    };

    this.#containers.set(id, c);
    return snapshot(c);
  }

  public async startContainer(id: ContainerId): Promise<void> {
    const c = this.#containers.get(id);
    if (!c) throw new Error(`Container ${id} not found`);
    if (c.status !== 'created') throw new Error(`Cannot start container in state: ${c.status}`);

    c.status = 'running';
    c.alive = true;
    c.startedAt = new Date().toISOString();
    c.ipAddress = allocateIp();
    c.logLines = genLogs(c);
  }

  public async stopContainer(id: ContainerId, timeoutSeconds?: number): Promise<void> {
    const c = this.#containers.get(id);
    if (!c) throw new Error(`Container ${id} not found`);
    if (c.status !== 'running' && c.status !== 'paused') throw new Error(`Container ${id} is ${c.status}, expected running`);

    c.logLines.push(`[${new Date().toISOString()}] received SIGTERM, shutting down...`);
    if (timeoutSeconds && timeoutSeconds > 0) {
      c.logLines.push(`[${new Date().toISOString()}] waiting ${timeoutSeconds}s for active connections to drain`);
    }
    c.logLines.push(`[${new Date().toISOString()}] exited`);

    c.alive = false;
    c.status = 'stopped';
    c.finishedAt = new Date().toISOString();
    c.exitCode = 0;
  }

  public async killContainer(id: ContainerId, signal?: string): Promise<void> {
    const c = this.#containers.get(id);
    if (!c) throw new Error(`Container ${id} not found`);
    c.logLines.push(`[${new Date().toISOString()}] received ${signal ?? 'SIGKILL'}, forced shutdown`);
    c.alive = false;
    c.status = 'stopped';
    c.finishedAt = new Date().toISOString();
    c.exitCode = signal === 'SIGKILL' || signal === '9' ? 137 : 143;
  }

  public async pauseContainer(id: ContainerId): Promise<void> {
    const c = this.#containers.get(id);
    if (!c) throw new Error(`Container ${id} not found`);
    if (c.status !== 'running') throw new Error(`Container ${id} is ${c.status}, expected running`);
    c.logLines.push(`[${new Date().toISOString()}] cgroup frozen`);
    c.status = 'paused';
  }

  public async unpauseContainer(id: ContainerId): Promise<void> {
    const c = this.#containers.get(id);
    if (!c) throw new Error(`Container ${id} not found`);
    if (c.status !== 'paused') throw new Error(`Container ${id} is ${c.status}, expected paused`);
    c.logLines.push(`[${new Date().toISOString()}] cgroup unfrozen, resuming`);
    c.status = 'running';
  }

  public async removeContainer(id: ContainerId): Promise<void> {
    const c = this.#containers.get(id);
    if (!c) throw new Error(`Container ${id} not found`);
    if (c.status === 'running') throw new Error(`Cannot remove running container ${id}`);
    this.#containers.delete(id);
  }

  public async inspectContainer(id: ContainerId): Promise<OciContainer | null> {
    const c = this.#containers.get(id);
    return c ? snapshot(c) : null;
  }

  public async listContainers(status?: OciContainerStatus): Promise<readonly OciContainer[]> {
    const all = [...this.#containers.values()];
    return (status ? all.filter(c => c.status === status) : all).map(snapshot);
  }

  public async getLogs(id: ContainerId, options?: OciLogOptions): Promise<string> {
    const c = this.#containers.get(id);
    if (!c) throw new Error(`Container ${id} not found`);

    let lines = c.logLines;
    if (options?.tail && options.tail > 0) lines = lines.slice(-options.tail);

    if (options?.timestamps) {
      lines = lines.map(l => `${new Date().toISOString()} ${l}`);
    }

    return lines.join('\n') + '\n';
  }
}

import type { KernLevel } from '../../core/audit/kern-level.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import { createFacility } from '../../core/brand.ts';

const FACILITY = createFacility('perm-audit');

// ─── Actor context ───

export interface AuditActor {
  userId?: string | undefined;
  ip?: string | undefined;
}

// ─── Event builders ───

export function permEvent(
  eventType: string,
  actor: AuditActor | undefined,
  fields: Record<string, unknown>,
  level: KernLevel,
  message?: string,
): AuditEntry {
  return {
    level,
    facility: FACILITY,
    message: message ?? `${eventType} by ${actor?.userId ?? 'unknown'}`,
    actorId: actor?.userId,
    metadata: {
      eventType,
      ...(actor?.userId ? { actorId: actor.userId } : {}),
      ...(actor?.ip ? { actorIp: actor.ip } : {}),
      timestamp: Date.now(),
      ...fields,
    },
  };
}

export function permLog(
  logger: IAuditWriter,
  eventType: string,
  actor: AuditActor | undefined,
  fields: Record<string, unknown>,
  level: KernLevel,
  message?: string,
): void {
  const entry = permEvent(eventType, actor, fields, level, message);
  logger.write({
    facility: FACILITY,
    level,
    message: entry.message,
    metadata: entry.metadata,
  });
}

export function permAudit(
  audit: IAuditWriter | undefined,
  eventType: string,
  actor: AuditActor | undefined,
  fields: Record<string, unknown>,
  level: KernLevel,
  message?: string,
): void {
  return audit?.write(permEvent(eventType, actor, fields, level, message));
}

// ─── Convenience: log + audit in one call ───

export function permLogAudit(
  logger: IAuditWriter,
  audit: IAuditWriter | undefined,
  eventType: string,
  actor: AuditActor | undefined,
  fields: Record<string, unknown>,
  level: KernLevel,
  message?: string,
): void {
  permLog(logger, eventType, actor, fields, level, message);
  return permAudit(audit, eventType, actor, fields, level, message);
}

// ─── Entity type ───

export type EntityType = 'policy' | 'userGroup' | 'permissionGroup' | 'routeAcl' | 'template';

/**
 * UserGroup + PermGroup CRUD — extracted from PermissionService
 */
import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import { KernLevel } from '../../core/audit/kern-level.ts';
import { createFacility } from '../../core/brand.ts';
import { AppError } from '../../core/types.ts';
import { applyUpdate } from '../../core/utils/apply-update.ts';
import { permLogAudit } from './audit.ts';
import type { AuditActor } from './audit.ts';
import { CrudStore } from './crud-store.ts';
import type {
  UserGroup, CreateUserGroupInput, UpdateUserGroupInput,
  PermissionGroup, CreatePermGroupInput, UpdatePermGroupInput,
  Template,
} from './types.ts';
import { generateUserGroupId, generatePermGroupId } from './types.ts';

const FACILITY = createFacility('perm');

export class GroupManager {
  public readonly ugStore: CrudStore<UserGroup>;
  public readonly pgStore: CrudStore<PermissionGroup>;
  public readonly templates: Template[];

  public constructor(
    _atomic: IAtomicStore,
    private readonly logger: IAuditWriter,
    private readonly audit?: IAuditWriter,
    templates: Template[] = [],
  ) {
    this.ugStore = new CrudStore<UserGroup>(_atomic, 'usergroup:', 'usergroup:ids', 'USERGROUP_NOT_FOUND');
    this.pgStore = new CrudStore<PermissionGroup>(_atomic, 'permgroup:', 'permgroup:ids', 'PERMGROUP_NOT_FOUND');
    this.templates = templates;
  }

  // ── User Groups ──

  public async createUserGroup(input: CreateUserGroupInput, actor?: AuditActor): Promise<UserGroup> {
    const id = generateUserGroupId();
    const memberIds = input.memberIds ?? [];
    const adminIds = input.adminIds ?? (actor?.userId ? [actor.userId] : []);
    const group: UserGroup = {
      id, name: input.name,
      description: input.description,
      memberIds,
      adminIds,
      dependsOn: input.dependsOn ?? [],
      createdAt: Date.now(), updatedAt: Date.now(),
    };
    await this.ugStore.insert(group);
    this.logger.write({
      facility: FACILITY, level: KernLevel.INFO, message: 'User group created',
      metadata: { groupId: id, name: input.name, memberCount: input.memberIds?.length },
    });
    permLogAudit(this.logger, this.audit, 'perm.userGroup.created', actor, { entityType: 'userGroup', entityId: id, newValue: group }, KernLevel.INFO);
    return group;
  }

  public async listUserGroups(): Promise<UserGroup[]> { return this.ugStore.list(); }
  public async listUserGroupsPaginated(page?: number, limit?: number, filter?: (item: UserGroup) => boolean): Promise<PaginatedResult<UserGroup>> { return this.ugStore.listPaginated(page, limit, filter); }
  public async getUserGroup(id: string): Promise<UserGroup | null> { return this.ugStore.get(id); }

  public async updateUserGroup(id: string, input: UpdateUserGroupInput, actor?: AuditActor): Promise<UserGroup> {
    const old = await this.ugStore.get(id);
    if (!old) throw new AppError(404, 'USERGROUP_NOT_FOUND', 'User group not found');
    const updated: UserGroup = applyUpdate(old, {
      ...input,
      updatedAt: Date.now(),
    });
    await this.ugStore.commitUpdate(id, updated);
    permLogAudit(this.logger, this.audit, 'perm.userGroup.updated', actor, { entityType: 'userGroup', entityId: id, changes: { old, new: updated } }, KernLevel.WARNING);
    return updated;
  }

  public async deleteUserGroup(id: string, actor?: AuditActor): Promise<void> {
    const old = await this.ugStore.get(id);
    if (!old) throw new AppError(404, 'USERGROUP_NOT_FOUND', 'User group not found');
    await this.ugStore.delete(id);
    permLogAudit(this.logger, this.audit, 'perm.userGroup.deleted', actor, { entityType: 'userGroup', entityId: id, oldValue: old }, KernLevel.NOTICE);
  }

  public async getGroupByUserId(userId: string): Promise<UserGroup[]> {
    const all = await this.ugStore.list();
    return all.filter(g => g.memberIds.includes(userId));
  }

  // ── Permission Groups ──

  public async createPermGroup(input: CreatePermGroupInput, actor?: AuditActor): Promise<PermissionGroup> {
    const id = generatePermGroupId();
    const group: PermissionGroup = {
      id, name: input.name,
      description: input.description,
      rules: input.rules,
      userGroupIds: input.userGroupIds ?? [],
      userIds: input.userIds ?? [],
      dependsOn: input.dependsOn ?? [],
      createdAt: Date.now(), updatedAt: Date.now(),
    };
    await this.pgStore.insert(group);
    this.logger.write({
      facility: FACILITY, level: KernLevel.INFO, message: 'Permission group created',
      metadata: { groupId: id, name: input.name, ruleCount: input.rules.length },
    });
    permLogAudit(this.logger, this.audit, 'perm.permissionGroup.created', actor, { entityType: 'permissionGroup', entityId: id, newValue: group }, KernLevel.INFO);
    return group;
  }

  public async listPermGroups(): Promise<PermissionGroup[]> { return this.pgStore.list(); }
  public async listPermGroupsPaginated(page?: number, limit?: number, filter?: (item: PermissionGroup) => boolean): Promise<PaginatedResult<PermissionGroup>> { return this.pgStore.listPaginated(page, limit, filter); }
  public async getPermGroup(id: string): Promise<PermissionGroup | null> { return this.pgStore.get(id); }

  public async updatePermGroup(id: string, input: UpdatePermGroupInput, actor?: AuditActor): Promise<PermissionGroup> {
    const old = await this.pgStore.get(id);
    if (!old) throw new AppError(404, 'PERMGROUP_NOT_FOUND', 'Permission group not found');
    const updated: PermissionGroup = applyUpdate(old, {
      ...input,
      updatedAt: Date.now(),
    });
    await this.pgStore.commitUpdate(id, updated);
    permLogAudit(this.logger, this.audit, 'perm.permissionGroup.updated', actor, { entityType: 'permissionGroup', entityId: id, changes: { old, new: updated } }, KernLevel.WARNING);
    return updated;
  }

  public async deletePermGroup(id: string, actor?: AuditActor): Promise<void> {
    const old = await this.pgStore.get(id);
    if (!old) throw new AppError(404, 'PERMGROUP_NOT_FOUND', 'Permission group not found');
    if (this.templates.some(t => t.id === old.name?.toLowerCase())) {
      throw new AppError(403, 'MAC_DENIED', `Cannot delete seed permission group "${old.name}" — protected by system policy`);
    }
    await this.pgStore.delete(id);
    permLogAudit(this.logger, this.audit, 'perm.permissionGroup.deleted', actor, { entityType: 'permissionGroup', entityId: id, oldValue: old }, KernLevel.NOTICE);
  }

  public async createFromTemplate(templateId: string, overrides: {
    name: string; description?: string | null | undefined; userGroupIds?: string[] | undefined; userIds?: string[] | undefined;
  }, actor?: AuditActor): Promise<PermissionGroup> {
    const template = this.templates.find(t => t.id === templateId);
    if (!template) throw new AppError(404, 'TEMPLATE_NOT_FOUND', `Template "${templateId}" not found`);
    return this.createPermGroup({
      name: overrides.name,
      description: overrides.description ?? template.description,
      rules: template.rules,
      userGroupIds: overrides.userGroupIds ?? [],
      userIds: overrides.userIds ?? [],
    }, actor);
  }

  // ── Compare (reuses original logic) ──

  public async comparePermGroups(idA: string, idB: string): Promise<CompareResult> {
    const a = await this.pgStore.get(idA);
    const b = await this.pgStore.get(idB);
    if (!a) throw new AppError(404, 'NOT_FOUND', `Permission group ${idA} not found`);
    if (!b) throw new AppError(404, 'NOT_FOUND', `Permission group ${idB} not found`);
    return buildCompareResult(a, b);
  }

  public async compareUserGroups(idA: string, idB: string): Promise<CompareResult> {
    const a = await this.ugStore.get(idA);
    const b = await this.ugStore.get(idB);
    if (!a) throw new AppError(404, 'NOT_FOUND', `User group ${idA} not found`);
    if (!b) throw new AppError(404, 'NOT_FOUND', `User group ${idB} not found`);
    return buildCompareResult(a, b);
  }
}

function normalizeItem(item: string | { id: string }): { id: string } {
  if (typeof item === 'string') return { id: item };
  return item;
}

function buildCompareResult(a: Record<string, unknown>, b: Record<string, unknown>): CompareResult {
  const common: Record<string, unknown>[] = [];
  const onlyA: Record<string, unknown>[] = [];
  const onlyB: Record<string, unknown>[] = [];
  const depDiff = { onlyA: [] as string[], onlyB: [] as string[], common: [] as string[] };

  const aItems = a.rules ?? a.memberIds ?? [];
  const bItems = b.rules ?? b.memberIds ?? [];

  for (const aItem of aItems) {
    const aJson = JSON.stringify(aItem);
    const match = bItems.find((bItem: { id: string } | string) => JSON.stringify(bItem) === aJson);
    const resolved = normalizeItem(aItem);
    if (match) common.push(resolved);
    else onlyA.push(resolved);
  }
  for (const bItem of bItems) {
    const bJson = JSON.stringify(bItem);
    const inA = aItems.some((aItem: { id: string } | string) => JSON.stringify(aItem) === bJson);
    if (!inA) onlyB.push(normalizeItem(bItem));
  }

  if ((a.dependsOn ?? []).length > 0 || (b.dependsOn ?? []).length > 0) {
    depDiff.onlyA = (a.dependsOn ?? []).filter((d: string) => !(b.dependsOn ?? []).includes(d));
    depDiff.onlyB = (b.dependsOn ?? []).filter((d: string) => !(a.dependsOn ?? []).includes(d));
    depDiff.common = (a.dependsOn ?? []).filter((d: string) => (b.dependsOn ?? []).includes(d));
  }

  return { a: { id: a.id, name: a.name }, b: { id: b.id, name: b.name }, common, onlyA, onlyB, depDiff };
}

import { Hono } from 'hono';
import type { Context } from 'hono';
import type { AppContext } from '../../core/deps.ts';
import type { IPermissionService } from './service.ts';
import type { RouteMeta } from '../../core/http-docs/types.ts';
import {
  CreatePolicySchema,
  UpdatePolicySchema,
  PermissionCheckSchema,
  CreateUserGroupSchema,
  UpdateUserGroupSchema,
  CreatePermGroupSchema,
  UpdatePermGroupSchema,
  CreateRouteAclSchema,
  UpdateRouteAclSchema,
  CreateUserTplSchema,
  UpdateUserTplSchema,
  CreateInviteSchema,
} from './schema.ts';
import { ok, fail } from '../../core/response.ts';
import type { ErrorCode } from '../../core/error-codes.ts';
import type { AuditActor } from './audit.ts';
import { z, type ZodType } from 'zod';
import type { CrudHandlerMap } from '../../core/crud/router.ts';
import { registerCrudRoutes } from '../../core/crud/router.ts';
import type { PaginatedResult } from '../../core/crud/types.ts';

const KernLevelNames = z.enum([
  'emerg', 'alert', 'crit', 'err', 'warning', 'notice', 'info', 'debug', 'none',
]);

const KNOWN_FACILITIES = [
  'user-service', 'perm', 'perm-audit', 'authz', 'sysgrp',
  'sandbox-service', 'template', 'dns-service', 'quota', 'http',
  'subnet', 'secgroup', 'system',
] as const;

const UpdateLogPolicySchema = z.object({
  defaultLevel: KernLevelNames.optional(),
  auditLevel: KernLevelNames.optional(),
  facilities: z.array(z.object({
    facility: z.enum(KNOWN_FACILITIES),
    level: KernLevelNames,
  })).optional(),
});

function actorFrom(c: any): AuditActor | undefined {
  const u = c.var?.currentUser;
  if (!u) return undefined;
  return { userId: u.id, ip: c.req.header('x-forwarded-for')?.split(',')[0]?.trim() };
}

function requireRoot(c: Context<{ Variables: AppContext }>): Response | null {
  const user = c.var?.currentUser;
  if (!user) return null;
  const isRoot = user.role === 'root' || user.role === 'Operator' || user.role === 'wheel';
  if (!isRoot) return c.json(fail('FORBIDDEN', 'Admin access required'), 403);
  return null;
}

function requireWheel(c: any): Response | null {
  const user = c.var?.currentUser;
  if (!user) return null;
  if (user.role !== 'wheel') return c.json(fail('FORBIDDEN', 'Wheel privilege required'), 403);
  return null;
}

// ─── CRUD sub-resource factory ───

interface SubCrudOpts<T> {
  guard: (c: any) => Response | null;
  createSchema: ZodType;
  createFn: (data: any, actor: AuditActor | undefined) => Promise<T>;
  listUrlFilter: (c: any) => ((item: any) => boolean) | undefined;
  listFn: (page: number, limit: number, filter: ((item: any) => boolean) | undefined) => Promise<PaginatedResult<T>>;
  getFn: (id: string) => Promise<T | null>;
  updateSchema: ZodType;
  updateFn: (id: string, data: any, actor: AuditActor | undefined) => Promise<T>;
  deleteFn: (id: string, actor: AuditActor | undefined) => Promise<void>;
  notFoundCode: ErrorCode;
  notFoundMsg: string;
}

/** Build a CrudHandlerMap for a sub-resource. TypeScript enforces all 5 actions are present. */
function subCrud<T>(opts: SubCrudOpts<T>): CrudHandlerMap {
  return {
    create: (r) => r.post('/', async (c) => {
      { const rv = opts.guard(c); if (rv) return rv; }
      const body: unknown = await c.req.json();
      const parsed = opts.createSchema.safeParse(body);
      if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      const result = await opts.createFn(parsed.data, actorFrom(c));
      return c.json(ok(result), 201);
    }),

    list: (r) => r.get('/', async (c) => {
      const page = parseInt(c.req.query('page') ?? '') || 1;
      const limit = parseInt(c.req.query('limit') ?? '') || 50;
      const filter = opts.listUrlFilter(c);
      return c.json(ok(await opts.listFn(page, limit, filter)));
    }),

    get: (r) => r.get('/:id', async (c) => {
      const result = await opts.getFn(c.req.param('id'));
      if (!result) return c.json(fail(opts.notFoundCode, opts.notFoundMsg), 404);
      return c.json(ok(result));
    }),

    update: (r) => r.put('/:id', async (c) => {
      { const rv = opts.guard(c); if (rv) return rv; }
      const body: unknown = await c.req.json();
      const parsed = opts.updateSchema.safeParse(body);
      if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      return c.json(ok(await opts.updateFn(c.req.param('id'), parsed.data, actorFrom(c))));
    }),

    delete: (r) => r.delete('/:id', async (c) => {
      { const rv = opts.guard(c); if (rv) return rv; }
      await opts.deleteFn(c.req.param('id'), actorFrom(c));
      return c.json(ok(null));
    }),
  };
}

// ─── Name-based filter helper ───

function nameFilter(c: any): ((item: any) => boolean) | undefined {
  const name = c.req.query('name');
  return name ? (item: any) => item.name?.toLowerCase().includes(name.toLowerCase()) : undefined;
}

function queryFilter(key: string) {
  return (c: any): ((item: any) => boolean) | undefined => {
    const q = c.req.query(key);
    return q ? (item: any) => (item.pathPrefix ?? '').toLowerCase().includes(q.toLowerCase()) || (item.method ?? '').toLowerCase().includes(q.toLowerCase()) : undefined;
  };
}

// ═══════════════════════════════════════════════════════════════
// Main router
// ═══════════════════════════════════════════════════════════════

export function createPermissionRouter(svc: IPermissionService): Hono<{ Variables: AppContext }> {
  const router = new Hono<{ Variables: AppContext }>();

  // ─── Policies CRUD ───
  {
    const policies = new Hono<any>();
    registerCrudRoutes(policies, subCrud({
      guard: requireRoot,
      createSchema: CreatePolicySchema,
      createFn: (data, actor) => svc.createPolicy(data, actor),
      listUrlFilter: nameFilter,
      listFn: (page, limit, filter) => svc.listPoliciesPaginated(page, limit, filter),
      getFn: (id) => svc.getPolicy(id),
      updateSchema: UpdatePolicySchema,
      updateFn: (id, data, actor) => svc.updatePolicy(id, data, actor),
      deleteFn: (id, actor) => svc.deletePolicy(id, actor),
      notFoundCode: 'POLICY_NOT_FOUND',
      notFoundMsg: 'Policy not found',
    }));
    router.route('/policies', policies);
    router.route('/policies/', policies);
  }

  // ─── User groups CRUD ───
  {
    const userGroups = new Hono<any>();
    registerCrudRoutes(userGroups, subCrud({
      guard: requireWheel,
      createSchema: CreateUserGroupSchema,
      createFn: (data, actor) => svc.createUserGroup(data, actor),
      listUrlFilter: nameFilter,
      listFn: (page, limit, filter) => svc.listUserGroupsPaginated(page, limit, filter),
      getFn: (id) => svc.getUserGroup(id),
      updateSchema: UpdateUserGroupSchema,
      updateFn: (id, data, actor) => svc.updateUserGroup(id, data, actor),
      deleteFn: (id, actor) => svc.deleteUserGroup(id, actor),
      notFoundCode: 'USERGROUP_NOT_FOUND',
      notFoundMsg: 'User group not found',
    }));
    router.route('/user-groups', userGroups);
    router.route('/user-groups/', userGroups);
  }

  // ─── Permission groups CRUD ───
  {
    const permGroups = new Hono<any>();

    registerCrudRoutes(permGroups, subCrud({
      guard: requireRoot,
      createSchema: CreatePermGroupSchema,
      createFn: (data, actor) => svc.createPermGroup(data, actor),
      listUrlFilter: nameFilter,
      listFn: (page, limit, filter) => svc.listPermGroupsPaginated(page, limit, filter),
      getFn: (id) => svc.getPermGroup(id),
      updateSchema: UpdatePermGroupSchema,
      updateFn: (id, data, actor) => svc.updatePermGroup(id, data, actor),
      deleteFn: (id, actor) => svc.deletePermGroup(id, actor),
      notFoundCode: 'PERMGROUP_NOT_FOUND',
      notFoundMsg: 'Permission group not found',
    }));

    // Extra route: create from template
    permGroups.post('/from-template/:templateId', async (c) => {
      { const r = requireRoot(c); if (r) return r; }
      const body: unknown = await c.req.json();
      const parsed = CreatePermGroupSchema.partial().safeParse(body);
      if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      const group = await svc.createPermGroupFromTemplate(c.req.param('templateId'), {
        name: parsed.data.name ?? c.req.param('templateId'),
        description: parsed.data.description,
        userGroupIds: parsed.data.userGroupIds,
        userIds: parsed.data.userIds,
      }, actorFrom(c));
      return c.json(ok(group), 201);
    });

    router.route('/groups', permGroups);
    router.route('/groups/', permGroups);
  }

  // ─── Templates (read-only) ───
  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  router.get('/templates', async (c) => {
    return c.json(ok(svc.listTemplates()));
  });

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  router.get('/templates/:id', async (c) => {
    const tpl = svc.getTemplate(c.req.param('id'));
    if (!tpl) return c.json(fail('TEMPLATE_NOT_FOUND', 'Template not found'), 404);
    return c.json(ok(tpl));
  });

  // ─── UserTemplate CRUD ───
  {
    const userTemplates = new Hono<any>();
    registerCrudRoutes(userTemplates, subCrud({
      guard: requireRoot,
      createSchema: CreateUserTplSchema,
      createFn: (data, actor) => svc.createUserTpl(data, actor),
      listUrlFilter: nameFilter,
      listFn: (page, limit, filter) => svc.listUserTplsPaginated(page, limit, filter),
      getFn: (id) => svc.getUserTpl(id),
      updateSchema: UpdateUserTplSchema,
      updateFn: (id, data, actor) => svc.updateUserTpl(id, data, actor),
      deleteFn: (id, actor) => svc.deleteUserTpl(id, actor),
      notFoundCode: 'USERTPL_NOT_FOUND',
      notFoundMsg: 'User template not found',
    }));
    router.route('/user-templates', userTemplates);
    router.route('/user-templates/', userTemplates);
  }

  // ─── Route ACL CRUD ───
  {
    const routeAcls = new Hono<any>();
    registerCrudRoutes(routeAcls, subCrud({
      guard: requireRoot,
      createSchema: CreateRouteAclSchema,
      createFn: (data, actor) => svc.createRouteAcl(data, actor),
      listUrlFilter: queryFilter('q'),
      listFn: (page, limit, filter) => svc.listRouteAclsPaginated(page, limit, filter),
      getFn: (id) => svc.getRouteAcl(id),
      updateSchema: UpdateRouteAclSchema,
      updateFn: (id, data, actor) => svc.updateRouteAcl(id, data, actor),
      deleteFn: (id, actor) => svc.deleteRouteAcl(id, actor),
      notFoundCode: 'ROUTEACL_NOT_FOUND',
      notFoundMsg: 'Route ACL not found',
    }));
    router.route('/route-acls', routeAcls);
    router.route('/route-acls/', routeAcls);
  }

  // ─── Invitations ───
  router.post('/invite', async (c) => {
    const body: unknown = await c.req.json();
    const parsed = CreateInviteSchema.safeParse(body);
    if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
    const user = c.var?.currentUser;
    if (!user) return c.json(fail('UNAUTHORIZED', 'Authentication required'), 401);
    const invite = await svc.sendInvite(parsed.data, user.id);
    return c.json(ok(invite), 201);
  });

  router.get('/invitations', async (c) => {
    const user = c.var?.currentUser;
    if (!user) return c.json(fail('UNAUTHORIZED', 'Authentication required'), 401);
    const invites = await svc.listInvitations(user.id);
    return c.json(ok(invites));
  });

  router.post('/invitations/:id/accept', async (c) => {
    const user = c.var?.currentUser;
    if (!user) return c.json(fail('UNAUTHORIZED', 'Authentication required'), 401);
    await svc.acceptInvite(c.req.param('id'), user.id);
    return c.json(ok(null));
  });

  router.post('/invitations/:id/reject', async (c) => {
    const user = c.var?.currentUser;
    if (!user) return c.json(fail('UNAUTHORIZED', 'Authentication required'), 401);
    await svc.rejectInvite(c.req.param('id'), user.id);
    return c.json(ok(null));
  });

  // ─── Log policy ───
  router.get('/log-policy', async (c) => {
    return c.json(ok(await svc.getLogPolicy()));
  });

  router.put('/log-policy', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    const body: unknown = await c.req.json();
    const parsed = UpdateLogPolicySchema.safeParse(body);
    if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
    const policy = await svc.updateLogPolicy(parsed.data as any, actorFrom(c));
    return c.json(ok(policy));
  });

  // ─── Capability management ───
  router.put('/caps/user/:userId', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    const { caps } = await c.req.json<{ caps: number }>();
    if (typeof caps !== 'number') return c.json(fail('VALIDATION_ERROR', 'caps must be a number (bitmask)'), 400);
    await svc.setUserCaps(c.req.param('userId'), caps, actorFrom(c));
    return c.json(ok({ userId: c.req.param('userId'), caps }));
  });

  router.get('/caps/user/:userId', async (c) => {
    const result = await svc.getUserCaps(c.req.param('userId'));
    return c.json(ok(result));
  });

  router.put('/caps/group/:groupId', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    const { caps } = await c.req.json<{ caps: number }>();
    if (typeof caps !== 'number') return c.json(fail('VALIDATION_ERROR', 'caps must be a number (bitmask)'), 400);
    await svc.setGroupCaps(c.req.param('groupId'), caps, actorFrom(c));
    return c.json(ok({ groupId: c.req.param('groupId'), caps }));
  });

  router.get('/caps/group/:groupId', async (c) => {
    const result = await svc.getGroupCaps(c.req.param('groupId'));
    return c.json(ok(result));
  });

  // ─── Temporary elevation (sudo) ───
  router.post('/elevate', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    const { userId, durationMs, capabilities } = await c.req.json<{ userId: string; durationMs?: number; capabilities?: number }>();
    if (!userId) return c.json(fail('VALIDATION_ERROR', 'userId required'), 400);
    const expiry = await svc.grantTempElevation(userId, durationMs, capabilities);
    return c.json(ok({ userId, expiry, capabilities }));
  });

  router.delete('/elevate/:userId', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    await svc.revokeTempElevation(c.req.param('userId'));
    return c.json(ok({ revoked: true }));
  });

  router.get('/elevations', async (c) => {
    const list = await svc.listTempElevations();
    return c.json(ok(list));
  });

  // ─── Compare ───
  router.post('/compare/perm-groups', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    const { idA, idB } = await c.req.json<{ idA: string; idB: string }>();
    if (!idA || !idB) return c.json(fail('VALIDATION_ERROR', 'idA and idB required'), 400);
    try { return c.json(ok(await svc.comparePermGroups(idA, idB))); }
    catch (e: any) { return c.json(fail('NOT_FOUND', e.message), 404); }
  });

  router.post('/compare/user-groups', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    const { idA, idB } = await c.req.json<{ idA: string; idB: string }>();
    if (!idA || !idB) return c.json(fail('VALIDATION_ERROR', 'idA and idB required'), 400);
    try { return c.json(ok(await svc.compareUserGroups(idA, idB))); }
    catch (e: any) { return c.json(fail('NOT_FOUND', e.message), 404); }
  });

  // ─── Permission check ───
  router.post('/check', async (c) => {
    { const r = requireRoot(c); if (r) return r; }
    const body: unknown = await c.req.json();
    const parsed = PermissionCheckSchema.safeParse(body);
    if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
    return c.json(ok(await svc.check(parsed.data)));
  });

  return router;
}

