  dependsOn?: string[] | null | undefined;
}

// ─── Log policy ───

export interface LogPolicyEntry {
  readonly facility: string;
  readonly level: string;        // 'debug' | 'info' | 'warn' | 'error' | 'none'
}

export interface LogPolicy {
  readonly defaultLevel: string;
  readonly auditLevel: string;
  readonly facilities: LogPolicyEntry[];
  readonly updatedAt: number;
  readonly updatedBy?: string | undefined;
}

// ─── Templates ───

export interface Template {
  id: string;
  name: string;
  description: string;
  rules: PermissionRule[];
}

// ─── Route ACL ───

declare const ROUTEACL_ID_BRAND: unique symbol;
export type RouteAclId = string & { readonly [ROUTEACL_ID_BRAND]: true };

export function generateRouteAclId(): RouteAclId {
  return `routeacl_${crypto.randomUUID()}` as RouteAclId;
}

export interface RouteAcl {
  id: RouteAclId;
  method: string;
  pathPrefix: string;
  matchType?: 'prefix' | 'exact' | 'regex' | undefined;
  effect?: 'allow' | 'deny' | undefined;
  userId?: string | undefined;
  userGroupId?: string | undefined;
  priority: number;
  createdAt: number;
  updatedAt: number;
}

export interface CreateRouteAclInput {
  method: string;
  pathPrefix: string;
  matchType?: 'prefix' | 'exact' | 'regex' | undefined;
  effect?: 'allow' | 'deny' | undefined;
  userId?: string | undefined;
  userGroupId?: string | undefined;
  priority?: number | undefined;
}

export interface UpdateRouteAclInput {
  method?: string | undefined;
  pathPrefix?: string | undefined;
  matchType?: 'prefix' | 'exact' | 'regex' | null | undefined;
  effect?: 'allow' | 'deny' | null | undefined;
  userId?: string | null | undefined;
  userGroupId?: string | null | undefined;
  priority?: number | undefined;
}

// ─── Invitation ───

export const INVITE_PREFIX = 'invite:';
export const INVITE_INDEX_KEY = 'invite:ids';
export const INVITE_PENDING_KEY = 'invite:pending:';

export type InviteStatus = 'pending' | 'accepted' | 'rejected';

export interface Invitation {
  id: string;
  /** Target user group ID. */
  groupId: string;
  /** User being invited. */
  inviteeId: string;
  /** User who sent the invitation. */
  invitedBy: string;
  status: InviteStatus;
  createdAt: number;
  expiresAt: number;
}

export interface CreateInviteInput {
  groupId: string;
  inviteeId: string;
}

// ─── Comparison ───

export interface CompareResult {
  a: { id: string; name: string };
  b: { id: string; name: string };
  common: Record<string, unknown>[];
  onlyA: Record<string, unknown>[];
  onlyB: Record<string, unknown>[];
  depDiff: {
    onlyA: string[];
    onlyB: string[];
    common: string[];
  };
}

// ─── Permission check (existing) ───

export interface PermissionCheckInput {
  userId: string;
  action: string;
  resource: string;
  ip?: string | undefined;
  timestamp?: number | undefined;
  context?: Record<string, unknown> | undefined;
  /** If set, the resource is owned by this user ID. Rules with `resource:$self`
   *  match when the acting user === the resource owner. */
  resourceOwnerId?: string | undefined;
}

export interface PolicyMatchResult {
  allowed: boolean;
  reason: string;
  matchedPolicy?: StoredPolicy | undefined;
  matchedGroup?: string | undefined;
  /** Which denial layer. Undefined if allowed. */
  layer?: DenialLayer;
  /** Audit type for denial events. */
  auditType?: string;
}

import { Hono } from 'hono';
import type { RouteMeta } from '../../core/http-docs/types.ts';
import type { AppContext } from '../../core/deps.ts';
import type { IProviderRegistry } from '../../core/provider/interfaces.ts';
import type { IAtomicStore } from '../../core/store/interfaces.ts';
import { InstanceService } from '../../core/region/instance.ts';
import { ALIBABA_REGIONS } from '../../core/region/types.ts';
import { getExtensionSchema } from '../../core/provider/extension-schema.ts';
import { ok, fail } from '../../core/response.ts';

export function createPlatformsRouter(
  registry: IProviderRegistry,
  atomicStore?: IAtomicStore,
): Hono<{ Variables: AppContext }> {
  const router = new Hono<{ Variables: AppContext }>();

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  router.get('/', async (c) => {
    const page = parseInt(c.req.query('page') ?? '') || 1;
    const limit = parseInt(c.req.query('limit') ?? '') || 50;
    const platforms = registry.availableProviders().map(p => ({
      name: p.name,
      containerAvailable: true,
    }));
    const total = platforms.length;
    const start = (page - 1) * limit;
    return c.json(ok({ items: platforms.slice(start, start + limit), total, page, limit }));
  });

  /**
   * GET /extension-fields?instanceId=xxx
   *
   * Returns the available extension field definitions for the compute instance's provider.
   * The frontend uses this to render dynamic forms for provider-specific parameters.
   */
  router.get('/extension-fields', async (c) => {
    const instanceId = c.req.query('instanceId');
    if (!instanceId) return c.json(fail('VALIDATION_ERROR', 'instanceId is required'), 400);

    if (!atomicStore) return c.json(fail('SERVICE_UNAVAILABLE', 'Atomic store not available'), 503);

    const instSvc = new InstanceService(atomicStore);
    const inst = await instSvc.get(instanceId as any);
    if (!inst) return c.json(fail('NOT_FOUND', 'Compute instance not found'), 404);

    const schema = getExtensionSchema(inst.platform);
    if (!schema) {
      return c.json(ok({ provider: inst.platform, label: inst.platform, instanceId: inst.id, instanceName: inst.name, fields: [] }));
    }

    return c.json(ok({
      provider: schema.provider,
      label: schema.label,
      instanceId: inst.id,
      instanceName: inst.name,
      fields: schema.fields,
    }));
  });

  /**
   * GET /regions?platform=alibaba
   * GET /regions?instanceId=xxx
   *
   * Returns available regions for a platform.
   * - ?platform=: 直接按平台查（无实例时用，鸡和蛋问题）
   * - ?instanceId=: 通过已有实例的凭证实时拉取
   */
  router.get('/regions', async (c) => {
    const platform = c.req.query('platform');
    const instanceId = c.req.query('instanceId');

    if (!platform && !instanceId) {
      return c.json(fail('VALIDATION_ERROR', 'Either platform or instanceId is required'), 400);
    }

    let resolvedPlatform = platform ?? '';
    let regions: readonly any[] | undefined;

    // ─── Path A: resolve via instanceId (has credentials for live API call) ───
    if (instanceId) {
      if (!atomicStore) return c.json(fail('SERVICE_UNAVAILABLE', 'Atomic store not available'), 503);
      const instSvc = new InstanceService(atomicStore);
      const inst = await instSvc.get(instanceId as any);
      if (!inst) return c.json(fail('NOT_FOUND', 'Compute instance not found'), 404);
      resolvedPlatform = inst.platform;

      switch (inst.platform) {
        case 'alibaba': {
          const client = await registry.resolveRawEciApi(instanceId as any);
          if (client) regions = await client.describeRegions();
          break;
        }
        case 'podman':
          regions = [{ regionId: 'local', endpoints: [{ endpoint: inst.endpoint }] }];
          break;
      }
    }

    // ─── Path B: static fallback (no instance or live API failed) ───
    if (!regions?.length) {
      switch (resolvedPlatform) {
        case 'alibaba':
          regions = ALIBABA_REGIONS.map(r => ({ RegionId: r }));
          break;
        case 'podman':
          regions = [{ regionId: 'local' }];
          break;
        default:
          regions = [];
      }
    }

    return c.json(ok({ platform: resolvedPlatform, regions }));
  });

  return router;
}

export const platformsRouteMeta: RouteMeta[] = [
  { method: 'GET', path: '/', description: '列出所有可用平台（podman / alibaba / stub）', responseDescription: '{ name }[]' },
  { method: 'GET', path: '/extension-fields', description: '获取指定计算实例的可用扩展字段（?instanceId=）', responseDescription: '{ provider, label, fields }' },
  { method: 'GET', path: '/regions', description: '获取实例所属平台的可选地域列表（?instanceId=），Alibaba ECI 从 DescribeRegions 实时拉取', responseDescription: '{ regions[] }' },
];

import type { Hono } from 'hono';
import type { FeatureDeps } from '../../core/deps.ts';
import { createPlatformsRouter } from './handler.ts';

export function createRouter(deps: FeatureDeps): Hono<any> {
  return createPlatformsRouter(deps.providers, deps.stores.atomic);
}

import type { IContainerProvider } from '../../../core/provider/interfaces.ts';
import type { CreateContainerGroupInput } from '../../../core/provider/types.ts';
import type { RegionId } from '../../../core/region/types.ts';
import type { InstanceId } from '../../../core/region/instance.ts';
import { createRegionId } from '../../../core/region/types.ts';
import type { IInfraManager } from './interfaces.ts';

/** Default infra (pause) image — smallest possible container that holds namespaces. */
const DEFAULT_INFRA_IMAGE = 'k8s.gcr.io/pause:3.6';
const LOCAL_REGION = createRegionId('local');

/**
 * Manages infra (pause) containers that hold shared kernel namespaces for a Pod.
 *
 * An infra container is a minimal container that does nothing but occupy
 * network / UTS / IPC / cgroup namespaces. Application containers in the same
 * Pod join these namespaces via `NetworkMode: container:<infra-id>`.
 *
 * For local Podman: creates a standalone pause container.
 * For cloud providers (ECI): infra is implicit (the container group itself
 * acts as the namespace anchor), so this manager is a no-op.
 */
export class InfraManager implements IInfraManager {
  readonly #containerProvider: IContainerProvider;
  readonly #region: RegionId;
  readonly #noop: boolean;

  /**
   * @param noop - When true (ECI), infra is implicit and createInfra() is a no-op.
   *               When false (Podman), actually creates a pause container.
   */
  public constructor(containerProvider: IContainerProvider, region?: RegionId, _instanceId?: InstanceId, noop = false) {
    this.#containerProvider = containerProvider;
    this.#region = region ?? LOCAL_REGION;
    this.#noop = noop;
  }

  public async createInfra(podName: string, infraImage?: string): Promise<string> {
    if (this.#noop) {
      return `${podName}-infra-noop`;
    }
    const input: CreateContainerGroupInput = {
      name: `${podName}-infra`,
      region: this.#region,
      // clusterId omitted — infra container doesn't need instance binding
      cpu: 0.1,
      memory: 16,
      restartPolicy: 'Never',
      containers: [
        {
          name: 'infra',
          image: infraImage ?? DEFAULT_INFRA_IMAGE,
          args: [],
          tty: false,
          stdin: false,
          imagePullPolicy: 'IfNotPresent',
        },
      ],
      network: {
        allocatePublicIp: false,
      },
      tags: [{ key: 'role', value: 'infra' }, { key: 'managed-by', value: 'hbi-aad' }, { key: 'pod', value: podName }],
      providerOverrides: { purpose: 'infra' },
    };

    const { providerId } = await this.#containerProvider.create(input);
    return providerId;
  }

  public async removeInfra(infraId: string): Promise<void> {
    if (this.#noop) return;
    await this.#containerProvider.delete({
      region: LOCAL_REGION,
      providerId: infraId,
    });
  }

  public async isInfraAlive(infraId: string): Promise<boolean> {
    if (this.#noop) return true; // infra is implicit, always alive
    try {
      const status = await this.#containerProvider.getStatus?.(infraId);
      return status?.containers.some(c => c.alive) ?? false;
    } catch {
      return false;
    }
  }
}

import { buildDag } from '../../../core/dag/graph.ts';
import type {
  Template,
  ResolveResult,
  ResolveError,
} from './types.ts';
import { TemplateKind } from './types.ts';
import type { CreateSandboxInput, ContainerConfig } from '../types.ts';

/** Mutable builder used internally during merge. Frozen to CreateSandboxInput on completion. */
interface MutableSandboxInput {
  name: string;
  description?: string;
  region: string;
  instanceId?: string;
  resourceSpec: { cpu: number; memory: number };
  restartPolicy: CreateSandboxInput['restartPolicy'];
  containers: ContainerConfig[];
  volumes?: CreateSandboxInput['volumes'];
  network: {
    subnetIds?: string[];
    securityGroupId?: string;
    allocatePublicIp: boolean;
    publicIpBandwidth?: number;
    instanceId?: string;
  };
  tags?: CreateSandboxInput['tags'];
  providerOverrides?: Record<string, unknown>;
}

// ─── DAG resolver ───

/**
 * Resolve an assembly template into a complete CreateSandboxInput.
 * Pure function — no side effects. All template data is passed in via `store`.
 */
export function resolveAssembly(
  rootName: string,
  store: ReadonlyMap<string, Template>,
): ResolveResult {
  const { dag, errors: buildErrors } = buildDag(
    rootName,
    name => store.get(name),
    t => t.kind === TemplateKind.Assembly
      ? (t).components.map(c => c.target)
      : [],
    t => t.name,
  );

  if (buildErrors.length > 0) {
    return {
      success: false,
      errors: buildErrors.map(e => ({ templateName: e.id, message: e.message })),
    };
  }

  const sorted = dag.topologicalSort();
  if (!sorted.success) {
    return {
      success: false,
      errors: [{ templateName: '(assembly)', message: sorted.error }],
    };
  }

  const merged = mergeTemplates([...sorted.sorted]);
  if (merged === null) {
    return { success: false, errors: [{ templateName: '(assembly)', message: 'Merge produced no result' }] };
  }

  // Apply assembly-level static overrides
  const root = store.get(rootName);
  if (root?.kind === TemplateKind.Assembly && (root).overrides) {
    Object.assign(merged, (root).overrides);
  }

  const validationErrors = validateConfig(merged);
  if (validationErrors.length > 0) {
    return { success: false, errors: validationErrors };
  }

  // Merge produces raw strings; RegionId is a zero-cost brand — the caller
  // (sandbox service) receives the struct and writes it to the store as-is.
  return { success: true, config: merged as unknown as CreateSandboxInput };
}

// ─── Merge engine ───

function mergeTemplates(sorted: Template[]): MutableSandboxInput | null {
  if (sorted.length === 0) return null;

  const config: MutableSandboxInput = {
    name: '',
    region: '',
    resourceSpec: { cpu: 0, memory: 0 },
    restartPolicy: 'Never',
    containers: [],
    network: { allocatePublicIp: false },
  };

  for (const template of sorted) {
    switch (template.kind) {
      case TemplateKind.Volume:
        // Volume templates are resolved at provision time from VolumeRepository.
        // The assembly only declares which volumes are needed via component edges.
        break;

      case TemplateKind.Container: {
        const ct = template;
        const idx = config.containers.findIndex(c => c.name === ct.spec.name);
        if (idx >= 0) {
          config.containers = [
            ...config.containers.slice(0, idx),
            { ...config.containers[idx], ...ct.spec },
            ...config.containers.slice(idx + 1),
          ];
        } else {
          config.containers = [...config.containers, ct.spec];
        }
        break;
      }

      case TemplateKind.Resource: {
        const rt = template;
        if (!config.providerOverrides) config.providerOverrides = {};
        const prev = (config.providerOverrides[rt.resourceType] ?? {}) as Record<string, unknown>;
        config.providerOverrides[rt.resourceType] = { ...prev, ...rt.spec };
        break;
      }

      case TemplateKind.Assembly:
        // No spec to merge — assembly only wires components
        break;
    }
  }

  return config;
}

// ─── Validation ───

function validateConfig(config: MutableSandboxInput): ResolveError[] {
  const errors: ResolveError[] = [];

  if (!config.name.trim()) {
    errors.push({ templateName: '(assembly)', message: 'name is required' });
  }
  if (!config.region.trim()) {
    errors.push({ templateName: '(assembly)', message: 'region is required' });
  }
  if (config.resourceSpec.cpu <= 0) {
    errors.push({ templateName: '(assembly)', message: 'resourceSpec.cpu must be > 0' });
  }
  if (config.resourceSpec.memory <= 0) {
    errors.push({ templateName: '(assembly)', message: 'resourceSpec.memory must be > 0' });
  }
  if (config.containers.length === 0) {
    errors.push({ templateName: '(assembly)', message: 'at least one container is required' });
  }

  return errors;
}

import type {
  BaseTemplate,
  DagEdge,
} from '../base.ts';
import type {
  VolumeType,
  NFSVolumeConfig,
  DiskVolumeConfig,
  SecretVolumeConfig,
  ContainerConfig,
  CreateSandboxInput,
} from '../types.ts';
import type { InstanceId } from '../../../core/region/instance.ts';

// ─── Template discriminator ───

export enum TemplateKind {
  Volume = 'volume',
  Container = 'container',
  Resource = 'resource',
  Assembly = 'assembly',
}

// ─── VolumeTemplate ───

export interface VolumeTemplateSpec {
  readonly type: VolumeType;
  readonly instanceId: string;
  readonly nfs?: NFSVolumeConfig;
  readonly disk?: DiskVolumeConfig;
  readonly secret?: SecretVolumeConfig;
}

export interface VolumeTemplate extends BaseTemplate<TemplateKind.Volume> {
  readonly kind: TemplateKind.Volume;
  readonly spec: VolumeTemplateSpec;
}

// ─── ContainerTemplate ───

export interface ContainerTemplate extends BaseTemplate<TemplateKind.Container> {
  readonly kind: TemplateKind.Container;
  readonly spec: ContainerConfig;
}

// ─── ResourceTemplate ───

export enum ResourceType {
  Dns = 'dns',
  Network = 'network',
  SecurityGroup = 'securityGroup',
}

export interface ResourceTemplate extends BaseTemplate<TemplateKind.Resource> {
  readonly kind: TemplateKind.Resource;
  readonly resourceType: ResourceType;
  readonly spec: Record<string, unknown>;
}

// ─── AssemblyTemplate ───

export interface AssemblyTemplate extends BaseTemplate<TemplateKind.Assembly> {
  readonly kind: TemplateKind.Assembly;
  /** Templates that form this assembly, resolved in declaration order. */
  readonly components: readonly DagEdge[];
  /** Static overrides applied after all components are merged. */
  readonly overrides?: Partial<CreateSandboxInput>;
}

// ─── Discriminated union ───

export type Template =
  | VolumeTemplate
  | ContainerTemplate
  | ResourceTemplate
  | AssemblyTemplate;

// ─── Resolver result ───

export interface ResolveError {
  /** Template name where the error occurred. */
  readonly templateName: string;
  readonly message: string;
}

export interface ResolveSuccess {
  readonly success: true;
  readonly config: CreateSandboxInput;
}

export interface ResolveFailure {
  readonly success: false;
  readonly errors: readonly ResolveError[];
}

export type ResolveResult = ResolveSuccess | ResolveFailure;

// ─── Pod-level types (docker-compose-like spec) ───

/** Shared namespaces for a Pod (analogous to Podman PodBasicConfig.SharedNamespaces). */
export enum SharedNamespace {
  NET = 'net',
  UTS = 'uts',
  IPC = 'ipc',
  CGROUP = 'cgroup',
}

/** Pod exit strategy — what happens when one container stops. */
export enum PodExitPolicy {
  STOP = 'stop',
  CONTINUE = 'continue',
}

/** Resource limit expressed as a string (e.g. "1.0" for 1 CPU, "512Mi" for memory). */
export interface ResourceLimits {
  readonly cpu?: string | undefined;
  readonly memory?: string | undefined;
}

/** Port mapping — exposed container port to optional host port. */
export interface PortMapping {
  readonly containerPort: number;
  readonly hostPort?: number | undefined;
  readonly protocol?: 'tcp' | 'udp' | undefined;
}

/** A service within a PodSpec — analogous to a docker-compose service. */
export interface ServiceDefinition {
  readonly image: string;
  readonly command?: string | readonly string[] | undefined;
  readonly environment?: Record<string, string> | undefined;
  readonly ports?: readonly PortMapping[] | undefined;
  readonly volumes?: readonly {
    readonly source: string;
    readonly destination: string;
    readonly readOnly?: boolean | undefined;
  }[] | undefined;
  readonly resources?: ResourceLimits | undefined;
  readonly dependsOn?: readonly string[] | undefined;
  readonly labels?: Record<string, string> | undefined;
  readonly healthCheck?: {
    readonly test: readonly string[];
    readonly intervalSeconds?: number | undefined;
    readonly timeoutSeconds?: number | undefined;
    readonly retries?: number | undefined;
    readonly startPeriodSeconds?: number | undefined;
  } | undefined;
}

/** A Pod-level specification — analogous to a docker-compose file or Podman's PodSpecGenerator. */
export interface PodSpec {
  readonly name: string;
  readonly region?: string | undefined;
  readonly instanceId?: InstanceId | undefined;
  readonly hostname?: string | undefined;
  readonly labels?: Record<string, string> | undefined;
  readonly sharedNamespaces?: readonly SharedNamespace[] | undefined;
  readonly exitPolicy?: PodExitPolicy | undefined;
  readonly infraImage?: string | undefined;
  readonly resources?: ResourceLimits | undefined;
  readonly services: Record<string, ServiceDefinition>;
}

// ─── DAG execution plan types ───

/** A single task node in the container orchestration DAG. */
export interface TaskNode {
  readonly id: string;
  readonly dependsOn: readonly string[];
  /** Container image reference. */
  readonly image: string;
  /** Container arguments. */
  readonly args?: readonly string[] | undefined;
  /** Environment variables. */
  readonly env?: Record<string, string> | undefined;
  /** Ports to expose. */
  readonly ports?: readonly {
    readonly containerPort: number;
    readonly hostPort?: number | undefined;
    readonly protocol?: 'tcp' | 'udp' | undefined;
  }[] | undefined;
  /** Network mode override (e.g. 'container:<infra-id>'). */
  readonly networkMode?: string | undefined;
  /** CPU limit (fractional cores). */
  readonly cpu?: number | undefined;
  /** Memory limit (MB). */
  readonly memory?: number | undefined;
  /** Health check spec. */
  readonly healthCheck?: {
    readonly test: readonly string[];
    readonly intervalSeconds?: number | undefined;
    readonly timeoutSeconds?: number | undefined;
    readonly retries?: number | undefined;
    readonly startPeriodSeconds?: number | undefined;
  } | undefined;
  /** Provider-specific overrides. */
  readonly providerOverrides?: Record<string, unknown> | undefined;
}

/** Result of executing a single task node. */
export interface TaskResult {
  readonly nodeId: string;
  readonly success: boolean;
  readonly providerId?: string | undefined;
  readonly error?: string | undefined;
}

/** Execution plan produced by PodResolver and consumed by DagOrchestrator. */
export interface ExecutionPlan {
  readonly tasks: readonly TaskNode[];
  /** Infra container provider ID, if one was created. */
  readonly infraId?: string | undefined;
}

/** Final result of executing an entire plan. */
export interface ExecutionPlanResult {
  readonly success: boolean;
  readonly results: readonly TaskResult[];
  readonly infraId?: string | undefined;
}

import { Hono } from 'hono';
import type { Context } from 'hono';
import type { ISandboxService } from './interfaces.ts';
import { createSandboxId } from './types.ts';
import type { CreateSandboxInput } from './types.ts';
import type { PodSpec } from '../../core/pod/types.ts';
import { createPodId } from '../../core/pod/types.ts';
import type { PodService } from '../../core/pod/service.ts';
import type { IProviderRegistry } from '../../core/provider/interfaces.ts';
import type { RouteMeta } from '../../core/http-docs/types.ts';
import type { AppContext } from '../../core/deps.ts';
import { ok, fail } from '../../core/response.ts';
import type { ErrorCode } from '../../core/error-codes.ts';

interface PermissionCheckFn { check(params: { userId: string; action: string; resource: string; ip?: string }): Promise<{ allowed: boolean; reason: string }> }

function errorStatus(e: unknown, fallbackCode: ErrorCode, fallbackStatus = 500): { code: ErrorCode; status: any } {
  const status: any = (e as any)?.statusCode ?? (e as any)?.status ?? fallbackStatus;
  const code = ((e as any)?.code as ErrorCode | undefined) ?? fallbackCode;
  return { code, status };
}

interface SandboxEnv { Variables: AppContext }

async function requirePerm(c: Context<SandboxEnv>, checker: PermissionCheckFn | undefined, action: string, resource: string, resourceOwnerId?: string): Promise<Response | null> {
  if (!checker) return null;
  const user = c.var.currentUser;
  if (!user) return null;
  const result = await checker.check({ userId: user.id, action, resource, ...(resourceOwnerId ? { resourceOwnerId } : {}) });
  if (!result.allowed) return c.json(fail('FORBIDDEN', result.reason), 403);
  return null;
}

export function createSandboxRouter(
  svc: ISandboxService,
  _providers: IProviderRegistry,
  permissionChecker?: PermissionCheckFn,
  podService?: PodService,
): Hono<{ Variables: AppContext }> {
  const router = new Hono<{ Variables: AppContext }>();

  // ─── Container group (Pod) API — K8s-aligned, PodService-backed ───

  // POST /pod — create a pod from K8s-aligned PodSpec (persisted + state machine)
  router.post('/pod', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'create', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const spec = await c.req.json<PodSpec>();
      if (!spec.metadata?.name || !spec.spec?.containers?.length) {
        return c.json(fail('VALIDATION_ERROR', 'PodSpec requires metadata.name and spec.containers'), 400);
      }
      const pod = await podService.provision(spec);
      return c.json(ok({ podId: pod.podId, providerId: pod.providerId, phase: pod.phase, name: pod.name }), 201);
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_CREATE_FAILED');
      return c.json(fail(code, e.message), status);
    }
  });

  // GET /pod — list persisted pods
  router.get('/pod', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'read', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const phase = c.req.query('phase') as any || undefined;
      const limit = parseInt(c.req.query('limit') ?? '50');
      const cursor = c.req.query('cursor');
      const result = await podService.list(phase, limit, cursor);
      return c.json(ok(result));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_LIST_FAILED');
      return c.json(fail(code, e.message), status);
    }
  });

  // GET /pod/:id — get a single pod by PodId
  router.get('/pod/:id', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'read', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const podId = createPodId(c.req.param('id'));
      const pod = await podService.getById(podId);
      if (!pod) return c.json(fail('POD_NOT_FOUND', 'Pod not found'), 404);
      return c.json(ok(pod));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_GET_FAILED');
      return c.json(fail(code, e.message), status);
    }
  });

  // POST /pod/:id/stop — stop a pod (phase transition)
  router.post('/pod/:id/stop', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const podId = createPodId(c.req.param('id'));
      const pod = await podService.stop(podId);
      return c.json(ok({ podId: pod.podId, phase: pod.phase }));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_STOP_FAILED', 409);
      return c.json(fail(code, e.message), status);
    }
  });

  // DELETE /pod/:id — terminate a pod (Terminating → Deleted)
  router.delete('/pod/:id', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'delete', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const podId = createPodId(c.req.param('id'));
      await podService.terminate(podId);
      return c.json(ok(null));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_DELETE_FAILED', 404);
      return c.json(fail(code, e.message), status);
    }
  });

  // POST /pod/:id/sync — sync runtime state from provider
  router.post('/pod/:id/sync', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const podId = createPodId(c.req.param('id'));
      const pod = await podService.syncRuntime(podId);
      return c.json(ok(pod));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'SYNC_FAILED', 502);
      return c.json(fail(code, e.message), status);
    }
  });

  // GET /pod/:id/logs — container logs
  router.get('/pod/:id/logs', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'read', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const podId = createPodId(c.req.param('id'));
      const containerName = c.req.query('container') ?? '';
      if (!containerName) return c.json(fail('VALIDATION_ERROR', 'Query parameter "container" is required'), 400);
      const limitBytesRaw = c.req.query('limitBytes');
      const sinceSecondsRaw = c.req.query('sinceSeconds');
      const timestamps = c.req.query('timestamps') === 'true' ? true : undefined;
      const options: { limitBytes?: number; sinceSeconds?: number; timestamps?: boolean } = {};
      if (limitBytesRaw) options.limitBytes = parseInt(limitBytesRaw);
      if (sinceSecondsRaw) options.sinceSeconds = parseInt(sinceSecondsRaw);
      if (timestamps !== undefined) options.timestamps = timestamps;
      const result = await podService.getLogs(podId, containerName, options);
      return c.json(ok(result));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_LOGS_FAILED');
      return c.json(fail(code, e.message), status);
    }
  });

  // POST /pod/:id/exec — create exec instance (returns WebSocket URI for interactive sessions)
  router.post('/pod/:id/exec', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const podId = createPodId(c.req.param('id'));
      const body = await c.req.json<{ cmd: string[]; containerName?: string }>();
      if (!body.cmd?.length) return c.json(fail('VALIDATION_ERROR', 'Body.cmd (string array) is required'), 400);
      const result = await podService.exec(podId, body.cmd, body.containerName);
      return c.json(ok(result));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_EXEC_FAILED');
      return c.json(fail(code, e.message), status);
    }
  });

  // PATCH /pod/:id — partial PodSpec update
  router.patch('/pod/:id', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox'); if (r) return r; }
    if (!podService) return c.json(fail('NOT_CONFIGURED', 'PodService not available'), 501);
    try {
      const podId = createPodId(c.req.param('id'));
      const specPatch = await c.req.json<Partial<PodSpec>>();
      const updated = await podService.update(podId, specPatch);
      return c.json(ok(updated));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'POD_UPDATE_FAILED', 409);
      return c.json(fail(code, e.message), status);
    }
  });

  // ─── Sandbox API (v1, single-container) ───

  router.get('/', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'read', 'sandbox'); if (r) return r; }
    const status = c.req.query('status') as any || undefined;
    const apiVer = c.req.query('apiVersion');
    const podPhase = c.req.query('podPhase')! || undefined;
    const limit = parseInt(c.req.query('limit') ?? '50');
    const cursor = c.req.query('cursor');
    let result = await svc.list?.(status, limit, cursor) ?? { items: [] };
    if (apiVer) {
      result = { ...result, items: result.items.filter(s => (s.config as any).apiVersion === apiVer) };
    } else {
      result = { ...result, items: result.items.filter(s => (s.config as any).apiVersion !== 'hbi-aad/v2') };
    }
    // Enrich with podPhase when PodService is available
    if (podService && result.items.length > 0) {
      const enriched = await Promise.all(result.items.map(async s => {
        const podUid = (s as unknown as Record<string, unknown>).podUid as string | undefined;
        if (!podUid) return { ...s, podPhase: null };
        try {
          const pod = await podService.getById(createPodId(podUid));
          return { ...s, podPhase: pod?.phase ?? null };
        } catch { return { ...s, podPhase: null }; }
      }));
      if (podPhase) {
        result = { ...result, items: enriched.filter(s => (s as Record<string, unknown>).podPhase === podPhase) };
      } else {
        result = { ...result, items: enriched };
      }
    }
    return c.json(ok(result));
  });

  router.get('/:id', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'read', 'sandbox'); if (r) return r; }
    const id = createSandboxId(c.req.param('id'));
    const sandbox = await svc.getById(id);
    if (!sandbox) return c.json(fail('SANDBOX_NOT_FOUND', 'Sandbox not found'), 404);
    // Project podPhase from PodService when available
    let podPhase: string | null = null;
    if (podService) {
      const podUid = (sandbox as unknown as Record<string, unknown>).podUid as string | undefined;
      if (podUid) {
        try {
          const pod = await podService.getById(createPodId(podUid));
          podPhase = pod?.phase ?? null;
        } catch { podPhase = null; }
      }
    }
    return c.json(ok({ ...sandbox, podPhase }));
  });

  router.post('/:id/stop', async (c) => {
    const id = createSandboxId(c.req.param('id'));
    const sandbox = await svc.getById(id);
    const ownerId = sandbox?.config?.creatorId;
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox', ownerId); if (r) return r; }
    try {
      const stopped = await svc.stop(id);
      return c.json(ok(stopped));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'STOP_FAILED', 409);
      return c.json(fail(code, e.message), status);
    }
  });

  router.post('/:id/start', async (c) => {
    const id = createSandboxId(c.req.param('id'));
    const sandbox = await svc.getById(id);
    const ownerId = sandbox?.config?.creatorId;
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox', ownerId); if (r) return r; }
    try {
      if (!svc.start) return c.json(fail('START_FAILED', 'Start not supported by this service'), 501);
      const started = await svc.start(id);
      return c.json(ok(started));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'START_FAILED', 409);
      return c.json(fail(code, e.message), status);
    }
  });

  router.delete('/:id', async (c) => {
    const id = createSandboxId(c.req.param('id'));
    const sandbox = await svc.getById(id);
    const ownerId = sandbox?.config?.creatorId;
    const actorId = c.var.currentUser?.id;
    { const r = await requirePerm(c, permissionChecker, 'delete', 'sandbox', ownerId); if (r) return r; }
    try {
      await svc.terminate(id, actorId);
      return c.json(ok(null));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'DELETE_FAILED', 404);
      return c.json(fail(code, e.message), status);
    }
  });

  router.post('/:id/sync', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox'); if (r) return r; }
    const id = createSandboxId(c.req.param('id'));
    try {
      const runtime = await svc.syncRuntime(id);
      const updated = await svc.getById(id);
      return c.json(ok({ runtime, sandbox: updated }), 200);
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'SYNC_FAILED', 502);
      return c.json(fail(code, e.message), status);
    }
  });

  router.get('/:id/health', async (c) => {
    { const r = await requirePerm(c, permissionChecker, 'read', 'sandbox'); if (r) return r; }
    const id = createSandboxId(c.req.param('id'));
    try {
      const health = await svc.getHealth(id);
      return c.json(ok(health));
    } catch (e: any) {
      return c.json(fail('HEALTH_FAILED', e.message), e.status ?? 500);
    }
  });

  router.post('/:id/restart', async (c) => {
    const id = createSandboxId(c.req.param('id'));
    const sandbox = await svc.getById(id);
    const ownerId = sandbox?.config?.creatorId;
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox', ownerId); if (r) return r; }
    try {
      const result = await svc.restart(id);
      return c.json(ok(result));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'RESTART_FAILED', 409);
      return c.json(fail(code, e.message), status);
    }
  });

  router.patch('/:id', async (c) => {
    const id = createSandboxId(c.req.param('id'));
    const sandbox = await svc.getById(id);
    const ownerId = sandbox?.config?.creatorId;
    { const r = await requirePerm(c, permissionChecker, 'update', 'sandbox', ownerId); if (r) return r; }
    try {
      const body = await c.req.json<Partial<CreateSandboxInput>>();
      const result = await svc.update(id, body);
      return c.json(ok(result));
    } catch (e: any) {
      const { code, status } = errorStatus(e, 'UPDATE_FAILED', 409);
      return c.json(fail(code, e.message), status);
    }
  });

  return router;
}

