/// <reference types="@cloudflare/workers-types" />

/**
 * LogStreamDO — 容器日志 WebSocket 流。
 *
 * 双模式:
 *   snapshot — app.ts 预取日志内容传入，DO 一次推送后关闭
 *   stream   — 连 Podman Docker API 实时流式推送（follow=1）
 *
 * 标准日志参数:
 *   content       — 预取日志内容（snapshot 模式）
 *   containerName — 容器名称（snapshot 模式）
 *   endpoint      — Docker API endpoint（stream 模式）
 *   providerId    — 容器/容器组 ID
 *   provider      — 平台类型
 *   tail, since   — 日志过滤参数
 *
 * Podman: HTTP streaming, 流结束时 inspect 容器状态
 * 其他 (Alibaba/AWS/GCP): app.ts 预取 → snapshot
 */

const IDLE_ALARM_MS = 300_000; // 5 min

function podmanLogsUrl(base: string, id: string, tail?: number, since?: number): string {
  const ep = base.replace(/\/+$/, '');
  let url = `${ep}/containers/${id}/logs?follow=1&stdout=1&stderr=1`;
  if (tail !== undefined && tail > 0) url += `&tail=${String(tail)}`;
  if (since !== undefined) url += `&since=${String(since)}`;
  return url;
}

function podmanInspectUrl(base: string, id: string): string {
  const ep = base.replace(/\/+$/, '');
  return `${ep}/containers/${id}/json`;
}

export class LogStreamDO implements DurableObject {
  readonly #sessions = new Set<WebSocket>();
  #abortController: AbortController | null = null;

  public constructor(public readonly ctx: DurableObjectState, public readonly _env: unknown) {}

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async fetch(request: Request): Promise<Response> {
    const url = new URL(request.url);
    const providerId = url.searchParams.get('providerId');
    const endpoint = url.searchParams.get('endpoint');
    const provider = url.searchParams.get('provider') ?? 'podman';
    const content = url.searchParams.get('content');
    const containerName = url.searchParams.get('containerName') ?? '';
    const tail = parseInt(url.searchParams.get('tail') ?? '0', 10) || undefined;
    const since = parseInt(url.searchParams.get('since') ?? '0', 10) || undefined;

    if (!providerId) {
      return new Response('Missing providerId', { status: 400 });
    }

    // WebSocket upgrade
    const pair = new WebSocketPair();
    const client = pair[0];
    const server = pair[1];

    this.#sessions.add(server);
    server.accept();
    server.addEventListener('close', () => {
      this.#sessions.delete(server);
      if (this.#sessions.size === 0) this.#stop();
    });
    server.addEventListener('error', () => {
      this.#sessions.delete(server);
      if (this.#sessions.size === 0) this.#stop();
    });

    // Refresh idle alarm
    this.ctx.storage.setAlarm(Date.now() + IDLE_ALARM_MS).catch(() => { /* noop */ });

    // Start streaming (only on first connection)
    if (!this.#abortController) {
      if (content !== null) {
        this.#snapshot(content, containerName);
      } else {
        this.#start(provider, endpoint, providerId, tail, since);
      }
    }

    return new Response(null, { status: 101, webSocket: client });
  }

  #start(provider: string, endpoint: string | null, containerId: string, tail?: number, since?: number): void {
    if (provider === 'podman' && endpoint) {
      void this.#streamFromPodman(endpoint, containerId, tail, since);
    } else {
      this.#broadcast(JSON.stringify({ event: 'error', message: `Unsupported provider: ${provider}` }));
      this.#stop();
    }
  }

  /** Snapshot mode: push pre-fetched content once, then close. */
  #snapshot(content: string, containerName: string): void {
    this.#abortController = new AbortController();
    this.#broadcast(JSON.stringify({ content, containerName, event: 'container_logs' }));
    this.#broadcast(JSON.stringify({ event: 'container_stopped' }));
    this.#stop();
  }

  async #streamFromPodman(endpoint: string, containerId: string, tail?: number, since?: number): Promise<void> {
    this.#abortController = new AbortController();
    try {
      const url = podmanLogsUrl(endpoint, containerId, tail, since);
      const resp = await fetch(url, { signal: this.#abortController.signal });
      if (!resp.ok || !resp.body) {
        if (resp.status === 404) {
          this.#broadcast(JSON.stringify({ event: 'container_deleted', message: 'Container not found' }));
          this.#scheduleCleanup(10_000);
        } else {
          this.#broadcast(JSON.stringify({ event: 'error', message: `Logs failed: ${String(resp.status)}` }));
        }
        return;
      }

      const reader = resp.body.getReader();
      const decoder = new TextDecoder();
      while (true) {
        const { done, value } = await reader.read();
        if (done) break; // stream ended → container stopped
        const text = decoder.decode(value, { stream: true });
        if (text) this.#broadcast(text);
      }

      // Stream ended — container stopped. Check if it still exists.
      this.#broadcast(JSON.stringify({ event: 'container_stopped' }));
      await this.#checkContainer(endpoint, containerId);
    } catch (e: unknown) {
      if ((e as Error)?.name === 'AbortError') return;
      this.#broadcast(JSON.stringify({ event: 'error', message: String(e) }));
    }
  }

  async #checkContainer(endpoint: string, containerId: string): Promise<void> {
    try {
      const resp = await fetch(podmanInspectUrl(endpoint, containerId));
      if (resp.status === 404) {
        // Container deleted → schedule DO cleanup
        this.#broadcast(JSON.stringify({ event: 'container_deleted' }));
        this.#scheduleCleanup(10_000);
      }
      // Container exists but stopped → stay alive, wait for restart
    } catch {
      // Network error — stay alive, retry logic could go here
    }
  }

  #broadcast(data: string): void {
    for (const ws of this.#sessions) {
      try { ws.send(data); } catch { /* client gone */ }
    }
  }

  #scheduleCleanup(delayMs: number): void {
    this.ctx.storage.setAlarm(Date.now() + delayMs).catch(() => { /* noop */ });
  }

  #stop(): void {
    this.#abortController?.abort();
    this.#abortController = null;
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async alarm(): Promise<void> {
    this.#stop();
    for (const ws of this.#sessions) {
      try { ws.close(1001, 'DO idle timeout'); } catch { /* already closed */ }
    }
    this.#sessions.clear();
  }
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import { KernLevel } from '../../core/audit/kern-level.ts';

/** Quota key prefix per user. */
const QUOTA_KEY = 'quota:user:';

export interface UserQuota {
  /** Max number of sandboxes (0 = unlimited). */
  readonly maxSandboxes?: number;
  /** Max total CPU across all sandboxes (0 = unlimited). */
  readonly maxCpu?: number;
  /** Max total memory in MB (0 = unlimited). */
  readonly maxMemory?: number;
}

export interface QuotaUsage {
  readonly sandboxes: number;
  readonly cpu: number;
  readonly memory: number;
}

/**
 * Lightweight user quota enforcement.
 *
 * Quotas are configurable per user via atomic store key `quota:user:<userId>`.
 * If no quota entry exists, no limits are enforced (unlimited).
 * Usage counters are tracked via OCC in the same key.
 */
export class QuotaService {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly audit?: IAuditWriter,
  ) {}

  public async getQuota(userId: string): Promise<UserQuota> {
    const entry = await this.atomic.get<UserQuota>(QUOTA_KEY + userId);
    return entry?.value ?? {};
  }

  public async getUsage(userId: string): Promise<QuotaUsage> {
    const entry = await this.atomic.get<QuotaUsage>(`${QUOTA_KEY}${userId}:usage`);
    return entry?.value ?? { sandboxes: 0, cpu: 0, memory: 0 };
  }

  public async setQuota(userId: string, quota: UserQuota): Promise<void> {
    const entry = await this.atomic.get<any>(QUOTA_KEY + userId);
    await this.atomic.set(QUOTA_KEY + userId, quota, entry?.version ?? null);
    this.audit?.write({
      level: KernLevel.NOTICE,
      facility: 'quota',
      message: `Quota set for user ${userId}`,
      metadata: { eventType: 'quota.set', userId, quota },
    });
  }

  /**
   * Check if a user has capacity to create a sandbox with the given resources.
   * Throws an error with `status` property if quota would be exceeded.
   */
  public async checkQuota(userId: string, cpu: number, memory: number): Promise<void> {
    const quota = await this.getQuota(userId);
    if (!quota.maxSandboxes && !quota.maxCpu && !quota.maxMemory) return; // unlimited

    const usage = await this.getUsage(userId);

    if (quota.maxSandboxes && usage.sandboxes >= quota.maxSandboxes) {
      const err: any = new Error(`Sandbox quota exceeded: ${String(usage.sandboxes)}/${String(quota.maxSandboxes)}`);
      err.status = 429;
      throw err;
    }
    if (quota.maxCpu && (usage.cpu + cpu) > quota.maxCpu) {
      const err: any = new Error(`CPU quota exceeded: ${String(usage.cpu + cpu)}/${String(quota.maxCpu)}`);
      err.status = 429;
      throw err;
    }
    if (quota.maxMemory && (usage.memory + memory) > quota.maxMemory) {
      const err: any = new Error(`Memory quota exceeded: ${String(usage.memory + memory)}/${String(quota.maxMemory)}`);
      err.status = 429;
      throw err;
    }
  }

  /**
   * Record a sandbox creation (increment counters).
   */
  public async recordCreate(userId: string, cpu: number, memory: number): Promise<void> {
    const key = `${QUOTA_KEY}${userId}:usage`;
    const entry = await this.atomic.get<QuotaUsage>(key);
    const current = entry?.value ?? { sandboxes: 0, cpu: 0, memory: 0 };
    await this.atomic.set(key, {
      sandboxes: current.sandboxes + 1,
      cpu: current.cpu + cpu,
      memory: current.memory + memory,
    }, entry?.version ?? null);
  }

  /**
   * Record a sandbox deletion (decrement counters).
   */
  public async recordDelete(userId: string, cpu: number, memory: number): Promise<void> {
    const key = `${QUOTA_KEY}${userId}:usage`;
    const entry = await this.atomic.get<QuotaUsage>(key);
    if (!entry) return;
    const current = entry.value;
    await this.atomic.set(key, {
      sandboxes: Math.max(0, current.sandboxes - 1),
      cpu: Math.max(0, current.cpu - cpu),
      memory: Math.max(0, current.memory - memory),
    }, entry.version);
  }
}

/** Pure mapping functions from provider runtime data to sandbox entity fields.
 *  Shared by SandboxService (syncRuntime) and health-check (auto-promotion).
 *  All functions are pure — no IO, no side effects. */

import type { ContainerGroupRuntime, OciContainerStatus } from '../../core/provider/types.ts';
import type { NetworkInfo, ContainerRuntime, ContainerEvent } from './types.ts';
import { ContainerStatus } from './types.ts';
import { createVolumeId } from './types.ts';

export function eipFromResources(
  resources: ContainerGroupRuntime['associatedResources'],
): string | undefined {
  const eip = resources.find(r => r.type === 'eip');
  return eip?.ip;
}

export function runtimeToNetwork(
  network: ContainerGroupRuntime['network'],
  associatedResources: ContainerGroupRuntime['associatedResources'],
): NetworkInfo {
  const publicIp = eipFromResources(associatedResources);
  return {
    ...(publicIp !== undefined ? { publicIp } : {}),
    ...(network.privateIp !== undefined ? { privateIp: network.privateIp } : {}),
    ...(network.vpcId !== undefined ? { vpcId: network.vpcId } : {}),
    ...(network.subnetId !== undefined ? { subnetId: network.subnetId } : {}),
    ...(network.securityGroupId !== undefined ? { securityGroupId: network.securityGroupId } : {}),
    ...(network.eniId !== undefined ? { eniId: network.eniId } : {}),
  };
}

export function ociStatusToContainerState(s: OciContainerStatus): ContainerStatus {
  switch (s) {
    case 'running': return ContainerStatus.Running;
    case 'paused': return ContainerStatus.Running;
    case 'stopped':
    case 'error':
    case 'deleted': return ContainerStatus.Terminated;
    case 'creating':
    case 'created':
    default: return ContainerStatus.Waiting;
  }
}

export function runtimeToContainers(r: ContainerGroupRuntime): ContainerRuntime[] {
  return r.containers.map(c => ({
    name: c.name,
    image: c.image,
    cpu: c.resources?.cpu ?? 0,
    memory: c.resources?.memory ?? 0,
    state: {
      state: ociStatusToContainerState(c.status),
      ready: c.health.status === 'healthy' || (c.health.status === 'none' && c.status === 'running'),
      restartCount: 0,
      ...(c.startedAt ? { startTime: c.startedAt } : {}),
      ...(c.finishedAt ? { finishedTime: c.finishedAt } : {}),
      ...(c.exitCode !== undefined ? { exitCode: c.exitCode } : {}),
    },
    volumeMounts: c.mounts.map(m => ({
      volumeId: createVolumeId('unknown'), // provider mounts don't reference our internal volume IDs
      mountPath: m.destination,
      readOnly: m.options?.includes('ro') ?? false,
    })),
    health: {
      status: c.health.status,
      ...(c.health.lastCheckedAt !== undefined ? { lastCheckedAt: c.health.lastCheckedAt } : {}),
      ...(c.health.message !== undefined ? { message: c.health.message } : {}),
    },
  }));
}

export function runtimeToEvents(r: ContainerGroupRuntime): ContainerEvent[] {
  return r.events.map(e => ({
    _brand: 'ValueObject' as const,
    reason: e.reason,
    type: e.type,
    message: e.message,
    count: e.count,
    ...(e.lastTimestamp !== undefined ? { lastTimestamp: e.lastTimestamp } : {}),
  }));
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { SandboxId, Sandbox , SandboxStatus} from './types.ts';
import { isValidTransition } from './types.ts';
import { generateVersionId } from '../../core/brand.ts';
import { AppError } from '../../core/types.ts';
import { getValidated } from '../../core/store/validate.ts';
import { SandboxSchema } from './entity-schema.ts';

const KEY_PREFIX = 'sandbox:';
const INDEX_KEY = 'sandbox:ids';

/** Pure data access for sandbox entities — no provider logic. */
export class SandboxStore {
  public constructor(private readonly atomic: IAtomicStore) {}

  public async getById(id: SandboxId): Promise<Sandbox | null> {
    const validated = await getValidated(this.atomic, `${KEY_PREFIX}${id}`, SandboxSchema);
    return validated as unknown as Sandbox | null;
  }

  public async list(status?: SandboxStatus, limit = 50, cursor?: string): Promise<{ items: Sandbox[]; nextCursor?: string }> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return { items: [] };

    let ids = idx.value;
    const startIdx = cursor ? parseInt(cursor, 10) : 0;
    if (isNaN(startIdx) || startIdx >= ids.length) return { items: [] };

    ids = ids.slice(startIdx, startIdx + limit);

    const entries = await Promise.all(
      ids.map(id => this.atomic.get<Sandbox>(`${KEY_PREFIX}${id}`)),
    );

    let items = entries.filter(e => e !== null).map(e => e.value);
    if (status) items = items.filter(s => s.status === status);

    const nextCursorVal = startIdx + limit < (idx?.value.length ?? 0)
      ? String(startIdx + limit)
      : undefined;

    return { items, ...(nextCursorVal !== undefined ? { nextCursor: nextCursorVal } : {}) };
  }

  public async addToIndex(id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    await this.atomic.set(INDEX_KEY, [...(idx?.value ?? []), id], idx?.version ?? null);
  }

  public async removeFromIndex(id: string): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (idx) await this.atomic.set(INDEX_KEY, idx.value.filter((i: string) => i !== id), idx.version);
  }

  /** Perform an OCC-guarded status transition. Returns the updated sandbox. */
  public async transition(id: SandboxId, to: SandboxStatus, _reason?: string, _actorId?: string): Promise<Sandbox> {
    const entry = await this.atomic.get<Sandbox>(`${KEY_PREFIX}${id}`);
    if (!entry) throw new AppError(404, 'SANDBOX_NOT_FOUND', `Sandbox ${id} not found`);

    const from = entry.value;
    if (!isValidTransition(from.status, to)) {
      throw new AppError(409, 'INVALID_TRANSITION', `Cannot transition from ${from.status} to ${to}`);
    }

    const updated: Sandbox = {
      ...from,
      status: to,
      updatedAt: Date.now(),
      version: generateVersionId(),
    };

    const newVersion = await this.atomic.set(`${KEY_PREFIX}${id}`, updated, entry.version);
    if (!newVersion) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');

    return updated;
  }
}

import { z } from 'zod';
import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type {
