// ─── Input mapping ───

/**
 * Convert a v2 PodSpec (docker-compose style) to CreateSandboxInput for
 * the SandboxService.provision() path.  This bridges the ContainerGroup
 * template kind into the full sandbox lifecycle (state machine, GC, etc.).
 */
export function podSpecToSandboxInput(spec: {
  name: string;
  region?: string | undefined;
  instanceId?: string | undefined;
  hostname?: string | undefined;
  labels?: Record<string, string> | undefined;
  resources?: { cpu?: string | undefined; memory?: string | undefined } | undefined;
  services: Record<string, {
    image: string;
    command?: string | readonly string[] | undefined;
    environment?: Record<string, string> | undefined;
    ports?: readonly { containerPort: number; hostPort?: number | undefined; protocol?: 'tcp' | 'udp' | undefined }[] | undefined;
    volumes?: readonly { source: string; destination: string; readOnly?: boolean | undefined }[] | undefined;
    resources?: { cpu?: string | undefined; memory?: string | undefined } | undefined;
  }>;
}): CreateSandboxInput {
  const names = Object.keys(spec.services);
  const containers = names.map(name => {
    const svc = spec.services[name]!;
    let args: string[] | undefined;
    if (typeof svc.command === 'string') {
      args = [svc.command];
    } else if (svc.command !== undefined) {
      args = [...svc.command];
    }
    const env = svc.environment
      ? Object.entries(svc.environment).map(([k, v]) => ({ name: k, value: v }))
      : undefined;
    const cpu = svc.resources?.cpu ? parseFloat(svc.resources.cpu) : 1;
    const memory = svc.resources?.memory ? parseMemoryString(svc.resources.memory) : 2048;
    return {
      name: `${spec.name}-${name}`,
      image: svc.image,
      ...(args ? { args } : {}),
      ...(env ? { env } : {}),
      ...(svc.ports ? { ports: svc.ports.map(p => ({ containerPort: p.containerPort, ...(p.protocol ? { protocol: p.protocol } : {}) })) } : {}),
      resources: { limits: { cpu, memory } },
    };
  });

  const totalCpu = spec.resources?.cpu ? parseFloat(spec.resources.cpu) : containers.reduce((s, c) => s + (c.resources?.limits?.cpu ?? 1), 0);
  const totalMem = spec.resources?.memory ? parseMemoryString(spec.resources.memory) : containers.reduce((s, c) => s + (c.resources?.limits?.memory ?? 2048), 0);

  return {
    name: spec.name,
    region: createRegionId(spec.region ?? 'local'),
    ...(spec.instanceId ? { instanceId: spec.instanceId as InstanceId } : {}),
    resourceSpec: { cpu: totalCpu, memory: totalMem },
    restartPolicy: 'Never',
    containers: containers,
    network: { allocatePublicIp: false },
    ...(spec.labels ? { tags: Object.entries(spec.labels).map(([k, v]) => ({ key: k, value: v })) } : {}),
  };
}

/** Parse memory string like "512Mi" or "1Gi" to MB. */
function parseMemoryString(s: string): number {
  const re = /^(\d+(?:\.\d+)?)\s*(Ki|Mi|Gi|Ti|k|M|G|T|KB|MB|GB|TB)?$/i;
  const m = re.exec(s);
  if (!m) return 512;
  const num = parseFloat(m[1]!);
  const unit = (m[2] ?? 'M').toLowerCase();
  const multipliers: Record<string, number> = {
    ki: 1 / 1024, k: 1 / 1024, kb: 1 / 1024,
    m: 1, mb: 1, mi: 1, '': 1,
    gi: 1024, g: 1024, gb: 1024,
    ti: 1024 * 1024, t: 1024 * 1024, tb: 1024 * 1024,
  };
  return num * (multipliers[unit] ?? 1);
}

export function toContainerGroupInput(input: CreateSandboxInput): CreateContainerGroupInput {
  return {
    name: sanitizeName(input.name),
    description: input.description,
    region: input.region,
    ...(input.instanceId ? { instanceId: input.instanceId } : {}),
    ...(input.zoneId ? { zoneId: input.zoneId } : {}),
    cpu: input.resourceSpec.cpu,
    memory: Math.max(1, Math.ceil(input.resourceSpec.memory / 1024)), // ECI expects GB, applicator provides MB
    gpu: input.resourceSpec.gpu,
    gpuType: input.resourceSpec.gpuType,
    // spotStrategy moved to providerOverrides.alibaba — provider-specific, not neutral.
    restartPolicy: input.restartPolicy,
    containers: input.containers.map(c => ({
      name: c.name,
      image: c.image,
      command: c.command,
      args: c.args,
      env: mapEnvVars(c.env),
      tty: c.tty,
      stdin: c.stdin,
      imagePullPolicy: c.imagePullPolicy,
      resources: c.resources,
      livenessProbe: c.livenessProbe,
      readinessProbe: c.readinessProbe,
      startupProbe: c.startupProbe,
      ports: mapPorts(c.ports),
      networkMode: c.networkMode,
      volumeMounts: mapVolumeMounts(c.volumeMounts?.map(vm => ({
        volumeId: String(vm.volumeId),
        mountPath: vm.mountPath,
        readOnly: vm.readOnly,
        mountPropagation: vm.mountPropagation,
      }))),
      providerOverrides: c.providerOverrides,
    })),
    volumes: mapVolumes(input.volumes?.map(v => ({
      id: String(v.id),
      type: v.type,
      nfs: v.nfs,
      disk: v.disk,
      secret: v.secret,
    }))),
    network: mapNetwork(mergeNetworkWithExtensions(input)),
    tags: mapTags(input.tags),
    providerOverrides: input.providerOverrides,
  };
}

/** Merge Alibaba-specific network settings from extensions into the standard network config.
 *  NetworkSpec.publicIp/vpc are deprecated in favor of extensions.providerOverrides.alibaba.
 *  Extensions take priority when both are present. */
function mergeNetworkWithExtensions(input: CreateSandboxInput): {
  subnetIds?: readonly string[] | undefined; securityGroupId?: string | undefined;
  allocatePublicIp: boolean; publicIpBandwidth?: number | undefined;
  bandwidth?: any;
} {
  const nw = input.network;
  const ext = (input.providerOverrides)?.alibaba as Record<string, unknown> | undefined;

  // EIP: extensions ONLY. Standard network.publicIp is silently ignored (EIP costs money).
  // VPC: standard network first, extensions as override.
  return {
    allocatePublicIp: ext?.autoCreateEip === true || ext?.autoCreateEip === 'true',
    ...(ext?.eipBandwidth !== undefined
      ? { publicIpBandwidth: Number(ext.eipBandwidth) }
      : {}),
    subnetIds: nw.subnetIds?.length
      ? nw.subnetIds
      : (ext?.vSwitchId ? String(ext.vSwitchId).split(',').map(s => s.trim()) : undefined),
    securityGroupId: nw.securityGroupId ?? ext?.securityGroupId as string | undefined,
    bandwidth: nw.bandwidth,
  };
}

/** Map a Partial<CreateSandboxInput> to Partial<CreateContainerGroupInput> for UpdateContainerGroup.
 *  Only maps fields that are present in the input, leaving everything else undefined. */
function toPartialContainerGroupInput(
  input: Partial<CreateSandboxInput>,
  _existing: CreateSandboxInput,
): Partial<CreateContainerGroupInput> {
  const region = input.region ?? _existing.region;

  return {
    ...(region ? { region } : {}),
    ...(input.name ? { name: sanitizeName(input.name) } : {}),
    ...(input.restartPolicy ? { restartPolicy: input.restartPolicy } : {}),
    ...(input.resourceSpec ? {
      cpu: input.resourceSpec.cpu,
      memory: Math.max(1, Math.ceil(input.resourceSpec.memory / 1024)),
      ...(input.resourceSpec.gpu !== undefined ? { gpu: input.resourceSpec.gpu } : {}),
      ...(input.resourceSpec.gpuType ? { gpuType: input.resourceSpec.gpuType } : {}),
    } : {}),
    ...(input.containers ? {
      containers: input.containers.map(c => ({
        name: c.name, image: c.image,
        ...(c.command ? { command: c.command } : {}),
        ...(c.args ? { args: c.args } : {}),
        ...(c.env ? { env: mapEnvVars(c.env) } : {}),
        ...(c.tty !== undefined ? { tty: c.tty } : {}),
        ...(c.stdin !== undefined ? { stdin: c.stdin } : {}),
        ...(c.imagePullPolicy ? { imagePullPolicy: c.imagePullPolicy } : {}),
        ...(c.resources ? { resources: c.resources } : {}),
        ...(c.livenessProbe ? { livenessProbe: c.livenessProbe } : {}),
        ...(c.readinessProbe ? { readinessProbe: c.readinessProbe } : {}),
        ...(c.startupProbe ? { startupProbe: c.startupProbe } : {}),
        ...(c.ports ? { ports: mapPorts(c.ports) } : {}),
        ...(c.networkMode ? { networkMode: c.networkMode } : {}),
      })),
    } : {}),
    ...(input.volumes ? {
      volumes: mapVolumes(input.volumes.map(v => ({
        id: String(v.id), type: v.type, nfs: v.nfs, disk: v.disk, secret: v.secret,
      }))),
    } : {}),
    ...(input.network ? {
      network: mapNetwork({
        subnetIds: input.network.subnetIds ?? _existing.network.subnetIds,
        securityGroupId: input.network.securityGroupId ?? _existing.network.securityGroupId,
        allocatePublicIp: input.network.allocatePublicIp ?? _existing.network.allocatePublicIp,
        publicIpBandwidth: input.network.publicIpBandwidth ?? _existing.network.publicIpBandwidth,
        bandwidth: input.network.bandwidth ?? _existing.network.bandwidth,
      }),
    } : {}),
    ...(input.tags ? { tags: mapTags(input.tags) } : {}),
    ...(input.providerOverrides ? { providerOverrides: input.providerOverrides } : {}),
    ...(input.zoneId ? { zoneId: input.zoneId } : {}),
  };
}

function toPodSpec(input: CreateSandboxInput): PodSpec {
  return {
    metadata: {
      name: input.name,
      ...(input.tags?.length ? { labels: Object.fromEntries(input.tags.map(t => [t.key, t.value])) } : {}),
    },
    spec: {
      containers: input.containers.map(c => ({
        name: c.name,
        image: c.image,
        command: c.command,
        args: c.args,
        env: c.env,
        resources: c.resources?.limits ? { limits: { cpu: c.resources.limits.cpu, memory: c.resources.limits.memory, ...(c.resources.limits.gpu !== undefined ? { gpu: c.resources.limits.gpu } : {}) } } : undefined,
        ports: c.ports,
        volumeMounts: c.volumeMounts,
        livenessProbe: c.livenessProbe,
        readinessProbe: c.readinessProbe,
        startupProbe: c.startupProbe,
        imagePullPolicy: c.imagePullPolicy,
        tty: c.tty,
        stdin: c.stdin,
        networkMode: c.networkMode,
        providerOverrides: c.providerOverrides,
      })),
      ...(input.initContainers?.length ? {
        initContainers: input.initContainers.map(c => ({
          name: c.name,
          image: c.image,
          command: c.command,
          args: c.args,
          env: c.env,
        })),
      } : {}),
      restartPolicy: input.restartPolicy,
      // volumes: mapped via providerOverrides for now (sandbox Volume entity ≠ PodSpec VolumeSpec)
    },
    ...(input.providerOverrides ? { providerOverrides: input.providerOverrides } : {}),
  };
}

/** 将云厂商错误翻译为用户可读的 AppError */
function translateProviderError(e: unknown, sandboxName: string): AppError {
  const msg = e instanceof Error ? e.message : String(e);
  const lower = msg.toLowerCase();

  if (lower.includes('fetch failed') || lower.includes('econnrefused') || lower.includes('connection refused')) {
    return new AppError(503, 'PROVIDER_UNREACHABLE',
      `Cannot reach container provider for sandbox "${sandboxName}". Is Podman running? Check PODMAN_ENDPOINT or instance connectivity. (detail: ${msg.slice(0, 200)})`);
  }
  if (lower.includes('401') || lower.includes('unauthorized') || lower.includes('invalid security token') || lower.includes('signature') || lower.includes('invalidaccesskeyid')) {
    return new AppError(401, 'PROVIDER_AUTH_FAILED',
      `Authentication failed for sandbox "${sandboxName}". Check your cloud credentials (ALIBABA_ACCESS_KEY_ID / ALIBABA_ACCESS_KEY_SECRET). (detail: ${msg.slice(0, 200)})`);
  }
  if (lower.includes('403') || lower.includes('forbidden') || lower.includes('accessdenied')) {
    return new AppError(403, 'PROVIDER_FORBIDDEN',
      `Access denied by cloud provider for sandbox "${sandboxName}". Check IAM/RAM permissions. (detail: ${msg.slice(0, 200)})`);
  }
  if (lower.includes('timeout') || lower.includes('timed out') || lower.includes('etimedout')) {
    return new AppError(504, 'PROVIDER_TIMEOUT',
      `Cloud provider timed out for sandbox "${sandboxName}". Check network connectivity and provider health. (detail: ${msg.slice(0, 200)})`);
  }
  if (lower.includes('not found') || lower.includes('404') || lower.includes('nosuchbucket') || lower.includes('nosuchkey')) {
    return new AppError(404, 'PROVIDER_NOT_FOUND',
      `Cloud resource not found for sandbox "${sandboxName}". Check that the target resource exists. (detail: ${msg.slice(0, 200)})`);
  }
  if (lower.includes('quota') || lower.includes('limit exceeded') || lower.includes('throttl')) {
    return new AppError(429, 'PROVIDER_QUOTA_EXCEEDED',
      `Cloud provider quota exceeded for sandbox "${sandboxName}". Check your account limits. (detail: ${msg.slice(0, 200)})`);
  }

  // Generic fallback with original message preserved
  return new AppError(502, 'PROVIDER_ERROR',
    `Cloud provider failed for sandbox "${sandboxName}": ${msg.slice(0, 300)}`);
}

/** Sanitize sandbox name for provider API constraints.
 *  Alibaba ECI: [a-zA-Z][a-zA-Z0-9]{1,62} — letters + digits only, no hyphens. */
function sanitizeName(name: string): string {
  let s = name.replace(/\s+/g, '').replace(/[^a-zA-Z0-9]/g, '').slice(0, 63);
  if (!s || s.length < 2) s = 'sbx' + Date.now().toString(36);
  if (!/^[a-zA-Z]/.test(s)) s = 's' + s;
  return s;
}

import { z } from 'zod';
import type {
  BaseEntity,
  PersistedEntity,
  ValueObject,
  Tag,
} from './base.ts';
import type { EnvVar, ProbeSpec, ResourceRequirements } from '../../core/provider/types.ts';
import type { ContainerRestartPolicy } from '../../core/scheduler/backoff.ts';
import type { RegionId } from '../../core/region/types.ts';
import type { NetworkId } from '../../core/network/types.ts';
import type { InstanceId } from '../../core/region/instance.ts';

// ─── Brand types (CEA: Zod .brand(), no `as` assertions) ───

const sandboxIdSchema = z.string().min(1).brand('SandboxId');
const volumeIdSchema = z.string().min(1).brand('VolumeId');
const metricSnapshotIdSchema = z.string().min(1).brand('MetricSnapshotId');

export type SandboxId = z.infer<typeof sandboxIdSchema>;
export type VolumeId = z.infer<typeof volumeIdSchema>;
export type MetricSnapshotId = z.infer<typeof metricSnapshotIdSchema>;

export function createSandboxId(raw: string): SandboxId { return sandboxIdSchema.parse(raw); }
export function createVolumeId(raw: string): VolumeId { return volumeIdSchema.parse(raw); }
export function createMetricSnapshotId(raw: string): MetricSnapshotId { return metricSnapshotIdSchema.parse(raw); }

// ─── Sandbox state machine (ECI-aligned 11 states) ───

export enum SandboxStatus {
  /** Creating — being scheduled to underlying compute resources. */
  Scheduling = 'Scheduling',
  /** Scheduling failed — insufficient resources, invalid params, zone unavailable. */
  ScheduleFailed = 'ScheduleFailed',
  /** Starting — pulling images, initializing init/sidecar containers. */
  Pending = 'Pending',
  /** Running normally. */
  Running = 'Running',
  /** Soft terminal — containers exited successfully (exit 0). Can be restarted (GHA RerunRun analogy). */
  Succeeded = 'Succeeded',
  /** Soft terminal — containers failed. Can be restarted (GHA RerunFailedJobs analogy). */
  Failed = 'Failed',
  /** Being restarted via RestartContainerGroup. */
  Restarting = 'Restarting',
  /** Being updated via UpdateContainerGroup. */
  Updating = 'Updating',
  /** Being stopped/deleted via DeleteContainerGroup. */
  Terminating = 'Terminating',
  /** Expired — spot instance reclaimed or ActiveDeadlineSeconds exceeded. */
  Expired = 'Expired',
  /** Resource removed from the system. Terminal sink state. */
  Deleted = 'Deleted',
}

/**
 * Hard terminal states — truly irreversible.
 * GHA/K8s Job design: Succeeded and Failed are soft terminals (can be restarted,
 * analogous to GHA's RerunRun/RerunFailedJobs). Only infrastructure-level failures
 * (ScheduleFailed, Expired) and Deleted are hard terminals.
 */
export const TERMINAL_STATES: ReadonlySet<SandboxStatus> = new Set([
  SandboxStatus.ScheduleFailed,
  SandboxStatus.Expired,
  SandboxStatus.Deleted,
]);

/** States that can be deleted via DeleteContainerGroup.
 *  GHA/K8s Job design: Succeeded and Failed sandboxes can be deleted (cleanup). */
export const DELETABLE_STATES: ReadonlySet<SandboxStatus> = new Set([
  SandboxStatus.Running,
  SandboxStatus.Pending,
  SandboxStatus.Restarting,
  SandboxStatus.Updating,
  SandboxStatus.Succeeded,
  SandboxStatus.Failed,
]);

export const VALID_TRANSITIONS: Readonly<Record<SandboxStatus, readonly SandboxStatus[]>> = {
  // T1-T2: Scheduling outcomes — can also be deleted (ECI asyncInit: user cancels before Running)
  [SandboxStatus.Scheduling]: [SandboxStatus.Pending, SandboxStatus.ScheduleFailed, SandboxStatus.Terminating],
  // T3-T4, T18: Pending outcomes — delete goes through Terminating (async cleanup)
  [SandboxStatus.Pending]: [SandboxStatus.Running, SandboxStatus.Failed, SandboxStatus.Terminating],
  // T5-T10: Running outcomes — delete goes through Terminating (async cleanup)
  [SandboxStatus.Running]: [
    SandboxStatus.Succeeded, SandboxStatus.Failed, SandboxStatus.Expired,
    SandboxStatus.Restarting, SandboxStatus.Updating, SandboxStatus.Terminating,
  ],
  // T11-T12, T16: Restarting outcomes — delete goes through Terminating
  [SandboxStatus.Restarting]: [SandboxStatus.Pending, SandboxStatus.Failed, SandboxStatus.Terminating],
  // T13-T14, T17: Updating outcomes — delete goes through Terminating
  [SandboxStatus.Updating]: [SandboxStatus.Running, SandboxStatus.Terminating],
  // T15: Terminating outcome — cloud cleanup confirmed, resource released
  [SandboxStatus.Terminating]: [SandboxStatus.Deleted],
  // Hard terminal states (infrastructure) — no cloud resources, direct cleanup
  [SandboxStatus.ScheduleFailed]: [SandboxStatus.Deleted],
  [SandboxStatus.Expired]: [SandboxStatus.Deleted],
  [SandboxStatus.Deleted]: [],
  // Soft terminal states (GHA/K8s Job) — restartable, deletable via Terminating
  [SandboxStatus.Succeeded]: [SandboxStatus.Running, SandboxStatus.Terminating],
  [SandboxStatus.Failed]: [SandboxStatus.Running, SandboxStatus.Terminating],
};

export function isValidTransition(from: SandboxStatus, to: SandboxStatus): boolean {
  return VALID_TRANSITIONS[from]?.includes(to) ?? false;
}

export function isTerminal(status: SandboxStatus): boolean {
  return TERMINAL_STATES.has(status);
}

// ─── Volume state machine ───

export enum VolumeStatus {
  Detached = 'Detached',
  Attached = 'Attached',
  Orphaned = 'Orphaned',
}

// ─── Volume ───

export enum VolumeType {
  NFS = 'NFSVolume',
  HostPath = 'HostPathVolume',
  EmptyDir = 'EmptyDirVolume',
  /** Cloud disk (阿里云 Disk / 云盘) — persistent block storage, single-instance attach. */
  Disk = 'DiskVolume',
  /** Secret — inject sensitive data (e.g. passwords, tokens) as in-memory files via provider (podman secret / KMS). */
  Secret = 'SecretVolume',
  /** ConfigMap — inject non-sensitive configuration data as files. */
  ConfigMap = 'ConfigMapVolume',
  /** OSS (Object Storage Service) — mount cloud object storage as a filesystem. */
  OSS = 'OSSVolume',
}

export interface NFSVolumeConfig {
  readonly server: string;
  readonly path: string;
  readonly readOnly: boolean;
}

export interface DiskVolumeConfig {
  /** Cloud disk ID (e.g. Alibaba Cloud disk ID: d-xxxxxxxx). */
  readonly diskId: string;
  /** Filesystem type: 'ext4' | 'xfs'. */
  readonly fsType: string;
  /** Disk size in GiB (for auto-provision). */
  readonly sizeGiB?: number;
  /** Cloud disk category: cloud_efficiency | cloud_ssd | cloud_essd. */
  readonly diskCategory?: string | undefined;
  /** Whether the disk is read-only. */
  readonly readOnly: boolean;
  /** Whether to delete the disk when the instance is released. */
  readonly deleteWithInstance?: boolean;
}

export interface SecretVolumeConfig {
  /** Secret name (provider-resolved). */
  readonly name: string;
  /** Specific items to project as files. Omit to project all keys. */
  readonly items?: readonly { readonly key: string; readonly path: string; readonly mode?: number }[];
}

export interface ConfigMapVolumeConfig {
  /** ConfigMap name (provider-resolved). */
  readonly name: string;
  /** Specific items to project as files. Omit to project all keys. */
  readonly items?: readonly { readonly key: string; readonly path: string; readonly mode?: number }[];
}

export interface OSSVolumeConfig {
  /** OSS bucket name. */
  readonly bucket: string;
  /** Path within the bucket (prefix). */
  readonly path?: string | undefined;
  /** Whether the mount is read-only. */
  readonly readOnly?: boolean | undefined;
  /** Custom OSS endpoint for VPC access. */
  readonly endpoint?: string | undefined;
}

/** Volume entity — bound to a ComputeInstance (spatial locality). */
export interface Volume extends BaseEntity<VolumeId, VolumeStatus> {
  readonly type: VolumeType;
  /** The compute instance this volume is bound to. Required — volumes do not exist outside an instance. */
  readonly instanceId: string;
  /** Reference a named Credential (from CredentialService) for external auth — NFS Kerberos, OSS AK/SK, etc. */
  readonly credentialRef?: string;
  readonly nfs?: NFSVolumeConfig;
  readonly disk?: DiskVolumeConfig;
  readonly secret?: SecretVolumeConfig;
  readonly configMap?: ConfigMapVolumeConfig;
  readonly oss?: OSSVolumeConfig;
}

// ─── VolumeMount ───

export interface VolumeMount {
  readonly volumeId: VolumeId;
  readonly mountPath: string;
  readonly readOnly: boolean;
  readonly mountPropagation?: string;
  /** Named credential reference for external auth (e.g. NFS Kerberos, OSS AK/SK). */
  readonly credentialRef?: string | undefined;
}

// ─── Container ───

export interface ContainerConfig {
  readonly name: string;
  readonly image: string;
  readonly command?: readonly string[];
  readonly args?: readonly string[];
  readonly env?: readonly EnvVar[];
  readonly tty?: boolean;
  readonly stdin?: boolean;
  readonly imagePullPolicy?: 'Always' | 'IfNotPresent' | 'Never';
  readonly resources?: ResourceRequirements;
  readonly volumeMounts?: readonly VolumeMount[];
  readonly ports?: readonly {
    readonly containerPort: number;
    readonly hostPort?: number | undefined;
    readonly protocol?: string | undefined;
  }[] | undefined;
  readonly livenessProbe?: ProbeSpec | undefined;
  readonly readinessProbe?: ProbeSpec | undefined;
  readonly startupProbe?: ProbeSpec | undefined;
  /** Per-container restart rules (K8s v1.34 Alpha). Overwrites pod-level restartPolicy. */
  readonly containerRestartPolicy?: ContainerRestartPolicy;
  /** Network mode: 'bridge' | 'host' | 'none' | 'container:<name|id>'. */
  readonly networkMode?: string | undefined;
  readonly providerOverrides?: Record<string, unknown>;
}

/** Init containers — run to completion before main containers start. */
export interface InitContainerConfig extends ContainerConfig {
  readonly restartPolicy?: 'Always' | 'OnFailure' | 'Never';
}

/** Container-level status — mirrors K8s container states. */
export enum ContainerStatus {
  Waiting = 'Waiting',
  Running = 'Running',
  Terminated = 'Terminated',
}

export interface ContainerState {
  readonly state: ContainerStatus;
  readonly startTime?: string;
  readonly finishedTime?: string;
  readonly ready: boolean;
  readonly restartCount: number;
  readonly message?: string;
  /** Set when state=Terminated */
  readonly exitCode?: number;
  /** Set when state=Terminated — Completed | Error | OOMKilled | ... */
  readonly reason?: string;
  /** Set when state=Terminated — signal number if killed by signal */
  readonly signal?: number;
}

export interface ContainerRuntime {
  readonly name: string;
  readonly image: string;
  readonly cpu: number;
  readonly memory: number;
  readonly state: ContainerState;
  readonly volumeMounts: readonly VolumeMount[];
  readonly health?: {
    readonly status: string;
    readonly lastCheckedAt?: string | undefined;
    readonly message?: string | undefined;
  } | undefined;
}

// ─── Network ───

export interface NetworkInfo {
  readonly publicIp?: string;
  readonly privateIp?: string;
  readonly ipAddress?: string;   // 用户指定的固定 IP（来自 subnet）
  readonly vpcId?: string;
  readonly subnetId?: string;
  readonly securityGroupId?: string;
  readonly eniId?: string;
}

// ─── Event (value object) ───

export interface ContainerEvent extends ValueObject {
  readonly reason: string;
  readonly type: 'Normal' | 'Warning';
  readonly message: string;
  readonly count: number;
  readonly lastTimestamp?: string;
}

// ─── Spot / preemptible ───

export enum SpotStrategy {
  None = 'None',
  SpotAsPriceGo = 'SpotAsPriceGo',
  SpotWithPriceLimit = 'SpotWithPriceLimit',
}

// ─── Resource spec ───

export interface ResourceSpec {
  readonly cpu: number;
  readonly memory: number;
  readonly gpu?: number | undefined;
  readonly gpuType?: string | undefined;
  readonly requests?: ResourceRequirements['requests'] | undefined;
  readonly limits?: ResourceRequirements['limits'] | undefined;
}

// ─── Pod condition ───

export type ConditionStatus = 'True' | 'False' | 'Unknown';

export interface PodCondition {
  readonly type: 'PodScheduled' | 'Initialized' | 'ContainersReady' | 'Ready';
  readonly status: ConditionStatus;
  readonly lastTransitionTime?: string;
  readonly reason?: string;
  readonly message?: string;
}

// ─── Network config (input) ───

export interface ProviderIdentity {
  /** Provider platform: 'podman' | 'alibaba' | 'aws' | 'stub' */
  readonly platform: string;
  /** ComputeInstance ID used for credential resolution */
  readonly instanceId?: string;
  /** Instance region (for ECI/OSS API calls) */
  readonly region?: string;
  /** Instance zone (for multi-AZ) */
  readonly zoneId?: string;
  /** Credential reference used at creation time */
  readonly credentialRef?: string;
}

export interface SandboxNetworkConfig {
  /** 引用 VirtualNetwork，继承其安全组和规则 */
  readonly networkId?: NetworkId | undefined;
  /** 引用 ComputeCluster，继承其 zone/networkDomain */
  readonly instanceId?: InstanceId | undefined;
  readonly subnetIds?: readonly string[] | undefined;
  readonly ipAddress?: string | undefined;   // 手动指定固定 IP（不设则由系统自动分配）
  readonly securityGroupId?: string | undefined;
  readonly allocatePublicIp: boolean;
  readonly publicIpBandwidth?: number | undefined;
  /** 带宽控制（Mbps），由系统自动从 SecurityGroup 继承 */
  readonly bandwidth?: {
    readonly egress?: number | undefined;
    readonly ingress?: number | undefined;
    readonly burst?: number | undefined;
    readonly priority?: number | undefined;
  } | undefined;
}

// ─── Sandbox ───

export interface CreateSandboxInput {
  readonly name: string;
  readonly description?: string;
  readonly region: RegionId;
  readonly instanceId?: InstanceId | undefined;
  /** Zone ID for provider scheduling (e.g. cn-hangzhou-a). Set by assembly pipeline. */
  readonly zoneId?: string | undefined;
  readonly resourceSpec: ResourceSpec;
  // spotStrategy moved to providerOverrides.alibaba — it's provider-specific.
  readonly restartPolicy: 'Always' | 'OnFailure' | 'Never';
  readonly initContainers?: readonly InitContainerConfig[];
  readonly containers: readonly ContainerConfig[];
  readonly volumes?: readonly Volume[];
  /** S3 存储桶挂载引用。由 template applicator 填充，用于自动生成访问密钥等。 */
  readonly bucketMounts?: readonly {
    readonly bucketId: string;
    readonly bucket: string;
    readonly endpoint: string;
    readonly region: string;
    readonly autoGenerateKeys?: boolean | undefined;
    readonly mountPath: string;
  }[];
  readonly network: SandboxNetworkConfig;
  readonly tags?: readonly Tag[];
  readonly account?: string | undefined;
  /** Max consecutive health check failures before auto-terminate. -1 = never terminate. */
  readonly healthMaxRetries?: number | undefined;
  /** User who created this sandbox. */
  readonly creatorId?: string | undefined;
  readonly providerOverrides?: Record<string, unknown>;
  /** Template ID that created this sandbox. Used for instance limit tracking (decoupled from sandbox name). */
  readonly templateRef?: string | undefined;
  /** API version of the template that created this sandbox ("hbi-aad/v1" or "hbi-aad/v2"). */
  readonly apiVersion?: string | undefined;
}

/** Full sandbox entity. Extends PersistedEntity for optimistic-concurrency state mutations. */
export interface Sandbox extends PersistedEntity<SandboxId, SandboxStatus> {
  readonly config: CreateSandboxInput;
  readonly podUid?: string;        // Kubernetes Pod UID
  readonly providerId?: string;    // Cloud provider instance ID
  readonly network: NetworkInfo;
  readonly containers: readonly ContainerRuntime[];
  readonly conditions?: readonly PodCondition[];
  readonly events: readonly ContainerEvent[];
  /** Ephemeral storage allocated by the cloud provider (GiB).
   *  ECI provides 30 GiB free. Populated from provider during syncRuntime. */
  readonly ephemeralStorageGiB?: number | undefined;
}

// ─── Pod ↔ Sandbox ↔ Provider mapping ───

export interface PodMapping {
  readonly podUid: string;
  readonly sandboxId: SandboxId;
  readonly providerId?: string;
  readonly createdAt: number;
  readonly updatedAt: number;
}

import { Hono } from 'hono';
import type { ISubnetService } from './service.ts';
import type { AppContext } from '../../core/deps.ts';
import { ok, fail } from '../../core/response.ts';
import type { RouteMeta } from '../../core/http-docs/types.ts';
import type { CreateSubnetInput, UpdateSubnetInput } from './types.ts';
import type { CrudHandlerMap } from '../../core/crud/router.ts';
import { registerCrudRoutes } from '../../core/crud/router.ts';

export function createSubnetRouter(svc: ISubnetService): Hono<{ Variables: AppContext }> {
  const router = new Hono<{ Variables: AppContext }>();

  const crud: CrudHandlerMap = {
    list: (r) => r.get('/', async (c) => {
      const page = parseInt(c.req.query('page') ?? '') || 1;
      const limit = parseInt(c.req.query('limit') ?? '') || 20;
      const name = c.req.query('name');
      const result = await svc.list(page, limit, name);
      return c.json(ok(result));
    }),

    create: (r) => r.post('/', async (c) => {
      try {
        const body = await c.req.json<CreateSubnetInput>();
        if (!body.name || !body.cidr || body.subnetPrefix === undefined || !body.instanceId) {
          return c.json(fail('VALIDATION_ERROR', 'name, cidr, subnetPrefix, and instanceId are required'), 400);
        }
        const actorId = c.var?.currentUser?.id;
        const subnet = await svc.create(body, actorId);
        return c.json(ok(subnet), 201);
      } catch (e: any) {
        return c.json(fail('CREATE_FAILED', e.message), 400);
      }
    }),

    get: (r) => r.get('/:id', async (c) => {
      const id = c.req.param('id') as any;
      const subnet = await svc.get(id);
      if (!subnet) return c.json(fail('NOT_FOUND', 'Subnet not found'), 404);
      return c.json(ok(subnet));
    }),

    update: (r) => r.put('/:id', async (c) => {
      try {
        const id = c.req.param('id') as any;
        const body = await c.req.json<UpdateSubnetInput>();
        const actorId = c.var?.currentUser?.id;
        const subnet = await svc.update(id, body, actorId);
        return c.json(ok(subnet));
      } catch (e: any) {
        return c.json(fail('UPDATE_FAILED', e.message), e.status ?? 400);
      }
    }),

    delete: (r) => r.delete('/:id', async (c) => {
      try {
        const id = c.req.param('id') as any;
        const actorId = c.var?.currentUser?.id;
        await svc.delete(id, actorId);
        return c.json(ok(null));
      } catch (e: any) {
        return c.json(fail('DELETE_FAILED', e.message), e.status ?? 400);
      }
    }),
  };

  return registerCrudRoutes(router, crud);
}

export const subnetRouteMeta: RouteMeta[] = [
  { method: 'GET', path: '/', description: '列出子网（分页）', responseDescription: '{ items: Subnet[], total, page, limit }' },
  { method: 'POST', path: '/', description: '创建子网', requestBody: { name: 'my-subnet', cidr: '10.2.0.0/16', subnetPrefix: 24, instanceId: 'inst_xxx' }, responseDescription: 'Subnet' },
  { method: 'GET', path: '/:id', description: '获取子网详情', responseDescription: 'Subnet' },
  { method: 'PUT', path: '/:id', description: '更新子网', responseDescription: 'Subnet' },
  { method: 'DELETE', path: '/:id', description: '删除子网', responseDescription: '{ ok: true }' },
];

import type { Hono } from 'hono';
import type { IAtomicStore } from '../../core/store/interfaces.ts';
import type { IAuditWriter } from '../../core/audit/types.ts';
import { ConsoleLogger } from '../../core/audit/console-logger.ts';
import { SubnetService } from './service.ts';
import { createSubnetRouter } from './handler.ts';
import { InstanceService } from '../../core/region/instance.ts';

/** Narrow dependency contract — only what this feature actually uses. */
export interface SubnetDeps {
  stores: { atomic: IAtomicStore };
  audit?: IAuditWriter;
}

export function createRouter(deps: SubnetDeps): Hono<any> {
  const instanceSvc = new InstanceService(deps.stores.atomic);
  const svc = new SubnetService(deps.stores.atomic, new ConsoleLogger(), deps.audit, instanceSvc);
  return createSubnetRouter(svc);
}

import type { IAtomicStore } from '../../core/store/interfaces.ts';
import { createFacility } from '../../core/brand.ts';
import { AppError } from '../../core/types.ts';
import { KernLevel } from '../../core/audit/kern-level.ts';
import { parseCidr } from '../../core/network/cidr.ts';
import type { InstanceService } from '../../core/region/instance.ts';
import type { Subnet, SubnetId, CreateSubnetInput, UpdateSubnetInput } from './types.ts';
import { generateSubnetId } from './types.ts';
import type { ICrudService, PaginatedResult } from '../../core/crud/index.ts';

const FACILITY = createFacility('subnet');
const PREFIX = 'subnet:';
const INDEX_KEY = 'subnet:ids';

export interface ISubnetService extends ICrudService<Subnet, CreateSubnetInput, UpdateSubnetInput, SubnetId> {
  create(input: CreateSubnetInput, actorId?: string): Promise<Subnet>;
  list(page?: number, limit?: number, name?: string): Promise<PaginatedResult<Subnet>>;
  get(id: SubnetId): Promise<Subnet | null>;
  update(id: SubnetId, input: UpdateSubnetInput, actorId?: string): Promise<Subnet>;
  delete(id: SubnetId, actorId?: string): Promise<void>;
}

export class SubnetService implements ISubnetService {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly logger: IAuditWriter,
    private readonly audit?: IAuditWriter,
    private readonly instanceSvc?: InstanceService,
  ) {}

  public async create(input: CreateSubnetInput, actorId?: string): Promise<Subnet> {
    try { parseCidr(input.cidr); } catch { throw new AppError(400, 'INVALID_CIDR', `Invalid CIDR: ${input.cidr}`); }

    const inst = this.instanceSvc ? await this.instanceSvc.get(input.instanceId) : null;
    if (!inst) throw new AppError(400, 'INSTANCE_NOT_FOUND', `ComputeInstance ${input.instanceId} not found`);

    const id = generateSubnetId();
    const now = Date.now();

    const subnet: Subnet = {
      id, name: input.name, description: input.description,
      cidr: input.cidr, subnetPrefix: input.subnetPrefix,
      instanceId: input.instanceId, provider: inst.platform, region: inst.region,
      visibility: input.visibility ?? 'private', creatorId: actorId,
      userIds: input.userIds ?? [], userGroupIds: input.userGroupIds ?? [],
      status: 'Active', createdAt: now, updatedAt: now,
    };

    await this.atomic.set(PREFIX + id, subnet, null);
    await this.#addToIndex(id);

    await this.logger.write({ facility: FACILITY, level: KernLevel.INFO, message: `Subnet created: ${input.name} (${input.cidr})`, actorId: actorId });
    this.audit?.write({ level: KernLevel.NOTICE, facility: FACILITY, message: `Subnet created — ${input.name} (${input.cidr})`, actorId, metadata: { eventType: 'subnet.created' } });

    return subnet;
  }

  public async list(page = 1, limit = 20, name?: string): Promise<PaginatedResult<Subnet>> {
    let all = (await this.#listAll()).reverse();
    if (name) all = all.filter(s => s.name.toLowerCase().includes(name.toLowerCase()));
    const total = all.length;
    const start = (page - 1) * limit;
    return { items: all.slice(start, start + limit), total, page, limit };
  }

  public async get(id: SubnetId): Promise<Subnet | null> {
    const entry = await this.atomic.get<Subnet>(PREFIX + id);
    return entry?.value ?? null;
  }

  public async update(id: SubnetId, input: UpdateSubnetInput, _actorId?: string): Promise<Subnet> {
    const entry = await this.atomic.get<Subnet>(PREFIX + id);
    if (!entry) throw new AppError(404, 'SUBNET_NOT_FOUND', 'Subnet not found');

    const updated: Subnet = {
      ...entry.value,
      ...(input.name !== undefined ? { name: input.name } : {}),
      ...(input.description !== undefined ? { description: input.description ?? undefined } : {}),
      ...(input.cidr !== undefined ? { cidr: input.cidr } : {}),
      ...(input.subnetPrefix !== undefined ? { subnetPrefix: input.subnetPrefix } : {}),
      ...(input.visibility !== undefined ? { visibility: input.visibility } : {}),
      ...(input.userIds !== undefined ? { userIds: input.userIds ?? [] } : {}),
      ...(input.userGroupIds !== undefined ? { userGroupIds: input.userGroupIds ?? [] } : {}),
      ...(input.status !== undefined ? { status: input.status } : {}),
      updatedAt: Date.now(),
    };

    const newVersion = await this.atomic.set(PREFIX + id, updated, entry.version);
    if (!newVersion) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');
    return updated;
  }

  public async delete(id: SubnetId, actorId?: string): Promise<void> {
    const entry = await this.atomic.get<Subnet>(PREFIX + id);
    if (!entry) throw new AppError(404, 'SUBNET_NOT_FOUND', 'Subnet not found');
    await this.atomic.set(PREFIX + id, null, entry.version);
    await this.#removeFromIndex(id);
    this.audit?.write({ level: KernLevel.WARNING, facility: FACILITY, message: `Subnet deleted — ${entry.value.name}`, actorId, metadata: { eventType: 'subnet.deleted' } });
  }

  async #listAll(): Promise<Subnet[]> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return [];
    const entries = await Promise.all(idx.value.map(id => this.atomic.get<Subnet>(PREFIX + id)));
    return entries.filter(e => e).map(e => e!.value);
  }
  async #addToIndex(id: SubnetId): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    await this.atomic.set(INDEX_KEY, [...(idx?.value ?? []), id], idx?.version ?? null);
  }
  async #removeFromIndex(id: SubnetId): Promise<void> {
    const idx = await this.atomic.get<string[]>(INDEX_KEY);
    if (!idx) return;
    await this.atomic.set(INDEX_KEY, idx.value.filter((i: string) => i !== id), idx.version);
  }
}

import type { InstanceId } from '../../core/region/instance.ts';

declare const SUBNET_ID_BRAND: unique symbol;
export type SubnetId = string & { readonly [SUBNET_ID_BRAND]: true };

export function generateSubnetId(): SubnetId {
  return `sub_${crypto.randomUUID()}` as SubnetId;
}

export type SubnetStatus = 'Active' | 'Inactive' | 'Full' | 'Error';

/** 子网实体 — 平台无关的 IP 段管理。
 *  通过绑定 ComputeInstance 自动继承 provider/region。 */
export interface Subnet {
  readonly id: SubnetId;
  readonly name: string;
  readonly description?: string | undefined;

  // ── 子网配置 ──
  /** CIDR 超网，如 "10.2.0.0/16" */
  readonly cidr: string;
  /** 子网前缀长度，如 24 表示 /24 子网 */
  readonly subnetPrefix: number;

  // ── 绑定 ──
  readonly instanceId: InstanceId;
  readonly provider: string;
  readonly region: string;

  // ── Provider 侧资源 ID ──
  readonly providerSubnetId?: string | undefined;

  // ── 访问控制 ──
  readonly visibility: 'public' | 'private';
  readonly creatorId?: string | undefined;
  readonly userIds?: readonly string[] | undefined;
  readonly userGroupIds?: readonly string[] | undefined;

  // ── 状态 ──
  readonly status: SubnetStatus;
  readonly createdAt: number;
  readonly updatedAt: number;
}

export interface CreateSubnetInput {
  name: string;
  description?: string | undefined;
  cidr: string;
  subnetPrefix: number;
  instanceId: InstanceId;
  visibility?: 'public' | 'private' | undefined;
  userIds?: string[] | undefined;
  userGroupIds?: string[] | undefined;
}

export interface UpdateSubnetInput {
  name?: string | undefined;
  description?: string | null | undefined;
  cidr?: string | undefined;
  subnetPrefix?: number | undefined;
  visibility?: 'public' | 'private' | undefined;
  userIds?: string[] | null | undefined;
  userGroupIds?: string[] | null | undefined;
  status?: SubnetStatus | undefined;
}

import { Hono } from 'hono';
import type { Context } from 'hono';
import type { ISysGroupService } from './service.ts';
import type { AppContext } from "../../core/deps.ts";
import { CreateSysGroupSchema, UpdateSysGroupSchema } from './schema.ts';
import { ok, fail } from '../../core/response.ts';
import type { RouteMeta } from '../../core/http-docs/types.ts';
import type { CrudHandlerMap } from '../../core/crud/router.ts';
import { registerCrudRoutes } from '../../core/crud/router.ts';

function requireRoot(c: Context<{ Variables: AppContext }>): Response | null {
  const user = c.var?.currentUser;
  if (!user) return null;
  const isRoot = user.role === 'root' || user.role === 'Operator' || user.role === 'wheel';
  if (!isRoot) return c.json(fail('FORBIDDEN', 'Admin access required'), 403);
  return null;
}

export function createSysGroupRouter(svc: ISysGroupService): Hono<any> {
  const router = new Hono<any>();

  const crud: CrudHandlerMap = {
    create: (r) => r.post('/', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      const body: unknown = await c.req.json();
      const parsed = CreateSysGroupSchema.safeParse(body);
      if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      const group = await svc.create(parsed.data, c.var?.currentUser?.id);
      return c.json(ok(group), 201);
    }),

    list: (r) => r.get('/', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      const page = parseInt(c.req.query('page') ?? '') || 1;
      const limit = parseInt(c.req.query('limit') ?? '') || 50;
      const name = c.req.query('name');
      const { items, total } = await svc.listPaginated(page, limit, name);
      return c.json(ok({ items, total, page, limit }));
    }),

    get: (r) => r.get('/:id', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      const group = await svc.get(c.req.param('id'));
      if (!group) return c.json(fail('SYSGROUP_NOT_FOUND', 'System group not found'), 404);
      return c.json(ok(group));
    }),

    update: (r) => r.put('/:id', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      const body: unknown = await c.req.json();
      const parsed = UpdateSysGroupSchema.safeParse(body);
      if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      return c.json(ok(await svc.update(c.req.param('id'), parsed.data, c.var?.currentUser?.id)));
    }),

    delete: (r) => r.delete('/:id', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      await svc.delete(c.req.param('id'), c.var?.currentUser?.id);
      return c.json(ok(null));
    }),
  };

  return registerCrudRoutes(router, crud);
}

