  validateToken(token: SessionToken): Promise<User | null>;
  clearLoginPolicy(id: UserId, actorId?: string): Promise<User>;
  clearPublicKey(id: UserId, actorId?: string): Promise<User>;
  getLoginInfo(email: string): Promise<LoginInfo>;
  /** Bust the KV cache for a user and fetch fresh from authoritative store. */
  refresh(id: UserId): Promise<User | null>;

  /** List active session tokens for a user. */
  listSessions(userId: UserId): Promise<readonly SessionToken[]>;

  /** Revoke a specific session token. No-op if already revoked. */
  revokeSession(token: SessionToken, actorId?: string): Promise<void>;

  /** Supplementary group management — RHEL §1 supp_groups. */
  addSupplementaryGroup(userId: UserId, gid: Gid, actorId?: string): Promise<User>;
  removeSupplementaryGroup(userId: UserId, gid: Gid, actorId?: string): Promise<User>;
  listSupplementaryGroups(userId: UserId): Promise<Gid[]>;
}

export class UserService implements IUserService {
  public constructor(
    private readonly atomic: IAtomicStore,
    private readonly logger: IAuditWriter,
    private readonly audit?: IAuditWriter,
  ) {}

  async #transactWithRetry<T>(fn: (txn: IStoreTransaction) => Promise<T>, maxRetries = 3): Promise<T> {
    for (let attempt = 0; attempt < maxRetries; attempt++) {
      try {
        return await this.atomic.transact(fn);
      } catch (err) {
        if (err instanceof TransactConflictError && attempt < maxRetries - 1) continue;
        throw err;
      }
    }
    throw new AppError(409, 'CONFLICT', 'Transaction failed after retries');
  }

  public async register(input: RegisterInput): Promise<{ user: User; token: SessionToken }> {
    const id = generateUserId();
    const uid = await this.#nextUid();
    const passwordHash = await hashPassword(input.password);
    this.logger.write({ facility: FACILITY, level: KernLevel.INFO, message: `PBKDF2 hash: ${lastPerf().toFixed(1)}ms`, metadata: { operation: 'hash', duration: lastPerf() } });
    const now = Date.now();

    const user: User = {
      id,
      email: input.email,
      passwordHash,
      name: input.name,
      role: input.role,
      uid,
      gid: createGid(GID_MIN), // default primary group = "users"
      gecos: input.name,
      directory: `${DEFAULT_HOME_PREFIX}${input.email}`,
      shell: DEFAULT_SHELL,
      supplementaryGids: [],
      createdAt: now,
      updatedAt: now,
    };

    // Atomically: write user + email index (uniqueness) + user ID index + UID index
    await this.#transactWithRetry(async (txn) => {
      const emailEntry = await txn.get<any>(EMAIL_INDEX_PREFIX + input.email);
      if (emailEntry) throw new AppError(409, 'EMAIL_EXISTS', 'Email already registered');
      const shardKey = USER_IDS_SHARD_PREFIX + String(shardIndex(id));
      const idx = await txn.get<string[]>(shardKey);
      txn.set(shardKey, [...(idx ?? []), id]);
      txn.set(USER_PREFIX + id, user);
      txn.set(EMAIL_INDEX_PREFIX + input.email, user);
      txn.set(UID_INDEX_PREFIX + uid, id);
    });

    // Best-effort counter update (outside transaction to avoid cross-shard contention)
    await this.#incrCounter().catch(() => { /* noop */ });

    // Create session token (separate — 'session' prefix maps to different DO shard)
    const token = await this.createSession(id);

    // Auto-join "users" group (Linux-style default group)
    await this.#joinDefaultGroup(id);

    // Root users also join the "root" and "wheel" groups for full admin access
    if (input.role === UserRole.Root) {
      await this.#joinNamedGroup(id, 'root');
      await this.#joinNamedGroup(id, 'wheel');
      // Belt-and-suspenders: direct capability bits in case group caps are stale
      await this.atomic.set(USER_CAP_KEY + id, Cap.ALL, null);
    }

    await this.logger.write({
      facility: FACILITY,
      level: KernLevel.INFO,
      message: 'User registered',
      metadata: { userId: id, email: input.email, role: input.role, uid },
    });

    await this.audit?.write({
      level: KernLevel.NOTICE,
      facility: FACILITY,
      message: `User registered — ${input.email} (role=${input.role}, uid=${String(uid)})`,
    });

    return { user, token };
  }

  public async login(input: LoginInput, ctx?: LoginContext): Promise<{ user: User; token: SessionToken }> {
    const email = input.email;
    const ip = ctx?.ip;

    // ─── Throttle check ───
    await checkThrottle(this.atomic, email, ip);

    // ─── Credentials ───
    const entry = await this.atomic.get<User>(EMAIL_INDEX_PREFIX + email);
    if (!entry) {
      await recordAttempt(this.atomic, email, false, ip);
      throw new AppError(401, 'INVALID_CREDENTIALS', 'Invalid email or password');
    }

    const user = entry.value;
    const valid = await serialisedHash(() => verifyPassword(input.password, user.passwordHash));
    this.logger.write({ facility: FACILITY, level: KernLevel.INFO, message: `PBKDF2 verify: ${lastPerf().toFixed(1)}ms`, metadata: { operation: 'verify', duration: lastPerf() } });
    if (!valid) {
      await recordAttempt(this.atomic, email, false, ip);
      throw new AppError(401, 'INVALID_CREDENTIALS', 'Invalid email or password');
    }

    // ─── Login policy check ───
    const policy = user.loginPolicy;
    if (policy) {
      if (!policy.enabled) {
        await recordAttempt(this.atomic, email, false, ip);
        throw new AppError(403, 'LOGIN_DISABLED', 'Login disabled for this account');
      }
      if (policy.passwordLoginDisabled) {
        await recordAttempt(this.atomic, email, false, ip);
        throw new AppError(403, 'PASSWORD_LOGIN_DISABLED', 'Password login disabled for this account — use key-based authentication');
      }
      if (policy.timeRanges.length) {
        const now = new Date();
        const mm = String(now.getUTCMinutes()).padStart(2, '0');
        const hh = String(now.getUTCHours()).padStart(2, '0');
        const current = `${hh}:${mm}`;
        const inRange = policy.timeRanges.some(r => current >= r.start && current <= r.end);
        if (!inRange) {
          await recordAttempt(this.atomic, email, false, ip);
          throw new AppError(403, 'LOGIN_TIME_RESTRICTED', 'Login not allowed at this time');
        }
      }
      if (policy.allowedCIDRs.length && ip) {
        const clientIp: string = ip;
        const allowed = policy.allowedCIDRs.some(cidr => ipInCIDR(clientIp, cidr));
        if (!allowed) {
          await recordAttempt(this.atomic, email, false, ip);
          throw new AppError(403, 'LOGIN_IP_RESTRICTED', 'Login not allowed from this IP');
        }
      }
    }

    const token = await this.createSession(user.id);
    await recordAttempt(this.atomic, email, true, ip);

    await this.logger.write({
      facility: FACILITY,
      level: KernLevel.INFO,
      message: 'User logged in',
      metadata: { userId: user.id, email, ip },
    });

    await this.audit?.write({
      level: KernLevel.NOTICE,
      facility: FACILITY,
      message: `User logged in — ${email}${ip ? ` from ${ip}` : ''}`,
    });

    return { user, token };
  }

  public async loginNoPassword(input: NoPasswordLoginInput, ctx?: LoginContext): Promise<{ user: User; token: SessionToken }> {
    const email = input.email;
    const ip = ctx?.ip;

    // ─── Throttle ───
    await checkThrottle(this.atomic, email, ip);

    // Decode one-time key: signature_b64url.timestamp_b64url.nonce_b64url
    const parts = input.oneTimeKey.split('.');
    if (parts.length !== 3) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(400, 'BAD_KEY_FORMAT', 'Invalid one-time key format'); }
    const sigB64 = parts[0];
    const tsB64 = parts[1];
    const nonceB64 = parts[2];
    if (!sigB64 || !tsB64 || !nonceB64) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(400, 'BAD_KEY_FORMAT', 'Empty component in one-time key'); }

    // Check timestamp window (±30s)
    let ts: number;
    try {
      ts = parseInt(atob(tsB64.replace(/-/g, '+').replace(/_/g, '/')), 10);
    } catch {
      await recordAttempt(this.atomic, email, false, ip); throw new AppError(400, 'BAD_TIMESTAMP', 'Invalid timestamp encoding');
    }
    if (isNaN(ts)) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(400, 'BAD_TIMESTAMP', 'Invalid timestamp'); }
    const skew = Date.now() - ts * 1000;
    if (Math.abs(skew) > 30_000) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(403, 'KEY_EXPIRED', 'One-time key expired'); }

    // Check nonce replay
    if (!await checkNonce(this.atomic, email, nonceB64)) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(403, 'REPLAY_DETECTED', 'One-time key already used'); }

    // Fetch user by email
    const entry = await this.atomic.get<User>(EMAIL_INDEX_PREFIX + input.email);
    if (!entry) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(401, 'INVALID_CREDENTIALS', 'Invalid email or one-time key'); }
    const user = entry.value;

    // Login policy check
    const policy = user.loginPolicy;
    if (policy) {
      if (!policy.enabled) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(403, 'LOGIN_DISABLED', 'Login disabled for this account'); }
      if (policy.timeRanges.length) {
        const now = new Date();
        const mm = String(now.getUTCMinutes()).padStart(2, '0');
        const hh = String(now.getUTCHours()).padStart(2, '0');
        const current = `${hh}:${mm}`;
        const inRange = policy.timeRanges.some(r => current >= r.start && current <= r.end);
        if (!inRange) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(403, 'LOGIN_TIME_RESTRICTED', 'Login not allowed at this time'); }
      }
      if (policy.allowedCIDRs.length && ctx?.ip) {
        const clientIp: string = ctx.ip;
        const allowed = policy.allowedCIDRs.some(cidr => ipInCIDR(clientIp, cidr));
        if (!allowed) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(403, 'LOGIN_IP_RESTRICTED', 'Login not allowed from this IP'); }
      }
    }

    // Verify public key exists
    const pubKeyB64 = user.publicKeyEd25519;
    if (!pubKeyB64) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(403, 'NO_PUBLIC_KEY', 'No public key configured for this account'); }

    // Verify Ed25519 signature
    let nonceBytes: ReturnType<typeof base64UrlDecode>;
    let signature: ReturnType<typeof base64UrlDecode>;
    try {
      nonceBytes = base64UrlDecode(nonceB64);
      signature = base64UrlDecode(sigB64);
    } catch {
      await recordAttempt(this.atomic, email, false, ip); throw new AppError(400, 'BAD_KEY_FORMAT', 'Invalid base64 encoding in one-time key');
    }
    const message = new Uint8Array(new TextEncoder().encode(`${String(ts)}${input.email}${ctx?.siteContext ?? ''}`));
    const pkRaw = atob(pubKeyB64);
    const publicKeyBytes = new Uint8Array(pkRaw.length);
    for (let i = 0; i < pkRaw.length; i++) publicKeyBytes[i] = pkRaw.charCodeAt(i);

    let valid: boolean;
    try {
      const key = await crypto.subtle.importKey('raw', publicKeyBytes, { name: 'Ed25519' }, false, ['verify']);
      const signedData = new Uint8Array(message.length + nonceBytes.length);
      signedData.set(message, 0);
      signedData.set(nonceBytes, message.length);
      valid = await crypto.subtle.verify({ name: 'Ed25519' }, key, signature, signedData);
    } catch {
      await recordAttempt(this.atomic, email, false, ip);
      throw new AppError(500, 'VERIFY_FAILED', 'Signature verification failed');
    }
    if (!valid) { await recordAttempt(this.atomic, email, false, ip); throw new AppError(403, 'BAD_SIGNATURE', 'Invalid signature'); }

    // Success
    const token = await this.createSession(user.id);
    await recordAttempt(this.atomic, input.email, true, ctx?.ip);

    await this.logger.write({
      facility: FACILITY,
      level: KernLevel.INFO,
      message: 'User logged in (no-password)',
      metadata: { userId: user.id, email: user.email, ip: ctx?.ip },
    });

    await this.audit?.write({
      level: KernLevel.NOTICE,
      facility: FACILITY,
      message: `User logged in (no-password) — ${user.email}${ctx?.ip ? ` from ${ctx.ip}` : ''}`,
    });

    return { user, token };
  }

  public async getById(id: UserId): Promise<User | null> {
    const entry = await this.atomic.get<User>(USER_PREFIX + id);
    if (!entry) return null;
    return normalizeUser(entry.value);
  }

  public async getByUid(uid: Uid): Promise<User | null> {
    const idEntry = await this.atomic.get<string>(UID_INDEX_PREFIX + uid);
    if (!idEntry) return null;
    return this.getById(createUserId(idEntry.value));
  }

  public async refresh(id: UserId): Promise<User | null> {
    // Evict KV cache → next getById() misses cache and re-fetches from DO
    await this.atomic.invalidateCache?.(USER_PREFIX + id);
    return this.getById(id);
  }

  public async update(id: UserId, input: UpdateUserInput, actorId?: string): Promise<User> {
    const entry = await this.atomic.get<User>(USER_PREFIX + id);
    if (!entry) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');
    const existing = normalizeUser(entry.value);

    const updated: User = {
      ...existing,
      ...(input.name !== undefined ? { name: input.name } : {}),
      ...(input.role !== undefined ? { role: input.role } : {}),
      ...(input.password !== undefined ? { passwordHash: await hashPassword(input.password) } : {}),
      ...(input.loginPolicy !== undefined ? { loginPolicy: input.loginPolicy } : {}),
      ...(input.publicKeyEd25519 !== undefined ? { publicKeyEd25519: input.publicKeyEd25519 } : {}),
      ...(input.gecos !== undefined ? { gecos: input.gecos } : {}),
      ...(input.directory !== undefined ? { directory: input.directory } : {}),
      ...(input.shell !== undefined ? { shell: input.shell } : {}),
      ...(input.supplementaryGids !== undefined ? { supplementaryGids: input.supplementaryGids.map(n => createGid(n)) } : {}),
      updatedAt: Date.now(),
    };

    if (input.password !== undefined) {
      this.logger.write({ facility: FACILITY, level: KernLevel.INFO, message: `PBKDF2 hash: ${lastPerf().toFixed(1)}ms`, metadata: { operation: 'hash', duration: lastPerf() } });
    }

    const newVersion = await this.atomic.set(USER_PREFIX + id, updated, entry.version);
    if (!newVersion) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');

    // Sync email index so login() reads fresh data (including loginPolicy)
    const emailEntry = await this.atomic.get<User>(EMAIL_INDEX_PREFIX + updated.email);
    if (emailEntry) {
      await this.atomic.set(EMAIL_INDEX_PREFIX + updated.email, updated, emailEntry.version);
    }

    await this.logger.write({
      facility: FACILITY,
      level: KernLevel.INFO,
      message: 'User updated',
      metadata: { userId: id },
    });

    await this.audit?.write({
      level: KernLevel.INFO,
      facility: FACILITY,
      message: `User profile updated — ${updated.email}`,
      metadata: { eventType: 'user.updated', userId: id, actorId },
    });

    return updated;
  }

  public async delete(id: UserId, actorId?: string): Promise<void> {
    const entry = await this.atomic.get<User>(USER_PREFIX + id);
    if (!entry) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');

    const email = entry.value.email;

    // Atomically: tombstone user + remove email index + remove from ID index
    await this.#transactWithRetry(async (txn) => {
      const e = await txn.get<User>(USER_PREFIX + id);
      if (!e) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');
      const shardKey = USER_IDS_SHARD_PREFIX + String(shardIndex(id));
      const idx = await txn.get<string[]>(shardKey);
      if (idx) txn.set(shardKey, idx.filter((i: string) => i !== id));
      txn.set(USER_PREFIX + id, null);
      const emEntry = await txn.get<any>(EMAIL_INDEX_PREFIX + email);
      if (emEntry) txn.set(EMAIL_INDEX_PREFIX + email, null);
    });

    // Best-effort counter update
    await this.#decrCounter().catch(() => { /* noop */ });

    await this.logger.write({
      facility: FACILITY,
      level: KernLevel.INFO,
      message: 'User deleted',
      metadata: { userId: id, email },
    });

    await this.audit?.write({
      level: KernLevel.WARNING,
      facility: FACILITY,
      message: `User deleted — ${email}`,
      metadata: { eventType: 'user.deleted', userId: id, email, actorId },
    });
  }

  /** Increment user count — best-effort, OCC retry ×3. */
  async #incrCounter(): Promise<void> {
    for (let attempt = 0; attempt < 3; attempt++) {
      const entry = await this.atomic.get<number>(USER_COUNT_KEY);
      const ver = await this.atomic.set(USER_COUNT_KEY, (entry?.value ?? 0) + 1, entry?.version ?? null);
      if (ver) return;
    }
  }

  /** Decrement user count — best-effort, OCC retry ×3. */
  async #decrCounter(): Promise<void> {
    for (let attempt = 0; attempt < 3; attempt++) {
      const entry = await this.atomic.get<number>(USER_COUNT_KEY);
      const cur = entry?.value ?? 0;
      if (cur <= 0) return;
      const ver = await this.atomic.set(USER_COUNT_KEY, cur - 1, entry?.version ?? null);
      if (ver) return;
    }
  }

  public async list(): Promise<User[]> {
    // Read all shards in parallel, then merge.
    const shardKeys = Array.from(
      { length: USER_IDS_SHARDS },
      (_, i) => USER_IDS_SHARD_PREFIX + String(i),
    );
    const shards = await Promise.all(shardKeys.map(k => this.atomic.get<string[]>(k)));
    const ids = shards.flatMap(s => s?.value ?? []);
    if (ids.length === 0) return [];

    const users = await Promise.all(ids.map(id => this.atomic.get<User>(USER_PREFIX + id)));
    return users.filter((u): u is NonNullable<typeof u> => u !== null).map(u => normalizeUser(u.value));
  }

  public async listPaginated(page = 1, limit = 50): Promise<{ items: User[]; total: number }> {
    // Read total from counter (1 I/O) — avoids reading all 16 shard indices.
    const countEntry = await this.atomic.get<number>(USER_COUNT_KEY);
    const total = countEntry?.value ?? 0;
    if (total === 0) return { items: [], total };

    const start = (page - 1) * limit;
    if (start >= total) return { items: [], total };

    // Scan shards sequentially, collecting only enough IDs for the requested page.
    const pageIds: string[] = [];
    let remaining = limit;
    let skip = start;

    for (let i = 0; i < USER_IDS_SHARDS && remaining > 0; i++) {
      const shard = await this.atomic.get<string[]>(USER_IDS_SHARD_PREFIX + String(i));
      const ids = shard?.value ?? [];
      if (ids.length === 0) continue;

      if (skip >= ids.length) {
        skip -= ids.length;
        continue;
      }

      const take = Math.min(ids.length - skip, remaining);
      pageIds.push(...ids.slice(skip, skip + take));
      remaining -= take;
      skip = 0;
    }

    if (pageIds.length === 0) return { items: [], total };

    const users = await Promise.all(pageIds.map(id => this.atomic.get<User>(USER_PREFIX + id)));
    const items = users.filter((u): u is NonNullable<typeof u> => u !== null).map(u => normalizeUser(u.value));
    return { items, total };
  }

  public async clearLoginPolicy(id: UserId, actorId?: string): Promise<User> {
    const entry = await this.atomic.get<User>(USER_PREFIX + id);
    if (!entry) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');

    const { loginPolicy: _p, ...rest } = entry.value;
    const updated: User = { ...rest, updatedAt: Date.now() };
    const newVersion = await this.atomic.set(USER_PREFIX + id, updated, entry.version);
    if (!newVersion) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');

    const emailEntry = await this.atomic.get<User>(EMAIL_INDEX_PREFIX + updated.email);
    if (emailEntry) await this.atomic.set(EMAIL_INDEX_PREFIX + updated.email, updated, emailEntry.version);

    await this.audit?.write({
      level: KernLevel.NOTICE,
      facility: FACILITY,
      message: `Login policy cleared for user — ${updated.email}`,
      metadata: { eventType: 'user.loginPolicy.cleared', userId: id, actorId },
    });

    return updated;
  }

  public async clearPublicKey(id: UserId, actorId?: string): Promise<User> {
    const entry = await this.atomic.get<User>(USER_PREFIX + id);
    if (!entry) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');
    const { publicKeyEd25519: _k, ...rest } = entry.value;
    const updated: User = { ...rest, updatedAt: Date.now() };
    const newVersion = await this.atomic.set(USER_PREFIX + id, updated, entry.version);
    if (!newVersion) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');
    const emailEntry = await this.atomic.get<User>(EMAIL_INDEX_PREFIX + updated.email);
    if (emailEntry) await this.atomic.set(EMAIL_INDEX_PREFIX + updated.email, updated, emailEntry.version);

    await this.audit?.write({
      level: KernLevel.NOTICE,
      facility: FACILITY,
      message: `Public key cleared for user — ${updated.email}`,
      metadata: { eventType: 'user.publicKey.cleared', userId: id, actorId },
    });

    return updated;
  }

  public async getLoginInfo(email: string): Promise<LoginInfo> {
    const entry = await this.atomic.get<User>(EMAIL_INDEX_PREFIX + email);
    if (!entry) return { exists: false, methods: [] };

    const user = entry.value;
    const methods: ('password' | 'no-password')[] = [];
    if (!user.loginPolicy?.passwordLoginDisabled) methods.push('password');
    if (user.publicKeyEd25519) methods.push('no-password');

    const policy = user.loginPolicy;
    if (!policy) return { exists: true, methods };

    return {
      exists: true,
      methods,
      policy: {
        enabled: policy.enabled,
        disabled: !policy.enabled,
        timeRestricted: !!(policy.timeRanges.length),
        timeRanges: policy.timeRanges,
      },
    };
  }

  public async validateToken(token: SessionToken): Promise<User | null> {
    const entry = await this.atomic.get<Session>(TOKEN_PREFIX + token);
    if (!entry) return null;
    const expiresAt = entry.value.expiresAt ?? entry.value.createdAt + SESSION_TTL_MS;
    if (Date.now() >= expiresAt) return null;
    const userId = createUserId(entry.value.userId);
    const user = await this.getById(userId);
    return user ? normalizeUser(user) : null;
  }

  private async createSession(userId: UserId): Promise<SessionToken> {
    // Reuse active session within TTL
    const idxEntry = await this.atomic.get<string>(USER_SESSION_PREFIX + userId);
    if (idxEntry) {
      const existingToken = createSessionToken(idxEntry.value);
      const sessEntry = await this.atomic.get<Session>(TOKEN_PREFIX + existingToken);
      if (sessEntry) {
        const expiresAt = sessEntry.value.expiresAt ?? sessEntry.value.createdAt + SESSION_TTL_MS;
        if (Date.now() < expiresAt) {
          return existingToken;
        }
      }
    }

    const now = Date.now();
    const token = generateSessionToken();
    const session: Session = {
      token,
      userId,
      createdAt: now,
      expiresAt: now + SESSION_TTL_MS,
    };
    await this.atomic.set(TOKEN_PREFIX + token, session, null);
    await this.atomic.set(USER_SESSION_PREFIX + userId, token, idxEntry?.version ?? null);

    // Track session in per-user list for revocation
    const sessIdx = await this.atomic.get<string[]>(USER_SESSIONS_PREFIX + userId);
    await this.atomic.set(
      USER_SESSIONS_PREFIX + userId,
      [...(sessIdx?.value ?? []), token],
      sessIdx?.version ?? null,
    );
    return token;
  }

  public async listSessions(userId: UserId): Promise<readonly SessionToken[]> {
    const entry = await this.atomic.get<string[]>(USER_SESSIONS_PREFIX + userId);
    if (!entry) return [];
    const live: SessionToken[] = [];
    const expired: string[] = [];
    const now = Date.now();
    for (const raw of entry.value) {
      const t = createSessionToken(raw);
      const s = await this.atomic.get<Session>(TOKEN_PREFIX + t);
      if (s) {
        const expiresAt = s.value.expiresAt ?? s.value.createdAt + SESSION_TTL_MS;
        if (now < expiresAt) live.push(t);
        else expired.push(t);
      }
    }
    // Clean up expired sessions from index
    if (expired.length > 0) {
      const remaining = entry.value.filter(r => !expired.includes(r));
      await this.atomic.set(USER_SESSIONS_PREFIX + userId, remaining, entry.version);
      // Best-effort remove from store
      await Promise.allSettled(expired.map(t => this.atomic.set(TOKEN_PREFIX + createSessionToken(t), null, null)));
    }
    return live;
  }

  public async revokeSession(token: SessionToken, actorId?: string): Promise<void> {
    // Read session before deleting to find userId for index cleanup
    const entry = await this.atomic.get<Session>(TOKEN_PREFIX + token);
    if (!entry) return;
    const userId = entry.value.userId;

    // Remove from store
    await this.atomic.set(TOKEN_PREFIX + token, null, entry.version);

    // Remove from user's session index
    const sessIdx = await this.atomic.get<string[]>(USER_SESSIONS_PREFIX + userId);
    if (sessIdx) {
      await this.atomic.set(
        USER_SESSIONS_PREFIX + userId,
        sessIdx.value.filter(t => t !== token),
        sessIdx.version,
      );
    }

    await this.audit?.write({
      level: KernLevel.INFO,
      facility: FACILITY,
      message: `Session revoked for user ${userId}`,
      metadata: { eventType: 'user.session.revoked', userId: userId, tokenHint: (token as string).slice(-4), actorId },
    });
  }

  /** Allocate next available UID — RHEL §1 UID auto-increment from 1000. */
  async #nextUid(): Promise<Uid> {
    for (let attempt = 0; attempt < 3; attempt++) {
      const entry = await this.atomic.get<number>(UID_COUNTER_KEY);
      const next = entry?.value ?? UID_MIN;
      const ver = await this.atomic.set(UID_COUNTER_KEY, next + 1, entry?.version ?? null);
      if (ver) return createUid(next);
    }
    throw new AppError(409, 'CONFLICT', 'Failed to allocate UID after retries');
  }

  // ─── Supplementary group management (RHEL §1 supp_groups) ───

  public async addSupplementaryGroup(userId: UserId, gid: Gid, actorId?: string): Promise<User> {
    const entry = await this.atomic.get<User>(USER_PREFIX + userId);
    if (!entry) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');
    const existing = normalizeUser(entry.value);
    if (existing.supplementaryGids.includes(gid)) return existing;

    const updated: User = {
      ...existing,
      supplementaryGids: [...existing.supplementaryGids, gid],
      updatedAt: Date.now(),
    };
    const ver = await this.atomic.set(USER_PREFIX + userId, updated, entry.version);
    if (!ver) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');

    await this.audit?.write({
      level: KernLevel.INFO,
      facility: FACILITY,
      message: `Supplementary group added — user ${String(userId)} → gid ${String(gid)}`,
      metadata: { eventType: 'user.suppGroup.added', userId: userId, gid, actorId },
    });
    return updated;
  }

  public async removeSupplementaryGroup(userId: UserId, gid: Gid, actorId?: string): Promise<User> {
    const entry = await this.atomic.get<User>(USER_PREFIX + userId);
    if (!entry) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');
    const existing = normalizeUser(entry.value);
    if (!existing.supplementaryGids.includes(gid)) return existing;

    const updated: User = {
      ...existing,
      supplementaryGids: existing.supplementaryGids.filter(g => g !== gid),
      updatedAt: Date.now(),
    };
    const ver = await this.atomic.set(USER_PREFIX + userId, updated, entry.version);
    if (!ver) throw new AppError(409, 'CONFLICT', 'Concurrent modification detected');

    await this.audit?.write({
      level: KernLevel.INFO,
      facility: FACILITY,
      message: `Supplementary group removed — user ${String(userId)} → gid ${String(gid)}`,
      metadata: { eventType: 'user.suppGroup.removed', userId: userId, gid, actorId },
    });
    return updated;
  }

  public async listSupplementaryGroups(userId: UserId): Promise<Gid[]> {
    const user = await this.getById(userId);
    if (!user) throw new AppError(404, 'USER_NOT_FOUND', 'User not found');
    return user.supplementaryGids;
  }

  /** Auto-join "users" group on registration (Linux-style). */
  async #joinDefaultGroup(userId: UserId): Promise<void> {
    return this.#joinNamedGroup(userId, 'users');
  }

  /** Add a user to a named user group by group name. */
  async #joinNamedGroup(userId: UserId, groupName: string): Promise<void> {
    try {
      const ugEntry = await this.atomic.get<string[]>('usergroup:ids');
      if (!ugEntry) return;
      for (const id of ugEntry.value) {
        const g = await this.atomic.get<any>('usergroup:' + id);
        if (g?.value?.name === groupName) {
          if (!g.value.memberIds.includes(userId)) {
            g.value.memberIds.push(userId);
            g.value.updatedAt = Date.now();
            await this.atomic.set('usergroup:' + id, g.value, g.version);
          }
          return;
        }
      }
    } catch {
      // Silently ignore — group may not exist yet
    }
  }

}

// ─── Brand types ───

declare const USER_ID_BRAND: unique symbol;
declare const SESSION_TOKEN_BRAND: unique symbol;
declare const UID_BRAND: unique symbol;
declare const GID_BRAND: unique symbol;

export type UserId = string & { readonly [USER_ID_BRAND]: true };
export type SessionToken = string & { readonly [SESSION_TOKEN_BRAND]: true };
/** Numeric user ID — RHEL §1 UID, allocated from 1000+. */
export type Uid = number & { readonly [UID_BRAND]: true };
/** Numeric group ID — RHEL §1 GID, allocated from 1000+. */
export type Gid = number & { readonly [GID_BRAND]: true };

const UUID_V4_PATTERN = /^[a-f0-9]{8}-[a-f0-9]{4}-4[a-f0-9]{3}-[89ab][a-f0-9]{3}-[a-f0-9]{12}$/i;

export function createUserId(raw: string): UserId {
  if (!UUID_V4_PATTERN.test(raw)) throw new TypeError(`Invalid UserId format, expected UUID v4: ${raw}`);
  return raw as UserId;
}

export function createSessionToken(raw: string): SessionToken {
  if (!raw) throw new TypeError('SessionToken must not be empty');
  return raw as SessionToken;
}

export function generateUserId(): UserId {
  return crypto.randomUUID() as UserId;
}

export function generateSessionToken(): SessionToken {
  return `sess_${crypto.randomUUID()}` as SessionToken;
}

export function createUid(n: number): Uid {
  if (!Number.isSafeInteger(n) || n < 0) throw new TypeError(`Invalid UID: ${String(n)}`);
  return n as Uid;
}

export function createGid(n: number): Gid {
  if (!Number.isSafeInteger(n) || n < 0) throw new TypeError(`Invalid GID: ${String(n)}`);
  return n as Gid;
}

/** First allocatable UID — RHEL convention: <1000 reserved for system. */
export const UID_MIN = 1000;
/** First allocatable GID. */
export const GID_MIN = 1000;

/** Default /etc/passwd values. */
export const DEFAULT_SHELL = '/bin/bash';
export const DEFAULT_HOME_PREFIX = '/home/';

// ─── Enums ───

export enum UserRole {
  Root = 'root',
  Operator = 'Operator',
  Viewer = 'Viewer',
  Wheel = 'wheel',
}

// ─── Entity ───

export interface User {
  id: UserId;
  email: string;
  passwordHash: string;
  /** Display name — RHEL /etc/passwd GECOS field. */
  name: string;
  role: UserRole;
  loginPolicy?: LoginPolicy;
  /** Ed25519 public key for key-based (no-password) login.
   *  The private key is NEVER stored server-side — it is generated on the
   *  client and only returned once in the registration response. */
  publicKeyEd25519?: string;
  // ── RHEL /etc/passwd 7-field model ──
  /** Numeric user ID — RHEL §1 passwd UID. */
  uid: Uid;
  /** Primary group ID — RHEL §1 passwd GID. */
  gid: Gid;
  /** GECOS comment field (full name / notes). */
  gecos: string;
  /** Home directory. */
  directory: string;
  /** Login shell. */
  shell: string;
  /** Supplementary group IDs — RHEL §1 supp_groups. */
  supplementaryGids: Gid[];
  createdAt: number;
  updatedAt: number;
}

// ─── Session entity ───

export interface Session {
  token: SessionToken;
  userId: UserId;
  createdAt: number;
  /** Absolute expiry timestamp. Checked against Date.now() at validation time
   *  instead of computing TTL from createdAt, so clock drift between the
   *  creating and validating isolate cancels out to first order. */
  expiresAt: number;
}

// ─── Login policy ───

export interface LoginTimeRange {
  /** Start time in "HH:mm" UTC */
  start: string;
  /** End time in "HH:mm" UTC */
  end: string;
}

export interface LoginPolicy {
  /** false = completely block login for this account */
  enabled: boolean;
  /** Time windows when login is allowed (UTC), empty = no restriction */
  timeRanges: LoginTimeRange[];
  /** CIDR whitelist, empty = no restriction */
  allowedCIDRs: string[];
  /** true = disable password login, require key-based (no-password) auth */
  passwordLoginDisabled?: boolean | undefined;
}

/** Runtime context passed into login() for policy evaluation. */
export interface LoginContext {
  /** Client IP address from X-Forwarded-For or cf-connecting-ip */
  ip: string | undefined;
  /** Site context string for no-password login signature binding */
  siteContext: string | undefined;
}

export interface LoginInfo {
  exists: boolean;
  methods: ('password' | 'no-password')[];
  policy?: {
    enabled: boolean;
    disabled: boolean;
    timeRestricted: boolean;
    timeRanges: LoginTimeRange[];
  };
}

// ─── DTOs (domain-facing, after validation + binding) ───

export interface RegisterInput {
  email: string;
  password: string;   // raw password, hashed before storage
  name: string;
  role: UserRole;
}

export interface LoginInput {
  email: string;
  password: string;
}

export interface UpdateUserInput {
  name: string | undefined;
  password: string | undefined;
  role: UserRole | undefined;
  loginPolicy: LoginPolicy | undefined;
  publicKeyEd25519: string | undefined;
  gecos: string | undefined;
  directory: string | undefined;
  shell: string | undefined;
  /** Replace supplementary groups entirely (not merge). */
  supplementaryGids: number[] | undefined;
}

export interface NoPasswordLoginInput {
  email: string;
  oneTimeKey: string;
}

import { Hono } from 'hono';
import type { Context } from 'hono';
import type { AppContext } from '../../core/deps.ts';
import type { IVolumeService } from './service.ts';
import { CreateVolumeSchema, UpdateVolumeSchema } from './schema.ts';
import type { CreateVolumeInput, UpdateVolumeInput } from './types.ts';
import { ok, fail } from '../../core/response.ts';
import type { RouteMeta } from '../../core/http-docs/types.ts';
import type { CrudHandlerMap } from '../../core/crud/router.ts';
import { registerCrudRoutes } from '../../core/crud/router.ts';

function requireRoot(c: Context<{ Variables: AppContext }>): Response | null {
  const user = c.var?.currentUser;
  if (!user) return null;
  const isRoot = user.role === 'root' || user.role === 'Operator' || user.role === 'wheel';
  if (!isRoot) return c.json(fail('FORBIDDEN', 'Admin access required'), 403);
  return null;
}

export function createVolumeRouter(svc: IVolumeService): Hono<any> {
  const router = new Hono<any>();

  const crud: CrudHandlerMap = {
    create: (r) => r.post('/', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      const body: unknown = await c.req.json();
      const parsed = CreateVolumeSchema.safeParse(body);
      if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      const volume = await svc.create(parsed.data as CreateVolumeInput);
      return c.json(ok(volume), 201);
    }),

    list: (r) => r.get('/', async (c) => {
      const page = parseInt(c.req.query('page') ?? '') || 1;
      const limit = parseInt(c.req.query('limit') ?? '') || 50;
      const filters: Record<string, string> = {};
      const n = c.req.query('name'); if (n) filters.name = n;
      const t = c.req.query('type'); if (t) filters.type = t;
      const s = c.req.query('status'); if (s) filters.status = s;
      const inst = c.req.query('instanceId'); if (inst) filters.instanceId = inst;
      return c.json(ok(await svc.listPaginated(page, limit, Object.keys(filters).length ? filters : undefined)));
    }),

    get: (r) => r.get('/:id', async (c) => {
      const vol = await svc.get(c.req.param('id'));
      if (!vol) return c.json(fail('VOLUME_NOT_FOUND', 'Volume not found'), 404);
      return c.json(ok(vol));
    }),

    update: (r) => r.put('/:id', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      const body: unknown = await c.req.json();
      const parsed = UpdateVolumeSchema.safeParse(body);
      if (!parsed.success) return c.json(fail('VALIDATION_ERROR', parsed.error.issues.map(i => i.message).join('; ')), 400);
      return c.json(ok(await svc.update(c.req.param('id'), parsed.data as UpdateVolumeInput)));
    }),

    delete: (r) => r.delete('/:id', async (c) => {
      const rv = requireRoot(c); if (rv) return rv;
      await svc.delete(c.req.param('id'));
      return c.json(ok(null));
    }),
  };

  return registerCrudRoutes(router, crud);
}

