const TOP_SCALARS = {
  name: {
    param: 'ContainerGroupName',
    responsePath: 'ContainerGroupName',
    encode: v => v,
    decode: decStr,
  },
  zoneId: {
    param: 'ZoneId',
    responsePath: 'ZoneId',
