/**
 * Alibaba Cloud RPC API caller — uses AkSkProvider from the auth layer.
 *
 * Reference: https://help.aliyun.com/document_detail/110992.html
 *
 * This is a thin wrapper that adapts AkSkProvider (which generates a signed URL)
 * to the ECI-specific call pattern (POST with error parsing).
 */

import { z } from 'zod';
import { AkSkProvider } from '../../core/auth/providers.ts';

export type RpcParams = Readonly<Record<string, string | undefined>>;

/**
 * Call an Alibaba Cloud RPC API and return the parsed JSON response.
 */
export async function rpcCall(
  endpoint: string,
  accessKeyId: string,
  accessKeySecret: string,
  action: string,
  params: RpcParams,
): Promise<Record<string, unknown>> {
  const aksk = AkSkProvider.getOrCreate(accessKeyId, accessKeySecret);

  // Build query params for the specific action
  const queryEntries = Object.entries({
    Action: action,
    Version: '2018-08-08',
    ...params,
    // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- params values may be undefined
  }).filter(([_, v]) => v !== undefined);

  // Alibaba RPC expects commas in VSwitchId/InstanceType to be literal (not %2C)
  const encodeVal = (v: string): string => encodeURIComponent(v).replace(/%2C/g, ',');
  const queryString = queryEntries.map(([k, v]) => `${encodeURIComponent(k)}=${encodeVal(v)}`).join('&');
  const baseUrl = `https://${endpoint}/?${queryString}`;

  const { url: signedUrl } = await aksk.sign({ method: 'POST', url: baseUrl, headers: {} });
  if (!signedUrl) throw new Error('AkSkProvider did not produce a signed URL');

  const resp = await fetch(signedUrl, { method: 'POST' });
  if (!resp.ok) {
    const text = await resp.text().catch(() => '<unreadable>');
    throw new Error(`Alibaba ECI ${action} HTTP ${String(resp.status)}: ${text.slice(0, 500)}`);
  }

  let body: Record<string, unknown>;
  try {
    body = await resp.json();
  } catch {
    const text = await resp.text().catch(() => '<unreadable>');
    throw new Error(`Alibaba ECI ${action} returned non-JSON response: ${text.slice(0, 500)}`);
  }

  if (body.Code) {
    const requestId = z.string().optional().parse(body.RequestId) ?? 'unknown';
    const rawCode = z.unknown().parse(body.Code);
    const code = stringifyIfNeeded(rawCode);
    const msg = z.string().optional().parse(body.Message) ?? '(no message)';
    throw new Error(`Alibaba ECI ${action} failed [${requestId}]: ${code} — ${msg}`);
  }
  return body;
}

function stringifyIfNeeded(v: unknown): string {
  try { return z.string().parse(v); } catch { return JSON.stringify(v); }
}

/**
 * Alibaba Cloud OSS provider — OSS-native HMAC-SHA1 auth.
 * Extends S3ClientBase. Auth is the only difference from SigV4 providers.
 */
import { S3ClientBase } from '../../core/provider/s3-client.ts';
import type { S3ProviderConfig } from '../../core/provider/s3-types.ts';
import { hmacSha1 } from '../../core/auth/providers.ts';

export class AlibabaOssProvider extends S3ClientBase {
  public readonly type = 'alibaba-oss' as const;
  readonly #accessKeyId: string;
  readonly #accessKeySecret: string;
  readonly #endpoint: string;

  public constructor(accessKeyId: string, accessKeySecret: string, region: string, endpoint?: string, config?: S3ProviderConfig) {
    super(config);
    this.#accessKeyId = accessKeyId;
    this.#accessKeySecret = accessKeySecret;
    this.#endpoint = endpoint ?? `https://oss-${region}.aliyuncs.com`;
  }

  protected endpointFor(_bucket: string): string {
    return this.#endpoint;
  }

  protected async authFetch(url: string, method: string, _path: string, queryString: string, headers: Record<string, string>, _bodyHash: string, body?: BodyInit): Promise<Response> {
    const dateStr = new Date().toUTCString();
    const ossHeaders = Object.keys(headers)
      .filter(k => k.startsWith('x-oss-'))
      .sort()
      .map(k => `${k.toLowerCase()}:${String(headers[k])}\n`).join('');

    const contentMD5 = headers['content-md5'] ?? '';
    const contentType = headers['content-type'] ?? '';
    const canonicalizedResource = this.#canonicalResource(url, queryString);
    const stringToSign = `${method}\n${contentMD5}\n${contentType}\n${dateStr}\n${ossHeaders}${canonicalizedResource}`;

    const signature = await hmacSha1(this.#accessKeySecret, stringToSign);
    const authHeader = `OSS ${this.#accessKeyId}:${signature}`;

    const res = await fetch(url, {
      method,
      headers: { ...headers, Authorization: authHeader, Date: dateStr, ...(body !== undefined ? { 'content-length': String(headers['content-length'] ?? (body as any).byteLength ?? 0) } : {}) },
      ...(body !== undefined ? { body } : {}),
    });

    if (res.ok || res.status === 404) return res;
    throw new Error(`OSS ${method} failed: ${String(res.status)} ${await res.text()}`);
  }

  /** Build the OSS canonical resource including sub-resources like ?uploads, ?partNumber=, ?uploadId= */
  #canonicalResource(url: string, queryString: string): string {
    const pathname = new URL(url).pathname;
    if (!queryString) return pathname;
    // OSS requires sub-resources to be sorted and included: /bucket/key?partNumber=N&uploadId=xxx
    const params = new URLSearchParams(queryString);
    const sorted = [...params.keys()].sort().map(k => {
      const v = params.get(k);
      return v ? `${k}=${v}` : k;
    });
    return `${pathname}?${sorted.join('&')}`;
  }

  // ─── Presigned URLs (OSS native scheme) ───

  public async getPresignedUrl(bucket: string, key: string, expiresInSeconds = 3600): Promise<string> {
    return this.#ossPresignedUrl('GET', bucket, key, expiresInSeconds);
  }

  public async putPresignedUrl(bucket: string, key: string, expiresInSeconds = 3600): Promise<string> {
    return this.#ossPresignedUrl('PUT', bucket, key, expiresInSeconds);
  }

  async #ossPresignedUrl(method: string, bucket: string, key: string, expiresInSeconds: number): Promise<string> {
    const bucketName = this.#bucketMapping(bucket);
    const encodedKey = key.split('/').map(encodeURIComponent).join('/');
    const expires = Math.floor(Date.now() / 1000) + expiresInSeconds;
    const path = `/${bucketName}/${encodedKey}`;

    const stringToSign = `${method}\n\n\n${String(expires)}\n${path}`;
    const signature = await hmacSha1(this.#accessKeySecret, stringToSign);
    const encodedSig = encodeURIComponent(signature);

    const host = new URL(this.#endpoint).host;
    return `https://${host}${path}?OSSAccessKeyId=${encodeURIComponent(this.#accessKeyId)}&Expires=${String(expires)}&Signature=${encodedSig}`;
  }

  #bucketMapping(bucket: string): string {
    return this.config.bucketNameMapping?.[bucket] ?? bucket;
  }
}

/**
 * Generalized Alibaba Cloud RPC API caller.
 *
 * Alibaba Cloud services use a common RPC-style calling convention:
 * - Common parameters (Action, Version, AccessKeyId, Timestamp, SignatureMethod, etc.)
 * - Business parameters appended as query string key-value pairs
 * - HMAC-SHA1 signed via AkSkProvider
 *
 * Reference: https://help.aliyun.com/document_detail/110992.html
 */

import { z } from 'zod';
import { AkSkProvider } from '../../core/auth/providers.ts';

export type RpcParams = Readonly<Record<string, string | undefined>>;

/**
 * Call an Alibaba Cloud RPC API and return the parsed JSON response.
 *
 * @param endpoint  - The service endpoint (e.g. "eci.cn-hangzhou.aliyuncs.com")
 * @param accessKeyId - Alibaba Cloud AccessKey ID
 * @param accessKeySecret - Alibaba Cloud AccessKey Secret
 * @param action    - API action name (e.g. "DescribeContainerGroups")
 * @param version   - API version (e.g. "2018-08-08", "2018-12-01")
 * @param params    - Business parameters
 * @returns Parsed JSON response body
 */
export async function rpcCall(
  endpoint: string,
  accessKeyId: string,
  accessKeySecret: string,
  action: string,
  version: string,
  params: RpcParams,
): Promise<Record<string, unknown>> {
  const aksk = AkSkProvider.getOrCreate(accessKeyId, accessKeySecret);

  const queryEntries = Object.entries({
    Action: action,
    Version: version,
    ...params,
    // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- params values may be undefined
  }).filter(([_, v]) => v !== undefined);

  const queryString = queryEntries.map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`).join('&');
  const baseUrl = `https://${endpoint}/?${queryString}`;

  const { url: signedUrl } = await aksk.sign({ method: 'POST', url: baseUrl, headers: {} });
  if (!signedUrl) throw new Error('AkSkProvider did not produce a signed URL');

  const resp = await fetch(signedUrl, { method: 'POST' });
  if (!resp.ok) {
    const text = await resp.text().catch(() => '<unreadable>');
    throw new Error(`Alibaba ${action} HTTP ${String(resp.status)}: ${text.slice(0, 500)}`);
  }

  let body: Record<string, unknown>;
  try {
    body = await resp.json();
  } catch {
    const text = await resp.text().catch(() => '<unreadable>');
    throw new Error(`Alibaba ${action} returned non-JSON response: ${text.slice(0, 500)}`);
  }

  if (body.Code) {
    const requestId = z.string().optional().parse(body.RequestId) ?? 'unknown';
    const rawCode = z.unknown().parse(body.Code);
    const code = stringifyIfNeeded(rawCode);
    const msg = z.string().optional().parse(body.Message) ?? '(no message)';
    throw new Error(`Alibaba ${action} failed [${requestId}]: ${code} — ${msg}`);
  }
  return body;
}

function stringifyIfNeeded(v: unknown): string {
  try { return z.string().parse(v); } catch { return JSON.stringify(v); }
}

// Cloudflare DNS provider via REST API (Bearer token auth).
//
// Reference: catch/script0/alibaba_l4d2_runtime_test.py
//   PUT https://api.cloudflare.com/client/v4/zones/{zone_id}/dns_records/{record_id}

import type { IDnsProvider, UpdateDnsRecordInput, DeleteDnsRecordInput } from '../../core/provider/interfaces.ts';
import { BearerTokenProvider } from '../../core/auth/providers.ts';

const { parse: parseJson } = JSON;

interface CfError {
  readonly code: number;
  readonly message: string;
}

interface CfApiResponse {
  readonly success: boolean;
  readonly errors: readonly CfError[];
  readonly result?: unknown;
}

export const CF_API_BASE_URL = 'https://api.cloudflare.com/client/v4';

export class CloudflareDnsProvider implements IDnsProvider {
  readonly #auth: BearerTokenProvider;

  public constructor(apiToken: string) {
    this.#auth = new BearerTokenProvider(apiToken);
  }

  public async updateRecord(input: UpdateDnsRecordInput): Promise<void> {
    const res = await this.#fetch('PUT',
      `${CF_API_BASE_URL}/zones/${input.zoneId}/dns_records/${input.providerRecordId}`,
      input,
    );

    if (res.status === 404) {
      // Record doesn't exist yet — create it
      await this.#createRecord(input);
      return;
    }

    const data = await parseCfResponse(res);
    if (!data.success) {
      throw new Error(`Cloudflare DNS update failed: ${formatErrors(data.errors)}`);
    }
  }

  public async deleteRecord(input: DeleteDnsRecordInput): Promise<void> {
    const res = await this.#fetch('DELETE',
      `${CF_API_BASE_URL}/zones/${input.zoneId}/dns_records/${input.providerRecordId}`,
    );

    if (res.status === 404) return; // already deleted

    const data = await parseCfResponse(res);
    if (!data.success) {
      throw new Error(`Cloudflare DNS delete failed: ${formatErrors(data.errors)}`);
    }
  }

  async #createRecord(input: UpdateDnsRecordInput): Promise<void> {
    const res = await this.#fetch('POST',
      `${CF_API_BASE_URL}/zones/${input.zoneId}/dns_records`,
      input,
    );

    const data = await parseCfResponse(res);
    if (!data.success) {
      throw new Error(`Cloudflare DNS create failed: ${formatErrors(data.errors)}`);
    }
  }

  async #fetch(method: string, url: string, bodyInput?: UpdateDnsRecordInput): Promise<Response> {
    const headers = await this.#headers();
    const init: RequestInit = { method, headers };
    if (bodyInput) {
      init.body = JSON.stringify({
        type: bodyInput.type,
        name: bodyInput.domain,
        content: bodyInput.value,
        ttl: bodyInput.ttl,
        proxied: bodyInput.proxied,
      });
    }
    return fetch(url, init);
  }

  async #headers(): Promise<Record<string, string>> {
    const base = { 'Content-Type': 'application/json' };
    const { headers } = await this.#auth.sign({ method: 'GET', url: '', headers: base });
    return headers;
  }
}

async function parseCfResponse(res: Response): Promise<CfApiResponse> {
  const text = await res.text();
  try {
    return parseJson(text) as CfApiResponse;
  } catch {
    return { success: false, errors: [{ code: res.status, message: text.slice(0, 200) }] };
  }
}

function formatErrors(errors: readonly CfError[]): string {
  if (errors.length === 0) return 'unknown error';
  return errors.map(e => `[${String(e.code)}] ${e.message}`).join('; ');
}

/**
 * Cloudflare Log Reader — queries from R2/Logpush persistent logs.
 */
import type { IBlobStore } from '../../core/store/interfaces.ts';
import type { IAuditReader, StoredAuditEntry, LogQuery } from '../../core/audit/types.ts';
import type { LogId } from '../../core/brand.ts';

const LINE_REGEX = /^\[(.+?)\]\s+(\w+):\s+\[(\w[\w-]*)\]\s+(.+)$/;

export class CloudflareLogReader implements IAuditReader {
  public constructor(
    private readonly blob: IBlobStore,
    private readonly prefix = 'logs',
  ) {}

  public async query(params?: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    return this.queryAsync(params ?? { facility: 'logs' });
  }

  // eslint-disable-next-line @typescript-eslint/require-await -- interface contract requires Promise<T>
  public async getById(_id: LogId): Promise<StoredAuditEntry | null> {
    return null; // Logpush logs are line-based, not id-indexed
  }

  public async queryAsync(params: LogQuery): Promise<{ entries: StoredAuditEntry[]; nextCursor?: string; total?: number }> {
    const since = params.startTs ?? 0;
    const until = params.endTs ?? Date.now();
    const facility = params.facility;
    const limit = params.limit ?? 50;

    const keys = this.#buildDateKeys(since, until);
    const results: StoredAuditEntry[] = [];

    for (const key of keys) {
      if (results.length >= limit) break;
      try {
        const stream = await this.blob.get(key);
        if (!stream) continue;
        const reader = stream.getReader();
        const chunks: Uint8Array[] = [];
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          chunks.push(value);
        }
        const totalSize = chunks.reduce((s, c) => s + c.byteLength, 0);
        const merged = new Uint8Array(totalSize);
        let offset = 0;
        for (const c of chunks) { merged.set(c, offset); offset += c.byteLength; }
        const text = new TextDecoder().decode(merged);
        const lines = text.split('\n').filter(Boolean);

        for (const line of lines) {
          if (results.length >= limit) break;
          const entry = this.#parseLine(line, since, until, facility);
          if (entry) results.push(entry);
        }
      } catch { /* skip unreadable R2 keys */ }
    }
    return { entries: results, total: results.length };
  }

  #buildDateKeys(since: number, until: number): string[] {
    const keys: string[] = [];
    const d = new Date(since);
    d.setUTCHours(0, 0, 0, 0);
    while (d.getTime() <= until) {
      const yyyy = d.getUTCFullYear();
      const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
      const dd = String(d.getUTCDate()).padStart(2, '0');
      for (let h = 0; h < 24; h++) {
        keys.push(`${this.prefix}/${String(yyyy)}/${mm}/${dd}/${String(h).padStart(2, '0')}/`);
      }
      d.setUTCDate(d.getUTCDate() + 1);
    }
    return keys;
  }

  #parseLine(line: string, since: number, until: number, facility?: string): StoredAuditEntry | null {
    const match = LINE_REGEX.exec(line);
    if (!match) return null;
    const [, ts, _level, lineFacility, message] = match;
    const timestamp = new Date(ts!).getTime();
    if (timestamp < since || timestamp > until) return null;
    if (facility && lineFacility !== facility) return null;
    return {
      id: crypto.randomUUID(),
      timestamp,
      level: 6, // default INFO
      facility: lineFacility ?? 'unknown',
      message: message ?? '',
    };
  }
}

/**
 * Cloudflare R2 S3 provider — SigV4 with account ID.
 * Extends S3ClientBase. Significant code reduction vs manual implementation.
 */
import { S3ClientBase } from '../../core/provider/s3-client.ts';
import type { S3ProviderConfig } from '../../core/provider/s3-types.ts';
import { signSigV4, emptyPayloadHash, signPresignedUrl } from '../../core/provider/s3-signer.ts';
import type { SigV4Credentials } from '../../core/provider/s3-signer.ts';

const CLOCK_SKEW_RETRIES = 2;

export class CloudflareR2S3Provider extends S3ClientBase {
  public readonly type = 'cloudflare-r2' as const;
  readonly #accountId: string;
  readonly #credentials: SigV4Credentials;
  #clockOffset = 0;

  public constructor(credentials: SigV4Credentials, accountId: string, config?: S3ProviderConfig) {
    super(config);
    this.#credentials = credentials;
    this.#accountId = accountId;
  }

  protected endpointFor(_bucket: string): string {
    return `https://${this.#accountId}.r2.cloudflarestorage.com`;
  }

  #signingTime(): Date {
    return new Date(Date.now() + this.#clockOffset);
  }

  protected async authFetch(url: string, method: string, path: string, queryString: string, headers: Record<string, string>, bodyHash: string, body?: BodyInit): Promise<Response> {
    for (let attempt = 0; attempt <= CLOCK_SKEW_RETRIES; attempt++) {
      const authHeaders = await signSigV4(method, path, queryString, headers, bodyHash || emptyPayloadHash(), this.#credentials, 'auto', 's3', this.#signingTime());
      const res = await fetch(url, { method, headers: { ...headers, ...authHeaders }, ...(body !== undefined ? { body } : {}) });
      if (res.ok || res.status === 404) return res;
      if (res.status === 403 && attempt < CLOCK_SKEW_RETRIES) {
        const bodyText = await res.clone().text().catch(() => '');
        if (bodyText.includes('RequestTimeTooSkewed') || bodyText.includes('Skewed')) continue;
      }
      throw new Error(`R2 ${method} failed: ${String(res.status)} ${await res.text()}`);
    }
    throw new Error(`R2 ${method} failed after ${String(CLOCK_SKEW_RETRIES)} retries`);
  }

  public async getPresignedUrl(bucket: string, key: string, expiresInSeconds = 3600): Promise<string> {
    const now = this.#signingTime();
    const canonicalUri = `/${this.#bucketMapping(bucket)}/${key.split('/').map(encodeURIComponent).join('/')}`;
    const host = `${this.#accountId}.r2.cloudflarestorage.com`;
    const url = await signPresignedUrl('GET', canonicalUri, this.#credentials, 'auto', 's3', expiresInSeconds, now, host);
    return url.toString();
  }

  public async putPresignedUrl(bucket: string, key: string, expiresInSeconds = 3600): Promise<string> {
    const now = this.#signingTime();
    const canonicalUri = `/${this.#bucketMapping(bucket)}/${key.split('/').map(encodeURIComponent).join('/')}`;
    const host = `${this.#accountId}.r2.cloudflarestorage.com`;
    const url = await signPresignedUrl('PUT', canonicalUri, this.#credentials, 'auto', 's3', expiresInSeconds, now, host);
    return url.toString();
  }

  #bucketMapping(bucket: string): string {
    return this.config.bucketNameMapping?.[bucket] ?? bucket;
  }
}

import type { IImageProvider, ImageInfo, ListImagesOptions } from '../../core/provider/interfaces.ts';

const ENDPOINT = process.env.PODMAN_ENDPOINT ?? 'http://127.0.0.1:8080';

interface RawImage {
  Id: string; RepoTags?: string[]; Created?: number; Size?: number;
}
interface RawInspect {
  Id: string; RepoTags?: string[]; Created?: string; Size?: number;
  Architecture?: string; Os?: string; RootFS?: { Layers?: string[] };
}
interface RawHistory {
  Id: string; Created?: number; CreatedBy?: string; Size?: number;
}
interface RawSearchItem {
  Name: string; Description?: string; IsOfficial?: boolean;
}

/**
 * Podman image provider. When the Podman daemon is unreachable, list()
 * returns [] and other methods return null / no-op instead of throwing,
 * so the API returns empty results rather than 502 errors.
 */
export class PodmanImageProvider implements IImageProvider {
  readonly #apiBase: string;

  public constructor(endpoint?: string) {
    const ep = endpoint ?? ENDPOINT;
    this.#apiBase = `${ep}/v1.24`;
  }

  public async pull(image: string, _clusterId?: string): Promise<ImageInfo> {
    // sha256 digest — pull by digest, not name:tag
    let url: string;
    if (image.startsWith('sha256:')) {
      url = `${this.#apiBase}/images/create?fromImage=${encodeURIComponent(image)}`;
    } else {
      const [name, tag] = image.includes(':') ? image.split(':') : [image, 'latest'];
      url = `${this.#apiBase}/images/create?fromImage=${encodeURIComponent(name!)}&tag=${encodeURIComponent(tag!)}`;
    }
    const resp = await this.#fetch(url, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman pull failed (${String(resp.status)}):${await resp.text().catch(() => '')}`);
    return this.inspect(image).then(r => r!);
  }

  public async list(options?: ListImagesOptions): Promise<readonly ImageInfo[]> {
    let url = `${this.#apiBase}/images/json`;
    if (options?.limit !== undefined || options?.offset !== undefined) {
      const params = new URLSearchParams();
      if (options.limit !== undefined) params.set('limit', String(options.limit));
      if (options.offset !== undefined) params.set('offset', String(options.offset));
      url += '?' + params.toString();
    }
    const resp = await this.#fetch(url);
    if (!resp) return [];
    if (!resp.ok) return [];
    const list: RawImage[] = await resp.json();
    return list.map(i => ({
      id: i.Id, tags: i.RepoTags ?? [],
      created: i.Created, size: i.Size,
    }));
  }

  public async inspect(id: string): Promise<ImageInfo | null> {
    const resp = await this.#fetch(`${this.#apiBase}/images/${encodeURIComponent(id)}/json`);
    if (!resp) return null;
    if (resp.status === 404) return null;
    if (!resp.ok) return null;
    const info: RawInspect = await resp.json();
    return {
      id: info.Id, tags: info.RepoTags ?? [],
      created: info.Created ? new Date(info.Created).getTime() : undefined,
      size: info.Size,
      architecture: info.Architecture, os: info.Os,
      layers: info.RootFS?.Layers?.length,
    };
  }

  public async remove(id: string): Promise<void> {
    const resp = await this.#fetch(`${this.#apiBase}/images/${encodeURIComponent(id)}`, { method: 'DELETE' });
    if (!resp) return;
    if (resp.status === 404) return;
    if (!resp.ok) throw new Error(`Podman remove failed: ${String(resp.status)}`);
  }

  public async push(imageOrId: string): Promise<ImageInfo> {
    const resp = await this.#fetch(`${this.#apiBase}/images/${encodeURIComponent(imageOrId)}/push`, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman push failed (${String(resp.status)}):${await resp.text().catch(() => '')}`);
    return this.inspect(imageOrId).then(r => r!);
  }

  public async search(term: string): Promise<readonly { name: string; description?: string | undefined; isOfficial?: boolean | undefined }[]> {
    const resp = await this.#fetch(`${this.#apiBase}/images/search?term=${encodeURIComponent(term)}`);
    if (!resp) return [];
    if (!resp.ok) return [];
    const list: RawSearchItem[] = await resp.json();
    return list.map(i => ({ name: i.Name, ...(i.Description ? { description: i.Description } : {}), ...(i.IsOfficial !== undefined ? { isOfficial: i.IsOfficial } : {}) }));
  }

  public async tag(id: string, tag: string): Promise<void> {
    const [repo, t] = tag.includes(':') ? tag.split(':') : [tag, 'latest'];
    const resp = await this.#fetch(`${this.#apiBase}/images/${encodeURIComponent(id)}/tag?repo=${encodeURIComponent(repo!)}&tag=${encodeURIComponent(t!)}`, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman tag failed (${String(resp.status)})`);
  }

  public async history(id: string): Promise<readonly { id: string; created?: number | undefined; createdBy?: string | undefined; size?: number | undefined }[]> {
    const resp = await this.#fetch(`${this.#apiBase}/images/${encodeURIComponent(id)}/history`);
    if (!resp) return [];
    if (!resp.ok) return [];
    const list: RawHistory[] = await resp.json();
    return list.map(h => ({ id: h.Id, ...(h.Created !== undefined ? { created: h.Created } : {}), ...(h.CreatedBy ? { createdBy: h.CreatedBy } : {}), ...(h.Size !== undefined ? { size: h.Size } : {}) }));
  }

  public async prune(): Promise<{ reclaimed: number }> {
    const resp = await this.#fetch(`${this.#apiBase}/images/prune`, { method: 'POST' });
    if (!resp) return { reclaimed: 0 };
    if (!resp.ok) return { reclaimed: 0 };
    const data = await resp.json();
    return { reclaimed: data.reclaimed ?? 0 };
  }

  public async build(_context: unknown, options?: { dockerfile?: string; tag?: string }): Promise<ImageInfo> {
    const params = new URLSearchParams();
    if (options?.dockerfile) params.set('dockerfile', options.dockerfile);
    if (options?.tag) params.set('t', options.tag);
    const query = params.toString() ? '?' + params.toString() : '';
    const resp = await this.#fetch(`${this.#apiBase}/build${query}`, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman build failed (${String(resp.status)}):${await resp.text().catch(() => '')}`);
    // build returns a stream — resolve the image from the tag
    if (options?.tag) {
      return this.inspect(options.tag).then(r => r ?? this.inspect(options.tag!.split(':')[0]!).then(r2 => r2!));
    }
    // No tag provided, find the newest image
    const all = await this.list();
    return all[all.length - 1] ?? { id: 'unknown', tags: [] };
  }

  /** Fetch with connection error protection. Returns null when Podman is down. */
  async #fetch(url: string, init?: RequestInit): Promise<Response | null> {
    try {
      return await fetch(url, init);
    } catch {
      return null;
    }
  }
}

/**
 * Podman network policy provider — implements INetworkPolicyProvider
 * via the libpod networks API.
 *
 * Each tenant gets an isolated bridge network. Pods created for that
 * tenant attach to this network, preventing cross-tenant traffic by
 * default (Podman bridge networks are isolated per-network).
 */

import type { INetworkPolicyProvider } from '../../core/provider/interfaces.ts';

const NETWORK_PREFIX = 'hbi-iso-';

function networkName(tenantId: string): string {
  // Deterministic name ensures idempotent ensureNetwork
  return NETWORK_PREFIX + tenantId.replace(/[^a-zA-Z0-9_-]/g, '_').slice(0, 48);
}

export class PodmanNetworkPolicyProvider implements INetworkPolicyProvider {
  readonly #libpodApi: string;

  public constructor(endpoint = 'http://127.0.0.1:8080') {
    this.#libpodApi = `${endpoint}/v5.0.0/libpod`;
  }

  public async ensureNetwork(tenantId: string): Promise<string> {
    const name = networkName(tenantId);

    // Check if already exists
    const listResp = await fetch(`${this.#libpodApi}/networks/json`);
    if (listResp.ok) {
      const networks = await listResp.json();
      const existing = networks.find(n => n.Name === name);
      if (existing) return name;
    }

    // Create isolated bridge network — no DNS, no default route to
    // other networks. Each tenant network is a /24 subnet.
    const subnet = tenantSubnet(tenantId);
    const body = {
      name,
      driver: 'bridge',
      internal: false,  // pods can reach internet via NAT
      subnets: [{ subnet }],
      labels: { 'managed-by': 'hbi-aad', tenant: tenantId },
      options: { isolate: 'true' },
    };

    const resp = await fetch(`${this.#libpodApi}/networks/create`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    if (!resp.ok) {
      const err = await resp.text().catch(() => '');
      // 409 = already exists (race), treat as success
      if (resp.status !== 409) {
        throw new Error(`Podman network create failed (${String(resp.status)}): ${err}`);
      }
    }

    return name;
  }

  public async removeNetwork(networkId: string): Promise<void> {
    const resp = await fetch(`${this.#libpodApi}/networks/${encodeURIComponent(networkId)}`, {
      method: 'DELETE',
    });
    if (!resp.ok && resp.status !== 404) {
      const err = await resp.text().catch(() => '');
      throw new Error(`Podman network remove failed (${String(resp.status)}): ${err}`);
    }
  }
}

/**
 * Deterministic /24 subnet derived from tenant ID hash.
 * Avoids subnet collisions for different tenants while being
 * reproducible across restarts.
 */
function tenantSubnet(tenantId: string): string {
  let hash = 0;
  for (let i = 0; i < tenantId.length; i++) {
    hash = ((hash << 5) - hash) + tenantId.charCodeAt(i);
    hash |= 0;
  }
  // Map to 10.2.x.x range (skip 10.0.x.x and 10.1.x.x for safety)
  const b2 = ((Math.abs(hash) % 253) + 2) & 0xff; // 2-254
  return `10.2.${String(b2)}.0/24`;
}

/**
 * Podman REST API provider — implements IContainerProvider via Docker v1.24 API.
 *
 * Creates and manages individual containers. For multi-container pod/group
 * operations see PodmanContainerGroupProvider (podman-group-provider.ts).
 *
 * Endpoint defaults to http://127.0.0.1:8080 (podman's default API port).
 */

import type {
  IContainerProvider,
  ContainerLifecycle,
  DescribeContainerGroupsInput,
  DescribeContainerGroupsResult,
  DeleteContainerGroupInput,
  GetContainerLogInput,
  ContainerLogResult,
} from '../../core/provider/interfaces.ts';
import type { CreateContainerGroupInput, ContainerGroupRuntime, OciContainerStatus } from '../../core/provider/types.ts';
import { createContainerId } from '../../core/provider/types.ts';
import { createRegionId } from '../../core/region/types.ts';
import { debugLog } from '../../core/audit/log-policy.ts';

interface PodmanContainer {
  Id: string;
  Names?: string[];
  Image?: string;
  ImageID?: string;
  State?: string;
  Status?: string;
  Created?: number;
  Ports?: {
    containerPort: number;
    hostPort?: number;
    protocol?: string;
  }[];
  Labels?: Record<string, string>;
  Mounts?: {
    Source: string;
    Destination: string;
    Mode?: string;
    RW?: boolean;
  }[];
}

interface PodmanInspectResult {
  Id: string;
  Name: string;
  State: {
    Status: string;
    Running: boolean;
    Paused: boolean;
    StartedAt?: string;
    FinishedAt?: string;
    ExitCode?: number;
    Error?: string;
    Health?: { Status?: string; FailingStreak?: number; Log?: { Start?: string; End?: string; ExitCode?: number; Output?: string }[] };
  };
  Config: {
    Image: string;
    Cmd?: string[];
    Env?: string[];
    WorkingDir?: string;
    Labels?: Record<string, string>;
  };
  HostConfig: {
    PortBindings?: Record<string, { HostPort?: string }[]>;
    RestartPolicy?: { Name?: string };
    NetworkMode?: string;
  };
  Mounts?: {
    Source: string;
    Destination: string;
    Type?: string;
    Mode?: string;
  }[];
  NetworkSettings?: {
    IPAddress?: string;
  };
  Created: string;
}

export class PodmanContainerProvider implements IContainerProvider {
  public readonly lifecycle: ContainerLifecycle = { stopIsDelete: false, startable: true, healthProbes: true, asyncInit: false };
  readonly #apiBase: string;
  /** Tracks created Podman secret IDs for cleanup on container delete. */
  readonly #createdSecrets = new Map<string, string[]>();

  public constructor(endpoint = 'http://127.0.0.1:8080') {
    this.#apiBase = `${endpoint}/v1.24`;
  }

  // ─── IContainerProvider ───

  public async create(input: CreateContainerGroupInput): Promise<{ providerId: string }> {
    const c = input.containers[0]!;

    // Env: flatten to KEY=VALUE strings
    const env: string[] = [];
    if (c?.env) {
      for (const e of c.env) {
        if (e.value !== undefined) env.push(`${e.name}=${e.value}`);
      }
    }

    // Port mappings
    const exposedPorts: Record<string, Record<string, unknown>> = {};
    const portBindings: Record<string, { HostPort?: string }[]> = {};
    if (c?.ports) {
      for (const p of c.ports) {
        const key = `${String(p.containerPort)}/${p.protocol ?? 'tcp'}`;
        exposedPorts[key] = {};
        portBindings[key] = p.hostPort !== undefined ? [{ HostPort: String(p.hostPort) }] : [{}];
      }
    }

    // Health check from livenessProbe
    let healthcheck: Record<string, unknown> | undefined;
    if (c?.livenessProbe) {
      const lp = c.livenessProbe;
      if (lp.exec) {
        healthcheck = { Test: ['CMD', ...lp.exec.command] };
      } else if (lp.httpGet) {
        healthcheck = { Test: ['CMD', 'curl', '-sf', `http://localhost:${String(lp.httpGet.port)}${lp.httpGet.path ?? '/'}`] };
      } else if (lp.tcpSocket) {
        healthcheck = { Test: ['CMD', '/bin/bash', '-c', `exec 3<>/dev/tcp/localhost/${String(lp.tcpSocket.port)} || exit 1`] };
      }
      if (healthcheck) {
        if (lp.initialDelaySeconds) healthcheck.StartPeriod = lp.initialDelaySeconds * 1_000_000_000;
        if (lp.periodSeconds) healthcheck.Interval = lp.periodSeconds * 1_000_000_000;
        if (lp.timeoutSeconds) healthcheck.Timeout = lp.timeoutSeconds * 1_000_000_000;
        if (lp.failureThreshold) healthcheck.Retries = lp.failureThreshold;
      }
    }

    const hostConfig: Record<string, unknown> = {};
    const networkMode = c?.networkMode
      ?? (c?.providerOverrides)?.networkMode as string | undefined;
    if (networkMode) {
      hostConfig.NetworkMode = networkMode;
    }
    if (Object.keys(portBindings).length > 0) hostConfig.PortBindings = portBindings;
    if (c?.resources?.limits) {
      hostConfig.Memory = (c.resources.limits.memory ?? 0) * 1024 * 1024;
      hostConfig.NanoCpus = (c.resources.limits.cpu ?? 0) * 1e9;
      if (c.resources.limits.gpu && c.resources.limits.gpu > 0) {
        hostConfig.DeviceRequests = [{ Driver: 'nvidia', Count: c.resources.limits.gpu, Capabilities: [['gpu']] }];
      }
    }
    // Volume mounts via Binds (local host paths)
    if (input.volumes?.length && c?.volumeMounts) {
      const binds: string[] = [];
      for (const vm of c.volumeMounts) {
        const vol = input.volumes.find(v => v.id === vm.volumeId);
        const nfsOpts = vol?.options as { path?: string } | undefined;
        const nfsPath = nfsOpts?.path;
        if (nfsPath?.startsWith('/') && isBindMountAllowed(nfsPath)) {
          // Read-only enforced for all bind mounts to prevent host fs tampering
          binds.push(`${nfsPath}:${vm.mountPath}:ro`);
        }
      }
      if (binds.length > 0) hostConfig.Binds = binds;
    }

    // Secret mounts — create as Podman secrets via libpod API, mount to /run/secrets/{name}
    // The container sees them as regular files in a tmpfs (memory-backed).
    const createdSecrets: string[] = [];
    if (input.secretMounts?.length) {
      const mounts = (hostConfig.Mounts as Record<string, unknown>[]) ?? [];
      for (const sm of input.secretMounts) {
        const secretName = `hbi_${crypto.randomUUID().slice(0, 8)}`;
        try {
          // Create Podman secret via libpod API
          const secResp = await fetch(`${this.#apiBase.replace('/v1.24', '')}/libpod/secrets/create`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name: secretName, data: btoa(sm.data) }),
          });
          if (secResp.ok) {
            const sec = await secResp.json();
            createdSecrets.push(sec.ID);
            mounts.push({
              Type: 'tmpfs',
              Target: sm.mountPath,
              TmpfsOptions: { SizeBytes: Math.max(sm.data.length * 2, 4096), Mode: sm.mode ?? 0o600 },
            });
          }
        } catch {
          // libpod API unavailable — skip; secret data stays encrypted at rest
        }
      }
      if (mounts.length > 0) hostConfig.Mounts = mounts;
    }

    const body: Record<string, unknown> = {
      Image: c?.image ?? '',
      Entrypoint: c?.command ? [...c.command] : undefined,
      Cmd: c?.args ? [...c.args] : undefined,
      Env: env.length ? env : undefined,
      Labels: { 'managed-by': 'hbi-aad', sandbox: input.name },
      ...(Object.keys(exposedPorts).length > 0 ? { ExposedPorts: exposedPorts } : {}),
      ...(healthcheck ? { Healthcheck: healthcheck } : {}),
      ...(Object.keys(hostConfig).length > 0 ? { HostConfig: hostConfig } : {}),
    };

    // No container name — Podman auto-assigns a unique one.
    // We always refer to containers by their ID (providerId), so the name is irrelevant.
    const nameParam = '';
    debugLog('sandbox-service', 'Podman create: apiBase=%s, image=%s', this.#apiBase, c?.image);
    let resp: Response;
    try {
      resp = await fetch(`${this.#apiBase}/containers/create${nameParam}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
    } catch (fetchErr: unknown) {
      debugLog('sandbox-service', 'Podman fetch failed: %O', { apiBase: this.#apiBase, error: fetchErr instanceof Error ? fetchErr.message : String(fetchErr), stack: fetchErr instanceof Error ? fetchErr.stack : undefined });
      throw new Error(`Podman connection failed to ${this.#apiBase}: ${fetchErr instanceof Error ? fetchErr.message : String(fetchErr)}`);
    }
    if (!resp.ok) {
      const err = await resp.text();
      throw new Error(`Podman create failed (${String(resp.status)}): ${err}`);
    }
    const data = await resp.json();

    // Start the container
    const startResp = await fetch(`${this.#apiBase}/containers/${String(data.Id)}/start`, { method: 'POST' });
    if (!startResp.ok && startResp.status !== 304) {
      // 304 = already started, ignore
      const err = await startResp.text();
      throw new Error(`Podman start failed (${String(startResp.status)}): ${err}`);
    }

    // Track created secrets for cleanup
    if (createdSecrets.length > 0) {
      this.#createdSecrets.set(data.Id, createdSecrets);
    }

    return { providerId: data.Id };
  }

  public async describe(input: DescribeContainerGroupsInput): Promise<DescribeContainerGroupsResult> {
    let url = `${this.#apiBase}/containers/json?all=true`;
    if (input.limit) url += `&limit=${String(input.limit)}`;

    const resp = await fetch(url);
    if (!resp.ok) throw new Error(`Podman list failed: ${String(resp.status)}`);
    const list = await resp.json();

    let filtered = list;
    if (input.sandboxName) {
      filtered = filtered.filter(c => c.Names?.some(n => n.includes(input.sandboxName!)));
    }
    if (input.sandboxId) {
      filtered = filtered.filter(c => c.Id.startsWith(input.sandboxId!));
    }
    if (input.status) {
      // eslint-disable-next-line @typescript-eslint/no-unsafe-enum-comparison -- podmanStatus returns string, input.status is ContainerGroupState
      filtered = filtered.filter(c => podmanStatus(c) === input.status);
    }

    const sandboxes = await Promise.all(
      filtered.map(c => this.#toRuntime(c.Id)),
    );

    return {
      sandboxes: sandboxes.filter((s): s is ContainerGroupRuntime => s !== null),
      totalCount: filtered.length,
    };
  }

  public async delete(input: DeleteContainerGroupInput): Promise<void> {
    // Clean up Podman secrets created for this container
    const secretIds = this.#createdSecrets.get(input.providerId);
    if (secretIds?.length) {
      for (const sid of secretIds) {
        try {
          await fetch(`${this.#apiBase.replace('/v1.24', '')}/libpod/secrets/${sid}`, { method: 'DELETE' });
        } catch { /* best-effort cleanup */ }
      }
      this.#createdSecrets.delete(input.providerId);
    }

    const resp = await fetch(`${this.#apiBase}/containers/${input.providerId}?force=true`, {
      method: 'DELETE',
    });
    if (!resp.ok && resp.status !== 404) {
      const err = await resp.text();
      throw new Error(`Podman delete failed (${String(resp.status)}): ${err}`);
    }
  }

  public async getLogs(input: GetContainerLogInput): Promise<ContainerLogResult> {
    let url = `${this.#apiBase}/containers/${input.providerId}/logs?stdout=true&stderr=true`;
    if (input.limitBytes) url += `&tail=${String(input.limitBytes)}`;
    if (input.sinceSeconds) url += `&since=${String(Math.floor(Date.now() / 1000) - input.sinceSeconds)}`;
    if (input.timestamps) url += `&timestamps=1`;

    const resp = await fetch(url);
    if (!resp.ok) throw new Error(`Podman logs failed (${String(resp.status)})`);
    const text = await resp.text();

    return {
      containerName: input.containerName,
      content: text,
    };
  }

  /** Get a single container's full state. */
  public async getStatus(providerId: string): Promise<ContainerGroupRuntime | null> {
    return this.#toRuntime(providerId);
  }

  // ─── Container lifecycle operations ───

  public async stop(providerId: string, timeoutSeconds?: number): Promise<void> {
    let url = `${this.#apiBase}/containers/${encodeURIComponent(providerId)}/stop`;
    if (timeoutSeconds !== undefined) url += `?t=${String(timeoutSeconds)}`;
    const resp = await this.#fetch(url, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (resp.status === 304) return; // already stopped
    if (!resp.ok) {
      const body = await resp.text().catch(() => '');
      throw new Error(`Podman stop failed (${String(resp.status)}): ${body.slice(0, 200)}`);
    }
  }

  public async start(providerId: string): Promise<void> {
    const url = `${this.#apiBase}/containers/${encodeURIComponent(providerId)}/start`;
    const resp = await this.#fetch(url, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (resp.status === 304) return; // already started
    if (!resp.ok) {
      const body = await resp.text().catch(() => '');
      throw new Error(`Podman start failed (${String(resp.status)}): ${body.slice(0, 200)}`);
    }
  }

  public async restart(providerId: string, timeoutSeconds?: number): Promise<void> {
    let url = `${this.#apiBase}/containers/${encodeURIComponent(providerId)}/restart`;
    if (timeoutSeconds !== undefined) url += `?t=${String(timeoutSeconds)}`;
    const resp = await this.#fetch(url, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (resp.status === 304) return; // already restarting
    if (!resp.ok) {
      const body = await resp.text().catch(() => '');
      throw new Error(`Podman restart failed (${String(resp.status)}): ${body.slice(0, 200)}`);
    }
  }

  public async kill(providerId: string, signal?: string): Promise<void> {
    let url = `${this.#apiBase}/containers/${encodeURIComponent(providerId)}/kill`;
    if (signal) url += `?signal=${encodeURIComponent(signal)}`;
    const resp = await this.#fetch(url, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (resp.status === 304) return; // already stopped/killed
    if (!resp.ok) {
      const body = await resp.text().catch(() => '');
      throw new Error(`Podman kill failed (${String(resp.status)}): ${body.slice(0, 200)}`);
    }
  }

  public async pause(providerId: string): Promise<void> {
    const resp = await this.#fetch(`${this.#apiBase}/containers/${encodeURIComponent(providerId)}/pause`, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman pause failed (${String(resp.status)})`);
  }

  public async unpause(providerId: string): Promise<void> {
    const resp = await this.#fetch(`${this.#apiBase}/containers/${encodeURIComponent(providerId)}/unpause`, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman unpause failed (${String(resp.status)})`);
  }

  public async wait(providerId: string, _condition?: 'not-running' | 'next-exit'): Promise<{ statusCode: number }> {
    const resp = await this.#fetch(`${this.#apiBase}/containers/${encodeURIComponent(providerId)}/wait`, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman wait failed (${String(resp.status)})`);
    const data = await resp.json();
    return { statusCode: data.StatusCode ?? -1 };
  }

  public async exec(providerId: string, cmd: readonly string[], _containerName?: string): Promise<{ execId: string; webSocketUri?: string }> {
    // Step 1: Create exec instance
    const createResp = await this.#fetch(`${this.#apiBase}/containers/${encodeURIComponent(providerId)}/exec`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ Cmd: [...cmd], AttachStdout: true, AttachStderr: true }),
    });
    if (!createResp) throw new Error('Podman daemon unreachable');
    if (!createResp.ok) throw new Error(`Podman exec create failed (${String(createResp.status)})`);
    const { Id: execId } = await createResp.json();

    // Step 2: Start exec
    const startResp = await this.#fetch(`${this.#apiBase}/exec/${String(execId)}/start`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ Detach: false, Tty: false }),
    });
    if (!startResp) throw new Error('Podman daemon unreachable');
    if (!startResp.ok) throw new Error(`Podman exec start failed (${String(startResp.status)})`);

    return { execId };
  }

  public async rename(providerId: string, newName: string): Promise<void> {
    const resp = await this.#fetch(`${this.#apiBase}/containers/${encodeURIComponent(providerId)}/rename?name=${encodeURIComponent(newName)}`, { method: 'POST' });
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman rename failed (${String(resp.status)})`);
  }

  public async stats(providerId: string): Promise<{ cpuUsage: number; memoryUsage: number; networkIO?: { rx: number; tx: number } }> {
    const resp = await this.#fetch(`${this.#apiBase}/containers/${encodeURIComponent(providerId)}/stats?stream=false`);
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman stats failed (${String(resp.status)})`);
    const data = await resp.json();
    const netKeys = data.networks ? Object.keys(data.networks) : [];
    return {
      cpuUsage: data.cpu_stats?.cpu_usage?.total_usage ?? 0,
      memoryUsage: data.memory_stats?.usage ?? 0,
      ...(netKeys.length > 0 ? { networkIO: { rx: data.networks![netKeys[0]!]?.rx_bytes ?? 0, tx: data.networks![netKeys[0]!]?.tx_bytes ?? 0 } } : {}),
    };
  }

  public async top(providerId: string, psArgs?: string): Promise<{ processes: readonly (readonly string[])[] }> {
    let url = `${this.#apiBase}/containers/${encodeURIComponent(providerId)}/top`;
    if (psArgs) url += `?ps_args=${encodeURIComponent(psArgs)}`;
    const resp = await this.#fetch(url);
    if (!resp) throw new Error('Podman daemon unreachable');
    if (!resp.ok) throw new Error(`Podman top failed (${String(resp.status)})`);
    const data = await resp.json();
    return { processes: data.Processes ?? [] };
  }

  /** Fetch with connection error protection. Returns null when Podman is down. */
  async #fetch(url: string, init?: RequestInit): Promise<Response | null> {
    try {
      return await fetch(url, init);
    } catch {
      return null;
    }
  }

  async #toRuntime(containerId: string): Promise<ContainerGroupRuntime | null> {
    const resp = await fetch(`${this.#apiBase}/containers/${containerId}/json`);
    if (resp.status === 404) return null;
    if (!resp.ok) return null;

    const info = await resp.json();
    const created = new Date(info.Created).toISOString();

    return {
      providerId: info.Id,
      name: info.Name.replace(/^\//, '') ?? '',
      status: mapPodmanState(info.State.Status),
      regionId: createRegionId('local'),
      creationTime: created,
      instanceType: 'podman',
      cpu: 0,
      memory: 0,
      network: {
        ...(info.NetworkSettings?.IPAddress ? { privateIp: info.NetworkSettings.IPAddress } : {}),
      },
      associatedResources: [],
      restartPolicy: info.HostConfig?.RestartPolicy?.Name ?? 'OnFailure',
      containers: [{
        id: createContainerId(info.Id ?? 'unknown'),
        name: info.Name.replace(/^\//, ''),
        image: info.Config?.Image ?? '',
        args: info.Config?.Cmd ?? [],
        env: parseEnv(info.Config?.Env),
        workingDir: info.Config?.WorkingDir ?? '',
        status: podmanToOciStatus(info.State.Status),
        alive: info.State.Running,
        createdAt: created,
        startedAt: info.State.StartedAt,
        finishedAt: info.State.FinishedAt,
        exitCode: info.State.ExitCode,
        labels: info.Config?.Labels ?? {},
        annotations: {},
        mounts: (info.Mounts ?? []).map((m: { Source?: string; Destination?: string; Type?: string; Mode?: string }) => ({
          source: m.Source ?? '',
          destination: m.Destination ?? '',
          type: m.Type,
          options: m.Mode ? [m.Mode] : undefined,
        })),
        health: {
          status: info.State.Running
            ? (info.State.Health?.Status ?? 'none')
            : 'starting',
          ...(info.State.Health?.FailingStreak && info.State.Health.FailingStreak > 0 ? { message: `Failing health check (${String(info.State.Health.FailingStreak)})` } : {}),
        },
      }] as unknown as readonly [],
      volumes: [],
      events: runtimeEvents(info),
      tags: [{ key: 'provider', value: 'podman' }],
    };
  }
}

/** Synthesize ContainerGroupRuntimeEvent[] from Podman container inspect. */
function runtimeEvents(info: PodmanInspectResult): { reason: string; type: 'Normal' | 'Warning'; message: string; count: number; lastTimestamp?: string }[] {
  const events: { reason: string; type: 'Normal' | 'Warning'; message: string; count: number; lastTimestamp?: string }[] = [];
  const ts = info.State?.StartedAt || info.Created;

  if (info.State?.Running && info.State?.StartedAt) {
    events.push({ reason: 'Started', type: 'Normal', message: 'Container started', count: 1, lastTimestamp: info.State.StartedAt });
  }
  if (info.State?.Status === 'exited' || info.State?.Status === 'stopped') {
    events.push({ reason: 'Stopped', type: 'Normal', message: `Container exited with code ${String(info.State.ExitCode ?? '?')}`, count: 1, lastTimestamp: info.State.FinishedAt ?? ts });
  }
  if (info.State?.Health?.Status === 'healthy') {
    events.push({ reason: 'HealthCheck', type: 'Normal', message: 'Health check passed', count: info.State.Health.Log?.length ?? 1, lastTimestamp: info.State.Health.Log?.[info.State.Health.Log.length - 1]?.End ?? ts });
  }
  if (info.State?.Health?.Status === 'unhealthy') {
    events.push({ reason: 'Unhealthy', type: 'Warning', message: `Health check failed (${String(info.State.Health.FailingStreak)}x)`, count: info.State.Health.FailingStreak ?? 1, lastTimestamp: ts });
  }
  if (info.State?.Error && info.State.Error !== '') {
    events.push({ reason: 'Error', type: 'Warning', message: info.State.Error, count: 1, lastTimestamp: ts });
  }

  return events;
}

// ─── Helpers ───

function podmanToOciStatus(status: string | undefined): OciContainerStatus {
  switch (status) {
    case 'running': return 'running';
    case 'paused': return 'paused';
    case 'exited':
    case 'dead': return 'stopped';
    case 'created': return 'created';
    default: return 'creating';
  }
}

function mapPodmanState(state: string): ContainerGroupRuntime['status'] {
  switch (state) {
    case 'running': return 'Running';
    case 'paused': return 'Running';
    case 'exited': return 'Succeeded';
    case 'dead': return 'Failed';
    case 'created': return 'Pending';
    default: return 'Pending';
  }
}

function podmanStatus(c: PodmanContainer): string {
  const s = c.State ?? '';
  return mapPodmanState(s);
}

function parseEnv(env?: string[]): Record<string, string> {
  if (!env) return {};
  const out: Record<string, string> = {};
  for (const e of env) {
    const eq = e.indexOf('=');
    if (eq > 0) out[e.slice(0, eq)] = e.slice(eq + 1);
  }
  return out;
}

// ─── Bind mount path validation ───

/** Paths whose direct bind-mount is always denied regardless of intent. */
const SENSITIVE_HOST_PATHS = new Set([
  '/etc/shadow',
  '/etc/gshadow',
  '/etc/sudoers',
  '/etc/sudoers.d',
  '/var/run/docker.sock',
  '/var/run/docker-ce.sock',
  '/run/docker.sock',
  '/run/docker-ce.sock',
]);

/** Path prefixes whose bind-mount is denied (catches sub-paths). */
const SENSITIVE_HOST_PREFIXES = [
  '/proc/',
  '/sys/',
  '/dev/',
  '/boot/',
  '/etc/ssh/',
  '/root/.ssh/',
  '/root/.docker/',
];

/**
 * Validate that a host path is allowed for bind-mount into containers.
 * Blocks well-known sensitive paths that could enable container escape,
 * credential theft, or host filesystem tampering.
 */
function isBindMountAllowed(hostPath: string): boolean {
  if (SENSITIVE_HOST_PATHS.has(hostPath)) return false;
  for (const prefix of SENSITIVE_HOST_PREFIXES) {
    if (hostPath.startsWith(prefix) || hostPath.startsWith(prefix.replace(/\/$/, ''))) return false;
  }
  return true;
}

/**
 * AWS S3 provider — SigV4 auth via S3ClientBase.
 * No SDK dependency: pure HTTP + SigV4 signing via Web Crypto API.
 */
import { S3ClientBase, encodeKey } from '../../core/provider/s3-client.ts';
import type { S3ProviderConfig } from '../../core/provider/s3-types.ts';
import { signSigV4, signPresignedUrl, emptyPayloadHash, extractServerTimeFromError } from '../../core/provider/s3-signer.ts';
import type { SigV4Credentials } from '../../core/provider/s3-signer.ts';

const CLOCK_SKEW_RETRIES = 2;

export class AwsS3Provider extends S3ClientBase {
  public readonly type = 'aws-s3' as const;
  readonly #region: string;
  readonly #endpoint: string;
  readonly #credentials: SigV4Credentials;
  #clockOffset = 0;

  public constructor(credentials: SigV4Credentials, region: string, endpoint?: string, config?: S3ProviderConfig) {
    super(config);
    this.#credentials = credentials;
    this.#region = region;
    this.#endpoint = endpoint ?? `https://s3.${region}.amazonaws.com`;
  }

  #signingTime(): Date {
    return new Date(Date.now() + this.#clockOffset);
  }

  protected endpointFor(_bucket: string): string {
    return this.#endpoint;
  }

  protected async authFetch(url: string, method: string, path: string, queryString: string, headers: Record<string, string>, bodyHash: string, body?: BodyInit): Promise<Response> {
    for (let attempt = 0; attempt <= CLOCK_SKEW_RETRIES; attempt++) {
      const authHeaders = await signSigV4(method, path, queryString, headers, bodyHash || emptyPayloadHash(), this.#credentials, this.#region, 's3', this.#signingTime());
      const res = await fetch(url, { method, headers: { ...headers, ...authHeaders }, ...(body !== undefined ? { body } : {}) });

      if (res.ok || res.status === 404) return res;

      if (res.status === 403 && attempt < CLOCK_SKEW_RETRIES) {
        const bodyText = await res.clone().text().catch(() => '');
        const serverTime = extractServerTimeFromError(bodyText);
        if (serverTime) {
          const serverTs = serverTime.getTime();
          if (!isNaN(serverTs)) {
            this.#clockOffset = serverTs - Date.now();
            continue;
          }
        }
      }
      throw new Error(`S3 ${method} failed: ${String(res.status)} ${await res.text()}`);
    }
    throw new Error(`S3 ${method} failed after ${String(CLOCK_SKEW_RETRIES)} retries`);
  }

  public async getPresignedUrl(bucket: string, key: string, expiresInSeconds = 3600): Promise<string> {
    const path = `/${this.bucketMapping(bucket)}/${encodeKey(key)}`;
    const hostname = new URL(this.#endpoint).hostname;
    const url = await signPresignedUrl('GET', path, this.#credentials, this.#region, 's3', expiresInSeconds, this.#signingTime(), hostname);
    return url.toString();
  }

  public async putPresignedUrl(bucket: string, key: string, expiresInSeconds = 3600): Promise<string> {
    const path = `/${this.bucketMapping(bucket)}/${encodeKey(key)}`;
    const hostname = new URL(this.#endpoint).hostname;
    const url = await signPresignedUrl('PUT', path, this.#credentials, this.#region, 's3', expiresInSeconds, this.#signingTime(), hostname);
    return url.toString();
  }
}

